<script setup>
import { ref } from "vue";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import comMessage from "@/constants/com-message.js";
import StringUtil from "@/utils/common/string-util.js"

//////////////////////////
// データ定義
//////////////////////////
const head = ref();
const screenName = "アクセス権エラー";
const E00Name = "ログアウトリンク";

//////////////////////////
// メソッド
//////////////////////////
const linkClick = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E00Name]));
  head.value.logoutClick();
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E00Name]));
}
</script>

<template>
  <Header ref="head" :isShow="false" />
  <div class="contents orgheight align-items-center">
    <div class="text-center">
      <label for="errMsg">利用権限のないユーザによるアクセスが行われました。<br />
        (長時間操作がなかったため、ログアウトされた可能性があります)<br />
        ユーザIDを確認し、<a href="#" @click.prevent.stop="linkClick">ログアウト</a>後、再度ログインをしてください。
      </label>
    </div>
  </div>
  <Footer />
</template>

<style scoped>
.orgheight {
  display: grid;
}
</style>