/**
 * 「初期表示」イベント
 */
 const ENT0301100E01 = async () =>{
  // ローディングの表示
  loadingModal.isshow(true);
  // 経営情報等一覧照会APIの呼び出し
  const reqParam = [
     [
       comConst.API_ID_ENT0301_38,
       {
         corporationId: targetCorp().corporationId,
         fiscalYear: targetCorp().fiscalYear
       },
     ],
  ];
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // 画面項目設定
    await setScreenItems(res);
    if ('1' === notificationLaterFlg.value) {
      uploadFlg.value = false;
      checkLater.value = true;
    } else {
      if (uploadJudgeFlg.value) {
        // アップロードボタン非活性
        uploadFlg.value = false;
      } else {
        // アップロードボタン活性
        uploadFlg.value = true;
      }
      checkLater.value = false;
    }
    // 排他制御
    await mutualExclusion(res[0].data.fileOpeMngSeqList[0]);
  // 結果コード = "1"（異常終了）の場合
  } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    messageErr.value = [res[0].data.messageErr, ...formatMessage(inputChkMessageErrList.value)];
  } else {
    // 処理無し
  }
    // 終了ログ出力
    console.log(StringUtil.convertString(comMessage.COMMON000005I, ["経営情報等一覧"]));
}

/**
 * 排他制御(前処理)
 */
const mutualExclusion = async (uploadingFileOpeMngSeq) => {
  // アップロード中のファイルあり
  if (uploadingFileOpeMngSeq) {
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000001I, ["事業報告書または経営情報等データのアップロード"])];
    // アップロードドロップダウンメニューを押下不可
    isUploadProcessing.value = true;
    // 非同期バッチ監視API呼び出しパラメータ設定
    const reqParam = [
      [
        comConst.API_ID_ENT0201_04,
        { fileOperationManageSeq: uploadingFileOpeMngSeq },
      ],
    ];
    // 排他制御(定期的に呼び出す)
    const intervalId = setInterval(function () {
      let finishFlg = singleMutualExclusion(reqParam);
      if (finishFlg) {
        clearInterval(intervalId);
      }
    }, comProperty.POLLING_INTERVAL);
  }
};

/**
 * 排他制御
 */
const singleMutualExclusion = async (reqParam) => {
  let finishFlg = true;
  // 非同期バッチ監視API呼び出し
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // ステータスが未処理または処理中の場合
    if (
      [comEnum.EnumFILE_OPERATION_MANAGE_STATUS.UNTREATED.val, comEnum.EnumFILE_OPERATION_MANAGE_STATUS.PROCESSING.val].includes(res[0].data.status)
      ) {
      finishFlg = false;
    // ステータスが完了の場合
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.COMPLETED.val) {
      finishFlg = true;
      // ローディングの非表示
      loadingModal.isshow(false);
      // アップロードドロップダウンメニューの押下不可を解除
      isUploadProcessing.value = false;
      // 経営情報等一覧照会API呼び出しパラメータ設定
      const reqParam = [
        [
          comConst.API_ID_ENT0301_38,
          {
            corporationId: targetCorp().corporationId,
            fiscalYear: targetCorp().fiscalYear
          },
        ],
      ];
      // 経営情報等一覧照会API呼び出し
      const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

      // 結果コード = "0"（正常終了）の場合
      if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
        // ローディングの非表示
        loadingModal.isshow(false);
        // アップロードドロップダウンメニューの押下不可を解除
        isUploadProcessing.value = false;
        // アップロード完了メッセージ設定
        messageInfo.value = [StringUtil.convertString(comMessage.COMMON000000I, ["アップロード"])];
        // 画面項目設定
        await setScreenItems(res);

      // 結果コード = "1"（異常終了）の場合
      } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
        // ローディングの非表示
        loadingModal.isshow(false);
        // メッセージ設定
        messageErr.value = [...res[0].data.messageErr.value, ...formatMessage(inputChkMessageErrList.value)];
      } else {
        // 処理無し
      }
    // ステータスがエラーの場合
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.ERR.val) {
      finishFlg = true;
      // ローディングの非表示
      loadingModal.isshow(false);
      // アップロードドロップダウンメニューの押下不可を解除
      isUploadProcessing.value = false;
      // アップロード失敗メッセージ設定
      messageInfo.value = [];
      messageErr.value = [StringUtil.convertString(comMessage.COMMON000018E, ["アップロード"]), ...formatMessage(inputChkMessageErrList.value)];
    }
  // 上記以外
  } else {
    // 処理無し
  }
  return finishFlg;
};

