/**
 * 入力フォームの一括アップロード（Excel, CSV）のモーダルでアップロードボタンクリック時イベント
 */
const fileUpload = async () => {
  // 開始ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000006I, ["経営情報等一覧画面", "アップロードボタンクリック"]));

  let errMessages;
  // アップロードファイルチェック
  if (eventId == "uploadCsv") {
    uploadingFileObject.value = [fileUploadModal.value.getFile()];
    errMessages = ComFileUpload.checkUploadFile(fileUploadModal.value.getFile(), [fileExtension.value]);
  } else if (eventId == "uploadExcel") {
    if (selectedFiles.value.length > 0) {
      selectedFiles.value.forEach(file => {
        errMessages = ComFileUpload.checkUploadFile(file, [fileExtension.value]);
        if (errMessages.length != 0) {
          return;
        }
      });
    }
    let errMsg = ComFileUpload.checkMaxRequestSize(selectedFiles.value);
    if (errMsg.length != 0) {
      errMessages = [...errMessages, errMsg];
    } else {
      errMessages = [...errMessages];
    }
    uploadingFileObject.value = [...selectedFiles.value];
  }

  if (errMessages && errMessages.length > 0) {
    messageInfo.value = [];
    messageErr.value = [...errMessages, ...formatMessage(inputChkMessageErrList.value)];
    // ローディングの非表示
    loadingModal.isshow(false);
    fileUploadModal.value.hide();
    uploadModal.value.hide();
    fileUploadModal.value.reset();
    clearSelectedFiles();
    return;
  }

  if (eventId == "uploadCsv") {
    fileUploadModal.value.hide();
    fileUploadModal.value.reset();
  } else if (eventId == "uploadExcel") {
    uploadModal.value.hide();
    clearSelectedFiles();
  }

  // 確認ダイヤログ表示
  modaltitle.value = "";
  modalmsg.value = StringUtil.convertString(comMessage.COMMON000000C, ["アップロード"]);
  commonModal.value.show();

  // 終了ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000007I, ["経営情報等一覧画面", "アップロードボタンクリック"]));
};

/**
 * 選択した複数ファイルを一覧で表示
 */
const showUploadFiles = async (fileList) => {
  if ( fileList !== null){
    selectedFiles.value = fileList.concat(selectedFiles.value);
  }
};

/**
 * 選択済みファイルをクリアする
 */
const clearSelectedFiles = async () => {
    selectedFiles.value = [];
};

/**
 * CommonDialogを閉じる際のイベント
 */
const closeModal = async (modalReturn) => {
  // 開始ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000006I, ["経営情報等一覧画面", "ダイヤログを閉じる"]));
  if (modalReturn == 2) {
    // キャンセル押されたとき
      return;
  }
  if (eventId == "uploadCsv") {
    const reqParamData = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      prefCode: targetCorp().prefCode,
      seq: "0",
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_MGT_INFO_ETC.val,
      operationId: comEnum.EnumOPE_ID.CSV_BULK_UL.val,
      screenId: commonInfo().screenId,
    };
    await callUploadApi(reqParamData);
  } else if (eventId == "uploadExcel") {
    const reqParamData = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      prefCode: targetCorp().prefCode,
      seq: "0",
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_MGT_INFO_ETC.val,
      operationId: comEnum.EnumOPE_ID.EXCEL_FORM_BULK_UL.val,
      screenId: commonInfo().screenId,
    };
    await callUploadApi(reqParamData);
  } else if (eventId == "downloadBlankForm") {
    const reqParamData = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      seq: null,
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_MGT_INFO_ETC.val,
      operationId: comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_BULK_UL.val,
      screenId: commonInfo().screenId,
    };
    isDownloadBlankForm = true;
    isDownloadInputtedExcel = false;
    await callRequestDownloadApi(reqParamData);
  } else if (eventId == "downloadInputtedExcel") {
    const reqParamData = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      seq: null,
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_MGT_INFO_ETC.val,
      operationId: comEnum.EnumOPE_ID.EXCEL_FORM_BULK_INP_DL.val,
      screenId: commonInfo().screenId,
    };
    isDownloadBlankForm = false;
    isDownloadInputtedExcel = true;
    await callRequestDownloadApi(reqParamData);
  } else if (eventId == "downloadUploadedCsv") {
    const reqParamData = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      seq: "0",
      prefCode: targetCorp().prefCode,
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_MGT_INFO_ETC.val,
      uploadOperationId: comEnum.EnumOPE_ID.CSV_BULK_UL.val,
      downloadOperationId: comEnum.EnumOPE_ID.UL_CSV_FORM_BULK_DL.val,
      attachDocumentId: null,
      screenId: commonInfo().screenId,
    };
    await callDownloadSyncApi(reqParamData);
  } else if (eventId == "downloadUploadedExcel") {
    const reqParamData = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      seq: "0",
      prefCode: targetCorp().prefCode,
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_MGT_INFO_ETC.val,
      uploadOperationId: comEnum.EnumOPE_ID.EXCEL_FORM_BULK_UL.val,
      downloadOperationId: comEnum.EnumOPE_ID.UL_EXCEL_FORM_BULK_DL.val,
      attachDocumentId: null,
      screenId: commonInfo().screenId,
    };
    await callDownloadSyncApi(reqParamData);
  } else if (eventId == "updateNotificationFlg") {
    if (modalReturn != 1) {
      checkLater.value = !checkLater.value;
      return;
    }
    const reqParamData = {
       corporationId: targetCorp().corporationId,
       fiscalYear: targetCorp().fiscalYear,
       notificationType: targetCorp().notificationType,
       notificationLaterFlg: checkLater.value ? "1" : "0",
       screenId: commonInfo().screenId,
    };
    await callUpdateNotificationLaterFlgApi(reqParamData);
  }
  // 終了ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000007I, ["経営情報等一覧画面", "ダイヤログを閉じる"]));
};

/**
 * アップロードAPI呼び出し
 */
const callUploadApi = async (reqParamData) => {
  // ローディングの表示
  loadingModal.isshow(true);
  // アップロードAPI呼び出しパラメータ設定
  const formData = new FormData();
  formData.append(
    "UploadUnSyncRequestDto",
    new Blob([JSON.stringify(reqParamData)], { type: "application/json" })
  );
  uploadingFileObject.value.forEach(file => {
    formData.append("uploadFiles", file);
  });
  const reqParam = [
    [
      comConst.API_ID_ENT0201_29, // パスパラメータ
      // リクエストパラメータ
      formData,
      "multipart/form-data",
    ],
  ];
  // アップロードAPI呼び出し
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    messageInfo.value = StringUtil.convertString(comMessage.COMMON000000I, ["経営情報等データのアップロード"]);
    // 排他制御
    await mutualExclusion(res[0].data.fileOperationManageSeq);
  // 結果コード = "1"（異常終了）の場合
  } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    messageErr.value = [res[0].data.messageErr, ...formatMessage(inputChkMessageErrList.value)];
    messageInfo.value = res[0].data.messageInfo;
    messageWarn.value = res[0].data.messageWarn;
  } else {
    // 処理無し
  }
};

/**
 * ダウンロード依頼API呼び出し
 */
const callRequestDownloadApi = async (reqParamData) => {
  // ローディングの表示
  loadingModal.isshow(true);
  const reqParam = [
    [
      comConst.API_ID_ENT0201_16,
      reqParamData,
    ],
  ];
  // ダウンロード依頼API呼び出し
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000003I, ["ダウンロード"])];
    // ダウンロード監視
    await monitorDownload(res[0].data.fileOperateManageSeq);
  // 結果コード = "1"（異常終了）の場合
  } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    clearMessage();
    messageErr.value = [res[0].data.messageErr, ...formatMessage(inputChkMessageErrList.value)];
  } else {
    // 処理無し
  }
};

/**
 * ダウンロード（同期用）API呼び出し
 */
const callDownloadSyncApi = async (reqParamData) => {
  // ローディングの表示
  loadingModal.isshow(true);
  // ダウンロード（同期用）API呼び出しパラメータ設定
  const reqParam = [
    [
      comConst.API_ID_ENT0201_07, // パスパラメータ
      // リクエストパラメータ
      reqParamData,
    ],
  ];
  // ダウンロード（同期用）依頼API呼び出し
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // ダウンロード完了メッセージ設定
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000000I, ["ダウンロード"])];
  // 結果コード = "1"（異常終了）の場合
  } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
    // ローディングの非表示
    loadingModal.isshow(false);
    clearMessage();
    if (res[0].data.messageErr.length > 0) {
      // メッセージ設定
      messageErr.value = [res[0].data.messageErr, ...formatMessage(inputChkMessageErrList.value)];
    } else {
      // メッセージ設定
      messageErr.value = [StringUtil.convertString(comMessage.COMMON000009E, ["ダウンロード"]), ...formatMessage(inputChkMessageErrList.value)];
    }
  // 上記以外
  } else {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    messageErr.value = [StringUtil.convertString(comMessage.COMMON000009E, ["ダウンロード"]), ...formatMessage(inputChkMessageErrList.value)];
