/**
 * ダウンロード監視(事前処理)
 */
const monitorDownload = async (downloadingFileOpeMngSeq) => {
  // ダウンロード中ファイル有り
  if (downloadingFileOpeMngSeq) {
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000003I, ["ダウンロード"])];
    // ダウンロードドロップダウンメニューを押下不可
    if (isDownloadBlankForm) {
      isDownloadBlankFormProcessing.value = true;
    } else if (isDownloadInputtedExcel) {
      isDownloadInputtedExcelProccessing.value = true;
    }
    // 非同期バッチ監視API呼び出しパラメータ設定
    const reqParam = [
      [
        comConst.API_ID_ENT0201_04,
        { fileOperationManageSeq: downloadingFileOpeMngSeq },
      ],
    ];
    // 排他制御(1秒ごと繰り返し)
    const intervalId = setInterval(function () {
      let finishFlg = singleMonitorDownload(reqParam, downloadingFileOpeMngSeq);
      if (finishFlg) {
        clearInterval(intervalId);
      }
    }, comProperty.POLLING_INTERVAL);
  } else {
    clearMessage();
    messageErr.value = [StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード依頼"]), ...formatMessage(inputChkMessageErrList.value)];
  }
};

/**
 * ダウンロード監視(1回)
 */
const singleMonitorDownload = async (reqParam, downloadingFileOpeMngSeq) => {
  let finishFlg = true;
  // 非同期バッチ監視API呼び出し
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // ステータスが未処理または処理中の場合
    if (
      [comEnum.EnumFILE_OPERATION_MANAGE_STATUS.UNTREATED.val, comEnum.EnumFILE_OPERATION_MANAGE_STATUS.PROCESSING.val].includes(res[0].data.status)
    ) {
      finishFlg = false;
    // ステータスが完了の場合
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.COMPLETED.val) {
      finishFlg = true;
      // ダウンロードAPI呼び出しパラメータ設定
      const reqParam = [
        [
          comConst.API_ID_ENT0201_01,
          {
            fileOpeMngSeq: downloadingFileOpeMngSeq,
          },
        ],
      ];
      // ダウンロードAPI呼び出し
      const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

      // 結果コード = "0"（正常終了）の場合
      if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
        // ダウンロードドロップダウンメニューの押下不可を解除
        if (isDownloadBlankForm) {
          isDownloadBlankFormProcessing.value = false;
        } else if (isDownloadInputtedExcel) {
          isDownloadInputtedExcelProccessing.value = false;
        }
        // ダウンロード完了メッセージ設定
        messageInfo.value = [StringUtil.convertString(comMessage.COMMON000000I, ["ダウンロード"])];
      // 上記以外
      } else {
        // ダウンロードドロップダウンメニューの押下不可を解除
        if (isDownloadBlankForm) {
          isDownloadBlankFormProcessing.value = false;
        } else if (isDownloadInputtedExcel) {
          isDownloadInputtedExcelProccessing.value = false;
        }
        // ダウンロード失敗メッセージ設定
        clearMessage();
        messageErr.value = [StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]), ...formatMessage(inputChkMessageErrList.value)];
      }
    // ステータスがエラーの場合
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.ERR.val) {
      finishFlg = true;
      // ダウンロードドロップダウンメニューの押下不可を解除
      if (isDownloadBlankForm) {
          isDownloadBlankFormProcessing.value = false;
        } else if (isDownloadInputtedExcel) {
          isDownloadInputtedExcelProccessing.value = false;
        }
      // ダウンロード失敗メッセージ設定
      clearMessage();
      messageErr.value = [StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]), ...formatMessage(inputChkMessageErrList.value)];
    }
  // 上記以外
  } else {
    // 処理無し
  }
  return finishFlg;
};

/**
 * 「後日届出を行う」チェッククリック
 */
const callUpdateNotificationLaterFlgApi = async (reqParamData) =>{
  // 開始ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000006I, ["経営情報等一覧画面", "「後日届出を行う」チェッククリック"]));
  // ローディングの表示
  loadingModal.isshow(true);
  // 後日届出フラグ更新APIの呼び出し
  const reqParam = [
     [
       comConst.API_ID_ENT0301_46,
       reqParamData,
     ],
  ];
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    notificationLaterFlg.value = checkLater.value ? "1" : "0";
    // アップロードボタンの制御
    if (checkLater.value) {
      uploadFlg.value = false;
    } else {
      uploadFlg.value = true;
    }
    tableObj.destroy();
    initializeDataTable();
    // 経営情報等一覧タブのアイコン更新
    iconClassManageInfo();
    // 後日届出更新メッセージ設定
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000000I, ["後日届出更新"])];
  // 結果コード = "1"（異常終了）の場合
  } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージ設定
    messageErr.value = [...res[0].data.messageErr, ...formatMessage(inputChkMessageErrList.value)];
    checkLater.value = !checkLater.value;
  } else {
    checkLater.value = !checkLater.value;
  }
  // 終了ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000007I, ["経営情報等一覧画面", "「後日届出を行う」チェッククリック"]));
};

