const setScreenItems = async (res) => {
  messageErrList.value = res[0].data.messageErr;
  messageWarn.value = res[0].data.messageWarn;
  inputChkMessageErrList.value = res[0].data.inputChkMessageErr;
  messageErr.value = [...messageErrList.value, ...formatMessage(inputChkMessageErrList.value)];
  csvFileOpeMngSeq.value = res[0].data.csvFileOpeMngSeq;
  excelFileOpeMngSeq.value = res[0].data.excelFileOpeMngSeq;
  isCsvUploaded.value = res[0].data.csvFileOpeMngSeq ? true : false;
  isExcelUploaded.value = res[0].data.excelFileOpeMngSeq ? true : false;
  notificationLaterFlg.value = res[0].data.notificationLaterFlg;
  notificationStatus.value = res[0].data.notificationStatus;
  notificationMethod.value = res[0].data.notificationMethod;
  managementDataList.value = res[0].data.managementDataList.map(item => {
    let mngInfoInpFlg;
    if ('1' === item.reportNotApplicableFlg) {
      mngInfoInpFlg = '4'
    } else if ('0' === item.mngInfoInpSituation) {
      mngInfoInpFlg = '3'
    } else if ('1' === item.mngInfoInpSituation) {
      mngInfoInpFlg = '1'
    } else if ('2' === item.mngInfoInpSituation) {
      mngInfoInpFlg = '2'
    }
    return {...item, mngInfoInpFlg}
  });
  // 入力画面ボタン表示名判定
  isValidCombination();
  // 経営情報一覧ステータス判定
  iconClassManageInfo();
};

/**
 * メッセージクリア
 */
 const clearMessage = () => {
  messageInfo.value = [];
  messageErr.value = [];
  messageWarn.value = [];
};

/**
 * 種別の変換
 */
const convertHospitalClinicType = (hospitalClinicType) => {
  if (hospitalClinicType === '1') {
    return "病院";
  } else {
    return "診療所";
  }
};

/**
 * メッセージの改行
 */
const formatMessage = (message) => {
  return message.flatMap(error => error.split('\\n').map(e => e.trim()).filter(e => e != ''));
};

/**
 * 経営情報等一覧ステータスアイコン表示制御
 */
const iconClassManageInfo = () => {
  const allOne = managementDataList.value.every(info => info.mngInfoInpSituation === '1');
  const hasTwo = managementDataList.value.some(info => info.mngInfoInpSituation === '2');
  const hasZero = managementDataList.value.some(info => info.mngInfoInpSituation === '0');

  if ("0" === notificationLaterFlg.value) {
    if (allOne) {
      iconClass.value = 'bi bi-record-circle-fill text-success';
    } else if (hasTwo) {
      iconClass.value = 'bi bi-triangle-fill text-warning';
    } else if (hasZero) {
      iconClass.value = 'bi bi-dash text-danger';
    }
  } else {
    iconClass.value = 'bi bi-record-circle-fill text-success';
  }
};

/**
 * 操作ボタン入力・照会判定
 */
const isValidCombination = () => {
  // 医療法人
  const validUserType1 = [
  comEnum.EnumNOTICE_STATUS.CORP_INP_WAIT.val,      // S1
  comEnum.EnumNOTICE_STATUS.CORP_INP_COMP_WAIT.val, // S2
  comEnum.EnumNOTICE_STATUS.REMAND.val              // S3
  ];

  // 都道府県
  const validUserType2 = [
  comEnum.EnumNOTICE_STATUS.PREF_APPR_WAIT.val      // S4
  ];

  // 代理入力
  const validUserType3 = [
  comEnum.EnumNOTICE_STATUS.CORP_INP_WAIT.val,      // S1
  comEnum.EnumNOTICE_STATUS.CORP_INP_COMP_WAIT.val, // S2
  comEnum.EnumNOTICE_STATUS.REMAND.val              // S3
  ];

  if (comEnum.EnumUSER_TYPE.MEDIC_CORP.val === userType.value) {
    buttonControlFlg.value = validUserType1.includes(notificationStatus.value);
    if (!buttonControlFlg.value) {
      // S4,S5はアップロードボタン非活性
      uploadJudgeFlg.value = true;
    }
  } else if (comEnum.EnumUSER_TYPE.PREF_STAFF.val === userType.value) {
    buttonControlFlg.value = validUserType2.includes(notificationStatus.value);
    // 都道府県はアップロードボタン非活性
    uploadJudgeFlg.value = true;
  } else if (comEnum.EnumUSER_TYPE.PROXY_INPUT_STAFF.val === userType.value) {
    buttonControlFlg.value = validUserType3.includes(notificationStatus.value);
    // S4,S5はアップロードボタン非活性
    if (!buttonControlFlg.value) {
      uploadJudgeFlg.value = true;
    }
  } else {
    // 機構職員はアップロードボタン非活性
    uploadJudgeFlg.value = true;
  }
};

