 法人情報登録・参照画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted, onUnmounted } from "vue";
import { useRouter, useRoute } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import Menu from "@/components/common/Menu.vue";
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import commonInfo from "@/store/common/common-info.js";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import MNM0201200Save from "@/store/MNM0201200/MNM0201200-save.js";
import MNM0301200Param from "@/store/MNM0301200/mnm0301200-param.js";
import loadingModal from "@/utils/common/loading-modal.js";
import targetCorp from "@/store/common/target-corp.js";
import apiCaller from "@/utils/common/api-caller.js";
import comDate from "@/utils/common/com-date.js";
import stringUtil from "@/utils/common/string-util.js";
import comMessage from "@/constants/com-message.js";
import CommonDialog from "@/components/common/CommonDialog.vue";
import DeleteDialog from "@/components/common/CommonDialog.vue";
import RegistDialog from "@/components/common/CommonDialog.vue";
import validator from "@/utils/common/validator.js";

//////////////////////////
// データ定義
//////////////////////////

const router = useRouter();
const route = useRoute();

/** モーダルメッセージ用 */
const modalmsg = ref("");
const modaltitle = ref("");
const modalOkBtn = ref("");
const modalCancelBtn = ref("");
const modalCloseBtn = ref("");
const showDeleteModal = ref();
const showRegistModal = ref();
const deleteModal = ref();
const registModal = ref();

/** ユーザ種別  */
const userType = ref("");

/** ユーザ種別Enum */
const enumUserType = comEnum.EnumUSER_TYPE;

/** モードフラグ */
const viewFlg = ref("参照");
const newFlg = ref("登録");
const editFlg = ref("編集");
const buttonFlg = ref(false);
const errorFlg = ref(false);
const breadcrumbListFlg = ref(false);
const showPrefNameFlg = ref(false);

/** 画面モード */
const screenMode = ref("");

/** パンくずリスト */
const breadcrumbObj = ref();

/** エラーメッセージ */
const errorMessages = ref({});

/** APIエラーメッセージ */
const errorMsg = ref("");

/** パスワード強制変更種別Enum */
const enumUploadNotificationExistType = comEnum.EnumUPLOAD_NOTIFICATION_EXIST_TYPE;

/** 会計年度の決算月Enum */
const enumMonthDivision = comEnum.EnumMONTH_DIVISION;

/** パスワード強制変更種別(ラジオボタン用) */
const radioNotificationExistType = ref([
  { dispname: enumUploadNotificationExistType.AVAILBLE.dispname, val: enumUploadNotificationExistType.AVAILBLE.val },
  { dispname: enumUploadNotificationExistType.NOT_AVAILBLE.dispname, val: enumUploadNotificationExistType.NOT_AVAILBLE.val },
]);

/** 会計年度の決算月(チェックボックス用) */
const checkboxMonthDivision = ref([
  { dispname: enumMonthDivision.JANUARY.dispname, val: enumMonthDivision.JANUARY.val },
  { dispname: enumMonthDivision.FEBRUARY.dispname, val: enumMonthDivision.FEBRUARY.val },
  { dispname: enumMonthDivision.MARCH.dispname, val: enumMonthDivision.MARCH.val },
  { dispname: enumMonthDivision.APRIL.dispname, val: enumMonthDivision.APRIL.val },
  { dispname: enumMonthDivision.MAY.dispname, val: enumMonthDivision.MAY.val },
  { dispname: enumMonthDivision.JUNE.dispname, val: enumMonthDivision.JUNE.val },
  { dispname: enumMonthDivision.JULY.dispname, val: enumMonthDivision.JULY.val },
  { dispname: enumMonthDivision.AUGUST.dispname, val: enumMonthDivision.AUGUST.val },
  { dispname: enumMonthDivision.SEPTEMBER.dispname, val: enumMonthDivision.SEPTEMBER.val },
  { dispname: enumMonthDivision.OCTOBER.dispname, val: enumMonthDivision.OCTOBER.val },
  { dispname: enumMonthDivision.NOVEMBER.dispname, val: enumMonthDivision.NOVEMBER.val },
  { dispname: enumMonthDivision.DECEMBER.dispname, val: enumMonthDivision.DECEMBER.val },
]);

/** 都道府県 Enum */
const enumPrefRegistMaps = ref([]);

/** 市区町村 Enum */
const enumCityMaps = ref([]);
const enumCityRegistMaps = ref([]);

/** 法人情報 */
const corporationInfo = ref({
  corporationId: "", // 法人ID
  prefCode: "", // 登録する都道府県
  medicCorpRefNumber: "", // 医療法人整理番号
  corporationName: "", // 医療法人名称
  postalNumberFirstThree: "", // 郵便番号〒 （上）
  postalNumberLastFour: "", // 郵便番号〒 （下）
  prefName: "", // 都道府県
  cityCode: "", // 市区町村
  cityName: "", // 市区町村
  townName: "", // 町域・番地
  buildingName: "", // 建物名
  bizRepoAccepHelthCenter: "", // 届出を受付ている保健所
  chairpersonLastName: "", // 理事長の氏名（性）
  chairpersonFirstName: "", // 理事長の氏名（名）
  upldBizReportRequest: "", // アップロードによる届出の希望
  fiscalYearEnd: "", // 会計年度の決算月
  registrationDate: "", // 登記年月日
  closedDate: "", // 廃止日
});

/** ログ用 */
const screenName = "法人情報登録・参照";
const E01Name = "「戻る」ボタンクリック";
const E02Name = "「登録」ボタンクリック";
const E03Name = "「ユーザ登録追加ボタン」ボタンクリック";
const E04Name = "「削除」ボタンクリック";
const E05Name = "「代理入力」ボタンクリック";

//////////////////////////
// メソッド
//////////////////////////

// 画面マウント時イベント
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.MNM0201200;
  // パンくずリストを設定
  breadcrumbObj.value.init(commonInfo().screenId);

  // modal初期化
  deleteModal.value.init();
  registModal.value.init();
  showDeleteModal.value.init();
  showRegistModal.value.init();

  // 「初期表示」イベント
  await MNM0201200E00();
});

/**
 * 「初期表示」イベント
 */
const MNM0201200E00 = async () => {
  // 初期表示開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000004I, [screenName]));

  // ローディングの表示
  loadingModal.isshow(true);

  // データ初期化
  deleteCorporationInfo();

  // ログインユーザのユーザ種別、元画面、モードによる分岐
  userType.value = commonInfo().userType;

  // 医療法人の場合
  if (userType.value === enumUserType.MEDIC_CORP.val) {
    screenMode.value = viewFlg.value;
    // 法人情報照会処理を行う。
    await MNM010105API(targetCorp().prefCode, targetCorp().corporationId);

    // 代理入力の場合
  } else if (userType.value === enumUserType.PROXY_INPUT_STAFF.val) {
    screenMode.value = viewFlg.value;
    // 法人情報照会処理を行う。
    await MNM010105API(targetCorp().prefCode, targetCorp().corporationId);

    // 都道府県・機構職員の場合
  } else if (userType.value === enumUserType.PREF_STAFF.val || userType.value === enumUserType.MEDIC_CARE_ORG_STAFF.val) {
    // 戻した場合
    if (route.params.cameBackFlg === comConst.CAME_BACK_FLG_RETURN) {
      getMNM0201200Save();
      handleDateCheck();
    } else {
      // 新規登録の場合
      if (!isEmptyCheck(targetCorp().corporationId)) {
        // 法人情報照会処理を行う。
        await MNM010105API(targetCorp().prefCode, targetCorp().corporationId);

        if (userType.value === enumUserType.PREF_STAFF.val) {
          // 初期設定
          corporationInfo.value.prefCode = targetCorp().prefCode;
          corporationInfo.value.prefName = valueToKeyChange(targetCorp().prefName);
        } else {
          showPrefNameFlg.value = true;
        }
        corporationInfo.value.upldBizReportRequest = "1";
        screenMode.value = newFlg.value;
      } else {
        // 参照 / 更新 / 削除の場合
        screenMode.value = editFlg.value;
        await MNM010105API(targetCorp().prefCode, targetCorp().corporationId);
        // 廃止日チェック
        handleDateCheck();
      }
    }
  }
  // メニューから遷移した場合、戻るボタン設定
  backButtonCheck();
  loadingModal.isshow(false);

  // 初期表示終了ログ
  console.log(stringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * 「法人情報照会API」イベント
 */
const MNM010105API = async (prefCode, corporationId) => {
  // 法人情報照会APIの呼び出し
  const reqParam = [
    [
      comConst.API_ID_MNM0201_05,
      {
        prefCode: prefCode,
        corporationId: corporationId,
      },
    ],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    const resData = res[0].data;

    // 登録する都道府県Map設定
    const convertToEnumPrefFormat = resData.prefMap;
    Object.keys(convertToEnumPrefFormat).forEach((key) => {
      enumPrefRegistMaps.value.push({ dispname: convertToEnumPrefFormat[key], val: key });
    });

    // 都道府県Map設定
    enumCityMaps.value = resData.cityMap;
    Object.keys(enumCityMaps.value).forEach((key) => {
      enumCityRegistMaps.value.push({ dispname: enumCityMaps.value[key], val: key });
    });

    // 画面項目設定
    if (resData.corporationInfoList.length !== 0) {
      corporationInfo.value = {
        corporationId: resData.corporationInfoList[0].corporationId,
        prefCode: resData.corporationInfoList[0].prefCode,
        medicCorpRefNumber: resData.corporationInfoList[0].medicCorpRefNumber,
        corporationName: resData.corporationInfoList[0].corporationName,
        postalNumberFirstThree: resData.corporationInfoList[0].postalNumberFirstThree,
        postalNumberLastFour: resData.corporationInfoList[0].postalNumberLastFour,
        prefName: valueToKeyChange(resData.corporationInfoList[0].prefName),
        cityCode: resData.corporationInfoList[0].cityCode,
        cityName: resData.corporationInfoList[0].cityName,
        townName: resData.corporationInfoList[0].townName,
        buildingName: resData.corporationInfoList[0].buildingName,
        bizRepoAccepHelthCenter: resData.corporationInfoList[0].bizRepoAccepHelthCenter,
        chairpersonLastName: resData.corporationInfoList[0].chairpersonLastName,
        chairpersonFirstName: resData.corporationInfoList[0].chairpersonFirstName,
        upldBizReportRequest: resData.corporationInfoList[0].upldBizReportRequest,
        fiscalYearEnd: resData.corporationInfoList[0].fiscalYearEnd,
        registrationDate: resData.corporationInfoList[0].registrationDate,
        closedDate: resData.corporationInfoList[0].closedDate,
      };
    }

    // 結果コード = "1"（異常終了）の場合
  } else {
    errorFlg.value = true;
    // エラーメッセージリストを表示する
    errorMsg.value = res[0].data.messageErr.join("\n");

    // ローディングの非表示
    loadingModal.isshow(false);
  }
};

/**
 * 「戻る」ボタンクリックイベント
 */
const MNM0201200E01 = async () => {
  // 処理開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, E01Name]));

  // 画面遷移
  router.push({
    name: comConst.MNM0201100,
    params: { cameBackFlg: comConst.CAME_BACK_FLG_RETURN },
  });
  // 処理終了ログ
  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, E01Name]));
};

/**
 * 「登録」ボタンクリックイベント
 */
const MNM0201200E02 = async () => {
  // 処理開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, E02Name]));

  // 入力チェック
  const ret = await checkInput();
  if (!ret) {
    return;
  }

  // ローディングの表示
  loadingModal.isshow(true);

  // 法人情報更新APIの呼び出し
  const reqParam = [
    [
      comConst.API_ID_MNM0201_04,
      {
        corporationId: targetCorp().corporationId,
        prefCode: corporationInfo.value.prefCode,
        medicCorpRefNumber: corporationInfo.value.medicCorpRefNumber,
        corporationName: corporationInfo.value.corporationName,
        postalNumberFirstThree: corporationInfo.value.postalNumberFirstThree,
        postalNumberLastFour: corporationInfo.value.postalNumberLastFour,
        prefName: KeyToKeyValueChange(corporationInfo.value.prefName),
        cityCode: corporationInfo.value.cityCode,
        cityName: corporationInfo.value.cityName,
        townName: corporationInfo.value.townName,
        buildingName: corporationInfo.value.buildingName,
        bizRepoAccepHelthCenter: corporationInfo.value.bizRepoAccepHelthCenter,
        chairpersonLastName: corporationInfo.value.chairpersonLastName,
        chairpersonFirstName: corporationInfo.value.chairpersonFirstName,
        upldBizReportRequest: corporationInfo.value.upldBizReportRequest,
        fiscalYearEnd: corporationInfo.value.fiscalYearEnd,
        registrationDate: corporationInfo.value.registrationDate,
        closedDate: corporationInfo.value.closedDate,
        screenMode: corporationInfo.value.screenMode,
        createPgmId: commonInfo().screenId,
      },
    ],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    if (screenMode.value === newFlg.value) {
      // 登録処理完了メッセージをダイヤログに表示する
      showRegistMessage(stringUtil.convertString(comMessage.COMMON000000I, ["法人情報の登録"]));
    } else {
      // 更新処理完了メッセージをダイヤログに表示する
      showRegistMessage(stringUtil.convertString(comMessage.COMMON000000I, ["法人情報の更新"]));
    }

    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラー表示エリアにメッセージを表示する
    const responseData = ref();
    // エラー表示
    errorMsg.value = res[0].data.messageErr.join("\n");
    // 項目エラー表示
    responseData.value = res[0].data.messageErrMap;
    if (responseData.value.size !== 0) {
      for (const [key, value] of Object.entries(responseData.value)) {
        errorMessages.value[key] = { value };
      }
    }
  }
  // ローディングの非表示
  loadingModal.isshow(false);

  // 処理終了ログ
  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, E02Name]));
};

/**
 * 「ユーザ登録追加ボタン」ボタンクリックイベント
 */
const MNM0201200E03 = async () => {
  // 処理開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, E03Name]));
  // 入力情報保存
  setMNM0201200Save();
  // ユーザ登録画面パラメータ設定
  MNM0301200Param().corporationId = targetCorp().corporationId;
  MNM0301200Param().corporationName = corporationInfo.value.corporationName;
  MNM0301200Param().medicCorpRefNumber = corporationInfo.value.medicCorpRefNumber;
  MNM0301200Param().prefCode = corporationInfo.value.prefCode;
  MNM0301200Param().prefCodeInfoMap = enumPrefRegistMaps.value;

  // ユーザ登録画面に遷移
  router.push({ name: comConst.MNM0301200 });

  // 処理終了ログ
  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, E03Name]));
};

/**
 * 「削除」ボタンクリックイベント
 */
const MNM0201200E04 = async () => {
  // 処理開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, E04Name]));

  // ローディングの表示
  loadingModal.isshow(true);
  // ユーザ削除APIの呼び出し
  const reqParam = [
    [
      comConst.API_ID_MNM0201_06,
      {
        prefCode: targetCorp().prefCode,
        corporationId: targetCorp().corporationId,
      },
    ],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // 更新処理完了メッセージをダイヤログに表示する
    await showDeleteMessage(stringUtil.convertString(comMessage.COMMON000000I, ["法人情報の削除"]));

    // ターゲット情報削除
    targetCorp().$reset();

    // ローディングの非表示
    loadingModal.isshow(false);
    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラー表示エリアにメッセージを表示する
    errorMsg.value = res[0].data.messageErr.join("\n");

    // ローディングの非表示
    loadingModal.isshow(false);

    // 処理終了ログ
    console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, E04Name]));
  }
};

/**
 * 「代理入力」ボタンクリックイベント
 */
const MNM0201200E05 = async () => {
  // 処理開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, E05Name]));

  // 対象の法人情報を更新
  targetCorp().corporationName = corporationInfo.value.corporationName;
  targetCorp().prefCode = corporationInfo.value.prefCode;
  targetCorp().prefName = KeyToKeyValueChange(corporationInfo.value.prefName);
  targetCorp().medicCorpRefNumber = corporationInfo.value.medicCorpRefNumber;
  targetCorp().address = targetCorp().prefName + corporationInfo.value.cityName + corporationInfo.value.townName + corporationInfo.value.buildingName;
  targetCorp().corporationId = corporationInfo.value.corporationId;

  // 年度別届出状況一覧画面に遷移
  router.push({ name: comConst.ENT0101100 });

  // 処理終了ログ
  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, E05Name]));
};

/**
 * 都道府県チェック
 */
const onPrefNameChange = () => {
  // 市区町村コード、名称初期化
  corporationInfo.value.cityCode = "";
  corporationInfo.value.cityName = "";
  showPrefNameFlg.value = false;

  // 選択した都道府県による該当市区町村設定
  if (corporationInfo.value.prefName) {
    const filteredCities = Object.keys(enumCityMaps.value)
      .filter((cityCode) => cityCode.startsWith(corporationInfo.value.prefName))
      .map((cityCode) => ({
        val: cityCode,
        dispname: enumCityMaps.value[cityCode],
      }));
    enumCityRegistMaps.value = filteredCities;
  }
};

/**
 * 市区町村チェック
 */
const changeCityCode = () => {
  // 該当市区町村名称設定
  corporationInfo.value.cityName = "";
  const name = enumCityRegistMaps.value.find((item) => item.val === corporationInfo.value.cityCode);
  corporationInfo.value.cityName = name ? name.dispname : null;
};

/**
 * 廃止日チェック
 */
const handleDateCheck = () => {
  // システム時間
  const date = new Date();
  const systemDate = comDate.formatDateYMDHyphen(date);

  // 廃止日が現在日より過去の場合ボタン非表示
  if (isEmptyCheck(corporationInfo.value.closedDate)) {
    if (comDate.formatDateYMDHyphen(corporationInfo.value.closedDate) < systemDate) {
      buttonFlg.value = true;
    }
  }
};

/**
 * 都道府県名をキーに変更
 * @type {boolean}　true：都道府県キー
 */
const valueToKeyChange = (prefName) => {
  // 都道府県名から該当キーを設定
  const foundKey = enumPrefRegistMaps.value.find((item) => item.dispname === prefName);
  return foundKey ? foundKey.val : null;
};

/**
 * 都道府県キーを名に変更
 * @type {boolean}　true：都道府県名
 */
const KeyToKeyValueChange = (key) => {
  // 都道府県キーから該当値を設定
  const foundValue = enumPrefRegistMaps.value.find((item) => item.val === key);
  return foundValue ? foundValue.dispname : null;
};

/**
 * 入力チェック
 * @type {boolean}　true：チェックOK、false：チェックNG
 */
const checkInput = async () => {
  const errmsg = errorMessages.value;
  let errFlg = false; // true：エラーあり

  // 全項目のエラーメッセージを削除
  Object.keys(errmsg).forEach((key) => {
    errmsg[key] = null;
  });

  // 医療法人整理番号
  let errs = [];
  if (!validator.IsNotNullEmpty(corporationInfo.value.medicCorpRefNumber)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000006E, ["医療法人整理番号"]));
  }
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.medicCorpRefNumber, 255, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["医療法人整理番号", 255]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["medicCorpRefNumber"] = errs;
    errFlg = true;
  }

  // 医療法人名称
  errs = [];
  // 必須チェック
  if (!validator.IsNotNullEmpty(corporationInfo.value.corporationName)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000006E, ["医療法人名称"]));
  }
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.corporationName, 80, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["医療法人名称", 80]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["corporationName"] = errs;
    errFlg = true;
  }

  // 郵便番号（前３桁）
  errs = [];
  // 必須チェック
  if (!validator.IsNotNullEmpty(corporationInfo.value.postalNumberFirstThree)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000006E, ["郵便番号（前３桁）"]));
  }
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.postalNumberFirstThree, 3, 3)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000020E, ["郵便番号（前３桁）", 3]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["postalNumberFirstThree"] = errs;
    errFlg = true;
  }

  // 郵便番号（後４桁）
  errs = [];
  // 必須チェック
  if (!validator.IsNotNullEmpty(corporationInfo.value.postalNumberLastFour)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000006E, ["郵便番号（後４桁）"]));
  }
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.postalNumberLastFour, 4, 4)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000020E, ["郵便番号（後４桁）", 4]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["postalNumberLastFour"] = errs;
    errFlg = true;
  }

  // 町域・番地
  errs = [];
  // 必須チェック
  if (!validator.IsNotNullEmpty(corporationInfo.value.townName)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000006E, ["町域・番地"]));
  }
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.townName, 21, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["町域・番地", 21]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["townName"] = errs;
    errFlg = true;
  }

  // 建物名
  errs = [];
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.buildingName, 40, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["建物名", 40]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["buildingName"] = errs;
    errFlg = true;
  }

  // 届出を受付ている保健所
  errs = [];
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.bizRepoAccepHelthCenter, 85, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["届出を受付ている保健所", 85]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["bizRepoAccepHelthCenter"] = errs;
    errFlg = true;
  }

  // 理事長の氏名（姓）
  errs = [];
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.chairpersonLastName, 40, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["理事長の氏名（姓）", 40]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["chairpersonLastName"] = errs;
    errFlg = true;
  }

  // 理事長の氏名（名）
  errs = [];
  // 桁数チェック
  if (!validator.validLength(corporationInfo.value.chairpersonFirstName, 40, 0)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000012E, ["理事長の氏名（名）", 40]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["chairpersonFirstName"] = errs;
    errFlg = true;
  }

  // 桁数チェック
  const regex = /^([0-9]{4})-(0[1-9]|1[0-2])-([0-2][0-9]|3[01])$/;

  // 登記年月日
  errs = [];
  // 入力フォーマットチェック
  if (corporationInfo.value.registrationDate && !regex.test(corporationInfo.value.registrationDate)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000009E, ["登記年月日"]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["registrationDate"] = errs;
    errFlg = true;
  }

  // 廃止日
  errs = [];
  // 入力フォーマットチェック
  if (corporationInfo.value.closedDate && !regex.test(corporationInfo.value.closedDate)) {
    errs.push(stringUtil.convertString(comMessage.COMMON000009E, ["廃止日"]));
  }
  // エラーがあった場合
  if (errs.length > 0) {
    errmsg["closedDate"] = errs;
    errFlg = true;
  }
  return !errFlg;
};

