<!--
  医療法人の経営情報等「経営状況に関する情報」「職種別給与総額及びその人数に関する情報」に共通のコンポーネント（経営情報等Web入力画面）
    法人名～職員数まで
  @version 1.0
  @author CSC
-->
<template>
  <tbody>
    <tr>
      <td style="width: 120px" class="col-form-label">法人名</td>
      <td colspan="5">
        <input
          type="text"
          class="form-control"
          v-model="mngInfoSBJ.n0005CorporationName.value"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n0005CorporationName.messageErr.length > 0 }"
          :disabled="allDisabled"
          @input="handleInput($event, 'n0005CorporationName')"
        />
      </td>
    </tr>
    <tr v-if="!allDisabled && (mngInfoSBJ.n0005CorporationName.messageErr.length > 0 || mngInfoSBJ.n0005CorporationName.messageWarn.length > 0)">
      <td colspan="2">
        <div v-for="msg in mngInfoSBJ.n0005CorporationName.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n0005CorporationName.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
    </tr>
    <tr>
      <td style="width: 130px" class="col-form-label">
        <template v-if="mngInfoSBJ.hospitalClinicType == comEnum.EnumHOSPITAL_CLINIC_TYPE.HOSPITAL.val">病院名</template>
        <template v-if="mngInfoSBJ.hospitalClinicType == comEnum.EnumHOSPITAL_CLINIC_TYPE.CLINIC.val">診療所名</template>
      </td>
      <td style="width: 310px">
        <input
          type="text"
          class="form-control"
          v-model="mngInfoSBJ.n0006HospitalClinicName.value"
          disabled
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n0006HospitalClinicName.messageErr.length > 0 }"
        />
      </td>
      <td style="width: 130px" class="col-form-label">役員数（人）</td>
      <td style="width: 100px">
        <input
          type="text"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="報告施設で直接業務に従事する役員の数を記載ください。"
          class="form-control"
          v-model="mngInfoSBJ.n0007OfficerCount.value"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n0007OfficerCount.messageErr.length > 0 }"
          :disabled="allDisabled"
          @input="handleInput($event, 'n0007OfficerCount')"
        />
      </td>
      <td style="width: 130px" class="col-form-label">職員数（人）</td>
      <td style="width: 100px">
        <input
          type="text"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="報告施設で直接業務に従事する職員の数を記載ください。"
          class="form-control"
          v-model="mngInfoSBJ.n0008StaffCount.value"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n0008StaffCount.messageErr.length > 0 }"
          :disabled="allDisabled"
          @input="handleInput($event, 'n0008StaffCount')"
        />
      </td>
    </tr>
    <tr
      v-if="
        !allDisabled &&
        (mngInfoSBJ.n0006HospitalClinicName.messageErr.length > 0 ||
          mngInfoSBJ.n0006HospitalClinicName.messageWarn.length > 0 ||
          mngInfoSBJ.n0007OfficerCount.messageErr.length > 0 ||
          mngInfoSBJ.n0007OfficerCount.messageWarn.length > 0 ||
          mngInfoSBJ.n0008StaffCount.messageErr.length > 0 ||
          mngInfoSBJ.n0008StaffCount.messageWarn.length > 0)
      "
    >
      <td colspan="2" v-if="mngInfoSBJ.n0006HospitalClinicName.messageErr.length > 0 || mngInfoSBJ.n0006HospitalClinicName.messageWarn.length > 0">
        <div v-for="msg in mngInfoSBJ.n0006HospitalClinicName.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n0006HospitalClinicName.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="2" v-else></td>
      <td colspan="2" v-if="mngInfoSBJ.n0007OfficerCount.messageErr.length > 0 || mngInfoSBJ.n0007OfficerCount.messageWarn.length > 0">
        <div v-for="msg in mngInfoSBJ.n0007OfficerCount.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n0007OfficerCount.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="2" v-else></td>
      <td colspan="2">
        <div v-for="msg in mngInfoSBJ.n0008StaffCount.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n0008StaffCount.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
    </tr>
  </tbody>
</template>
<style scoped>
.col-form-label {
  padding-left: 15px !important;
  line-height: 1.17 !important;
  vertical-align: middle;
}
</style>
<script setup>
import { onMounted, ref } from "vue";
import { Tooltip } from "bootstrap";
import comEnum from "@/constants/com-enum.js";

/** props：コンポーネントの引数 */
const props = defineProps({
  editClass: { type: String, default: "3" }, // 編集区分
  allDisabled: { type: Boolean, default: false }, // 全項目非活性
});

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["input"]);

// 初期値
const inputItemDto = { value: "", messageErr: [], messageWarn: [] };
const mngInfoSBJ = ref({
  hospitalClinicType: "",
  // "n0001HospitalClinicDivision": "",
  // "n0002PrefCode": "",
  // "n0001MedicCorpRefNo": "",
  // "n0002CorporateNo": inputItemDto,
  // "n00031SickbedOutpatCtrlnoExist": inputItemDto,
  // "n00032SickbedOutpatCtrlNo": inputItemDto,
  // "n00041MedicInstiCdExist": inputItemDto,
  // "n00042MedicInstiCd": inputItemDto,
  n0005CorporationName: inputItemDto,
  n0006HospitalClinicName: inputItemDto,
  n0007OfficerCount: inputItemDto,
  n0008StaffCount: inputItemDto,
  // "n00091Prefecture": inputItemDto,
  // "n00092City": inputItemDto,
  // "n00093TownArea": inputItemDto,
  // "n0010SecoundaryMedicalArea": inputItemDto,
});

/**
 * コンポーネントの初期表示イベント
 */
onMounted(() => {
  // ツールチップ
  let helpBtnList = [].slice.call(document.querySelectorAll('[data-bs-toggle="help"]'));
  helpBtnList.map(function (_btnElement) {
    return new Tooltip(_btnElement, { trigger: "hover", placement: "bottom", html: true });
  });
  let targetList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
  targetList.map(function (_element) {
    return new Tooltip(_element, { trigger: "focus", html: true, animation: false });
  });
});

/**
 * テキスト変更時のイベント
 * @param event
 * @param id bindされた項目名
 */
const handleInput = (event, id) => {
  emit("input", { event: event, id: id });
};

/**
 * コンポーネント初期化
 */
const init = () => {};

/**
 * mngInfoSalaryByJobtypeオブジェクトの取得
 */
const getMngInfoSBJ = () => {
  return mngInfoSBJ.value;
};

/**
 * mngInfoSalaryByJobtypeオブジェクトの設定
 * @return mngInfoSalaryByJobtype
 */
const setMngInfoSBJ = (_mngInfoSalaryByJobtype) => {
  mngInfoSBJ.value = _mngInfoSalaryByJobtype;
};

/** コンポーネントのメソッド公開 */
defineExpose({
  /** 初期化 */
  init,
  /** mngInfoSalaryByJobtypeオブジェクトの取得 */
  getMngInfoSBJ,
  /** mngInfoSalaryByJobtypeオブジェクトの設定 */
  setMngInfoSBJ,
});
</script>
