/**
 *  メール設定編集画面間連携データ（パラメータ）を定義する
 *
 *  @version 1.0
 *  @author CSC
 */
import { defineStore } from "pinia";

const ENT0201100Param = defineStore("ENT0201100Param", {
  state: () => {
    return {
      corpId: "",             // 会社ID
      mailSettingId: "",             // メール設定ID
    };
  },
  persist: {
    storage: window.sessionStorage,
  },
});

export default ENT0201100Param;
