<!--
 商品詳細画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted } from "vue";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import commonInfo from "@/store/common/common-info.js";
import targetCorp from "@/store/common/target-corp.js";
import { useRouter } from "vue-router";
import apiCaller from "@/utils/common/api-caller.js";
import validator from "@/utils/common/validator.js";
import StringUtil from "@/utils/common/string-util.js";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";
import ATH0101200Param from "@/store/ATH0101200/ath0101200-param.js";

/** ログ用 */
const screenName = "トップ画面";
const E01Name = "初期表示";
const product = ref({language:[]});
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();
var messageErrFlg = ref(false);
var messageErr = ref("");

// 画面マウント時イベント
onMounted(() => {
  // modal初期化
  myModal.value.init();
  ATH0101200E01();
});

/**
* 初期表示イベント
*/
const ATH0101200E01 = () => {

  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E01Name]));

  product.value = ATH0101200Param().productInfo;

  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E01Name]));
};


const addToCart = () => {
  // 假设这里有 Vuex 或 Pinia 管理购物车
  var haveItem = false;
  for(var i = 0; i<commonInfo().cartList.length; i++) {
    var element = commonInfo().cartList[i];
    if (element.PRODUCT_ID == ATH0101200Param().productInfo.PRODUCT_ID) {
      haveItem = true;
      break;
    }
  }
  if (!haveItem) {
    commonInfo().cartList.push(ATH0101200Param().productInfo);
    showMessage("已加入购物车");
  } else {
    showMessage("购物车中已有该商品");
  }
}

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

// Dialog閉じるイベント
const closeDialog = (modalReturn) => {

};
</script>

<template>
  <Header />
  <div class="product-detail">
    <!-- エラー表示エリア -->
    <div class="align-items-center center place_items_center">
      <div class="alert alert-danger text-danger width_100" v-if="messageErrFlg" role="alert">{{ messageErr }}</div>
    </div>
    <div class="product-image">
      <img :src="product.PRODUCT_IMG" :alt="product.language[commonInfo().languageType]?.PRODUCT_NAME" />
    </div>
    <div class="product-info">
      <h1>{{ product.language[commonInfo().languageType]?.PRODUCT_NAME }}</h1>
      <p class="product-description">{{ product.language[commonInfo().languageType]?.PRODUCT_DETAIL }}</p>
      <p class="product-price">{{ Number(product.PRICE).toLocaleString() }}{{ product.PRICE_CURRENCY }}</p>
      <button @click="addToCart" class="add-to-cart">加入购物车</button>
    </div>
  </div>
  <Footer />
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>
.product-detail {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 20px;
  font-family: Arial, sans-serif;
  margin-bottom: 60px;
}

.product-image img {
  width: 100%;
  max-width: 400px;
  border-radius: 8px;
}

.product-info {
  text-align: center;
  margin-top: 20px;
}

.product-description {
  font-size: 16px;
  color: #555;
}

.product-price {
  font-size: 24px;
  color: #333;
  margin: 10px 0;
}

.add-to-cart {
  padding: 10px 20px;
  font-size: 16px;
  background-color: #007bff;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  transition: background-color 0.3s;
}

.add-to-cart:hover {
  background-color: #0056b3;
}
</style>