 トップ画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import Menu from "@/components/common/Menu.vue";
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import MedicCorpInfo from "@/components/ENT0401100/MedicCorpInfo.vue";
import commonInfo from "@/store/common/common-info.js";
import UTL0101100Save from "@/store/UTL0101100/UTL0101100-save.js";
import MNM0101100Save from "@/store/MNM0101100/MNM0101100-save.js";
import apiCaller from "@/utils/common/api-caller.js";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import loadingModal from "@/utils/common/loading-modal.js";
import comProperty from "@/constants/com-property.js";
import comMessage from "@/constants/com-message.js";
import ComFileDownload from "@/utils/common/com-file-download.js";
import ComDate from "@/utils/common/com-date.js";
import StringUtil from "@/utils/common/string-util.js";

// ルータ
const router = useRouter();
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();
// パンくずリスト
var breadcrumbObj = ref();
// 届出管理データリスト
var notificationMngList = ref();
// 集計月毎リスト
var aggrMonthlyList = ref();
// 都道府県マスタリスト
var prefInfoList = ref();
// PDFダウンロード情報今年度
var pdfInfoCurrentYear = ref({
  fiscalYear: "",
  updateDatetime: "",
  fileOperationManageSeq: "",
  saveFileName: "",
});
// PDFダウンロード情報前年度
var pdfInfoPreviousYear = ref({
  fiscalYear: "",
  updateDatetime: "",
  fileOperationManageSeq: "",
  saveFileName: "",
});
// 届出履歴
var notificationHistory = ref();
// 表示件数
var displayNum = ref();
// お知らせ
var htmlContent = ref();
// システム日付
var systemDate = ref();
// ユーザ種別
var userType = ref();
// ログ用
const screenName = "トップ";
/** MedicCorpInfo用 */
var corpInfoFlg = ref(false);
const corpName = ref("");
const prefNo = ref("");
const prefName = ref("");
const medicCorpRefNumber = ref("");
const address = ref("");

// 画面マウント時イベント
onMounted(() => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.UTL0101100;

  // パンくずリストを設定
  breadcrumbObj.value.init(commonInfo().screenId);

  if (commonInfo().userType === comEnum.EnumUSER_TYPE.MEDIC_CORP.val) {
    //ユーザ種別が医療法人
    corpInfoFlg.value = true;
    corpName.value = commonInfo().corporationName;
    prefNo.value = commonInfo().prefCode;
    prefName.value = commonInfo().prefName;
    medicCorpRefNumber.value = commonInfo().medicCorpRefNumber;
    address.value = commonInfo().address;
  } else {
    //ユーザ種別が医療法人以外
    corpInfoFlg.value = false;
  }

  // modal初期化
  myModal.value.init();

  // 初期表示件数
  displayNum = Number(comProperty.NOTIFI_HISTORY_INITIAL_NUMBER);

  // システム日付
  var date = new Date();
  systemDate = ComDate.formatDateYMDHM(date);

  // トップ画面-初期表示
  UTL0101100E01();
});

// トップ画面-初期表示
const UTL0101100E01 = async () => {
  // 開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));
  // 1	トップ画面表示API
  // 1-1 ローディングモーダルを表示にする
  loadingModal.isshow(true);
  // 1-2 トップ画面表示APIを呼び出す
  // commonInfo.ユーザ種別
  userType = commonInfo().userType;
  // UTL0101100Save.都道府県番号
  if (comEnum.EnumUSER_TYPE.PREF_STAFF.val === userType) {
    // ログインユーザの都道府県番号
    UTL0101100Save.prefCode = commonInfo().prefCode;
  } else if (comEnum.EnumUSER_TYPE.MEDIC_CARE_ORG_STAFF.val === userType) {
    // 00:全国
    if (!UTL0101100Save.prefCode) {
      UTL0101100Save.prefCode = comConst.PREF_ALL_CD;
    }
  }

  // トップ画面表示API　を呼び出す
  const reqParam = [
    [
      comConst.API_ID_MNM0301_09,
      {
        prefCode: UTL0101100Save.prefCode,
      },
    ],
  ];

  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    var topPageInfo = res[0].data;
    // 01.医療法人
    if (comEnum.EnumUSER_TYPE.MEDIC_CORP.val === userType) {
      UTL0101100Save.notificationHistoryAll = topPageInfo.notificationHistoryList;
      if (UTL0101100Save.notificationHistoryAll && UTL0101100Save.notificationHistoryAll.length < displayNum) {
        displayNum = notificationHistory.length;
      }
      notificationHistory.value = limitCount(UTL0101100Save.notificationHistoryAll);
    } else if (comEnum.EnumUSER_TYPE.PREF_STAFF.val === userType) {
      // 02.都道府県
      notificationMngList.value = topPageInfo.prefNotificationMngList;
      aggrMonthlyList.value = topPageInfo.prefAggrMonthlyList;
      pdfInfoCurrentYear.value = topPageInfo.pdfInfoCurrentYearResDto;
      pdfInfoPreviousYear.value = topPageInfo.pdfInfoPreviousYearResDto;
    } else if (comEnum.EnumUSER_TYPE.MEDIC_CARE_ORG_STAFF.val === userType) {
      // 04.機構職員
      notificationMngList.value = topPageInfo.notificationMngList;
      aggrMonthlyList.value = topPageInfo.corpAggrMonthlyList;
      prefInfoList.value = topPageInfo.prefInfoList;
    }
    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラーメッセージリストをダイヤログに表示する
    showOkMessage(res[0].data.messageErr.join("\n"));
    return;
  }
  // 2 各メニュー説明の表示制御
  // 2-1 お知らせエリア
  // 2-1-1 プロパティファイルからトップ画面お知らせのHTMLファイルの格納先を取得する
  var htmlFilePath = "";
  // お知らせのHTMLファイルの格納先 = プロパティファイルから取得した　お知らせHTMLファイルパス+プロパティファイルから取得した　お知らせHTMLファイル名
  // 01.医療法人
  if (comEnum.EnumUSER_TYPE.MEDIC_CORP.val === userType) {
    htmlFilePath = comProperty.NOTICE_FILE_PATH + comProperty.NOTICE_FILE_MEDIC_CORP;
  } else if (comEnum.EnumUSER_TYPE.PREF_STAFF.val === userType) {
    // 02.都道府県
    htmlFilePath = comProperty.NOTICE_FILE_PATH + comProperty.NOTICE_FILE_PREF;
  } else if (comEnum.EnumUSER_TYPE.PROXY_INPUT_STAFF.val === userType) {
    // 03.代理入力
    htmlFilePath = comProperty.NOTICE_FILE_PATH + comProperty.NOTICE_FILE_PROXYINPUT;
  } else if (comEnum.EnumUSER_TYPE.MEDIC_CARE_ORG_STAFF.val === userType) {
    // 04.機構職員
    htmlFilePath = comProperty.NOTICE_FILE_PATH + comProperty.NOTICE_FILE_MEDIC_CARE_ORG;
  }
  // 2-1-2 HTMLデータをお知らせの表示部分へHTMLとして出力する。
  fetch(htmlFilePath).then((res) => {
    res.text().then((html) => {
      htmlContent.value = html;
    });
  });
  // 2-6 1-1で表示したローディングモーダルを非表示にする
  loadingModal.isshow(false);

  // 終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};
// Dialog閉じるイベント
const closeDialog = (modalReturn) => {
  // 何もしない
};

// 過去の履歴ボタンクリック
const UTL0101100E02 = (arg) => {
  var eventName = "過去の履歴ボタンクリック";
  // 開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, eventName]));
  if (notificationHistory.value && UTL0101100Save && notificationHistory.value.length < UTL0101100Save.notificationHistoryAll.length) {
    // 指定件数を追加する
    displayNum = displayNum + Number(comProperty.NOTIFI_HISTORY_DESIGNATION_NUMBER);
    notificationHistory.value = limitCount(UTL0101100Save.notificationHistoryAll);
  } else {
    modalmsg.value = comMessage.UTL010110000I;
    myModal.value.show();
  }
  // 終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, eventName]));
};

// 都道府県プールダウンリスト変更
const prefInfoChange = (event) => {
  UTL0101100E01();
};

// 年度別届出状況リンククリック
const UTL0101100E03 = (searchInfo) => {
  var eventName = "年度別届出状況リンククリック";
  // 開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, eventName]));
  MNM0101100Save().cityCode = ""; //市区町村
  MNM0101100Save().medicCorpRefNumber = ""; //医療法人整理番号
  MNM0101100Save().corporationName = ""; //医療法人名称
  MNM0101100Save().fiscalYearEnd = ""; //会計月
  MNM0101100Save().notificationType = ""; //届出タイプ
  MNM0101100Save().notificationDatetimeStart = ""; //届出年月日（開始）
  MNM0101100Save().notificationDatetimeEnd = ""; //届出年月日（終了）
  MNM0101100Save().approvalDatetimeStart = ""; //承認年月日（開始）
  MNM0101100Save().approvalDatetimeEnd = ""; //承認年月日（終了）
  MNM0101100Save().manageInfoStatus = ""; //経営情報届出状況
  if (comEnum.EnumUSER_TYPE.PREF_STAFF.val === userType) {
    // 02.都道府県
    MNM0101100Save().prefCode = commonInfo().prefCode; // 都道府県コード
  } else if (comEnum.EnumUSER_TYPE.MEDIC_CARE_ORG_STAFF.val === userType) {
    // 04.機構職員
    MNM0101100Save().prefCode = UTL0101100Save.prefCode;
  }
  MNM0101100Save().fiscalYear = searchInfo.fiscalYear; //会計年度
  MNM0101100Save().notificationStatus = searchInfo.notificationStatus; //状態
  MNM0101100Save().notificationMethod = searchInfo.notificationMethod; //届出方法
  router.push({ name: comConst.MNM0101100 });
  // 終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, eventName]));
};

// 指定件数
const limitCount = (lists) => {
  if (lists && lists.length > 0) {
    return lists.slice(0, displayNum);
  } else {
    return null;
  }
};

// PDFダウンロードクリック
const UTL0101100E04 = async (fileOperationManageSeq, fileName) => {
  var eventName = "PDFダウンロードクリック";
  // 開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, eventName]));
  // ローディングモーダルを表示にする
  loadingModal.isshow(true);
  // ダウンロードAPI　を呼び出す
  const reqParam = [
    [
      comConst.API_ID_ENT0201_01,
      {
        corporationId: commonInfo().corporationId,
        fileOperationManageSeq: fileOperationManageSeq,
      },
    ],
  ];

  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);

  // 結果コード = "200"（正常終了）の場合
  if (res[0].status === 200) {
    ComFileDownload.download(res[0].data, {}, fileName);
    // 上記以外の場合
  } else {
    // エラーメッセージリストをダイヤログに表示する
    showOkMessage(StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]));
  }
  // 2-6 1-1で表示したローディングモーダルを非表示にする
  loadingModal.isshow(false);
  // 開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, eventName]));
};

/**
 * OKメッセージ表示
 * タイトルなし、OKボタンのみ表示
 * @type {String}　メッセージ
 */
const showOkMessage = async (msg) => {
  modaltitle.value = "";
  modalmsg.value = msg;
  modalCloseBtn.value = "OK";
  myModal.value.show();
};
</script>

<template>
  <Header />
  <div class="contents">
    <Menu :selectedMenu="'UTL0101100'" />
    <Breadcrumb ref="breadcrumbObj" />
    <MedicCorpInfo
      v-if="corpInfoFlg"
      :corpName="corpName"
      :prefNo="prefNo"
      :prefName="prefName"
      :address="address"
      :medicCorpRefNumber="medicCorpRefNumber"
    />
    <div class="sub_contents border_all">
      <span class="label">お知らせ</span>
      <div v-html="htmlContent"></div>
    </div>
    <div id="divTodokedeRireki" class="sub_contents border_all height_auto" v-if="commonInfo().userType === comEnum.EnumUSER_TYPE.MEDIC_CORP.val">
      <div class="col padding-10">
        <span class="label">届出履歴</span>
        <div class="row align-items-center width_100p-200 margin-left-right-100">
          <span class="label width_auto"><i class="bi-file-earmark-check"></i>届出</span>
          <span class="label width_auto"><i class="bi-file-earmark-arrow-down"></i>取戻し・差戻し</span>
          <span class="label width_auto"><i class="bi-file-earmark"></i>書面での届出</span>
        </div>
        <table class="table table-white mt-3 text-center align-middle top-table width_100p-200 margin-left-right-100 height_auto">
          <thead>
            <tr>
              <th></th>
              <th class="width_230">日時</th>
              <th>届出履歴</th>
            </tr>
          </thead>
          <tbody>
            <tr v-for="obj in notificationHistory">
              <td><i :class="obj.icon"></i></td>
              <td>{{ obj.operationDatetime }}</td>
              <td class="left">{{ obj.notificationHistMsg }}</td>
            </tr>
          </tbody>
        </table>
        <div class="center">
          <button class="btn btn-primary" @click="UTL0101100E02"><i class="bi bi-database"></i>過去の履歴</button>
        </div>
      </div>
    </div>
    <div
      id="divTodokedeJokyo"
      class="sub_contents border_all row"
      v-if="
        commonInfo().userType === comEnum.EnumUSER_TYPE.PREF_STAFF.val || commonInfo().userType === comEnum.EnumUSER_TYPE.MEDIC_CARE_ORG_STAFF.val
      "
    >
      <div class="width_50p">
        <div class="row align-items-center">
          <div class="col">
            <span class="label left width_190">年度別届出状況</span>
          </div>
          <div class="col-auto margin-left-right-10">
            <span class="label right width_auto">更新日時：{{ systemDate }}</span>
          </div>
        </div>
        <div class="row">
          <div class="col">
            <div class="row">
              <div class="col margin-left-right-10">
                <span class="label sub_title" v-if="commonInfo().userType === comEnum.EnumUSER_TYPE.PREF_STAFF.val">{{ commonInfo().prefName }}</span>
                <select
                  class="ms-1"
                  v-if="commonInfo().userType === comEnum.EnumUSER_TYPE.MEDIC_CARE_ORG_STAFF.val"
                  v-model="UTL0101100Save.prefCode"
                  @change="prefInfoChange($event)"
                >
                  <option v-for="(value, key) in prefInfoList" v-bind:value="key">
                    {{ value }}
                  </option>
                </select>
              </div>
            </div>
            <div class="row" v-for="notiInfo in notificationMngList">
              <div class="col margin-left-right-10">
                <table class="table table-white mt-3 text-center align-middle top-table">
                  <thead>
                    <tr>
                      <th scope="col" rowspan="2">{{ notiInfo.fiscalYear }}年度</th>
                      <th scope="col" colspan="2" style="border-bottom-width: 0 !important">未届出法人数({{ notiInfo.totalUnreportCorp }})</th>
                      <th scope="col" colspan="3">
                        届出法人数({{ notiInfo.notifiedCorp }})　届出率{{ notiInfo.notificationRate }}%<span class="font-size10">※</span>
                      </th>
                    </tr>
                    <tr>
                      <th scope="col" style="border-top-color: #cde7f3"></th>
                      <th scope="col">差戻し</th>
                      <th scope="col">未承認</th>
                      <th scope="col">承認済み</th>
                      <th scope="col">書面による届出</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr>
                      <td>　　　</td>
                      <td>
                        <a href="#" @click.prevent.stop="UTL0101100E03({ fiscalYear: notiInfo.fiscalYear, notificationStatus: 'S1,S2' })">{{
                          notiInfo.unreportCorp
                        }}</a>
                      </td>
                      <td>
                        <a href="#" @click.prevent.stop="UTL0101100E03({ fiscalYear: notiInfo.fiscalYear, notificationStatus: 'S3' })">{{
                          notiInfo.remandUnreportCorp
                        }}</a>
                      </td>
                      <td>
                        <a
                          href="#"
                          @click.prevent.stop="UTL0101100E03({ fiscalYear: notiInfo.fiscalYear, notificationStatus: 'S4' })"
                          class="sub_title"
                          >{{ notiInfo.unapprNotifiedCorp }}</a
                        >
                      </td>
                      <td>
                        <a
                          href="#"
                          @click.prevent.stop="
                            UTL0101100E03({ fiscalYear: notiInfo.fiscalYear, notificationStatus: 'S5', notificationMethod: '0,1' })
                          "
                          >{{ notiInfo.apprNotifiedCorp }}</a
                        >
                      </td>
                      <td>
                        <a
                          href="#"
                          @click.prevent.stop="UTL0101100E03({ fiscalYear: notiInfo.fiscalYear, notificationStatus: 'S5', notificationMethod: '2' })"
                          >{{ notiInfo.writApprNotifiedCorp }}</a
                        >
                      </td>
                    </tr>
                    <tr>
                      <td>対象法人数</td>
                      <td colspan="5">{{ notiInfo.targetCorp }}</td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
            <div class="row">
              <div class="col">
                <span class="label left width_190">※届出率＝届出法人数÷対象法人数</span>
              </div>
            </div>
          </div>
        </div>
      </div>
      <div class="width_50p border-left">
        <div class="row align-items-center">
          <div class="col">
            <span class="label left width_190">直近12ヶ月届出状況</span>
          </div>
          <div class="col-auto margin-left-right-10">
            <span class="label right width_auto">更新日時：{{ systemDate }}</span>
          </div>
        </div>
        <div class="row">
          <div class="col margin-left-right-10">
            <table class="table table-white mt-3 text-center align-middle top-table">
              <thead>
                <tr>
                  <th>決算月</th>
                  <th>対象法人数</th>
                  <th>届出法人数</th>
                  <th>届出率</th>
                </tr>
              </thead>
              <tbody>
                <tr v-for="aggrMonthly in aggrMonthlyList">
                  <td>{{ aggrMonthly.fiscalYear }}年{{ aggrMonthly.fiscalYearEnd }}月</td>
                  <td>{{ aggrMonthly.targetCorpCount }}</td>
                  <td>{{ aggrMonthly.notificationCount }}</td>
                  <td>{{ aggrMonthly.notificationRate }}％</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
    <div class="sub_contents border_all row" v-if="commonInfo().userType === comEnum.EnumUSER_TYPE.PREF_STAFF.val">
      <div class="row align-items-center">
        <div class="col">
          <span class="label">PDFダウンロード</span>
        </div>
        <div class="col-auto"></div>
      </div>
      <div class="row">
        <div class="col margin-left-right-10">
          <table class="table table-white mt-3 text-center align-middle top-table">
            <thead>
              <tr>
                <th>都道府県</th>
                <th>会計年度</th>
                <th>更新日時</th>
                <th>ダウンロード</th>
              </tr>
            </thead>
            <tbody>
              <tr v-if="pdfInfoCurrentYear.fiscalYear">
                <td rowspan="2">{{ commonInfo().prefName }}</td>
                <td>{{ pdfInfoCurrentYear.fiscalYear }}年</td>
                <td>{{ pdfInfoCurrentYear.updateDatetime }}</td>
                <td>
                  <a href="#" @click.prevent.stop="UTL0101100E04(pdfInfoCurrentYear.fileOperationManageSeq, pdfInfoCurrentYear.saveFileName)">{{
                    pdfInfoCurrentYear.saveFileName
                  }}</a>
                </td>
              </tr>
              <tr v-if="!pdfInfoCurrentYear.fiscalYear">
                <td rowspan="2">{{ commonInfo().prefName }}</td>
                <td>―</td>
                <td>―</td>
                <td>―</td>
              </tr>
              <tr v-if="pdfInfoPreviousYear.fiscalYear">
                <td>{{ pdfInfoPreviousYear.fiscalYear }}年</td>
                <td>{{ pdfInfoPreviousYear.updateDatetime }}</td>
                <td>
                  <a href="#" @click.prevent.stop="UTL0101100E04(pdfInfoPreviousYear.fileOperationManageSeq, pdfInfoPreviousYear.saveFileName)">{{
                    pdfInfoPreviousYear.saveFileName
                  }}</a>
                </td>
              </tr>
              <tr v-if="!pdfInfoPreviousYear.fiscalYear">
                <td>―</td>
                <td>―</td>
                <td>―</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>
  <Footer />
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>
.sub_contents {
  margin: 10px auto;
  overflow: auto;
}

.border_all {
  border: solid;
  border-width: 1px;
  border-color: #000000;
}

.left {
  text-align: left;
}

.center {
  text-align: center;
}

.txt_x_small {
  font-size: x-small;
}

.height_180 {
  height: 180px;
}

.height_300 {
  height: 300px;
}

.height_400 {
  height: 400px;
}

.height_auto {
  height: auto;
}

.width_190 {
  width: 190px;
}

.width_230 {
  width: 230px;
}

.width_50p {
  width: 50%;
}

.width_100p {
  width: 100%;
}

.width_100p-200 {
  width: calc(100% - 200px);
}

.width_auto {
  width: auto;
}

.border-left {
  border-left: solid;
  border-width: 1px;
}

.sub_title {
  font-size: larger;
  font-weight: bolder;
}

.padding-10 {
  padding: 10px;
}

.label {
  padding-left: 10px;
}

.margin-left-right-10 {
  margin-left: 10px;
  margin-right: 10px;
}

