<!--
 ファイル選択コンポーネント
 @version 1.0
 @author CSC
-->
<template>
    <div class="row align-items-center">
        <!-- ファイルInput -->
        <div :class="getFileInputClass()">
            <input type="file" class="visually-hidden" ref="refInputFile" :accept="accept" @change="fileSelect" multiple />
            <input type="button" @click="refInputFile.click()" value="ファイル選択" :disabled="disabled" />
        </div>
        <!-- すべてクリア -->
        <div :class="getRemoveFilesClass()">
            <input type="button" class="btn btn-link" @click="removeAllFiles" value="すべてクリア" />
        </div>
    </div>
    <div class="row">
        <!-- ドロップエリア -->
        <div :class="getDropAreaClass()">
            <div class="drop-area" :class="getDropAreaAddClass()" 
                @dragenter="dragEnter" @dragleave="dragLeave" @drop.prevent="dropFile" @dragover.prevent="dragOver">
                {{ dropareamsg }}
            </div>
        </div>
    </div>
</template>
<style scoped>
/* ドロップエリア */
.drop-area {
    padding: 3px;
    color: gray;
    font-weight: bold;
    display: flex;
    justify-content: center;
    align-items: center;
    border: 2px dashed gray;
    white-space: pre-wrap;
    text-align: center;
}

/* エリア内ドラッグ時 */
.drop-area-enter {
    border: 2px dashed powderblue;
}

/* エリア内無効時 */
.drop-area-disabled {
    color: lightgray;
}
</style>
<script setup>
import { ref } from "vue";

/** props：コンポーネントの引数 */
const props = defineProps({
    /**
     * ドロップエリアに表示するテキスト
     * @type {string}
     */
    dropareamsg: {
        type: String,
        default: "ここにアップロードしたいファイルをドロップしてください"
    },
    /**
     * 受け付けるファイル種別
     * @type {string}
     */
    accept: {
        type: String,
        default: ""
    },
    /**
     * 各項目の 表示エリアに設定する class（上書き）
     * @type {object}
     */
    divClass: {
        type: Object,
        default() {
            return {
                /**
                 * 「ファイルInput」表示エリアclass
                 * @type {string}
                 */
                fileInput: null,
                /**
                 * 「すべてクリア」表示エリアclass
                 * @type {string}
                 */
                removeFiles: null,
                /**
                 * 「ドロップエリア」表示エリアclass
                 * @type {string}
                 */
                dropArea: null
            }
        }
    },
    /**
     * 「ドロップエリア」に追加するclass
     * @type {string}
     */
    dropAreaAddClass: {
        type: String,
        default: ""
    },
    /**
     * ファイル選択を無効化
     * @type {boolean}
     */
     disabled: {
        type: Boolean,
        default: false
     }
});

// 変数
/** ドロップエリアの範囲内かどうか */
const isEnter = ref(false);
/** ファイルInput部品のref */
const refInputFile = ref(null);
/** 「ファイルInput」表示エリアclass */
const fileInputClass = ref("col");
/** 「すべてクリア」表示エリアclass */
const removeFilesClass = ref("col text-end");
/** 「ドロップエリア」表示エリアclass */
const dropAreaClass = ref("col");
/** イベント通知 */
const emit = defineEmits(['add-files', 'remove-all-files']);

// 関数
/** 
 * 「ファイルInput」表示エリアに設定する class を返す
 * @return {string} ファイルInputに設定する class
 */
 const getFileInputClass = () => {
    // 「ファイルInput」表示エリアのクラス
    if (props.divClass && props.divClass.fileInput !== undefined && props.divClass.fileInput !== null) {
        fileInputClass.value = props.divClass.fileInput;
    }
    return fileInputClass.value;
};
/** 
 * 「すべてクリア」表示エリアに設定する class を返す
 * @return {string} すべてクリアに設定する class
 */
 const getRemoveFilesClass = () => {
    // 「すべてクリア」表示エリアのクラス
    if (props.divClass && props.divClass.removeFiles !== undefined && props.divClass.removeFiles !== null) {
        removeFilesClass.value = props.divClass.removeFiles;
    }
    return removeFilesClass.value;
};

/** 
 * 「ドロップエリア」表示エリアに設定する class を返す
 * @return {string} ドロップエリアに設定する class
 */
 const getDropAreaClass = () => {
    // 「ドロップエリア」表示エリアのクラス
    if (props.divClass && props.divClass.dropArea !== undefined && props.divClass.dropArea !== null) {
        dropAreaClass.value = props.divClass.dropArea;
    }
    return dropAreaClass.value;
};

/** 
 * ドロップエリアに設定する class を返す
 * @return {string} ドロップエリアに設定する class
 */
const getDropAreaAddClass = () => {
    // 指定された値の追加
    let result = "";
    // ドロップエリアの追加クラス
    if (props.dropAreaAddClass) {
        result += props.dropAreaAddClass;
    }
    // エリア内ドラッグが無効の場合 class を追加
    if (props.disabled) {
        result += " drop-area-disabled";
        return result;
    }
    // エリア内ドラッグの場合の class を追加
    if (isEnter.value) {
        result += " drop-area-enter";
    }
    return result;
};

/**
 * 「ファイルの選択」ダイアログ「開く」ボタンクリック
 * ファイルの選択ダイアログで ファイル選択した場合の処理を行う。
 * @param {Event} event クリックイベント
 */
const fileSelect = (event) => {
    select(event.target.files);
    // 同一ファイルを続けて選択したときに
    // changeイベントが発生しないことを回避するために必要
    refInputFile.value.value = null;
};
/**
 * ファイル選択時の共通処理
 * @param {File} files 選択したFileListオブジェクト
 */
const select = (files) => {
    let fileList = [];
    for (let i = 0; i < files.length; i++) {
        fileList.push(files[i]);
    }
    emit('add-files', fileList);
};
/**
 * 「すべてクリア」クリック時の処理
 */
const removeAllFiles = () => {
    emit('remove-all-files');
};
/** 
 * 「ドロップエリア」のエリア内ドラッグ
 * 「ドロップエリア」のエリア内ドラッグ時の表示制御を行う。
 */
const dragEnter = () => {
    if (props.disabled) {
        return;
    }
    isEnter.value = true;
};
/** 
 * 「ドロップエリア」のエリア外ドラッグ
 * 「ドロップエリア」のエリア外ドラッグ時の表示制御を行う。
 */
const dragLeave = () => {
    if (props.disabled) {
        return;
    }
    isEnter.value = false;
};
/** 
 * 「ドロップエリア」のエリア内ドロップ
 * 「ドロップエリア」のエリア内ドロップ時の処理を行う。
 * @param {Event} event ドロップイベント
 */
const dropFile = (event) => {
    if (props.disabled) {
        return;
    }
    isEnter.value = false;
    select(event.dataTransfer.files);
};
/** 
 * 「ドロップエリア」のエリア内ドラッグオーバー
 */
const dragOver = () => {
    // 処理なし(ブラウザのデフォルトの動作をさせないためのもの)
};
</script>
