<script setup>
import { ref, onMounted } from "vue";
import { Tooltip } from "bootstrap";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import Menu from "@/components/common/Menu.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import commonInfo from "@/store/common/common-info.js";
import loadingModal from "@/utils/common/loading-modal.js";
import apiCaller from "@/utils/common/api-caller.js";
import ComFileDownload from "@/utils/common/com-file-download.js";
import StringUtil from "@/utils/common/string-util.js";
import comEnum from "@/constants/com-enum.js";
import comMessage from "@/constants/com-message.js";
import comProperty from "@/constants/com-property.js";
import { useRouter } from "vue-router";
import ComDate from "@/utils/common/com-date";

const router = useRouter();

const msg = ref("");
const enumTest = ref("");
const modalmsg = ref("defaultモーダルMsg");
const modaltitle = ref("testタイトル");
const modalOkBtn = ref("");
const modalCancelBtn = ref("");
const modalCloseBtn = ref("閉じる");
const myModal = ref();
const errMessage = ref();
const selectedFile = ref();
const breadcrumbObj = ref();
let selectedval = ref("01");
let todayYMDHM = ref("");
let todayYM = ref("");
let lastMonthYMDHM = ref("");
let lastMonthYM = ref("");
let lastYearYM = ref("");
let lastYearLastMonthYM = ref("");
let nextYearYM = ref("");
let formatDateYMDHM = ref("");
let formatDateYMD = ref("");
let formatDateYM = ref("");
let formatDate2_1_1 = ref("");
let formatDate2_1_2 = ref("");
let formatDate2_1_3 = ref("");
let formatDate2_1_4 = ref("");
let formatDate2_1_5 = ref("");
let formatDate2_1_6 = ref("");
let formatDate2_1_7 = ref("");
let formatDate2_1_8 = ref("");
let formatDate2_1_9 = ref("");
let formatDate2_1_10 = ref("");
let formatDate2_1_11 = ref("");
let formatDate2_1_12 = ref("");
let formatDate2_1_13 = ref("");
let formatDate2_1_14 = ref("");
let formatDate2_1_15 = ref("");
let nowTime = ref("");
// モード
const mode = ref("");
mode.value = SYS_ENV_MODE; // 設定ファイルから取得してセット

// 画面マウント時イベント
onMounted(async () => {
  
  // 自分の画面IDを設定
  commonInfo().screenId = "Test";
  // Enum読み込み
  enumTest.value = comEnum.EnumUSER_TYPE;
  selectedval.value = commonInfo().userType;
  // メッセージ読み込み
  msg.value = StringUtil.convertString(comMessage.COMMON000000I, ["【置き換え文字】"]);
  // パンくずリストを設定
  if(breadcrumbObj.value) breadcrumbObj.value.init(commonInfo().screenId); 

  //modal初期化
  myModal.value.init();

  let helpBtnList = [].slice.call(document.querySelectorAll('[data-bs-toggle="help"]'));
  helpBtnList.map(function (_btnElement) {
    return new Tooltip(_btnElement,{trigger:'hover', placement:'bottom', html:true})
  });

});

// 独自定義の関数（引数のミリ秒だけ処理を止める）
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

// 「ナビゲーションガードTESTボタン」押下時イベント
const btn1Click = async () => {
  loadingModal.isshow(true); // ぐるぐる出す
  await sleep(1500); // この間にAPIリクエスト等の処理を行う（暫定で1.5秒待ちするだけの処理）
  loadingModal.isshow(false); // ぐるぐる閉じる
};

// 「ヘッダフッタ表示非表示ボタン」押下時イベント
const btn2Click = async (arg) => {
  if(arg){
    modalOkBtn.value = "OK";
    modalCancelBtn.value = "キャンセル";
    modalCloseBtn.value = "閉じる";
  }else{
    modalOkBtn.value = "OK";
    modalCancelBtn.value = "キャンセル";
    modalCloseBtn.value = "";
  }
  myModal.value.show();
};
// 「ユーザー種別変更ボタン」押下時イベント
const btn3Click = async () => {
  commonInfo().userType = selectedval.value;
  router.push({ name: "UTL0101100" });
};

// 「日付操作ボタン」押下時イベント
const btn7Click = () =>{
  todayYMDHM.value = ComDate.getTodayYMDHM();
  todayYM.value = ComDate.getTodayYM();
  lastMonthYMDHM.value = ComDate.getLastMonthYMDHM();
  lastMonthYM.value = ComDate.getLastMonthYM();
  lastYearYM.value = ComDate.getLastYearYM();
  lastYearLastMonthYM.value = ComDate.getLastYearLastMonthYM();
  nextYearYM.value = ComDate.getNextYearYM(new Date());
  formatDateYMDHM.value = ComDate.formatDateYMDHM(new Date());
  formatDateYMD.value = ComDate.formatDateYMD(new Date());
  formatDateYM.value = ComDate.formatDateYM(new Date());
  formatDate2_1_1.value = ComDate.formatDateYMDHyphen(20240123);
  formatDate2_1_2.value = ComDate.formatDateYMDHyphen(20241301);
  formatDate2_1_3.value = ComDate.formatDateYMDHyphen(2024123);
  formatDate2_1_4.value = ComDate.formatDateYMDHyphen(120240123);
  formatDate2_1_5.value = ComDate.formatDateYMDHyphen("2024/01/23");
  formatDate2_1_6.value = ComDate.formatDateYMDHyphen("2024-01-23");
  formatDate2_1_7.value = ComDate.formatDateYMDHyphen("20240123");
  formatDate2_1_8.value = ComDate.formatDateYMDHyphen("202401/23");
  formatDate2_1_9.value = ComDate.formatDateYMDHyphen("2024/01/23/");
  formatDate2_1_10.value = ComDate.formatDateYMDHyphen("2024/13/01");
  formatDate2_1_11.value = ComDate.formatDateYMDHyphen("2024年元旦");
  formatDate2_1_12.value = ComDate.formatDateYMDHyphen("");
  formatDate2_1_13.value = ComDate.formatDateYMDHyphen(new Date(2024,0,23));
  formatDate2_1_14.value = ComDate.formatDateYMDHyphen(null);
  formatDate2_1_15.value = ComDate.formatDateYMDHyphen([2024,11,1]);
  nowTime = ComDate.getNowTime(new Date());
}

const linkClick = async (arg) => {
  // 画面遷移
  router.push({ name: arg });
};
// エラー系画面遷移サンプルボタン押下時イベント
const errSampleClick = async (url) => {
  const reqParam = [[url, {}]];
  const screenId = commonInfo().screenId;
  await apiCaller.httpService(reqParam, screenId);
};

// ファイル選択
const fileSelect = async (e) => {
  selectedFile.value = e.target.files[0];
};

// アップロードボタン押下
const fileUpload = async () => {
  const formData = new FormData();
  formData.append(
    "fileUploadRequeset",
    new Blob(
      [
        JSON.stringify({
          fiscalYear: "会計年度",
          corpId: "法人ID", // TODO:corpIdはNG、corporationIdに要変更
          fileType: "ファイル種別",
          operateId: "操作ID",
        }),
      ],
      { type: comProperty.CONTENT_TYPE_JSON }
    )
  );

  formData.append("facilityData1", selectedFile.value);

  const reqParam = [
    ["SAMPLE_UPLOAD", formData, comProperty.CONTENT_TYPE_MULTIPART],
  ];

  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);
};

// ダウンロードボタン押下
const fileDwnload = async () => {
  const reqParam = [
    [
      "SAMPLE_DOWNLOAD",
      { fileHistorySeq: "ファイル履歴SEQ" },
      null,
      comProperty.RESPONSE_TYPE_BLOB,
      0,
    ],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);
  console.log(res[0].headers.resultcode);
  if (res[0].headers.resultcode == "0") {
    ComFileDownload.download(res[0].data, res[0].headers, null);
  }
};

// Dialog閉じるイベント
const closeDialog = (modalReturn) => {
  alert("モーダルの戻り値：" + modalReturn);
  document.querySelector("#modalMsgText").focus();
};
</script>

<template>
  <Header />
  <div class="contents" v-if="mode == 'DEBUG'">
  <div class="row align-items-start me-0">
    <Menu />
    <Breadcrumb ref="breadcrumbObj" />
    <!--左端エリア-->
    <div class="col-sm-4">
      <div class="card p-2 mb-3">
        <button id="btn1" type="button" class="btn btn-primary" @click="btn1Click">
          ナビゲーションガード(loading)
        </button>
      </div>
      <div class="card p-2 mb-3">
        <input type="text" id="modalMsgText" class="form-control mb-2" v-model="modalmsg">
        <div>
          <button id="btn2" type="button" class="btn btn-primary me-1" @click="btn2Click(true)">
            モーダル表示(全ボタン)
          </button>
          <button id="btn2-2" type="button" class="btn btn-primary" @click="btn2Click(false)">
            モーダル表示(閉じるなし)
          </button>
        </div>
      </div>
      ※以下はログインしていないと想定と異なる挙動をします
      <div class="card p-2 mb-3">
        <button
          id="btn4"
          type="button"
          class="btn btn-primary"
          @click="errSampleClick('FORBIDDEN')"
        >
          権限エラー画面遷移サンプル
        </button>
      </div>
      <div class="card p-2 mb-3">
        <button
          id="btn5"
          type="button"
          class="btn btn-primary"
          @click="errSampleClick('UNAUTHORIZED')"
        >
          セッションエラー画面遷移サンプル
        </button>
      </div>
      <div class="card p-2 mb-3">
        <button
          id="btn6"
          type="button"
          class="btn btn-primary"
          @click="errSampleClick('SERVER_ERROR')"
        >
          システムエラー画面遷移サンプル
        </button>
      </div>
    </div>
    <!--真ん中エリア-->
    <div class="col-sm-4">
      <div class="card p-2 mb-3">
        <h5>ユーザ種別&nbsp;<button id="btn3" type="button" class="btn btn-primary" @click="btn3Click()">変更
        </button>&nbsp;<button class="btn-help" data-bs-toggle="help" data-bs-custom-class="help-tooltip" title="commonInfoのユーザ種別を変更" />
        </h5>
        <select class="form-select" v-model="selectedval">
          <option v-for="enumObj in enumTest" v-bind:value="enumObj.val">
            {{ enumObj.dispname }}
          </option>
        </select>
      </div>
      <div class="card p-2 mb-3">
        <h5>メッセージ読み込み</h5>
        <span class="message-area text-danger">{{ msg }}</span>
      </div>
      ※以下はログインしていないと想定と異なる挙動をします
      <div class="card p-2 mb-3">
        <label>ファイル選択：</label>
        <input
          type="file"
          accept=".xlsx"
          ref="selectedFile"
          @change="fileSelect"
        />
        <div v-for="erm in errMessage">
          <label class="text-danger">{{ erm }}</label>
        </div>
        <button
          id="uploadBtn"
          type="button"
          @click="fileUpload"
          class="btn btn-primary"
        >
          アップロード
        </button>
      </div>

      <div class="card p-2 mb-3">
        <button
          id="btn6"
          type="button"
          class="btn btn-primary"
          @click="fileDwnload"
        >
          ダウンロード
        </button>
      </div>
    </div>
    <!--右端エリア-->
    <div class="col-sm-4">
      <div class="card p-2 mb-3">
        <h5>画像の読み込み</h5>
        <img src="@/asset/vue.svg" style="width: 3rem" alt="TESTイメージ" />
      </div>
      <div class="card p-2 mb-3">
        <h5>参考リンク</h5>
        <a href="./sample.html">デザインガイドサンプルページ</a>
        <a  href="#" @click.prevent.stop="linkClick('Test2')">Test2</a>
        ---
        <a href="https://ja.vuejs.org/guide/introduction.html" target="_blank">本家vue.jsガイド</a>
        <a href="https://iret.media/88631" target="_blank">Vue3入門</a>
        <a href="https://b1san-blog.com/post/vue/vue-3-composition-api/" target="_blank">Vue2(Options API)とVue3(Composition API)の書き方比較</a>
      </div>
    </div>
  </div>
  <div class="row align-items-start me-0">
      <div class="card p-2 mb-3">
        <h5>日付操作実行結果
          <button id="btn3" type="button" class="btn btn-primary" style="width: 200px;" @click="btn7Click">
          日付操作実行
          </button>
        </h5>
        <div class="row">
          <div class="col-1">ケース1-1-2</div>
          <div class="col-4">&emsp;現在日付のyyyy/MM/dd HH:mm形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ todayYMDHM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-3</div>
          <div class="col-4">&emsp;現在日付のyyyy/MM形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ todayYM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-4</div>
          <div class="col-4">&emsp;現在日時 - 1ヵ月の日付のyyyy/MM/dd HH:mm形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ lastMonthYMDHM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-5</div>
          <div class="col-4">&emsp;現在日時 - 1ヵ月の日付のyyyy/MM形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ lastMonthYM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-6</div>
          <div class="col-4">&emsp;現在日時 - 1年前の日付のyyyy/MM形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ lastYearYM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-7</div>
          <div class="col-4">&emsp;現在日時の前年 - 1ヵ月の日付のyyyy/MM形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ lastYearLastMonthYM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-8</div>
          <div class="col-4">&emsp;現在日時の一年後の日付のyyyy/MM形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ nextYearYM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-9</div>
          <div class="col-4">&emsp;現在日付のyyyy/MM/dd HH:mm形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ formatDateYMDHM }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-10</div>
          <div class="col-4">&emsp;現在日付のyyyy/MM/dd形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ formatDateYMD }}</div>
        </div>
        <div class="row">
          <div class="col-1">ケース1-1-11</div>
          <div class="col-4">&emsp;現在日付のyyyy/MM形式出力</div>
          <div class="col-2">&emsp;出力結果：{{ formatDateYM }}</div>
        </div>
        <hr />
        <div class="row">
          <div class="col-1">ケース2-1-1</div>
          <div class="col-4">&emsp;引数にYYYYMMDD形式の数値８桁</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_1 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-2</div>
          <div class="col-4">&emsp;引数にYYYYMMDD形式でない数値８桁（20241301）</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_2 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-3</div>
          <div class="col-4">&emsp;引数に数値7桁(2024123)</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_3 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-4</div>
          <div class="col-4">&emsp;引数に数値9桁(120240123)</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_4 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-5</div>
          <div class="col-4">&emsp;引数にYYYY/MM/DD形式の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_5 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-6</div>
          <div class="col-4">&emsp;引数にYYYY-MM-DD形式の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_6 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-7</div>
          <div class="col-4">&emsp;引数にYYYYMMDD形式の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_7 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-8</div>
          <div class="col-4">&emsp;引数にYYYY/MMDD形式（スラッシュが少ない）の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_8 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-9</div>
          <div class="col-4">&emsp;引数にYYYY/MM/DD/形式（スラッシュが多い）の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_9 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-10</div>
          <div class="col-4">&emsp;引数にありえない日付（2024/13/01）の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_10 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-11</div>
          <div class="col-4">&emsp;引数に日付でない文字列（2024年元旦）の文字列</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_11 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-12</div>
          <div class="col-4">&emsp;引数に空文字</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_12 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-13</div>
          <div class="col-4">&emsp;引数にDate型オブジェクト</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_13 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-14</div>
          <div class="col-4">&emsp;引数にnull</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_14 }}」</div>
        </div>
        <div class="row">
          <div class="col-1">ケース2-1-15</div>
          <div class="col-4">&emsp;引数に配列（[2024,11,01]）</div>
          <div class="col-2">&emsp;出力結果：「{{ formatDate2_1_15 }}」</div>
        </div>
      </div>
    </div>
  </div>

  <Footer />
  <CommonDialog ref="myModal"
    id="commonDialog"
    :msg="modalmsg"
    :title="modaltitle"
    :okButton="modalOkBtn"
    :cancelButton="modalCancelBtn"
    :closeButton="modalCloseBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>
.message-area {
  white-space: pre-wrap;
  word-break: break-all;
}
</style>
