<!--
 医療法人情報表示エリアコンポーネント
 @version 1.0
 @author CSC
-->
<script setup>
import { computed, onMounted } from "vue";
import comEnum from "@/constants/com-enum.js";

// コンポーネントの引数
const props = defineProps({
  corpName: { type: String, default: "" }, // 医療法人名称
  prefNo: { type: String, default: "" }, // 都道府県番号
  prefName: { type: String, default: "" }, // 都道府県名
  medicCorpRefNumber: { type: String, default: "" }, // 医療法人整理番号
  address: { type: String, default: "" }, // 法人住所
  notificationMethodType: { type: String, default: "" }, // 届出方法
});

/** 届出方法Enum */
const enumNotifMethodType = comEnum.EnumNOTIFICATION_METHOD_TYPE;

// 書面での届出アイコン表示設定
const flg1 = computed(() => {
  // 届出方法が書面入力の場合は表示
  if (
    props.notificationMethodType === enumNotifMethodType.DOCUMENT_INPUTS.val
  ) {
    return true;
  } else {
    return false;
  }
});

// 画面マウント時イベント
onMounted(async () => {});
</script>

<template>
  <div class="d-flex align-items-center">
    <div class="title">
      {{ props.corpName }}
    </div>
    <div class="ms-1">
      <div class="font-size12">都道府県番号：{{ props.prefNo }}（{{ props.prefName }}）</div>
      <div class="font-size12">医療法人整理番号：{{ props.medicCorpRefNumber }}</div>
    </div>
    <div v-if="flg1">
      <i class="bi bi-file-earmark ms-2">：既に書面で届出がなされた内容が入力されています。</i>
    </div>
  </div>
  <div>{{ props.address }}</div>
</template>

<style scoped>
i span {
  color: black;
  font-style: normal;
}
</style>
