<!--
 ファイル選択コンポーネント
 @version 1.0
 @author CSC
-->
<template>
    <!-- 選択ファイル名 -->
    <div :class="fileNameClass" v-show="isShowSelectFileName">
        <label>{{ fileName }}</label>
    </div>
    <!-- 選択クリアボタン -->
    <div :class="clearClass" v-show="isShowSelectFileName">
        <button @click="reset" class="btn" title="ファイルクリア" type="button">
            <img class="testicon" src="@/asset/x-circle.svg" title="ファイルクリア" />
        </button>
    </div>
    <!-- ファイルInput -->
    <div :class="fileInputClass" v-show="isShowFileInput">
        <input type="file" :accept="accept" ref="refInputFile" @change="fileSelect" />
    </div>
    <!-- ドロップエリア -->
    <div :class="dropAreaDivClass" v-show="isShowFileInput">
        <div class="drop-area" @dragenter="dragEnter" @dragleave="dragLeave" @dragover.prevent="dragOver"
            @drop.prevent="dropFile" :class="getDropAreaClass()">
            {{ dropAreaMsg }}
        </div>
    </div>
</template>
<style scoped>
/* ドロップエリア */
.drop-area {
    padding: 3px;
    color: gray;
    font-weight: bold;
    display: flex;
    justify-content: center;
    align-items: center;
    border: 2px dashed gray;
    white-space: pre-wrap;
    text-align: center;
}

/* エリア内ドラッグ時 */
.drop-area-enter {
    border: 2px dashed powderblue;
}
</style>
<script setup>
import { onMounted, ref, computed } from "vue";

/** props：コンポーネントの引数 */
const props = defineProps({
    /**
     * ドロップエリアに表示するテキスト
     * @type {string}
     */
    dropareamsg: String,
    /**
     * 受け付けるファイル種別
     * @type {string}
     */
    accept: String,
    /**
     * 各項目の 表示エリアに設定する class（上書き）
     * @type {string}
     */
    divClass: {
        /**
         * 「ファイルInput」表示エリアclass
         * @type {string}
         */
        fileInput: String,
        /**
         * 「ドロップエリア」表示エリアclass
         * @type {string}
         */
        dropArea: String,
        /**
         * 「選択ファイル名」表示エリアclass
         * @type {string}
         */
        fileName: String,
        /**
         * 「選択クリアボタン」表示エリアclass
         * @type {string}
         */
        clear: String,
    },
    /**
     * 「ドロップエリア」に追加するclass
     * @type {string}
     */
    dropAreaAddClass: String,
});

/**
 * 選択ファイル取得
 * 選択したファイルを取得する
 * @return {?File} 選択したFileオブジェクト
 */
const getFile = () => {
    return selectedFile.value;
};
/**
 * 「選択クリア」ボタンクリック
 * ファイル選択の解除を行う
 */
const reset = () => {
    refInputFile.value.value = null;

    selectedFile.value = null;
    fileName.value = '';

    isSelected.value = false;
};

/** コンポーネントのメソッド公開 */
defineExpose({
    /** 選択ファイル取得 */
    getFile,
    /** ファイル選択クリア */
    reset,
});

// 変数
/** ドロップエリアの範囲内かどうか */
const isEnter = ref(false);
/** ファイル選択中フラグ */
const isSelected = ref(false);
/** 選択したFileオブジェクト */
const selectedFile = ref(null);
/** ファイルInput部品のref */
const refInputFile = ref(null);
/** 選択したファイル名 */
const fileName = ref("");
/** ドロップエリアに表示するテキスト */
const dropAreaMsg = ref("添付したいファイルをここに\n" + "ドラッグ＆ドロップしてください");
// div class
/** 「ファイルInput」表示エリアclass */
const fileInputClass = ref("col");
/** 「ドロップエリア」表示エリアclass */
const dropAreaDivClass = ref("col");
/** 「選択ファイル名」表示エリアclass */
const fileNameClass = ref("col");
/** 「選択クリアボタン」表示エリアclass */
const clearClass = ref("col");
// isShow
/** @type {boolean} 「選択ファイル名／選択クリアボタン」表示フラグ */
const isShowSelectFileName = computed(() => {
    // ファイル選択時に表示
    return isSelected.value;
});
/** @type {boolean} 「ファイルInput／ドロップエリア」表示フラグ */
const isShowFileInput = computed(() => {
    // ファイル非選択時に表示
    return !isSelected.value;
});

/**
 * コンポーネントのマウント後の処理
 */
onMounted(() => {
    // 初期処理
    init();
});

// 関数
/**
 * ファイル選択コンポーネント初期表示
 */
const init = () => {
    // 表示文言の設定
    if (props.dropareamsg !== undefined) {
        dropAreaMsg.value = props.dropareamsg;
    }

    // 各項目の表示エリアで使用する class 設定
    if (props.divClass === undefined) {
        return;
    }
    if (props.divClass.fileInput !== undefined) {
        fileInputClass.value = props.divClass.fileInput;
    }
    if (props.divClass.dropArea !== undefined) {
        dropAreaDivClass.value = props.divClass.dropArea;
    }
    if (props.divClass.fileName !== undefined) {
        fileNameClass.value = props.divClass.fileName;
    }
    if (props.divClass.clear !== undefined) {
        clearClass.value = props.divClass.clear;
    }
};

/** 
 * ドロップエリアに設定する class を返す
 * @return {string} ドロップエリアに設定する class
 */
const getDropAreaClass = () => {
    let result = "";
    // 指定された値の追加
    if (props.dropAreaAddClass !== undefined) {
        result += props.dropAreaAddClass;
    }
    // エリア内ドラッグの場合の class を追加
    if (isEnter.value) {
        result += " drop-area-enter";
    }
    return result;
};
/**
 * 「ファイルの選択」ダイアログ「開く」ボタンクリック
 * ファイルの選択ダイアログで ファイル選択した場合の処理を行う。
 * @param {Event} event クリックイベント
 */
const fileSelect = (event) => {
    select(event.target.files[0]);
};
/**
 * ファイル選択時の共通処理
 * @param {File} file 選択したFileオブジェクト
 */
const select = (file) => {
    selectedFile.value = file;
    console.log(file);
    console.log(file.size);

    fileName.value = selectedFile.value.name;
    isSelected.value = true;
};
/** 
 * 「ドロップエリア」のエリア内ドラッグ
 * 「ドロップエリア」のエリア内ドラッグ時の表示制御を行う。
 */
const dragEnter = () => {
    isEnter.value = true;
};
/** 
 * 「ドロップエリア」のエリア外ドラッグ
 * 「ドロップエリア」のエリア外ドラッグ時の表示制御を行う。
 */
const dragLeave = () => {
    isEnter.value = false;
};
/** 
 * 「ドロップエリア」のエリア内ドロップ
 * 「ドロップエリア」のエリア内ドロップ時の処理を行う。
 * @param {Event} event ドロップイベント
 */
const dropFile = (event) => {
    isEnter.value = false;
    select(event.dataTransfer.files[0]);
};
/** 
 * 「ドロップエリア」のエリア内ドラッグオーバー
 */
const dragOver = () => {
    // 処理なし
};
</script>