/**
 *  ユーザ登録画面の画面間連携データ（パラメータ）を定義する
 *
 *  @version 1.0
 *  @author CSC
 */
import { defineStore } from "pinia";

const MNM0301200Param = defineStore("MNM0301200Param", {
    state: () => {
      return {
        userId: "",             // ユーザID
        prefCode: "",           // 都道府県番号
        prefName: "",           // 都道府県名
        corporationId: "",      // 法人ID
        corporationName: "",    // 法人名称
        medicCorpRefNumber: "", // 医療法人整理番号
        prefCodeInfoMap: [],    // 都道府県マップ
      };
    },
    persist: {
      storage: window.sessionStorage,
    },
  });
  
  export default MNM0301200Param;