<!--
 メール設定一覧画面
 @version 1.0
 @author C
-->
<script setup>
import { ref, onMounted, reactive } from 'vue';
import { useRouter } from 'vue-router';
import Header from '@/components/common/Header.vue';
import Footer from '@/components/common/Footer.vue';
import Menu from '@/components/common/Menu.vue';
import Breadcrumb from '@/components/common/Breadcrumb.vue';
import CommonDialog from "@/components/common/CommonDialog.vue";
import StatusExplanation from '@/components/ENT0401100/StatusExplanation.vue';
import MedicCorpInfo from '@/components/ENT0401100/MedicCorpInfo.vue';
import comConst from '@/constants/com-const.js';
import comEnum from '@/constants/com-enum.js';
import commonInfo from '@/store/common/common-info.js';
import targetCorp from '@/store/common/target-corp.js';
import StringUtil from '@/utils/common/string-util.js';
import comMessage from '@/constants/com-message.js';
import loadingModal from '@/utils/common/loading-modal.js';
import apiCaller from '@/utils/common/api-caller.js';
import comDate from '@/utils/common/com-date.js';
import messageUtil from '@/utils/common/message-util.js';
import ENT0102100Param from '@/store/ENT0102100/ent0102100-param.js';

/** VueRouter */
const router = useRouter();
const props = defineProps({
  corpId: String,
});

/** 画面名 */
const screenName = 'メール設定一覧画面';
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面キャンセルボタン
const modalCancelBtn = ref("キャンセル");
// ポップアップ画面
const myModal = ref();
// メール設定情報一覧
const mailSettingList = ref([
  {
    id: 1,
    email: 'user1@example.com',
    incomingServer: 'imap.example.com',
    outgoingServer: 'smtp.example.com'
  }
]);
/** イベント項目 */
const eventName = ref("");

// 初期表示
const ENT0101100E01 = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));
	eventName.value = "init";
  	if (props.corpId != null) {
		commonInfo().corpId = props.corpId;
	}
	// ローディングの表示
	loadingModal.isshow(true);

	// メール設定一覧情報取得APIの呼び出し
	const reqManageInfoParam = [
		[
			comConst.API_ID_ENT0101_01,
			{
				corporationId: commonInfo().corpId,
			},
		],
	];
	const res = await apiCaller.httpService(reqManageInfoParam, commonInfo().screenId);
	// 結果コード = "0"（正常終了）の場合
	if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
		// ローディングの非表示
		loadingModal.isshow(false);
		mailSettingList.value = res[0].data.mailSettingList || [];
	}
	// 上記以外
	else {
		// ローディングの非表示
		loadingModal.isshow(false);
		// 終了ログ
		console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
		// システムエラー画面へ遷移
		router.push({ name: comConst.UTL9999993 });
	}

	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * 追加ボタン押下
 */
const clickAddBtn = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, '追加ボタン押下']));

	eventName.value = "add";
	ENT0102100Param().mailSetting = {};
	ENT0102100Param().mailSetting.SHOP_ID = commonInfo().corpId;
	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, '追加ボタン押下']));
	// メール追加画面へ遷移
	router.push({ name: comConst.ENT0102100 });
};

/**
 * 編集ボタン押下
 */
const clickEditBtn = async (mailSetting) => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, '編集ボタン押下']));

	eventName.value = "update";
	ENT0102100Param().mailSetting = mailSetting;
	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, '編集ボタン押下']));
	// メール編集画面へ遷移
	router.push({ name: comConst.ENT0102100 });
};


/**
 * 削除ボタン押下
 */
const clickDeleteBtn = (mailSetting) => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, '削除ボタン押下']));

	eventName.value = "delete";
	ENT0102100Param().mailSetting = mailSetting;
  	confirmMessage(comMessage.COMMON100031I);

	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, '削除ボタン押下']));
}

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  if (modalReturn == 1) {
    if ("delete" === eventName.value) {
      // メール設定削除
      ATH0101100E03();
    }
  }
};

/**
 * メール設定削除
 */
const ATH0101100E03 = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, 'メール設定削除']));

	// ローディングの表示
	loadingModal.isshow(true);

	// メール設定削除APIの呼び出し
	const reqManageInfoParam = [
		[
			comConst.API_ID_ENT0101_04,
			{
				emailSetting: ENT0102100Param().mailSetting
			},
		],
	];
	const res = await apiCaller.httpService(reqManageInfoParam, commonInfo().screenId);
	// 結果コード = "0"（正常終了）の場合
	if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
		// ローディングの非表示
		loadingModal.isshow(false);
		// 削除完了メッセージ表示
		showMessage(comMessage.MNM0301_0300I);
	}
	// 上記以外
	else {
		// ローディングの非表示
		loadingModal.isshow(false);
		// 終了ログ
		console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
		// システムエラー画面へ遷移
		router.push({ name: comConst.UTL9999993 });
	}
	ENT0101100E01();
	ENT0102100Param().mailSetting = {};
	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, 'メール設定削除']));
};

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const confirmMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  modalCancelBtn.value = "キャンセル";
  myModal.value.show();
};

/**
 * メール一覧画面
 */
const ENT0101100E05 = () => {	
  // 「ENT0201100：メール一覧画面」へ遷移する。
  router.push({ name: comConst.ENT0201100 });
};

/**
 * 注文一覧画面
 */
const ENT0201100E06 = () => {	
  // 「ENT0201200：注文一覧画面」へ遷移する。
  router.push({ name: comConst.ENT0201200});
};

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  modalCancelBtn.value = "";
  myModal.value.show();
};

// 画面マウント時イベント
onMounted(async () => {
	// 自分の画面IDを設定
	commonInfo().screenId = comConst.ENT0101100;
	// modal初期化
	myModal.value.init();

	// 初期表示
	await ENT0101100E01();
});

</script>
<template>
  <div class="menu">	
	<button class="menu-btn" v-on:click="ENT0101100E05">メール一覧</button>
	<button class="menu-btn" v-on:click="ENT0201100E06">オーダ一覧</button>
  </div>
  <div class="container">
    <h2 class="title">メール設定一覧</h2>

    <div class="actions">
      <button class="btn add" @click="clickAddBtn">追加</button>
    </div>

    <table class="mail-table">
      <thead>
        <tr>
          <th>#</th>
          <th>メールアドレス</th>
          <th>受信サーバ</th>
          <th>送信サーバ</th>
          <th>操作</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="(mail, index) in mailSettingList" :key="mail.EMAIL_SETTING_ID">
          <td>{{ index + 1 }}</td>
          <td>{{ mail.EMAIL_ADDRESS }}</td>
          <td>{{ mail.RECEIVE_SERVER }}</td>
          <td>{{ mail.SEND_SERVER }}</td>
          <td>
            <button class="btn edit" @click="clickEditBtn(mail)">編集</button>
            <button class="btn delete" @click="clickDeleteBtn(mail)">削除</button>
          </td>
        </tr>
        <tr v-if="mailSettingList.length === 0">
          <td colspan="5" class="no-data">データがありません</td>
        </tr>
      </tbody>
    </table>
  </div>
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="modalCancelBtn"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>

.title {
  font-size: 24px;
  text-align: center;
  margin-bottom: 20px;
}

.actions {
  text-align: right;
  margin-bottom: 10px;
}

.mail-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 14px;
}

.mail-table th,
.mail-table td {
  border: 1px solid #ccc;
  padding: 8px;
  text-align: left;
}

.mail-table th {
  background-color: #f4f4f4;
}

.btn {
  padding: 6px 12px;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 13px;
}

.btn.add {
  background-color: #28a745;
  color: white;
}

.btn.edit {
  background-color: #007bff;
  color: white;
  margin-right: 6px;
}

.btn.delete {
  background-color: #dc3545;
  color: white;
}

.no-data {
  text-align: center;
  color: #888;
  font-style: italic;
}
</style>
