<!--
  医療法人の経営情報等「経営状況に関する情報」「職種別給与総額及びその人数に関する情報」に共通のコンポーネント（経営情報等Web入力画面）
    病院所在地～二次医療圏まで
  @version 1.0
  @author CSC
-->
<template>
  <tbody>
    <tr>
      <td></td>
      <td colspan="2"></td>
      <td></td>
      <td v-show="!allDisabled" colspan="3" style="text-align: center"><label for="cityDirectCheckFlg" class="form-check-label">直接入力</label></td>
      <td colspan="2"></td>
      <td></td>
      <td v-show="!allDisabled" colspan="3" style="text-align: center">
        <label for="secoundaryDirectCheckFlg" class="form-check-label">直接入力</label>
      </td>
    </tr>
    <tr>
      <td class="text_aline_center" style="width: 8%; align-content: center">
        <template v-if="mngInfoSBJ.hospitalClinicType == comEnum.EnumHOSPITAL_CLINIC_TYPE.HOSPITAL.val">病院所在地</template>
        <template v-if="mngInfoSBJ.hospitalClinicType == comEnum.EnumHOSPITAL_CLINIC_TYPE.CLINIC.val">診療所所在地</template>
      </td>
      <td class="col-form-label" style="width: 9%">都道府県</td>
      <td style="width: 9%">
        <select
          class="form-select pref-select"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="病院が所在する都道府県を選択ください。"
          v-model="mngInfoSBJ.n00091Prefecture.value"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n00091Prefecture.messageErr.length > 0 }"
          :disabled="allDisabled"
          @input="handleInput($event, 'n00091Prefecture')"
        >
          <option value=""></option>
          <option v-for="pref in props.prefList" v-bind:value="pref.prefName">
            {{ pref.prefName }}
          </option>
        </select>
      </td>
      <td class="col-form-label" style="width: 9%">市区町村</td>
      <td v-if="!allDisabled" style="width: 9%">
        <select
          id="selectBox5"
          class="form-select city-select"
          :disabled="cityDirectCheckFlg"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="都道府県を選択するとリストが表示されます。リストにない場合は直接記載ください。"
          v-model="cityNameDisp"
          :class="{ errordisp: !allDisabled && !cityDirectCheckFlg && mngInfoSBJ.n00092City.messageErr.length > 0 }"
          @input="handleInput($event, 'n00092City')"
        >
          <option value=""></option>
          <option v-for="city in cityList" v-bind:value="city.cityName">
            {{ city.cityName }}
          </option>
        </select>
      </td>
      <td v-if="!allDisabled" style="width: 1%; align-content: center">
        <input type="checkbox" id="cityDirectCheckFlg" class="form-check-input" v-model="cityDirectCheckFlg" />
      </td>
      <td style="width: 9%">
        <input
          type="text"
          id="textBox5"
          class="form-control"
          :disabled="allDisabled || !cityDirectCheckFlg"
          v-bind:value="cityDirectCheckFlg || allDisabled ? mngInfoSBJ.n00092City.value : null"
          v-model="mngInfoSBJ.n00092City.value"
          :class="{ errordisp: !allDisabled && cityDirectCheckFlg && mngInfoSBJ.n00092City.messageErr.length > 0 }"
          @input="handleInput($event, 'n00092City')"
        />
      </td>
      <td class="col-form-label" style="width: 9%">町域</td>
      <td style="width: 9%">
        <input
          type="text"
          class="form-control"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="町域のみ記載ください。丁目番地号は記載不要です。"
          v-model="mngInfoSBJ.n00093TownArea.value"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n00093TownArea.messageErr.length > 0 }"
          :disabled="allDisabled"
          @input="handleInput($event, 'n00093TownArea')"
        />
      </td>
      <td class="col-form-label" style="width: 9%">二次医療圏</td>
      <td v-if="!allDisabled" style="width: 9%">
        <select
          id="selectBox6"
          class="form-select"
          :disabled="allDisabled || secoundaryDirectCheckFlg"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="市区町村を選択するとリストが表示されます。リストにない場合は直接記載ください。"
          v-model="secondaryMedicalAreaNameDisp"
          :class="{ errordisp: !allDisabled && !secoundaryDirectCheckFlg && mngInfoSBJ.n0010SecoundaryMedicalArea.messageErr.length > 0 }"
          @input="handleInput($event, 'n0010SecoundaryMedicalArea')"
        >
          <option value=""></option>
          <option v-for="area in secondaryMedicalAreaList" v-bind:value="area.secoundaryMedicalAreaName">{{ area.secoundaryMedicalAreaName }}</option>
        </select>
      </td>
      <td v-if="!allDisabled" style="width: 1%; align-content: center">
        <input type="checkbox" id="secoundaryDirectCheckFlg" class="form-check-input" v-model="secoundaryDirectCheckFlg" />
      </td>
      <td style="width: 9%">
        <input
          type="text"
          id="textBox6"
          class="form-control"
          :disabled="!secoundaryDirectCheckFlg"
          v-bind:value="secoundaryDirectCheckFlg || allDisabled ? mngInfoSBJ.n0010SecoundaryMedicalArea.value : null"
          v-model="mngInfoSBJ.n0010SecoundaryMedicalArea.value"
          :class="{ errordisp: !allDisabled && secoundaryDirectCheckFlg && mngInfoSBJ.n0010SecoundaryMedicalArea.messageErr.length > 0 }"
          @input="handleInput($event, 'n0010SecoundaryMedicalArea')"
        />
      </td>
    </tr>
    <tr
      v-if="
        !allDisabled &&
        (mngInfoSBJ.n00091Prefecture.messageErr.length > 0 ||
          mngInfoSBJ.n00091Prefecture.messageWarn.length > 0 ||
          mngInfoSBJ.n00092City.messageErr.length > 0 ||
          mngInfoSBJ.n00092City.messageWarn.length > 0 ||
          mngInfoSBJ.n00093TownArea.messageErr.length > 0 ||
          mngInfoSBJ.n00093TownArea.messageWarn.length > 0 ||
          mngInfoSBJ.n0010SecoundaryMedicalArea.messageErr.length > 0 ||
          mngInfoSBJ.n0010SecoundaryMedicalArea.messageWarn.length > 0)
      "
    >
      <td></td>
      <td colspan="2" v-if="mngInfoSBJ.n00091Prefecture.messageErr.length > 0 || mngInfoSBJ.n00091Prefecture.messageWarn.length > 0">
        <div v-for="msg in mngInfoSBJ.n00091Prefecture.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00091Prefecture.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="2" v-else></td>
      <td colspan="4" v-if="mngInfoSBJ.n00092City.messageErr.length > 0 || mngInfoSBJ.n00092City.messageWarn.length > 0">
        <div v-for="msg in mngInfoSBJ.n00092City.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00092City.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="4" v-else></td>
      <td colspan="2" v-if="mngInfoSBJ.n00093TownArea.messageErr.length > 0 || mngInfoSBJ.n00093TownArea.messageWarn.length > 0">
        <div v-for="msg in mngInfoSBJ.n00093TownArea.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00093TownArea.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="2" v-else></td>
      <td colspan="4">
        <div v-for="msg in mngInfoSBJ.n0010SecoundaryMedicalArea.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n0010SecoundaryMedicalArea.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
    </tr>
  </tbody>
</template>
<style scoped>
.text_aline_center {
  place-items: center;
  text-align: center;
}

.col-form-label {
  padding-left: 15px !important;
  line-height: 1.17 !important;
  vertical-align: middle;
}
</style>
<script setup>
import { onMounted, ref, computed } from "vue";
import { Tooltip } from "bootstrap";
import comEnum from "@/constants/com-enum.js";

/** props：コンポーネントの引数 */
const props = defineProps({
  prefList: { type: Object, default: [] }, // 都道府県マスタリスト
  cityList: { type: Object, default: [] }, // 市区町村マスタリスト
  secondaryMedicalAreaList: { type: Object, default: [] }, // 二次医療圏マスタリスト
  editClass: { type: String, default: "3" }, // 編集区分
  allDisabled: { type: Boolean, default: false }, // 全項目非活性
});

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["input"]);

const cityDirectCheckFlg = ref(false);
const secoundaryDirectCheckFlg = ref(false);

// 初期値
const inputItemDto = { value: "", messageErr: [], messageWarn: [] };
const mngInfoSBJ = ref({
  hospitalClinicType: "",
  // "n0001HospitalClinicDivision": "",
  // "n0002PrefCode": "",
  // "n0001MedicCorpRefNo": "",
  // "n0002CorporateNo": inputItemDto,
  // "n00031SickbedOutpatCtrlnoExist": inputItemDto,
  // "n00032SickbedOutpatCtrlNo": inputItemDto,
  // "n00041MedicInstiCdExist": inputItemDto,
  // "n00042MedicInstiCd": inputItemDto,
  // "n0005CorporationName": inputItemDto,
  // "n0006HospitalClinicName": inputItemDto,
  // "n0007OfficerCount": inputItemDto,
  // "n0008StaffCount": inputItemDto,
  n00091Prefecture: inputItemDto,
  n00092City: inputItemDto,
  n00093TownArea: inputItemDto,
  n0010SecoundaryMedicalArea: inputItemDto,
});

/**
 * コンポーネントの初期表示イベント
 */
onMounted(() => {
  // ツールチップ
  let helpBtnList = [].slice.call(document.querySelectorAll('[data-bs-toggle="help"]'));
  helpBtnList.map(function (_btnElement) {
    return new Tooltip(_btnElement, { trigger: "hover", placement: "bottom", html: true });
  });
  let targetList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
  targetList.map(function (_element) {
    return new Tooltip(_element, { trigger: "focus", html: true, animation: false });
  });
});

/**
 * 市区町村セレクトボックスの設定
 */
const cityList = computed(() => {
  const selectedPref = props.prefList.find((pref) => pref.prefName == mngInfoSBJ.value.n00091Prefecture.value);
  let cityList = [];
  if (selectedPref) {
    cityList = props.cityList.filter((city) => city.prefCode == selectedPref.prefCode);
  }
  if (cityList.find((city) => city.cityName == mngInfoSBJ.value.n00092City.value) || !mngInfoSBJ.value.n00092City.value) {
    cityDirectCheckFlg.value = false;
  } else {
    cityDirectCheckFlg.value = true;
  }
  return cityList;
});

/**
 * 市区町村セレクトボックスの選択値の設定
 */
const cityNameDisp = computed(() => {
  if (cityDirectCheckFlg.value) {
    return "";
  } else {
    return mngInfoSBJ.value.n00092City.value;
  }
});

/**
 * 二次医療圏セレクトボックスの設定
 */
const secondaryMedicalAreaList = computed(() => {
  const selectedPref = props.prefList.find((pref) => pref.prefName == mngInfoSBJ.value.n00091Prefecture.value);
  const selectedCity = props.cityList.find((city) => city.cityName == mngInfoSBJ.value.n00092City.value);
  let secondaryMedicalAreaList = [];
  if (selectedCity) {
    secondaryMedicalAreaList = props.secondaryMedicalAreaList.filter(
      (area) => area.prefCode == selectedPref.prefCode && area.cityCode == selectedCity.cityCode
    );
  }
  if (
    secondaryMedicalAreaList.find(
      (secondaryMedicalArea) => secondaryMedicalArea.secoundaryMedicalAreaName == mngInfoSBJ.value.n0010SecoundaryMedicalArea.value
    )
  ) {
    secoundaryDirectCheckFlg.value = false;
  } else {
    secoundaryDirectCheckFlg.value = true;
  }
  return secondaryMedicalAreaList;
});

/**
 * 二次医療圏セレクトボックスの選択値の設定
 */
const secondaryMedicalAreaNameDisp = computed(() => {
  if (secoundaryDirectCheckFlg.value) {
    return "";
  } else {
    return mngInfoSBJ.value.n0010SecoundaryMedicalArea.value;
  }
});

/**
 * テキスト変更時のイベント
 * @param event
 * @param id bindされた項目名
 */
const handleInput = (event, id) => {
  emit("input", { event: event, id: id });
};

/**
 * コンポーネント初期化
 */
const init = () => {};

/**
 * mngInfoSalaryByJobtypeオブジェクトの取得
 */
const getMngInfoSBJ = () => {
  return mngInfoSBJ.value;
};

/**
 * mngInfoSalaryByJobtypeオブジェクトの設定
 * @return mngInfoSalaryByJobtype
 */
const setMngInfoSBJ = (_mngInfoSalaryByJobtype) => {
  mngInfoSBJ.value = _mngInfoSalaryByJobtype;
};

/** コンポーネントのメソッド公開 */
defineExpose({
  /** 初期化 */
  init,
  /** mngInfoSalaryByJobtypeオブジェクトの取得 */
  getMngInfoSBJ,
  /** mngInfoSalaryByJobtypeオブジェクトの設定 */
  setMngInfoSBJ,
});
</script>
