<!--
 トップに戻るボタン
 @version 1.0
 @author CSC
-->
<template>
  <button type="button" id="scrollToTopBtn" class="btn btn-primary normal_button" @click="scrollToTop">トップ<br>に戻る</button>
</template>
<script setup>
  import { onMounted } from "vue";

   /** emit：イベント定義 */
   const emit = defineEmits(["blur","focus","input"]);
  
  // 画面生成時のイベント
  onMounted(() =>{
    // NOP
  });

  // トップに戻るボタン押下時イベント
  const scrollToTop = (event) => {
    document.getElementsByClassName("contents")[0].scrollTo({
      top: 0,
      behavior: 'smooth',
    });
  }

  /** expose：公開メソッド定義(scriptの一番下に記載) */
  defineExpose({
    scrollToTop
  });
</script>
<style scoped>
  /** コンポーネント固有のstyle設定 */
  /* トップに戻るボタン */
  #scrollToTopBtn {
    position: fixed;
    bottom: 8%;
    right: 2%;
    width: 90px;
    height: 90px;
    border-radius: 100%;
    cursor: pointer;
    z-index: 1000;
    opacity: 0.8 ; /* 全体の透明度を設定 */
  }     
</style>
  