<!--
  医療法人の経営情報等「経営状況に関する情報」「職種別給与総額及びその人数に関する情報」に共通のコンポーネント（経営情報等Web入力画面）
    都道府県～医療機関コードまで
  @version 1.0
  @author CSC
-->
<template>
  <tbody>
    <tr>
      <td class="col-form-label">都道府県</td>
      <td colspan="2">
        <input type="text" class="form-control" v-bind:value="n0002PrefCodeDisp" disabled />
      </td>
    </tr>
    <tr>
      <td class="col-form-label" style="min-width: 10rem">医療法人整理番号</td>
      <td colspan="2">
        <input type="text" class="form-control" v-model="mngInfoSBJ.n0001MedicCorpRefNo" disabled />
      </td>
    </tr>
    <tr>
      <td class="col-form-label">法人番号</td>
      <td colspan="2">
        <input
          id="corporation_number"
          type="text"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="13桁の数字を半角で記載ください。"
          class="form-control"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n0002CorporateNo.messageErr.length > 0 }"
          v-model="mngInfoSBJ.n0002CorporateNo.value"
          :disabled="allDisabled"
          @input="handleInput($event, 'n0002CorporateNo')"
        />
      </td>
    </tr>
    <tr v-if="!allDisabled && (mngInfoSBJ.n0002CorporateNo.messageErr.length > 0 || mngInfoSBJ.n0002CorporateNo.messageWarn.length > 0)">
      <td colspan="2">
        <div v-for="msg in mngInfoSBJ.n0002CorporateNo.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n0002CorporateNo.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
    </tr>
    <tr>
      <td class="col-form-label" style="min-width: 10rem">病床・外来管理番号</td>
      <td style="width: 90px">
        <select
          id="selectBox3"
          class="form-select me-0"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="病床・外来管理番号付与の有無を選択ください。"
          v-model="mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.value"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageErr.length > 0 }"
          @input="handleInput($event, 'n00031SickbedOutpatCtrlnoExist')"
          :disabled="allDisabled"
        >
          <option v-for="enumObj in comEnum.EnumEXIST_TYPE" v-bind:value="enumObj.dispname">
            {{ enumObj.dispname }}
          </option>
        </select>
      </td>
      <td>
        <input
          id="textBox3"
          type="text"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="8桁の数字を半角で記載ください。"
          class="form-control"
          style="width: 100%"
          v-model="mngInfoSBJ.n00032SickbedOutpatCtrlNo.value"
          :disabled="allDisabled || mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.value == comEnum.EnumEXIST_TYPE.NOT_AVAILBLE.dispname"
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n00032SickbedOutpatCtrlNo.messageErr.length > 0 }"
          @input="handleInput($event, 'n00032SickbedOutpatCtrlNo')"
        />
      </td>
    </tr>
    <tr
      v-if="
        !allDisabled &&
        (mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageErr.length > 0 ||
          mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageWarn.length > 0 ||
          mngInfoSBJ.n00032SickbedOutpatCtrlNo.messageErr.length > 0 ||
          mngInfoSBJ.n00032SickbedOutpatCtrlNo.messageWarn.length > 0)
      "
    >
      <td
        colspan="2"
        v-if="mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageErr.length > 0 || mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageWarn.length > 0"
      >
        <div v-for="msg in mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00031SickbedOutpatCtrlnoExist.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="2" v-else></td>
      <td>
        <div v-for="msg in mngInfoSBJ.n00032SickbedOutpatCtrlNo.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00032SickbedOutpatCtrlNo.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
    </tr>
    <tr>
      <td class="col-form-label">医療機関コード</td>
      <td>
        <select
          id="selectBox4"
          class="form-select me-0"
          data-bs-toggle="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="保険医療機関指定の有無を選択ください。"
          v-model="mngInfoSBJ.n00041MedicInstiCdExist.value"
          disabled
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n00041MedicInstiCdExist.messageErr.length > 0 }"
        >
          <option v-for="enumObj in comEnum.EnumEXIST_TYPE" v-bind:value="enumObj.dispname">
            {{ enumObj.dispname }}
          </option>
        </select>
      </td>
      <td>
        <input
          id="textBox4"
          type="text"
          data-bs-toggle1="tooltip"
          data-bs-custom-class="text-tooltip"
          data-bs-placement="right"
          title="10桁の数字を半角で記載ください。（都道府県番号2桁＋点数表番号1桁＋医療機関コード7桁）"
          class="form-control"
          v-model="mngInfoSBJ.n00042MedicInstiCd.value"
          disabled
          :class="{ errordisp: !allDisabled && mngInfoSBJ.n00042MedicInstiCd.messageErr.length > 0 }"
        />
      </td>
    </tr>
    <tr
      v-if="
        !allDisabled &&
        (mngInfoSBJ.n00041MedicInstiCdExist.messageErr.length > 0 ||
          mngInfoSBJ.n00041MedicInstiCdExist.messageWarn.length > 0 ||
          mngInfoSBJ.n00042MedicInstiCd.messageErr.length > 0 ||
          mngInfoSBJ.n00042MedicInstiCd.messageWarn.length > 0)
      "
    >
      <td colspan="2" v-if="mngInfoSBJ.n00041MedicInstiCdExist.messageErr.length > 0 || mngInfoSBJ.n00041MedicInstiCdExist.messageWarn.length > 0">
        <div v-for="msg in mngInfoSBJ.n00041MedicInstiCdExist.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00041MedicInstiCdExist.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
      <td colspan="2" v-else></td>
      <td>
        <div v-for="msg in mngInfoSBJ.n00042MedicInstiCd.messageErr" class="form-text">{{ msg }}</div>
        <div v-for="msg in mngInfoSBJ.n00042MedicInstiCd.messageWarn" class="alert-area">{{ msg }}</div>
      </td>
    </tr>
  </tbody>
</template>
<style scoped>
.col-form-label {
  padding-left: 15px !important;
  line-height: 1.17 !important;
  vertical-align: middle;
}
</style>
<script setup>
import { onMounted, ref, computed } from "vue";
import { Tooltip } from "bootstrap";
import comEnum from "@/constants/com-enum.js";

/** props：コンポーネントの引数 */
const props = defineProps({
  prefList: { type: Object, default: [] }, // 都道府県マスタリスト
  editClass: { type: String, default: "3" }, // 編集区分
  allDisabled: { type: Boolean, default: false }, // 全項目非活性
});

const n0002PrefCodeDisp = computed(() => {
  const pref = props.prefList.find((pref) => pref.prefCode == mngInfoSBJ.value.n0002PrefCode);
  return pref ? pref.prefName : null;
});

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["input"]);

// 初期値
const inputItemDto = { value: "", messageErr: [], messageWarn: [] };
const mngInfoSBJ = ref({
  hospitalClinicType: "",
  n0001HospitalClinicDivision: "",
  n0002PrefCode: "",
  n0001MedicCorpRefNo: "",
  n0002CorporateNo: inputItemDto,
  n00031SickbedOutpatCtrlnoExist: inputItemDto,
  n00032SickbedOutpatCtrlNo: inputItemDto,
  n00041MedicInstiCdExist: inputItemDto,
  n00042MedicInstiCd: inputItemDto,
});

/**
 * コンポーネントの初期表示イベント
 */
onMounted(() => {
  // ツールチップ
  let helpBtnList = [].slice.call(document.querySelectorAll('[data-bs-toggle="help"]'));
  helpBtnList.map(function (_btnElement) {
    return new Tooltip(_btnElement, { trigger: "hover", placement: "bottom", html: true });
  });
  let targetList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
  targetList.map(function (_element) {
    return new Tooltip(_element, { trigger: "focus", html: true, animation: false });
  });
});

/**
 * テキスト変更時のイベント
 * @param event
 * @param id bindされた項目名
 */
const handleInput = (event, id) => {
  emit("input", { event: event, id: id });
};

/**
 * コンポーネント初期化
 */
const init = () => {};

/**
 * mngInfoSalaryByJobtypeオブジェクトの取得
 */
const getMngInfoSBJ = () => {
  return mngInfoSBJ.value;
};

/**
 * mngInfoSalaryByJobtypeオブジェクトの設定
 * @return mngInfoSalaryByJobtype
 */
const setMngInfoSBJ = (_mngInfoSalaryByJobtype) => {
  mngInfoSBJ.value = _mngInfoSalaryByJobtype;
};

/** コンポーネントのメソッド公開 */
defineExpose({
  /** 初期化 */
  init,
  /** mngInfoSalaryByJobtypeオブジェクトの取得 */
  getMngInfoSBJ,
  /** mngInfoSalaryByJobtypeオブジェクトの設定 */
  setMngInfoSBJ,
});
</script>
