class validator {
    /// <summary>
    /// 文字列の長さをチェックします。
    /// </summary>
    /// <param name="value">チェック対象の文字列</param>
    /// <param name="max">最大文字数</param>
    /// <param name="min">最小文字数</param>
    /// <returns>エラー時はfalse、正常時はtrueを返す</returns>
    static validLength(value, max = Number.MAX_VALUE, min = 0) {
      if (value.length >= min && value.length <= max) return true;
      return false;
    }
  
    /// <summary>
    /// 整数値であることをチェックします。
    /// </summary>
    /// <param name="value">チェック対象の文字列</param>
    /// <returns>エラー時はfalse、正常時はtrueを返す(空白は正常扱い)</returns>
    static IsInteger(value) {
      let i = 0;
      if (null == value || "" == value) return true;
      if (!isNaN(parseInt(value))) return true;
      return false;
    }

    /// <summary>
    /// 半角英数字であることをチェックします。
    /// </summary>
    /// <param name="value">チェック対象の文字列</param>
    /// <returns>エラー時はfalse、正常時はtrueを返す</returns>
    static IsHalfwidthAlphanumeric(value) {
      const regex = /^[a-zA-Z0-9]*$/;
      return regex.test(value ?? '');
    }
  
    /// <summary>
    /// <c>null</c>値及び空白値でないことをチェックします。
    /// </summary>
    /// <param name="value">チェック対象の文字列</param>
    /// <returns>エラー時はfalse、正常時はtrueを返す</returns>
    static IsNotNullEmpty(value) {
      if (null !== value && value.length > 0) return true;
      return false;
    }
  }
  export default validator;
  