<!--
 買い物箱画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted } from "vue";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import commonInfo from "@/store/common/common-info.js";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";
import apiCaller from "@/utils/common/api-caller.js";
import StringUtil from "@/utils/common/string-util.js"
import { useRouter } from "vue-router";

//////////////////////////
// データ定義
//////////////////////////
const router = useRouter();
/** モーダル設定 */
const modalmsg = ref("");
const modalOkBtn = ref("");
const myModal = ref();
/** エラーメッセージ */
const errorMsg = ref("");
/** 入力項目用 */
const userId = ref("");
/** エラー表示エリア表示制御  false：非表示 */
const isShowerrorMsg = ref(false);
/** ログ用 */
const screenName = "買い物箱画面";
const E01Name = "「買い物箱画面」ボタンクリック";
var deleteIndex = 0;
/** イベント項目 */
const eventName = ref("");

//////////////////////////
// メソッド
//////////////////////////
/**
 * 「初期表示」イベント
 */
const ATH0102100E00 = () => {
  // 初期表示開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));
  if (commonInfo().cartList && commonInfo().cartList.length > 0) {
    commonInfo().cartList.forEach(element => {
      if (!element.NUMBER) {
        element.NUMBER = 1;
        element.AMONT = element.PRICE;
      }
    });
    errorMsg.value = "";
    isShowerrorMsg.value = false;
    refreshTotalAmont();
  } else {
    errorMsg.value = "選択された商品がありません";
    isShowerrorMsg.value = true;
  }
  
  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

/**
 * 商品の数を減る
 */
const reduceAmount = (index) => {
  if (commonInfo().cartList && commonInfo().cartList.length > index) {
    var NUMBER = commonInfo().cartList[index].NUMBER;
    if (NUMBER > 1) {
      NUMBER = NUMBER - 1;
      commonInfo().cartList[index].NUMBER = NUMBER;
      commonInfo().cartList[index].AMONT = NUMBER*commonInfo().cartList[index].PRICE;
    } else {
      deleteIndex = index;
      eventName.value = "deleteItem";
      showMessage("該当商品を削除しますか？");
    }
    refreshTotalAmont();
  }
};

/**
 * 商品の数を増える
 */
const increaseAmount = (index) => {
  if (commonInfo().cartList && commonInfo().cartList.length > index) {
    var NUMBER = commonInfo().cartList[index].NUMBER;
    NUMBER = NUMBER + 1;
    commonInfo().cartList[index].NUMBER = NUMBER;
    commonInfo().cartList[index].AMONT = NUMBER*commonInfo().cartList[index].PRICE;
    refreshTotalAmont();
  }
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  if (modalReturn == 1) {
    if ("deleteItem" === eventName.value) {
      commonInfo().cartList.splice(deleteIndex, 1);
      // 初期表示
      ATH0102100E00();
    } else if ("commitOrder" === eventName.value) {
      // オーダーコミット
      ATH0102100E01();
    } else if ("orderSuccess" === eventName.value) {
      //「ATH0101100：商品一覧画面」へ遷移する。
      router.push({ name: comConst.ATH0101100 });
    }
  }
};

const orderCommit = () => {
  eventName.value = "commitOrder";
  showMessage("オーダをコミットしますか？");
}
/**
 * 「オーダーコミット」イベント
 */
const ATH0102100E01 = async() => {
  // オーダーコミット開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "オーダーコミット"]));
  if (commonInfo().cartList && commonInfo().cartList.length > 0) {
    var taltalAmont = 0;
    var priceCurrency = "";
    var orderDetailsInfo = [];
    commonInfo().cartList.forEach(element => {
      taltalAmont += element.AMONT;
      priceCurrency = element.PRICE_CURRENCY;
      element.ORDER_ID = 0;
      element.ORDER_PRODUCT_ID = 0;
      orderDetailsInfo.push(element)
    });
    errorMsg.value = "";
    isShowerrorMsg.value = false;

    // オーダーインフォ
    var orderInfo = {};
    orderInfo.ORDER_ID = 0;
    orderInfo.SHOP_ID = commonInfo().shopId;
    orderInfo.TABLE_ID = commonInfo().tableId;
    orderInfo.SUB_TABLE_ID = commonInfo().subTableId;
    orderInfo.PRICE_CURRENCY = priceCurrency;
    orderInfo.AMONT = taltalAmont;
    orderInfo.orderDetailsInfo = orderDetailsInfo;

    // オーダーコミットAPI呼出し
    const reqParam = [
      [
        comConst.API_ID_ATH0102_01,
        { orderInfo: orderInfo
        },
      ],
    ];
    const res = await apiCaller.httpServiceWithShield(reqParam, commonInfo().screenId);
    // 結果コード = "0"（正常終了）の場合
    if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
      // 成功の場合
      eventName.value = "orderSuccess";
      showMessage("オーダ完了しました。");
      // 結果コード = "1"（異常終了）の場合
    } else {
      // エラーメッセージを表示する
      messageErrFlg.value = true;
      messageErr.value = res[0].data.messageErr.join("\n");
    }
  } else {
    errorMsg.value = "選択された商品がありません";
    isShowerrorMsg.value = true;
  }
  
  // オーダーコミット終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "オーダーコミット"]));
};

const refreshTotalAmont = () => {
  if (commonInfo().cartList && commonInfo().cartList.length > 0) {
    var tatalAmont = 0;
    var priceCurrency = "";
    for (var i=0; i<commonInfo().cartList.length; i++){
      var NUMBER = commonInfo().cartList[i].NUMBER;
      commonInfo().cartList[i].AMONT = NUMBER*commonInfo().cartList[i].PRICE;
      tatalAmont += commonInfo().cartList[i].AMONT;
      priceCurrency = commonInfo().cartList[i].PRICE_CURRENCY;
    }
    commonInfo().cartInfo.AMONT = tatalAmont;
    commonInfo().cartInfo.PRICE_CURRENCY = priceCurrency;
  }
};


//////////////////////////
// ライフサイクルフック
//////////////////////////
/**
* 画面マウント時イベント
*/
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.ATH0102100;
  // 初期表示
  await ATH0102100E00();
  //modal初期化
  myModal.value.init();
});
</script>

<template>
  <Header />
  <!-- 菜单内容区域 -->
  <main>
    <div>
      <!-- エラー表示エリア -->
      <div class="align-items-center center place_items_center">
        <div class="alert alert-danger text-danger width_100" v-if="isShowerrorMsg" role="alert">{{ errorMsg }}</div>
      </div>
      <section class="cart-items">
        <!-- 菜单项1 -->
        <div v-for="(obj, index) in commonInfo().cartList" :key="index" class="cart-item">
          <img :src="obj.PRODUCT_IMG" :alt="obj.language[commonInfo().languageType]?.PRODUCT_NAME" class="cart-item-img">
          <div class="cart-item-info">
            <span class="item-price">{{ Number(obj.PRICE).toLocaleString() }}{{ obj.PRICE_CURRENCY }}</span>
            <div class="cart-item-right">
              <button @click="reduceAmount(index)" class="add-to-cart">-</button>
              <h1>{{ obj.NUMBER }}</h1>
              <button @click="increaseAmount(index)" class="add-to-cart">+</button>
            </div>
          </div>
        </div>
        <div class="cart-item">
          <label class="cart-item-title">合計：</label>
          <div class="cart-item-info">
            <div class="cart-item-right">
              <span class="item-price">{{ commonInfo().cartInfo.AMONT }}{{ commonInfo().cartInfo.PRICE_CURRENCY }}</span>
            </div>
          </div>
        </div>
        <!-- 更多菜单项 -->
        <div class="cart-item cart-aline-center">
          <button @click="orderCommit()" class="btn normal_button">オーダコミット</button>
        </div>
        <!-- 可以继续添加菜单项 -->
      </section>
    </div>
  </main>
  <Footer />
  <CommonDialog ref="myModal" id="commonDialog" :cancelButton="''" :closeButton="''" :msg="modalmsg" :title="''"
    :okButton="modalOkBtn" @common-dialog-close="closeDialog" />
</template>

<style scoped>

.cart-items {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
  width: 100%;
  display: block;
}

.cart-item {
  background-color: white;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  text-align: center;
  display: flex;
  width: 100%;
  margin-bottom: 10px;
}

.cart-item img {
  width: 100px;
  height: 100px;
  object-fit: cover;
}

.cart-item-info {
  padding: 15px;
  display: flex;
  width: 80%;
  align-items: center;
}

.cart-item-right {
  padding: 15px;
  display: flex;
  width: 60%;
  align-items: center;
  justify-content: flex-end;
}

.cart-item-info .item-name {
  font-size: 1.2em;
  margin: 10px 0;
}

.cart-item-info .item-description {
  color: #666;
  font-size: 0.9em;
}

.cart-item-info .item-price {
  font-size: 1.1em;
  color: #d9534f;
  font-weight: bold;
}

.cart-item-title {
  display: grid;
  place-items: center;
  font-weight: bolder;
  padding-left: 5px;
}

.add-to-cart {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  font: 1.5em sans-serif;
  text-align: center;
}

.cart-aline-center {
  justify-content: center;
}
</style>