<!--
 メール設定画面
 @version 1.0
 @author C
-->
<script setup>
import { ref, onMounted, reactive } from 'vue';
import { useRouter } from 'vue-router';
import Header from '@/components/common/Header.vue';
import Footer from '@/components/common/Footer.vue';
import Menu from '@/components/common/Menu.vue';
import Breadcrumb from '@/components/common/Breadcrumb.vue';
import CommonDialog from "@/components/common/CommonDialog.vue";
import StatusExplanation from '@/components/ENT0401100/StatusExplanation.vue';
import MedicCorpInfo from '@/components/ENT0401100/MedicCorpInfo.vue';
import comConst from '@/constants/com-const.js';
import comEnum from '@/constants/com-enum.js';
import commonInfo from '@/store/common/common-info.js';
import targetCorp from '@/store/common/target-corp.js';
import StringUtil from '@/utils/common/string-util.js';
import comMessage from '@/constants/com-message.js';
import loadingModal from '@/utils/common/loading-modal.js';
import apiCaller from '@/utils/common/api-caller.js';
import comDate from '@/utils/common/com-date.js';
import ENT0102100Param from '@/store/ENT0102100/ent0102100-param.js';

/** VueRouter */
const router = useRouter();

const form = reactive({
  EMAIL_SETTING_ID : "",
  SHOP_ID : "",
  EMAIL_ADDRESS : "",
  PASSWORD : "",
  RECEIVE_SERVER : "",
  RECEIVE_PORT : "",
  SEND_SERVER : "",
  SEND_PORT : "",
  SSL_TLS_FLG : "",
  RECEIVE_SPA_AUTH_FLG : "",
  ENCRYPTION_METHOD : "",
  SEND_SPA_AUTH_FLG : "",
})

/** 画面名 */
const screenName = 'メール設定画面';
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();
var messageErrFlg = ref(false);
var messageErr = ref("");

// 初期表示
const ENT0102100E01 = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));
  form.EMAIL_SETTING_ID = ENT0102100Param().mailSetting.EMAIL_SETTING_ID
  form.SHOP_ID = ENT0102100Param().mailSetting.SHOP_ID
  form.EMAIL_ADDRESS = ENT0102100Param().mailSetting.EMAIL_ADDRESS
  form.PASSWORD = ENT0102100Param().mailSetting.PASSWORD
  form.RECEIVE_SERVER = ENT0102100Param().mailSetting.RECEIVE_SERVER
  form.RECEIVE_PORT = ENT0102100Param().mailSetting.RECEIVE_PORT
  form.SEND_SERVER = ENT0102100Param().mailSetting.SEND_SERVER
  form.SEND_PORT = ENT0102100Param().mailSetting.SEND_PORT
  form.SSL_TLS_FLG = ENT0102100Param().mailSetting.SSL_TLS_FLG == "1"
  form.RECEIVE_SPA_AUTH_FLG = ENT0102100Param().mailSetting.RECEIVE_SPA_AUTH_FLG == "1"
  form.ENCRYPTION_METHOD = ENT0102100Param().mailSetting.ENCRYPTION_METHOD
  form.SEND_SPA_AUTH_FLG = ENT0102100Param().mailSetting.SEND_SPA_AUTH_FLG == "1"
	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * 保存ボタン押下
 */
const clickSaveBtn = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, '保存ボタン押下']));

	var inputCheckResult = inputCheck();
	if (!inputCheckResult) {
		showMessage(comMessage.COMMON100030E);
		return false;
	}
	// ローディングの表示
	loadingModal.isshow(true);
  var apiId = "";
  // 新規の場合
  if (!form.EMAIL_SETTING_ID || form.EMAIL_SETTING_ID == "")
  {
    apiId = comConst.API_ID_ENT0101_02;
  } else {
    apiId = comConst.API_ID_ENT0101_03;
  }
	// メール保存API引数を設定
	const reqParam = [[apiId, { 
    emailSetting: form,
    }],];

	// メール保存APIの呼び出し
	var res = await apiCaller.httpService(reqParam, commonInfo().screenId);


	// 結果コード = "0"（正常終了）の場合
	if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {

    // ローディングの非表示
    loadingModal.isshow(false);
		// エラー表示エリアをクリア
		messageErr.value = [];

		// 保存完了メッセージ表示
		showMessage(res[0].data.messageInfo[0]);
	}
	// 上記以外
	else {
		// ローディングの非表示
		loadingModal.isshow(false);
		// 終了ログ
		console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
		// システムエラー画面へ遷移
		router.push({ name: comConst.UTL9999993 });
	}
	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, '届出ボタン押下']));
};

const inputCheck = () => {
	var result = true;

	if (!form.SHOP_ID || form.SHOP_ID == "") {
		result = false;
	}
	if (!form.EMAIL_ADDRESS || form.EMAIL_ADDRESS == "") {
		result = false;
	}
	if (!form.PASSWORD || form.PASSWORD == "") {
		result = false;
	}
	if (!form.RECEIVE_SERVER || form.RECEIVE_SERVER == "") {
		result = false;
	}
	if (!form.RECEIVE_PORT || form.RECEIVE_PORT == "") {
		result = false;
	}
	if (!form.SEND_SERVER || form.SEND_SERVER == "") {
		result = false;
	}
	if (!form.SEND_PORT || form.SEND_PORT == "") {
		result = false;
	}
  if (form.SSL_TLS_FLG == true) {
    form.SSL_TLS_FLG = 1;
  } else {
    form.SSL_TLS_FLG = 0;
  }
  if (form.RECEIVE_SPA_AUTH_FLG == true) {
    form.RECEIVE_SPA_AUTH_FLG = 1;
  } else {
    form.RECEIVE_SPA_AUTH_FLG = 0;
  }
	if (!form.ENCRYPTION_METHOD || form.ENCRYPTION_METHOD == "") {
		result = false;
	}
  if (form.SEND_SPA_AUTH_FLG == true) {
    form.SEND_SPA_AUTH_FLG = 1;
  } else {
    form.SEND_SPA_AUTH_FLG = 0;
  }
	return result;
};

/**
 * メール設定一覧画面
 */
const ENT0102100E05 = () => {	
  // 「ENT0101100：メール設定一覧画面」へ遷移する。
  router.push({ name: comConst.ENT0101100 });
};

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

// 画面マウント時イベント
onMounted(async () => {
	// 自分の画面IDを設定
	commonInfo().screenId = comConst.ENT0102100;
	// modal初期化
	myModal.value.init();

	// 初期表示
	await ENT0102100E01();
});

/**
 * 注文一覧画面
 */
const ENT0201100E06 = () => {	
  // 「ENT0201200：注文一覧画面」へ遷移する。
  router.push({ name: comConst.ENT0201200});
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  // メール一覧画面へ遷移
  router.push({ name: comConst.ENT0101100 });
};
</script>
<script setup>
</script>

<template>
  <div class="menu">	
	<button class="menu-btn" v-on:click="ENT0102100E05">メール設定一覧</button>
	<button class="menu-btn" v-on:click="ENT0201100E06">オーダ一覧</button>
  </div>
  <div class="container">
    <h2 class="title">メール設定</h2>
    <!-- エラー表示エリア -->
    <div class="align-items-center center place_items_center">
      <div class="alert alert-danger text-danger width_100" v-if="messageErrFlg" role="alert">{{ messageErr }}</div>
    </div>
    <form class="form">
      <fieldset>
        <legend>基本情報</legend>
        <div class="form-group">
          <label for="email">メールアドレス</label>
          <input id="email" v-model="form.EMAIL_ADDRESS" type="email" required />
        </div>
        <div class="form-group">
          <label for="password">パスワード</label>
          <input id="password" v-model="form.PASSWORD" type="password" required />
        </div>
      </fieldset>

      <fieldset>
        <legend>受信設定</legend>
        <div class="form-group">
          <label for="inServer">受信サーバー</label>
          <input id="inServer" v-model="form.RECEIVE_SERVER" type="text" required/>
        </div>
        <div class="form-group">
          <label for="inPort">ポート番号</label>
          <input id="inPort" v-model="form.RECEIVE_PORT" type="number" required/>
        </div>
        <div class="form-group checkbox-group">
          <label><input type="checkbox" v-model="form.SSL_TLS_FLG" /> SSL/TLS</label>
          <label><input type="checkbox" v-model="form.RECEIVE_SPA_AUTH_FLG" /> SPA認証</label>
        </div>
      </fieldset>

      <fieldset>
        <legend>送信設定</legend>
        <div class="form-group">
          <label for="outServer">送信サーバー</label>
          <input id="outServer" v-model="form.SEND_SERVER" type="text" required/>
        </div>
        <div class="form-group">
          <label for="outPort">ポート番号</label>
          <input id="outPort" v-model="form.SEND_PORT" type="number" required/>
        </div>
        <div class="form-group">
          <label for="encryption">暗号化方式</label>
          <select id="encryption" v-model="form.ENCRYPTION_METHOD">
            <option value="0">なし</option>
            <option value="1">SSL</option>
            <option value="2">TLS</option>
          </select>
        </div>
        <div class="form-group checkbox-group">
          <label><input type="checkbox" v-model="form.SEND_SPA_AUTH_FLG" /> SPA認証</label>
        </div>
      </fieldset>

      <div class="form-group full-width">
        <button type="button" class="submit-btn" @click="clickSaveBtn">保存</button>
      </div>
    </form>
  </div>
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>
/* 全体のレイアウト */

.title {
  text-align: center;
  font-size: 24px;
  margin-bottom: 24px;
}

/* フォーム基本スタイル */
.form {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

fieldset {
  border: 1px solid #ccc;
  padding: 16px;
  border-radius: 8px;
}

legend {
  font-weight: bold;
  margin-bottom: 8px;
}

.form-group {
  display: flex;
  flex-direction: column;
  margin-bottom: 16px;
}

.form-group label {
  margin-bottom: 4px;
  font-size: 14px;
}

input, select {
  padding: 8px;
  font-size: 14px;
  border: 1px solid #aaa;
  border-radius: 4px;
}

.checkbox-group {
  display: flex;
  gap: 20px;
  flex-wrap: wrap;
}

.full-width {
  text-align: center;
}

/* ボタン */
.submit-btn {
  background-color: #007BFF;
  color: white;
  padding: 10px 24px;
  border: none;
  border-radius: 6px;
  font-size: 16px;
  cursor: pointer;
}

.submit-btn:hover {
  background-color: #0056b3;
}

/* レスポンシブ対応 */
@media (max-width: 768px) {
  .container {
    padding: 12px;
  }

  .form-group {
    width: 100%;
  }
}

@media (max-width: 480px) {
  .form-group {
    flex-direction: column;
  }

  .checkbox-group {
    flex-direction: column;
  }

  .submit-btn {
    width: 100%;
  }
}
</style>