<!--
 ユーザ情報画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted, onUnmounted, computed } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import Menu from "@/components/common/Menu.vue";
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import commonInfo from "@/store/common/common-info.js";
import loadingModal from "@/utils/common/loading-modal.js";
import apiCaller from "@/utils/common/api-caller.js";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import comMessage from "@/constants/com-message.js";
import stringUtil from "@/utils/common/string-util.js";
import CommonDialog from "@/components/common/CommonDialog.vue";

//////////////////////////
// データ定義
//////////////////////////

/** モーダルメッセージ用 */
const modalmsg = ref("");
const modaltitle = ref("");
const modalOkBtn = ref("");
const modalCancelBtn = ref("");
const modalCloseBtn = ref("");
const myModal = ref();
const errInfoMap = ref([]);
const router = useRouter();
const breadcrumbObj = ref();
/** ログ用 */
const screenName = "ユーザ情報";
const updateProc = "更新";

/** ユーザ情報 */
const userInfo = ref({
  userId:"",  // ユーザID
  userType:"",  // ユーザ種別
  prefName:"",  // 都道府県名
  corporationName:"", // 医療法人
  managerLastName:"", // 担当者（姓）
  managerFirstName:"",  // 担当者（名）
  telephoneNumber:"", // 担当者の連絡先（電話番号）
  mailAddress1:"",  // 担当者のメールアドレス➀
  mailAddress2:"",  // 担当者のメールアドレス➁
  mailAddress3:"",  // 担当者のメールアドレス➂
  updatePgmId:"", // 更新処理ID
});

/** エラーメッセージ */
const errorMessages = ref("");

/** 更新完了メッセージ */
const updateMsg = ref("");

/** 画面の非活性状態(戻るボタン除く)を管理  true：非活性 */
const isScreenDisabled = ref(true);

/** ユーザ種別Enum */
const enumUserType = comEnum.EnumUSER_TYPE;

/** ログイン有効無効種別Enum */
const enumPrefMailNotifyType = comEnum.EnumPREF_MAIL_NOTIFY_TYPE;

/** 表示判定  false：非表示 */
const isShowUpdateMsg = ref(false);

/** エラー表示判定  false：非表示 */
const isShowErrMsg = ref(false);


/** 法人からの届出メール等通知(ラジオボタン用) */
const
 radioMailNotify = ref([
  {dispname: enumPrefMailNotifyType.RECEIVE.dispname, val: enumPrefMailNotifyType.RECEIVE.val},
  {dispname: enumPrefMailNotifyType.NOT_RECEIVE.dispname, val: enumPrefMailNotifyType.NOT_RECEIVE.val},
]);


//////////////////////////
// 算出プロパティ
//////////////////////////

/**
 * 法人からの届出メール等通知表示判定
 * @type {boolean}　true：表示、false：非表示
 */
 const isShowprefMailNoticeFlg = computed(() => {
  // ログインユーザ種別が都道府県の場合、表示する
  return enumUserType.PREF_STAFF.val.includes(commonInfo().userType);
});

//////////////////////////
// メソッド
//////////////////////////

/**
 * OKメッセージ表示
 * タイトルなし、OKボタンのみ表示
 * @type {String}　メッセージ
 */
 const showOkMessage = async (errorMessages) => {
  modaltitle.value = "";
  modalmsg.value = errorMessages;
  modalCloseBtn.value = "OK";
  myModal.value.show();
};

/**
 * 画面のタイトルを取得
 * @type {String}　
 */
 const getTitle = computed(() => {

  let title = "";
  if (enumUserType.MEDIC_CORP.val.includes(commonInfo().userType)) {
     title = commonInfo().corporationName;
  } else if (enumUserType.PREF_STAFF.val.includes(commonInfo().userType)) {
     title = commonInfo().prefName;
  } else if (enumUserType.MEDIC_CARE_ORG_STAFF.val.includes(commonInfo().userType)) {
     title = "福祉医療機構";
  } else {
     title = "福祉医療機構（代理入力ユーザ）";
  };
   return title;
  });

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
 const closeDialog = (modalReturn) => {
  // 戻り値による実装なし
  };

/**
 * 「初期表示」イベント
 */
const MNM0301300E01 = async () =>{

  // 開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000004I, [screenName]));

  // ローディングの表示
  loadingModal.isshow(true);
  //ユーザ照会APIの呼び出し
  const reqParam = [
    [comConst.API_ID_MNM0301_06, { 
      userId: commonInfo().userId,
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);
  //結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
      const resData = res[0].data;
      userInfo.value = {
      managerLastName: resData.managerLastName,
      managerFirstName: resData.managerFirstName,
      mailAddress1: resData.mailAddress1,
      mailAddress2: resData.mailAddress2,
      mailAddress3: resData.mailAddress3,
      telephoneNumber: resData.telephoneNumber,
      prefMailNoticeFlg: resData.prefMailNoticeFlg,
    };

  // 結果コード = "1"（異常終了）の場合
  } else {

    const responseData = ref();
    responseData.value = res[0].data;

    // エラーメッセージリストをセット
    errorMessages.value = responseData.value.messageErr;
    isShowErrMsg.value = true;
    
    // ローディングの非表示
    loadingModal.isshow(false);
    return;
  }
  
// 画面状態を活性にする
isScreenDisabled.value = false;

// ローディングの非表示
loadingModal.isshow(false);

// 終了ログ
console.log(stringUtil.convertString(comMessage.COMMON000005I, [screenName]));
}

/**
 * 「更新」イベント
 */
 const MNM0301300E02 = async () =>{

  // 開始ログ
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, updateProc]));

  // ローディングの表示
  loadingModal.isshow(true);

  //ユーザ情報更新APIの呼び出し
  const reqParam = [
    [comConst.API_ID_MNM0301_07, { 
      userId: commonInfo().userId,
      managerLastName: userInfo.value.managerLastName,
      managerFirstName: userInfo.value.managerFirstName,
      mailAddress1: userInfo.value.mailAddress1,
      mailAddress2: userInfo.value.mailAddress2,
      mailAddress3: userInfo.value.mailAddress3,
      telephoneNumber: userInfo.value.telephoneNumber,
      prefMailNoticeFlg: userInfo.value.prefMailNoticeFlg,
      updatePgmId:commonInfo().screenId,
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);

  // 結果コード = "1"（異常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_ERROR) {
    const responseData = ref();
    responseData.value = res[0].data;
    // エラーメッセージを設定
    errInfoMap.value = responseData.value.messageErrMap;

    // ローディングの非表示
    loadingModal.isshow(false);
    return;
  } else {
    isShowUpdateMsg.value = true;
    updateMsg.value = comMessage.MNM030130000I;
  }

  // 画面状態を活性にする
  isScreenDisabled.value = false;

  // ローディングの非表示
  loadingModal.isshow(false);

  // 終了ログ
  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, updateProc]));
}

//////////////////////////
// ライフサイクルフック
//////////////////////////

// 画面マウント時イベント
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.MNM0301300;

  // パンくずリストを設定
  breadcrumbObj.value.init(commonInfo().screenId); 

  //modal初期化
  myModal.value.init();

  // 初期表示
  await MNM0301300E01();
});

/**
 * 画面アンマウント時イベント
 */
 onUnmounted(async () => {

});

</script>

<template>
  <Header />
  <div class="contents">
    <Menu :selectedMenu="'MNM0301300'" />
	<Breadcrumb ref="breadcrumbObj" />
    <div class="alert alert-danger text-danger" v-if="isShowErrMsg"><span class="pt-1">{{ errorMessages }}</span></div>
    <div class="alert alert-success text-success" v-if="isShowUpdateMsg"><span class="pt-1">{{ updateMsg }}</span></div>
    <div class="mainContents-margin px-3 orgheight">
      <form name="MNM0301300form" autocomplete="off" >
        <table  role="presentation">
          <tbody>
            <tr>
              <td class="pt-1" colspan="2"><label class="title">{{ getTitle }}</label></td>
            </tr>
            <tr>
              <td class="left" colspan="2"><label class="text-danger">(※は必須入力項目です)</label></td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">ユーザID</label></td>
              <td class="pt-1"><input type="text" v-model="commonInfo().userId" class="form-control ms-1" disabled/></td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">担当者（姓）<span class="text-danger">※</span></label></td>
              <td class="pt-1">
                <input type="text" v-model="userInfo.managerLastName" 
                    :disabled="isScreenDisabled" 
                    class = "form-control ms-1 width_400"
                    :class="{'errordisp': errInfoMap.managerLastName}"
                    maxlength="255"
                    />
              </td>
            </tr>
            <tr>
              <td class="pt-1" colspan="2">
                <div class="col ps-0">
                  <template v-if="errInfoMap && errInfoMap.managerLastName && errInfoMap.managerLastName.length > 0 ">
                    <div v-for="erm in errInfoMap.managerLastName"><span class="form-text">{{ erm }}</span></div>
                  </template>
                </div>
              </td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">担当者（名）<span class="text-danger">※</span></label></td>
              <td class="pt-1">
                <input type="text" v-model="userInfo.managerFirstName"
                    :disabled="isScreenDisabled"
                    class = "form-control ms-1 width_400"
                    :class="{'errordisp': errInfoMap.managerFirstName}"
                    maxlength="255" />
              </td>
            </tr>
            <tr>
              <td class="pt-1" colspan="2">
                <div class="col ps-0">
                  <template v-if="errInfoMap && errInfoMap.managerFirstName && errInfoMap.managerFirstName.length > 0 ">
                    <div v-for="erm in errInfoMap.managerFirstName"><span class="form-text">{{ erm }}</span></div>
                  </template>
                </div>
              </td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">担当者の連絡先（電話番号）<span class="text-danger">※</span></label></td>
              <td class="pt-1">
                <input type="text" v-model="userInfo.telephoneNumber"
                    :disabled="isScreenDisabled" 
                    class="form-control ms-1" 
                    :class="{'errordisp': errInfoMap.telephoneNumber}"
                    maxlength="15" />
              </td>
            </tr>
            <tr>
              <td class="pt-1" colspan="2">
                <div class="col ps-0">
                  <template v-if="errInfoMap && errInfoMap.telephoneNumber && errInfoMap.telephoneNumber.length > 0">
                    <div v-for="erm in errInfoMap.telephoneNumber"><span class="form-text">{{ erm }}</span></div>
                  </template>
                </div>
              </td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">担当者のメールアドレス➀<span class="text-danger">※</span></label></td>
              <td class="pt-1">
                <input type="text" v-model="userInfo.mailAddress1" 
                    :disabled="isScreenDisabled" 
                    class="form-control ms-1 width_200" 
                    :class="{'errordisp': errInfoMap.mailAddress1}"
                    maxlength="255" />
              </td>
            </tr>
            <tr>
              <td class="pt-1" colspan="2">
                <div class="col ps-0">
                  <template v-if="errInfoMap && errInfoMap.mailAddress1 && errInfoMap.mailAddress1.length > 0 > 0">
                    <div v-for="erm in errInfoMap.mailAddress1"><span class="form-text">{{ erm }}</span></div>
                  </template>
                </div>
              </td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">担当者のメールアドレス➁</label></td>
              <td class="pt-1">
                <input type="text" v-model="userInfo.mailAddress2" 
                    :disabled="isScreenDisabled" 
                    class="form-control ms-1 width_200" 
                    :class="{'errordisp': errInfoMap.mailAddress2}"
                    maxlength="255" />
              </td>
            </tr>
            <tr>
              <td class="pt-1" colspan="2">
                <div class="col ps-0">
                  <template v-if="errInfoMap && errInfoMap.mailAddress2 && errInfoMap.mailAddress2.length > 0">
                    <div v-for="erm in errInfoMap.mailAddress2"><span class="form-text">{{ erm }}</span></div>
                  </template>
                </div>
              </td>
            </tr>
            <tr>
              <td class="pt-1"><label class="width_260 col-form-label">担当者のメールアドレス➂</label></td>
              <td class="pt-1">
                <input type="text" v-model="userInfo.mailAddress3" 
                    :disabled="isScreenDisabled" 
                    class="form-control ms-1 width_200" 
                    :class="{'errordisp': errInfoMap.mailAddress3}"
                    maxlength="255" />
              </td>
            </tr>
            <tr>
              <td class="pt-1" colspan="2">
                <div class="col ps-0">
                  <template v-if="errInfoMap && errInfoMap.mailAddress3 && errInfoMap.mailAddress3.length > 0">
                    <div v-for="erm in errInfoMap.mailAddress3"><span class="form-text">{{ erm }}</span></div>
                  </template>
                </div>
              </td>
            </tr>
            <tr v-if="isShowprefMailNoticeFlg">
                <td class="pt-1"><label class="width_260 col-form-label">法人からの届出メール等通知</label></td>
                <td class="pt-1">
                  <span class="ms-1"  v-for="(item, index) in radioMailNotify">
                    <input type="radio" :value="item.val" v-model="userInfo.prefMailNoticeFlg" 
                     :id="`radioMailNotifyFlg${index}`" name="radioMailNotifyFlg" class="form-check-input" />
                    <label class="form-check-label" :for="`radioMailNotifyFlg${index}`">{{item.dispname}}</label>
                  </span>
                </td>
            </tr>
            <tr>
              <td></td>
              <td class="center pt-1">
                <button type="button" class="btn btn-primary" @click="MNM0301300E02">
                  <i class="bi bi-envelope"></i>更新</button>
              </td>
            </tr>
          </tbody>
        </table>
      </form>
    </div>
  </div>
  <Footer />
  <CommonDialog ref="myModal"
    id="commonDialog"
    :msg="modalmsg"
    :title="modaltitle"
    :okButton="modalOkBtn"
    :cancelButton="modalCancelBtn"
    :closeButton="modalCloseBtn"
    @common-dialog-close="closeDialog"
  />
</template>
<style scoped>
.width_260 {
    width: 260px;
}
.orgheight {
    display: grid;
    height: calc(100vh - 110px);
}
</style>