<!--
 ステッパー＋戻るボタンのコンポーネント
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, computed, onMounted } from "vue";
import comEnum from "@/constants/com-enum.js";
import commonInfo from "@/store/common/common-info.js";

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["stepper-back"]);

// Enum
/** ユーザ種別 */
const enumUserType = comEnum.EnumUSER_TYPE;
/** ステッパー表示種別 */
const enumStepperType = comEnum.EnumSTEPPER_DISPLAY_TYPE;
/** 届出ステータス */
const enumNoticeStat = comEnum.EnumNOTICE_STATUS;
/** 届出方法種別 */
const enumNotifMethodType = comEnum.EnumNOTIFICATION_METHOD_TYPE;

// コンポーネントの引数
const props = defineProps({
  noticeStatus: { type: String, default: "" }, // 届出ステータス
  notificationMethodType: { type: String, default: "" }, // 届出方法
  isButtonVisible: { type: Boolean, default: true }, // 戻るボタン表示フラグ
});

// ステッパー表示種別
const stepItems = ref([
  enumStepperType.UNINP.dispname,
  enumStepperType.INP.dispname,
  enumStepperType.APPR_WAIT.dispname,
  enumStepperType.APPR.dispname,
]);

// 画面マウント時イベント
onMounted(async () => {
  if (commonInfo().userType === enumUserType.MEDIC_CORP.val){ //医療法人
    stepItems.value = [enumStepperType.UNINP.dispname, enumStepperType.INP.dispname, enumStepperType.NOTICE.dispname];
  } else {
    stepItems.value = [enumStepperType.UNINP.dispname, enumStepperType.INP.dispname, enumStepperType.APPR_WAIT.dispname, enumStepperType.APPR.dispname];
  }
});

// 届出ステータスによってstepperの選択状態を設定
const selectedIndex = computed(() => {
  if (props.noticeStatus === enumNoticeStat.CORP_INP_WAIT.val) {
    // 法人入力待ち
    return 0;
  } else if (props.noticeStatus === enumNoticeStat.CORP_INP_COMP_WAIT.val) {
    // 法人入力完了待ち
    return 1;
  } else if (props.noticeStatus === enumNoticeStat.REMAND.val) {
    // 差戻し
    return 1;
  } else if (props.noticeStatus === enumNoticeStat.PREF_APPR_WAIT.val) {
    // 都道府県承認待ち
    return 2;
  } else if (props.noticeStatus === enumNoticeStat.APPR.val) {
    // 承認済
    if (commonInfo().userType === enumUserType.MEDIC_CORP.val) {
      // 医療法人
      return 2;
    } else {
      return 3;
    }
  }
  return -1;
});

// stepperの非活性を設定
const disabledIndex = computed(() => {
  // ユーザ種別
  let userType = commonInfo().userType;
  
  // 代理入力の場合
  if (userType === enumUserType.PROXY_INPUT_STAFF.val) {
    if (
      props.noticeStatus !== enumNoticeStat.PREF_APPR_WAIT.val &&
      props.noticeStatus !== enumNoticeStat.APPR.val
    ) {
      return 2; // 都道府県承認待ち・承認済 以外は index=2(承認待ち)を非活性
    }
  }

  // 承認済の場合
  if (props.noticeStatus === enumNoticeStat.APPR.val) {
    if (userType !== enumUserType.MEDIC_CORP.val) {
      if (
        props.notificationMethodType === enumNotifMethodType.DOCUMENT_INPUTS.val
      ) {
        return 2; // 医療法人以外で書面入力の時は index=2(承認待ち)を非活性
      }
    }
  }
  return -1;
});

// 戻るボタン押下時
const back = () => {
  emit("stepper-back"); //イベント出すだけ
};
</script>

<template>
  <div class="d-flex align-items-center" id="stepper">
    <button id="stepperBack" type="button" class="btn btn-secondary" v-if="props.isButtonVisible" @click="back">
      <i class="bi bi-box-arrow-left me-1"></i>戻る
    </button>
    <ol class="step" id="Steps">
      <li v-for="(value, index) in stepItems" v-bind:key="value"
        :class="{'step-item':true, 'selected': selectedIndex == index}"
        :aria-disabled="disabledIndex == index">
        <span>{{value}}</span>
      </li>
    </ol>
  </div>
</template>

<style scoped>
  #Steps {
    width: 70%;
  }
</style>
