<!--
 金額入力テキストボックス(自動計算項目：引き算用)コンポーネント(経営情報等Web入力画面用カスタム)
 @version 1.0
 @author CSC
-->
<template>
  <input
    :id="id"
    ref="inputDom"
    type="text"
    :value="dispValue"
    class="form-control me-3"
    placeholder=" "
    :class="{ errordisp: inputItemDto.messageErr.length > 0 }"
    @input="handleInput($event)"
    @blur="handleBlur"
    @focus="handleFocus"
  />
</template>
<!-- :placeholder-shownで未入力時に背景色を付加 -->
<script setup>
import { onMounted, ref, defineModel, computed, onUpdated } from "vue";

/** 内部変数定義 */
// フォーカス有無
const isFocus = ref(false);
// inputタグ へのテンプレート参照
const inputDom = ref(null);
// 内部保持する値
const internalValue = defineModel(); // 部品に指定されたv-model属性を参照（https://ja.vuejs.org/api/sfc-script-setup#definemodel）
// 画面表示する値（フォーカス有無で切り分け）
const dispValue = computed(() => {
  // 当期純利益（又は当期純損失）ハイフン表示
  if (props.id == "n11NetIncomeLoss" && props.valList.length > 0 && ["*", "＊", ""].includes(props.valList[0])) {
    return "-";
  }
  // 引き算する金額の合計
  let reducingVal = 0;
  if (props.valList.length > 0) {
    const numberList = props.valList.map((str) => {
      if (str && isFinite(str)) {
        return Number(str);
      } else {
        return 0;
      }
    });
    reducingVal = numberList.reduce((num1, num2) => num1 + num2);
  }
  // 引き算する元になる金額
  let masterVal = 0;
  if (props.masterValList.length > 0) {
    const masterValNumList = props.masterValList.map((str) => {
      if (str && isFinite(str)) {
        return Number(str);
      } else {
        return 0;
      }
    });
    masterVal = masterValNumList.reduce((num1, num2) => num1 + num2);
  }
  // 引き算
  return (masterVal - reducingVal).toLocaleString("ja-JP");
});

/** props：引数定義 */
const props = defineProps({
  id: String,
  inputItemDto: { type: Object, default: { value: "", messageErr: [], messageWarn: [] } },
  masterValList: { type: Object, default: [] },
  valList: { type: Object, default: [] },
});

/** emit：イベント定義 */
const emit = defineEmits(["blur", "focus", "input"]);

// 画面生成時のイベント
onMounted(() => {
  // NOP
});

// フォーカス時のイベント
const handleFocus = (event) => {
  isFocus.value = true; // フラグ更新のみ
  emit("focus", event);
};

// フォーカスアウト時のイベント
function handleBlur(event) {
  let rep = "";
  // 前後の空白は詰める＋NULLは空白にする
  if (internalValue.value != null) {
    rep = (internalValue.value + "").trim().replace(/,/g, "");
  }
  if (rep !== "" && isFinite(rep)) {
    // 数値と認識できる値であれば、数値変換して再度文字列にする（先頭の0などが削除される）
    rep = Number(rep) + "";
  }
  internalValue.value = rep; // 数値にできそうなのは数値に変換して保持
  isFocus.value = false; // フラグ更新
  emit("blur", event);
}

// 入力時のイベント
const handleInput = (event) => {
  // 画面で入力された値を内部値に入れる
  internalValue.value = event.target.value;
  // エラー枠の表示を解除
  event.target.classList.remove("errordisp");
  emit("input", event);
};

// 内部のinputタグにフォーカスあてる
const focusInput = () => {
  inputDom.value.focus();
};

/** expose：公開メソッド定義(scriptの一番下に記載) */
defineExpose({
  focusInput,
});
</script>
<style scoped>
/** コンポーネント固有のstyle設定 */
</style>
