<!--
 ファイル選択コンポーネント（添付書類Web入力画面）
 @version 1.0
 @author CSC
-->
<template>
  <!-- 選択ファイル名 -->
  <div :class="fileNameClass" v-if="getDispPattern == 'fileSelected'">
    <label class="ms-3 wordwrap-break">{{ fileName }}</label>
  </div>
  <!-- アップロードファイル名 -->
  <div :class="fileNameClass" v-if="getDispPattern == 'uploadedFileDisp'">
    <label class="ms-3 wordwrap-break">{{ uploadedFileName }}</label>
  </div>
  <!-- （編集区分が「法人入力」でない または 代理入力専用のため入力不可） かつ アップロードファイルがない 場合のダミー表示 -->
  <div :class="fileNameClass" v-if="getDispPattern == 'blank'"></div>
  <!-- ファイルInput -->
  <div :class="fileInputClass" v-show="getDispPattern == 'weitInput'">
    <input type="file" :accept="accept" :class="fileInputInnerClass" ref="refInputFile" @change="fileSelect" />
  </div>

  <!-- 選択クリアボタン -->
  <div :class="clearClass" v-show="getDispPattern == 'fileSelected'">
    <button @click="reset" v-show="getDispPattern == 'fileSelected'" class="btn" title="ファイルクリア" type="button">
      <img class="testicon" v-show="getDispPattern == 'fileSelected'" src="@/asset/x-circle.svg" title="ファイルクリア" alt="ファイルクリア" />
    </button>
  </div>

  <!-- ドロップエリア -->
  <div
    :class="dropAreaDivClass"
    v-show="getDispPattern == 'weitInput'"
    @dragenter="dragEnter"
    @dragleave="dragLeave"
    @dragover.prevent="dragOver"
    @drop.prevent="dropFile"
  >
    {{ dropAreaMsg }}
  </div>
  <!-- 登録日時 -->
  <div class="col-3 p-2 wid-30" v-show="getDispPattern == 'uploadedFileDisp'">登録日時：{{ updateDatetime }}</div>
  <!-- ファイル選択時 または （編集区分が「法人入力」でない または 代理入力専用のため入力不可） かつ アップロードファイルがない 場合のダミー表示 -->
  <div class="col-3 p-2 wid-30" v-show="getDispPattern == 'fileSelected' || getDispPattern == 'blank'"></div>

  <!-- 削除ボタン-->
  <div class="col-sm p-1 mw-5">
    <i class="bi bi-trash3 delete fs-5" v-show="getDispPattern == 'uploadedFileDisp'" @click="btnDelClick()"></i>
  </div>
  <CommonDialog
    ref="FileSelectAttachModal"
    :id="id"
    :title="modaltitle"
    :okButton="modalOkBtn"
    :cancelButton="modalCancelBtn"
    closeButton=""
    :msg="modalmsg"
    @common-dialog-close="closeDialog"
  />
</template>
<style scoped>
/* ドロップエリア */
.drop-area {
  padding: 3px;
  color: gray;
  font-weight: bold;
  display: flex;
  justify-content: center;
  align-items: center;
  border: 2px dashed gray;
  white-space: pre-wrap;
  text-align: center;
}

/* エリア内ドラッグ時 */
.drop-area-enter {
  border: 2px dashed powderblue;
}
.border-dashedEtc {
  border: dashed;
  align-content: center;
  text-align: center;
}
.mw-5 {
  max-width: 5%;
}
.wid-30 {
  width: 33.33%;
}
.wordwrap-break {
  word-wrap: break-word !important;
  width: 420px;
}
</style>
<script setup>
import { onMounted, ref, computed } from "vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";

/** props：コンポーネントの引数 */
const props = defineProps({
  /**
   * タグのID
   * @type {string}
   *
   */
  id: String,
  /**
   * 添付書類ID
   * @type {string}
   */
  attachDocumentId: String,
  /**
   * ドロップエリアに表示するテキスト
   * @type {string}
   */
  dropareamsg: String,
  /**
   * 受け付けるファイル種別
   * @type {string}
   */
  accept: String,
  /**
   * 各項目の 表示エリアに設定する class（上書き）
   * @type {string}
   */
  divClass: {
    /**
     * 「ファイルInput」表示のdivのclass
     * @type {string}
     */
    fileInput: String,
    /**
     * 「ファイルInput」のclass
     * @type {string}
     */
    fileInputInner: String,
    /**
     * 「ドロップエリア」表示エリアclass
     * @type {string}
     */
    dropArea: String,
    /**
     * 「選択ファイル名」表示エリアclass
     * @type {string}
     */
    fileName: String,
    /**
     * 「選択クリアボタン」表示エリアclass
     * @type {string}
     */
    clear: String,
  },
  /**
   * 「ドロップエリア」に追加するclass
   * @type {string}
   */
  dropAreaAddClass: String,

  /**
   * アップロード済みファイル名
   * @type {string}
   */
  uploadedFileName: String,
  /**
   * 登録日時
   * @type {string}
   */
  updateDatetime: String,

  /**
   * 編集区分
   * @type {string}
   */
  editType: String,

  /**
   * 代理入力の場合のみ入力が可能となる添付書類ID群
   * @type {Array}
   */
  proxyInputAttachDocumentIds: Array,

  /**
   * 結果コード
   * @type {string}
   */
  resultCode: String,
});

/** コンポーネントから呼び出し元への受け渡し用 */
/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["file-select1", "file-delete1"]);

/**
 * 選択ファイル取得
 * 選択したファイルを取得する
 * @return {?File} 選択したFileオブジェクト
 */
const getFile = () => {
  return selectedFile.value;
};
/**
 * 「選択クリア」ボタンクリック
 * ファイル選択の解除を行う
 */
const reset = () => {
  refInputFile.value.value = null;

  selectedFile.value = null;
  fileName.value = "";

  isSelected.value = false;
};

/** コンポーネントのメソッド公開 */
defineExpose({
  /** 選択ファイル取得 */
  getFile,
  /** ファイル選択クリア */
  reset,
});

// 変数
/** ドロップエリアの範囲内かどうか */
const isEnter = ref(false);
/** ファイル選択中フラグ */
const isSelected = ref(false);
/** ファイルがアップロード済みかどうか */
const isFileUploaded = ref(false);
/** (アップロード済みファイルの)削除が選択されたかどうか */
const isFileDelEnable = ref();
/** 選択したFileオブジェクト */
const selectedFile = ref(null);
/** ファイルInput部品のref */
const refInputFile = ref(null);
/** 選択したファイル名 */
const fileName = ref("");
/** ドロップエリアに表示するテキスト */
const dropAreaMsg = ref("添付したいファイルをここに\n" + "ドラッグ＆ドロップしてください");
// div class
/** 「ファイルInput」表示エリアclass */
const fileInputClass = ref("col");
/** 「ファイルInput」のclass */
const fileInputInnerClass = ref("col");
/** 「ドロップエリア」表示エリアclass */
const dropAreaDivClass = ref("col");
/** 「選択ファイル名」表示エリアclass */
const fileNameClass = ref("col");
/** 「選択クリアボタン」表示エリアclass */
const clearClass = ref("col");
/** 添付書類ID */
const attachDocumentId = ref();
/** アップロード済みファイル名 */
const uploadedFileName = ref("");
/** 登録日時 */
const updateDatetime = ref("");
/** 編集区分 */
const editType = ref();
/** 代理入力の場合のみ入力が可能となる添付書類ID群 */
const proxyInputAttachDocumentIds = ref();
/** 結果コード */
const resultCode = ref();
/** 削除指示のあった添付書類ID */
const curDelTargetAttachmentId = ref();

/** 確認ダイアログ */
const FileSelectAttachModal = ref();
const modalmsg = ref();
const modaltitle = ref();
const modalOkBtn = ref();
const modalCancelBtn = ref();

// ファイル選択の表示パターン
const showPattern = ref();

/**
 * ファイル選択の表示パターン取得
 * 　パターン１：weitInput：入力待ち状態
 * 　パターン２：fileSelected：ファイル選択状態
 * 　パターン３：uploadedFileDisp：アップロードファイル表示状態
 * 　パターン４：blank：何も表示なし状態
 */
const getDispPattern = computed(() => {
  if (isSelected.value) {
    showPattern.value = "fileSelected";
  } else if (isFileUploaded.value && !isFileDelEnable.value) {
    showPattern.value = "uploadedFileDisp";
  } else if (
    (editType.value == "corpInput" || editType.value == "proxyInput") &&
    ((!isSelected.value && !isFileUploaded.value) || (!isSelected.value && isFileDelEnable.value))
  ) {
    // 該当する添付書類IDが、代理入力専用の場合
    if (props.proxyInputAttachDocumentIds.includes(attachDocumentId.value)) {
      if (editType.value == "proxyInput") {
        showPattern.value = "weitInput";
      } else {
        showPattern.value = "blank";
      }
    } else {
      showPattern.value = "weitInput";
    }
  } else {
    showPattern.value = "blank";
  }
  return showPattern.value;
});

/**
 * コンポーネントのマウント後の処理
 */
onMounted(() => {
  // 初期処理
  init();

  //modal初期化
  FileSelectAttachModal.value.init();
});

// 関数
/**
 * ファイル選択コンポーネント初期表示
 */
const init = () => {
  // 添付書類IDの設定
  if (props.attachDocumentId !== undefined) {
    attachDocumentId.value = props.attachDocumentId;
  }
  // 表示文言の設定
  if (props.dropareamsg !== undefined) {
    dropAreaMsg.value = props.dropareamsg;
  }

  // 各項目の表示エリアで使用する class 設定
  if (props.divClass === undefined) {
    return;
  }
  if (props.divClass.fileInput !== undefined) {
    fileInputClass.value = props.divClass.fileInput;
  }
  if (props.divClass.fileInputInner !== undefined) {
    fileInputInnerClass.value = props.divClass.fileInputInner;
  }
  if (props.divClass.dropArea !== undefined) {
    dropAreaDivClass.value = props.divClass.dropArea;
  }
  if (props.divClass.fileName !== undefined) {
    fileNameClass.value = props.divClass.fileName;
  }
  if (props.divClass.clear !== undefined) {
    clearClass.value = props.divClass.clear;
  }
  if (props.uploadedFileName !== null && props.uploadedFileName !== "") {
    uploadedFileName.value = props.uploadedFileName;
    isFileUploaded.value = true;
  }
  if (props.updateDatetime !== null) {
    updateDatetime.value = props.updateDatetime;
  }
  if (props.editType !== null && props.editType !== undefined) {
    editType.value = props.editType;
  }
  if (props.proxyInputAttachDocumentIds !== null && props.proxyInputAttachDocumentIds !== undefined) {
    proxyInputAttachDocumentIds.value = props.proxyInputAttachDocumentIds;
  }
  if (props.resultCode !== null && props.resultCode !== undefined) {
    resultCode.value = props.resultCode;
  }
};

/**
 * ドロップエリアに設定する class を返す
 * @return {string} ドロップエリアに設定する class
 */
const getDropAreaClass = () => {
  let result = "";
  // 指定された値の追加
  if (props.dropAreaAddClass !== undefined) {
    result += props.dropAreaAddClass;
  }
  // エリア内ドラッグの場合の class を追加
  if (isEnter.value) {
    result += " drop-area-enter";
  }
  return result;
};
/**
 * 「ファイルの選択」ダイアログ「開く」ボタンクリック
 * ファイルの選択ダイアログで ファイル選択した場合の処理を行う。
 * @param {Event} event クリックイベント
 */
const fileSelect = (event) => {
  select(event.target.files[0]);
};
/**
 * ファイル選択時の共通処理
 * @param {File} file 選択したFileオブジェクト
 */
const select = (file) => {
  selectedFile.value = file;

  fileName.value = selectedFile.value.name;
  isSelected.value = true;
  // 親がイベントを拾う
  emit("file-select1", [attachDocumentId.value, file]);
};
/**
 * 「ドロップエリア」のエリア内ドラッグ
 * 「ドロップエリア」のエリア内ドラッグ時の表示制御を行う。
 */
const dragEnter = () => {
  isEnter.value = true;
};
/**
 * 「ドロップエリア」のエリア外ドラッグ
 * 「ドロップエリア」のエリア外ドラッグ時の表示制御を行う。
 */
const dragLeave = () => {
  isEnter.value = false;
};
/**
 * 「ドロップエリア」のエリア内ドロップ
 * 「ドロップエリア」のエリア内ドロップ時の処理を行う。
 * @param {Event} event ドロップイベント
 */
const dropFile = (event) => {
  isEnter.value = false;
  select(event.dataTransfer.files[0]);
};
/**
 * 「ドロップエリア」のエリア内ドラッグオーバー
 */
const dragOver = () => {
  // 処理なし
};

/**
 * 「削除ボタン」押下時イベント
 * @param {string} arg 削除対象の添付書類ID
 */
const btnDelClick = () => {
  curDelTargetAttachmentId.value = attachDocumentId.value;
  modaltitle.value = "";
  modalmsg.value = comMessage.COMMON000002C;
  modalOkBtn.value = "OK";
  modalCancelBtn.value = "キャンセル";

  FileSelectAttachModal.value.show();
};
// Dialog閉じるイベント
const closeDialog = (modalReturn) => {
  if (modalReturn == 1) {
    // OK押されたとき

    isFileDelEnable.value = true;
    // 削除対象の添付書類IDを親vueへ送る
    emit("file-delete1", curDelTargetAttachmentId.value);
  }
};
</script>
