/**
 *  サーバーからダウンロードしたファイルをローカルにダウンロードするクラスです。
 *
 *  @version 1.0
 *  @author CSC
 */
export default class ComFileDownload {

    /**
     * aタグの download 属性を使って、ファイルをダウンロードする
     *
     * @param {Blob} data - ファイルデータ
     * @param {Object} headers - HTTPヘッダ
     * @param {String} defaultName - デフォルトファイル名
     */
    static download(data, headers, defaultName) {
		const fileName = this.getFileNameFromHeader(headers, defaultName)
        const downloadUrl = window.URL.createObjectURL(new Blob([data]));
        const link = document.createElement("a");
        link.href = downloadUrl;
        link.setAttribute("download", fileName);
        document.body.appendChild(link);
        link.click();
        link.remove();
    }

	/**
	 * HTTPヘッダのcontent-dispositionよりファイル名を取得する
	 *
	 * @param {Object} headers - HTTPヘッダ
	 * @param {String} defaultName - デフォルトファイル名
	 * @reterns {String} ファイル名
	 */
	static getFileNameFromHeader(headers, defaultName) {
		const content = headers["content-disposition"];
	    if (content === undefined) {
			return defaultName;
		} 
	    const regex = content.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
	    if (regex === null) {
			return defaultName;
        }
        return decodeURIComponent(regex[1]).replace(/(^['"])|(['";\s]+$)/g, '') || defaultName;
	}

    /**
     * レスポンスヘッダーからエラーメッセージを取得
     *
     * @param {Object} headers - HTTPヘッダ
     * @reterns {String[]} エラーメッセージ配列
     */
    static getErrMessages(headers) {
        const errmes = headers["errmessages"];
	    if (errmes === undefined || errmes.length === 0) {
			return [];
		} 
        const messages = decodeURIComponent(errmes);
		return JSON.parse(messages);
    }

}
