<script setup>
import { ref, onMounted } from "vue";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import commonInfo from "@/store/common/common-info.js";
import targetCorp from "@/store/common/target-corp.js";
import { useRouter } from "vue-router";
import apiCaller from "@/utils/common/api-caller.js";
import validator from "@/utils/common/validator.js";
import StringUtil from "@/utils/common/string-util.js";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";
import ATH0101200Param from "@/store/ATH0101200/ath0101200-param.js";

// ルータ
const router = useRouter();
const props = defineProps({
  shopId: String,
  tableId: String,
  subTableId: String,
});
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();
// エラーメッセージID、エラーメッセージ
const errorMsgId = ref("");
// 警告メッセージID
const warnMsgId = ref("");

const mode = ref("");
mode.value = SYS_ENV_MODE; // 設定ファイルから取得してセット
/** ログ用 */
const screenName = "トップ画面";
const E01Name = "初期表示";
var ATH0101000Data = ref([]);
var messageErrFlg = ref(false);
var messageErr = ref("");

// 画面マウント時イベント
onMounted(() => {
  // modal初期化
  myModal.value.init();
  ATH0101000E01();
});

/**
* 初期表示イベント
*/
const ATH0101000E01 = async () => {

  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E01Name]));

  if (props.shopId != null) {
    commonInfo().shopId = props.shopId;
  }
  if (props.tableId != null) {
    commonInfo().tableId = props.tableId;
  }
  if (props.subTableId != null) {
    commonInfo().subTableId = props.subTableId;
  }

  // 利用規約同意API呼出し
  const reqParam = [
    [
      comConst.API_ID_ATH0100_01,
      { shopId: commonInfo().shopId
      },
    ],
  ];
  const res = await apiCaller.httpServiceWithShield(reqParam, commonInfo().screenId);
  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    // トップ画面へ遷移する
    commonInfo().languageList = res[0].data;
    ATH0101000Data.value = res[0].data;
    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラーメッセージを表示する
    messageErrFlg.value = true;
    messageErr.value = res[0].data.messageErr.join("\n");
  }

  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E01Name]));
};

// Dialog閉じるイベント
const closeDialog = (modalReturn) => {
  if ("ATH010100005E" === errorMsgId.value) {
    // OKボタン押下後、「ATH0103100：パスワードリセット画面」へ遷移する。
    router.push({ name: comConst.ATH0103100 });
  } else if ("ATH010100001I" === warnMsgId.value) {
    // OKボタン押下後、「ATH0101200：利用規約同意画面」へ遷移する。
    router.push({ name: comConst.ATH0101200 });
  } else {
    // 「UTL0101100：トップ画面」へ遷移する。
    router.push({ name: comConst.UTL0101100 });
  }
};

// 商品クリック
const itemClick = (languageType) => {
  commonInfo().languageType = languageType;
  // 商品リンク押下後、「ATH0101200：商品詳細画面」へ遷移する。
  router.push({ name: comConst.ATH0101100 });
};
</script>

<template>
  <div id="app">
    <!-- エラー表示エリア -->
    <div class="align-items-center center place_items_center">
      <div class="alert alert-danger text-danger width_100" v-if="messageErrFlg" role="alert">{{ messageErr }}</div>
    </div>
    <!-- 菜单内容区域 -->
    <main>
        <section class="menu-items">
            <!-- 菜单项1 -->
            <div v-for="(obj, key) in ATH0101000Data" :key="key" class="menu-item" v-on:click="itemClick(obj.LANGUAGE_TYPE)">
                <div class="menu-item-info">
                    <h3 class="item-name">{{ obj.LANGUAGE_NAME }}</h3>
                </div>
            </div>

            <!-- 更多菜单项 -->
            <!-- 可以继续添加菜单项 -->
        </section>
    </main>
  </div>
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

