<!--
 金額入力テキストボックスコンポーネント
 @version 1.0
 @author CSC
-->
<template><input :id="id" ref="inputDom" type="text" :disabled="disabled" :value="dispValue"
  @input="handleInput" @blur="handleBlur" @focus="handleFocus" /></template>
<script setup>
  import { onMounted, ref, defineModel,computed } from "vue";

  /** 内部変数定義 */
  // フォーカス有無
  const isFocus = ref(false);
  // inputタグ へのテンプレート参照
  const inputDom = ref(null);
  // 内部保持する値
  const internalValue = defineModel(); // 部品に指定されたv-model属性を参照（https://ja.vuejs.org/api/sfc-script-setup#definemodel）
  // 画面表示する値（フォーカス有無で切り分け）
  const dispValue = computed(() => {
    if (!isFocus.value) {
      let rep = '';
      // 前後の空白は詰める＋NULLは空白にする
      if(internalValue.value != null){
        rep = (internalValue.value + '').trim().replace(/,/g, '');
      }
      if (rep !== '' && isFinite(rep)) {
        // 数値だったらカンマを挿入して返す
        return Number(rep).toLocaleString("ja-JP"); 
      } else {
        // 数字以外はそのまま(NULLは空白にする)
        return (internalValue.value != null)? internalValue.value : '';
      }
    } else {
      return internalValue.value;
    }
  });

  /** props：引数定義 */
  const props = defineProps({
    id: String,
    disabled: {type:Boolean, default:false}
  });
  
   /** emit：イベント定義 */
   const emit = defineEmits(["blur","focus","input"]);
  
  // 画面生成時のイベント
  onMounted(() =>{
    // NOP
  });

  // フォーカス時のイベント
  const handleFocus = (event) => {
    isFocus.value = true; // フラグ更新のみ
    emit('focus', event);
  }

  // フォーカスアウト時のイベント
  function handleBlur(event) {
    let rep = '';
    // 前後の空白は詰める＋NULLは空白にする
    if(internalValue.value != null){
      rep = (internalValue.value + '').trim().replace(/,/g, '');
    }
    if (rep !== '' && isFinite(rep)) {
      // 数値と認識できる値であれば、数値変換して再度文字列にする（先頭の0などが削除される）
      rep = (Number(rep) + ''); 
    }
    internalValue.value = rep; // 数値にできそうなのは数値に変換して保持
    isFocus.value = false; // フラグ更新
    emit('blur', event);
  }

  // テキスト変更時のイベント
  const handleInput = (event) => {
    // 画面で入力された値を内部値に入れる
    internalValue.value = event.target.value;
    emit('input', event);
  }

  // 内部のinputタグにフォーカスあてる
  const focusInput = () => {
    inputDom.value.focus();
  }

  /** expose：公開メソッド定義(scriptの一番下に記載) */
  defineExpose({
    focusInput
  });
</script>
<style scoped>
  /** コンポーネント固有のstyle設定 */
</style>
  