import loadingModal from "@/utils/common/loading-modal.js";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";
import commonInfo from "@/store/common/common-info.js";
import targetCorp from "@/store/common/target-corp.js";
import router from "@/router/index.js";

// エラーハンドリング処理
function _errorHandling(message) {
  // モーダルを閉じる
  loadingModal.isshow(false);

  // ステータスコードが403の場合（権限エラー）
  if (message?.includes(`HTTPステータス：${comConst.FORBIDDEN}`)) {
    // storeに保存している情報を削除
    commonInfo().$reset();
    targetCorp().$reset();
    // アクセス権エラー画面へ遷移
    router.push({ name: comConst.UTL9999991 });

    // ステータスコードが401の場合（認証エラー）
  } else if (message?.includes(`HTTPステータス：${comConst.UNAUTHORIZED}`)) {
    // storeに保存している情報を削除
    commonInfo().$reset();
    targetCorp().$reset();
    // セッションタイムアウト画面へ遷移
    router.push({ name: comConst.UTL9999992 });

    // 上記以外でステータスコードが存在する場合
  } else if (message?.includes(`HTTPステータス：`)) {
    // システムエラー画面へ遷移
    router.push({ name: comConst.UTL9999993 });

    // 上記以外（接続不良やパラメータ不備などJSのエラー）
  } else {
    // storeに保存している情報を削除
    commonInfo().$reset();
    targetCorp().$reset();
    alert(comMessage.COMMON000014E);
    // ログイン画面へ遷移
    router.push({ name: comConst.ATH0101100 });
  }
}

export default {
  errorHandlerService(app) {
    // vueで明示的に例外投げた時のイベント
    app.config.errorHandler = (err, vm, info) => {
      //下記コンソールログに出力する値をログ出力部品に流す。
      console.log(err.stack);
      _errorHandling(err.stack);
    };
    // vueで明示的にワーニング投げた時のイベント
    app.config.warnHandler = (msg, vm, trace) => {
      //ここはコンソールログだけ。
      console.log(`Captured in Vue.config.warnHandler: ${trace}`, msg);
    };
    // JSの例外イベント
    window.addEventListener("error", (event) => {
      if (
        event.origin !== undefined &&
        event.origin !== window.location.origin
      ) {
        return;
      }
      console.log("Captured in error EventListener", event.error);
      _errorHandling(event.error);
    });
    // JS並列処理での例外イベント
    window.addEventListener("unhandledrejection", (event) => {
      if (
        event.origin !== undefined &&
        event.origin !== window.location.origin
      ) {
        return;
      }
      console.log(
        "Captured in unhandledrejection EventListener",
        event.reason.stack
      );
      _errorHandling(event.reason.stack);
    });
  },
};
