<template>

<div class="pagination">
<div>合計：{{ this.total }}件</div>
<button @click="goPage(1)" :disabled="currentPage===1">
&lt;&lt;
</button>

<button @click="prevPage" :disabled="currentPage===1">
&lt;
</button>

<button
v-for="page in pages"
:key="page"
@click="goPage(page)"
:class="{active:page===currentPage}"
>
{{page}}
</button>

<button @click="nextPage" :disabled="currentPage===totalPage">
&gt;
</button>

<button @click="goPage(totalPage)" :disabled="currentPage===totalPage">
&gt;&gt;
</button>

</div>

</template>

<script>
export default{

props:{
total:Number,
pageSize:Number
},

data(){
return{
currentPage:1
}
},

computed:{

totalPage(){
return Math.ceil(this.total/this.pageSize)
},

pages(){

let start = Math.max(1,this.currentPage-2)
let end = Math.min(this.totalPage,start+4)

let arr=[]
for(let i=start;i<=end;i++){
arr.push(i)
}

return arr
}

},

methods:{

goPage(page){
  console.log("this.total:" + this.total.toString());
  console.log("this.pageSize:" + this.pageSize.toString());
  this.currentPage=page
  this.$emit("page-change",page)
},

nextPage(){
  console.log("this.total:" + this.total.toString());
  console.log("this.pageSize:" + this.pageSize.toString());
  this.goPage(this.currentPage+1)
},

prevPage(){
  console.log("this.total:" + this.total.toString());
  console.log("this.pageSize:" + this.pageSize.toString());
  this.goPage(this.currentPage-1)
}

}

}
</script>

<style>

.pagination button{
margin:4px;
padding:4px 10px;
border:1px solid #ccc;
cursor:pointer;
}

.active{
background:#409eff;
color:white;
}

</style>