<script setup>
import { ref, onMounted } from "vue";
import testInfo from "@/store/test-info.js";

/** emit：このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["oya-ni-modosu"]);

/** props：このコンポーネントの引数定義 */
const props = defineProps({
  msg: {type:String, default:"まだなし"}
});

const test3Msg = ref();
const storeMsg = ref();

// 画面マウント時イベント
onMounted(async () => {

});

const modosu = () => {
  emit("oya-ni-modosu", test3Msg.value);
};

const hozon = () => {
  testInfo().testMsg = storeMsg.value;
};
</script>

<template>
  <div class="tab-pane fade show active p-2" style="background-color: #f66ff6;">
    TEST3
    <div class="row me-0" style="width: 33em;">
      <input type="text" id="msgText" class="col form-control mb-2" v-model="test3Msg" placeholder="親画面に戻すメッセージ" style="width: 10em;">
      <button id="btn0" type="button" class="col-3 btn btn-primary ms-2" @click="modosu">戻す</button>
    </div>
    親画面から来たメッセージ：{{ props.msg }}
<hr />
    <div class="row me-0" style="width: 33em;">
      <input type="text" id="piniaText" class="col form-control mb-2" v-model="storeMsg" placeholder="storeに保存するメッセージ" style="width: 10em;">
      <button id="btn1" type="button" class="col-3 btn btn-secondary ms-2" @click="hozon">保存</button>
    </div>
  </div>
</template>

