<!--
  入力値と計算値を切り替えるボタン（経営情報等Web入力画面）
  @version 1.0
  @author CSC
-->
<template>
  <input
    id="props.id"
    type="button"
    class="btn btn-primary btn-sm button-switch p-1 me-1 mb-1"
    :value="isCalculated ? '計算値' : '入力値'"
    @click="changeMode"
  />
</template>
<style scoped>
.button-switch {
  min-width: 60px !important;
  height: 35px !important;
}
</style>
<script setup>
import { onMounted, defineModel, computed } from "vue";
import comEnum from "@/constants/com-enum.js";

// 内部保持する値
const internalValue = defineModel(); // 部品に指定されたv-model属性を参照（https://ja.vuejs.org/api/sfc-script-setup#definemodel）
// 画面表示する値(v-modelを元に決定)
const isCalculated = computed(() => {
  if (internalValue.value == comEnum.EnumINPUT_CHANGE_TYPE.INPUT_VALUE.val) {
    // 入力値
    return false;
  } else if (internalValue.value == comEnum.EnumINPUT_CHANGE_TYPE.CALCULATED_VALUE.val) {
    // 計算値
    return true;
  } else {
    // それ以外は入力値
    return false;
  }
});

/** props：コンポーネントの引数 */
const props = defineProps({
  id: { type: String },
});

/** emit：イベント定義 */
const emit = defineEmits(["click"]);

/**
 * コンポーネントの初期表示イベント
 */
onMounted(() => {});

/**
 * コンポーネント初期化
 */
const init = () => {};

/**
 * ボタンクリック時イベント
 */
const changeMode = (event) => {
  if (internalValue.value == comEnum.EnumINPUT_CHANGE_TYPE.INPUT_VALUE.val) {
    // 入力値-->計算値
    internalValue.value = comEnum.EnumINPUT_CHANGE_TYPE.CALCULATED_VALUE.val;
  } else if (internalValue.value == comEnum.EnumINPUT_CHANGE_TYPE.CALCULATED_VALUE.val) {
    // 計算値-->入力値
    internalValue.value = comEnum.EnumINPUT_CHANGE_TYPE.INPUT_VALUE.val;
  } else {
    // それ以外は入力値-->計算値
    internalValue.value = comEnum.EnumINPUT_CHANGE_TYPE.CALCULATED_VALUE.val;
  }
  emit("click", event);
};

/** コンポーネントのメソッド公開 */
defineExpose({
  /** 初期化 */
  init,
});
</script>
