<!--
 ステータスアイコン説明コンポーネント
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted } from "vue";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import commonInfo from "@/store/common/common-info.js";

// コンポーネントの引数
const props = defineProps({
  screenId: { type: String, default: "" }, // 画面ID
});

/** 代理入力 */
const flg1 = ref(false);
/** 書面での届出 */
const flg2 = ref(false);
/** 届出タイプ選択 */
const flg3 = ref(false);

/** ユーザ種別Enum */
const enumUserType = comEnum.EnumUSER_TYPE;

// 画面マウント時イベント
onMounted(async () => {
  // 年度別届出状況一覧画面の場合、ユーザ種別によって表示文言を変更
  if (props.screenId === comConst.ENT0101100) {
    let ut = commonInfo().userType;
    if (ut === enumUserType.MEDIC_CORP.val) {
      // 医療法人
      flg1.value = false;
      flg2.value = true;
      flg3.value = true;
    } else if (ut === enumUserType.PREF_STAFF.val) {
      // 都道府県
      flg1.value = false;
      flg2.value = true;
      flg3.value = false;
    } else if (ut === enumUserType.MEDIC_CARE_ORG_STAFF.val) {
      // 機構職員
      flg1.value = true;
      flg2.value = false;
      flg3.value = false;
    } else if (ut === enumUserType.PROXY_INPUT_STAFF.val) {
      // 代理入力
      flg1.value = true;
      flg2.value = false;
      flg3.value = true;
    }
  } else {
    flg1.value = false;
    flg2.value = false;
    flg3.value = false;
  }
});
</script>

<template>
  <div class="mt-4 font-size12">
    <i class="ms-2 bi bi-person-fill"         v-if="flg1"><span>：代理入力</span></i>
    <i class="ms-2 bi bi-file-earmark"        v-if="flg2"><span>：書面での届出</span></i>
    <i class="ms-2 bi bi-gear"                v-if="flg3"><span>：届出タイプ選択</span></i>
    <i class="ms-2 bi bi-record-circle-fill text-success"><span>：届出可能</span></i>
    <i class="ms-2 bi bi-triangle-fill text-warning"     ><span>：エラーあり (届出不可)</span></i>
    <i class="ms-2 bi bi-dash text-danger"               ><span>：未入力 (未保存)</span></i>
  </div>
</template>

<style scoped>
i span {
  color: black;
  font-style: normal;
}
</style>
