<script setup>
import { ref, onMounted, reactive } from 'vue';
import { useRouter } from 'vue-router';
import Header from '@/components/common/Header.vue';
import Footer from '@/components/common/Footer.vue';
import Menu from '@/components/common/Menu.vue';
import Breadcrumb from '@/components/common/Breadcrumb.vue';
import CommonDialog from "@/components/common/CommonDialog.vue";
import Pagination from '@/components/common/Pagination.vue';
import StatusExplanation from '@/components/ENT0401100/StatusExplanation.vue';
import MedicCorpInfo from '@/components/ENT0401100/MedicCorpInfo.vue';
import comConst from '@/constants/com-const.js';
import comEnum from '@/constants/com-enum.js';
import commonInfo from '@/store/common/common-info.js';
import targetCorp from '@/store/common/target-corp.js';
import StringUtil from '@/utils/common/string-util.js';
import comMessage from '@/constants/com-message.js';
import loadingModal from '@/utils/common/loading-modal.js';
import apiCaller from '@/utils/common/api-caller.js';
import ENT0201100Param from '@/store/ENT0201100/ent0201100-param.js';

/** VueRouter */
const router = useRouter();

// オーダ情報一覧
const orderInfoList = ref([]);

/** 画面名 */
const screenName = 'オーダ一覧';
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();
// 検索条件
const searchForm = ref({
  shopId: commonInfo().corpId,
  lastOrderId:999999999,
  totalCount:0,
  pageSize:20,
  cursorMap:{},
  customerName:"",
  coordinatorName:"",
  orderKey:"",
  orderStatus:"",
  updateStatus:"",
  cancelStatus:"",
  eventDateFrom:"",
  eventDateTo:"",
  dateFrom:"",
  dateTo:""
});

const loadpage = async (page) => {
  if(searchForm.value.cursorMap[page]){
    await loadByCursor(searchForm.value.cursorMap[page])
  }else{
    await loadByOffset(page)
  }
}

const loadByCursor = async (lastOrderId) => {
  searchForm.value.offset = null;
  await ENT0201200E01();
  if (orderInfoList.value.length > 0) {
    searchForm.value.lastOrderId = orderInfoList.value[orderInfoList.value.length - 1].ORDER_ID;
    searchForm.value.cursorMap[searchForm.value.currentPage+1] = searchForm.value.lastOrderId;
    console.log("searchForm.value.lastOrderId:" + searchForm.value.lastOrderId.toString())
  }
}

const loadByOffset = async (page) => {
  searchForm.value.offset=(page-1)*searchForm.value.pageSize;
  searchForm.value.lastOrderId = null;
  await ENT0201200E01();
  if (orderInfoList.value.length > 0) {
    searchForm.value.lastOrderId = orderInfoList.value[orderInfoList.value.length - 1].ORDER_ID;
    searchForm.value.cursorMap[searchForm.value.currentPage+1] = searchForm.value.lastOrderId;
    console.log("searchForm.value.lastOrderId:" + searchForm.value.lastOrderId.toString())
  }
}

// 初期表示
const ENT0201200E01 = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));

	// ローディングの表示
	loadingModal.isshow(true);

	// オーダ一覧画面照会APIの呼び出し
	const reqManageInfoParam = [
		[
			comConst.API_ID_ENT0212_01,
			{
				joken: searchForm
			},
		],
	];
	const res = await apiCaller.httpService(reqManageInfoParam, commonInfo().screenId);
	// 結果コード = "0"（正常終了）の場合
	if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
		// ローディングの非表示
		loadingModal.isshow(false);
		orderInfoList.value = res[0].data.orderList || [];
    if (searchForm.value.lastOrderId == 999999999) {
      if (orderInfoList.value.length > 0) {
        searchForm.value.totalCount = orderInfoList.value[0].ORDER_ID;
      } else {
        searchForm.value.totalCount = 0;
      }
      console.log("searchForm.value.totalCount:" + searchForm.value.totalCount.toString())
    }
	}
	// 上記以外
	else {
    searchForm.value.totalCount = 0;
		// ローディングの非表示
		loadingModal.isshow(false);
		// 終了ログ
		console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
		// システムエラー画面へ遷移
		router.push({ name: comConst.UTL9999993 });
	}

	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  if (modalReturn == 1) {
    if ("delete" === eventName.value) {
    }
  }
};

/**
 * メール一覧画面
 */
const ENT0201200E05 = () => {	
  // 「ENT0201100：メール一覧画面」へ遷移する。
  router.push({ name: comConst.ENT0201100 });
};

/**
 * メール詳細画面
 */
const ENT0201200E06 = (mailId) => {
  commonInfo().emailId = mailId;
  // 「ENT0201300：メール詳細画面」へ遷移する。
  router.push({ name: comConst.ENT0201300 });
};

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

// 画面マウント時イベント
onMounted(async () => {
	// 自分の画面IDを設定
	commonInfo().screenId = comConst.ENT0201200;
	// modal初期化
	myModal.value.init();

	// 初期表示
	await ENT0201200E01();
});

function formatDateTime(date) {
  if (!date) return ''
  const d = new Date(date)

  const y = d.getFullYear()
  const m = String(d.getMonth() + 1).padStart(2, '0')
  const day = String(d.getDate()).padStart(2, '0')
  const h = String(d.getHours()).padStart(2, '0')
  const min = String(d.getMinutes()).padStart(2, '0')

  return `${y}年${m}月${day}日 ${h}:${min}`
}
</script>


<template>
  <div class="menu">
    <button class="menu-btn" @click="ENT0201200E05">メール一覧</button>
  </div>


  <div class="container">
    <h2 class="title">オーダ一覧</h2>

    <!-- 🔍 検索条件 -->
    <div class="search-box">
      <div class="form-group">
        <label>法人名・団体名</label>
        <input v-model="searchForm.customerName" type="text" placeholder="例：Amazon" />
      </div>

      <div class="form-group">
        <label>ご担当者様</label>
        <input v-model="searchForm.coordinatorName" type="text" placeholder="注文太郎" />
      </div>

      <div class="form-group">
        <label>問い合わせ番号</label>
        <input v-model="searchForm.orderKey" type="text" placeholder="123456" />
      </div>

      <div class="form-group">
        <label>注文状態</label>
        <select v-model="searchForm.orderStatus">
          <option value="">すべて</option>
          <option value="1">済</option>
          <option value="0">未</option>
        </select>
      </div>

      <div class="form-group">
        <label>更新状態</label>
        <select v-model="searchForm.updateStatus">
          <option value="">すべて</option>
          <option value="1">済</option>
          <option value="0">未</option>
        </select>
      </div>

      <div class="form-group">
        <label>キャンセル状態</label>
        <select v-model="searchForm.cancelStatus">
          <option value="">すべて</option>
          <option value="1">済</option>
          <option value="0">未</option>
        </select>
      </div>

      <div class="form-group">
        <label>催事日 From</label>
        <input type="date" v-model="searchForm.eventDateFrom" />
      </div>

      <div class="form-group">
        <label>催事日 To</label>
        <input type="date" v-model="searchForm.eventDateTo" />
      </div>

      <div class="form-group">
        <label>注文日 From</label>
        <input type="date" v-model="searchForm.dateFrom" />
      </div>

      <div class="form-group">
        <label>注文日 To</label>
        <input type="date" v-model="searchForm.dateTo" />
      </div>

      <div class="search-actions">
        <button class="btn search-btn" @click="ENT0201200E01">検索</button>
      </div>
    </div>

    <!-- 🔽 テーブル -->
    <div class="table-wrapper">
      <table class="mail-table">
        <thead>
          <tr>
            <th style="width: 50px;" rowspan="2">#</th>
            <th style="width: 90px;">合計</th>
            <th style="width: 125px;">催事日時</th>
            <th style="width: 100px;">準備・<br/>納品時間</th>
            <th style="width: 120px;">法人名・団体名</th>
            <th style="width: 125px;">ご担当者様</th>
            <th style="width: 100px;">電話番号</th>
            <th style="width: 100px;">メール<br/>アドレス</th>
            <th style="width: 100px;">お届け先</th>
            <th style="width: 100px;">納品時対応</th>
            <th style="width: 100px;">問合せ番号</th>
            <th style="width: 100px;">決済の種類</th>
            <th style="width: 120px;">領収書但し書き</th>
            <th style="width: 120px;">領収書宛名指定</th>
            <th style="width: 100px;" rowspan="2">備考</th>
          </tr>
          <tr>
            <th>更新フラグ</th>
            <th>更新日時</th>
            <th>変更内容</th>
            <th>注文状態</th>
            <th>注文日時</th>
            <th>準備状態</th>
            <th>準備日時</th>
            <th>配送状態</th>
            <th>配送日時</th>
            <th>支払状態</th>
            <th>支払日時</th>
            <th>取消状態</th>
            <th>取消日時</th>
          </tr>
        </thead>

        <tbody>
          <template v-for="orderInfo in orderInfoList" :key="orderInfo.ORDER_ID">
            <tr>
              <td style="width: 50px;" rowspan="2"><div class="cell-scroll">{{ orderInfo.ORDER_ID }}</div></td>
              <td style="width: 90px;">{{ Number(orderInfo.AMONT).toLocaleString() }} 円</td>
              <td style="width: 125px;">{{ orderInfo.EVENT_DATE }}</td>
              <td style="width: 100px;">{{ orderInfo.PREPARE_TIME }}</td>
              <td style="width: 120px;">{{ orderInfo.CUSTOMER_NAME }}</td>
              <td style="width: 125px;"><div class="cell-scroll">{{ orderInfo.COORDINATOR_NAME }}</div></td>
              <td style="width: 100px;">{{ orderInfo.PHONE_NUMBER }}</td>
              <td style="width: 100px;"><div class="cell-scroll">{{ orderInfo.EMAIL }}</div></td>
              <td style="width: 100px;"><div class="cell-scroll">{{ orderInfo.ADDRESS }}</div></td>
              <td style="width: 100px;"><div class="cell-scroll">{{ orderInfo.MESSAGE }}</div></td>
              <td style="width: 100px;"><a @click="ENT0201200E06(orderInfo.EMAIL_ID)" class="link-btn">{{ orderInfo.ORDER_KEY }}</a></td>
              <td style="width: 100px;"><div class="cell-scroll">{{ orderInfo.PAYMENT_TIPE }}</div></td>
              <td style="width: 120px;"><div class="cell-scroll">{{ orderInfo.RECEIPT_DISCLAIMER }}</div></td>
              <td style="width: 120px;"><div class="cell-scroll">{{ orderInfo.RECEIPT_ADDRESSEE }}</div></td>
              <td style="width: 100px;" rowspan="2"><div class="cell-scroll">{{ orderInfo.MEMO }}</div></td>
            </tr>
            <tr>
              <td :class="{ 'bg-yellow': orderInfo.ORDER_UPDATE_FLG == '1' }">{{ orderInfo.ORDER_UPDATE_FLG == '1' ? '済' : '未' }}</td>
              <td>{{ orderInfo.ORDER_UPDATE_TIME }}</td>
              <td><div class="cell-scroll">{{ orderInfo.ORDER_UPDATE_MEMO }}</div></td>
              <td>{{ orderInfo.ORDERED_FLG == '1' ? '済' : '未' }}</td>
              <td>{{ formatDateTime(orderInfo.ORDERED_TIME) }}</td>
              <td>{{ orderInfo.PREPARE_FLG == '1' ? '済' : '未' }}</td>
              <td>{{ orderInfo.PREPARE_TIME }}</td>
              <td>{{ orderInfo.SERVING_FLG == '1' ? '済' : '未' }}</td>
              <td>{{ formatDateTime(orderInfo.SERVING_TIME) }}</td>
              <td>{{ orderInfo.PAYED_FLG == '1' ? '済' : '未' }}</td>
              <td>{{ formatDateTime(orderInfo.PAYED_TIME) }}</td>
              <td :class="{ 'bg-red': orderInfo.CANCEL_FLG == '1' }">{{ orderInfo.CANCEL_FLG == '1' ? '済' : '未' }}</td>
              <td>{{ formatDateTime(orderInfo.CANCEL_TIME) }}</td>
            </tr>
          </template>
          <tr v-if="orderInfoList.length === 0">
            <td colspan="20" class="no-data">データがありません</td>
          </tr>
        </tbody>
      </table>
    </div>
    <Pagination
      :total="searchForm.totalCount"
      :pageSize="20"
      @page-change="loadpage"></Pagination>
  </div>

  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>
/* ---------------------------- */
/* フレーム全体                */
/* ---------------------------- */

/* タイトル */
.title {
  font-size: 26px;
  text-align: center;
  margin-bottom: 25px;
}
/* ---------------------------- */
/* 検索条件フォーム             */
/* ---------------------------- */
.search-box {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 16px;
  background: #fafafa;
  padding: 15px;
  border-radius: 8px;
  margin-bottom: 20px;
  border: 1px solid #ddd;
}

.form-group {
  display: flex;
  flex-direction: column;
}

.form-group label {
  font-size: 14px;
  margin-bottom: 4px;
  color: #333;
}

.form-group input,
.form-group select {
  padding: 6px 10px;
  border: 1px solid #ccc;
  border-radius: 4px;
}

.search-actions {
  display: flex;
  align-items: end;
}

.search-btn {
  width: 100%;
  padding: 8px 14px;
  background: #007bff;
  color: #fff;
  border-radius: 4px;
  border: none;
  cursor: pointer;
}
.search-btn:hover {
  opacity: 0.9;
}

/* ---------------------------- */
/* テーブル                     */
/* ---------------------------- */
.table-wrapper{
  height:500px;
  overflow:auto;
  border:1px solid #000;
}
.mail-table{
  width:100%;
  table-layout:fixed;
  border-collapse:separate;
  border-spacing:0;
}
.mail-table th{
  padding:8px;
  border:1px solid #000;
  word-break:break-all;
  background:#90bdee;
  position:sticky;
  z-index:20;
}
/* 第一行表头 */
.mail-table thead tr:nth-child(1) th{
  top:0;
  height:64px;
}
/* 第二行表头 */
.mail-table thead tr:nth-child(2) th{
  top:65px;
}
.mail-table td{
  padding:8px;
  border:1px solid #000000;
}
.cell-scroll{
  max-width:100%;
  overflow-x:hidden;
  white-space:nowrap;
}

.cell-scroll:hover{
  overflow-x:auto;
}
/*
.mail-table td{
  overflow:hidden;
  text-overflow:ellipsis;
  white-space:nowrap;
  border:1px solid #ddd;
}*/
.bg-yellow{
  background-color: yellow;
}
.bg-red{
  background-color: red;
}
.no-data {
  text-align: center;
  padding: 12px;
  color: #777;
  font-style: italic;
}

/* ボタン */
.btn {
  padding: 6px 12px;
  font-size: 13px;
  border-radius: 4px;
  cursor: pointer;
  border: none;
}
</style>
