/**
 *  共通情報を定義する
 *  ログインユーザ情報、CSRFトークン、画面ID、パンくずリストを保持する
 *
 *  @version 1.0
 *  @author CSC
 */
import { defineStore } from "pinia";

const commonInfo = defineStore("commonInfo", {
  state: () => {
    return {
      shopId: "",             // ショップID
      rollId: "",             // ロールID
      languageType: "",            // 言語種類
      tableId: "",            // テーブルID
      subTableId: "",            // 子テーブルID
      languageList: [],            // 言語リスト
      ATH0101100Data: [],            // 商品一覧
      cartList: [],                   // 買い物箱リスト
      cartInfo: {},                   // 買い物箱情報
      corpId: "",             // 会社ID
      emailId: "",             // メールID
    };
  },
  persist: {
    storage: window.sessionStorage,
  },
});

export default commonInfo;
