<!--
 注文一覧画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted, defineProps } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import commonInfo from "@/store/common/common-info.js";
import comConst from "@/constants/com-const.js";
import comEnum from '@/constants/com-enum.js';
import comMessage from "@/constants/com-message.js";
import apiCaller from "@/utils/common/api-caller.js";
import StringUtil from "@/utils/common/string-util.js"

//////////////////////////
// データ定義
//////////////////////////
/** VueRouter */
const router = useRouter();
const props = defineProps({
  shopId: String,
  rollId: String,
});
/** モーダル設定 */
const modalmsg = ref("");
const modalOkBtn = ref("");
const myModal = ref();
/** エラーメッセージ */
const errorMsg = ref("");
/** 入出力項目 */
var orderInfors = ref({
  language:[]
});
const urlExpiredMessage = ref(comMessage.ATH010220003E);
/** エラー表示エリア表示制御  false：非表示 */
const isShowerrorMsg = ref(false);
/** URL有効期限切れ文言表示制御  false：非表示 */
const isShowUrlExpiredMessage = ref(false);
/** ログ用 */
const screenName = "注文一覧";
const E01Name = "「注文一覧」ボタンクリック";


//////////////////////////
// メソッド
//////////////////////////
/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = async (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  // ログイン画面へ遷移する
  router.push({ name: comConst.ATH0101100 });
};

/**
* 「初期表示」イベント
*/
const ATH0103100E00 = async () => {
  // 初期表示開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "初期表示"]));

  if (props.shopId != null) {
    commonInfo().shopId = props.shopId;
  }
  if (props.rollId != null) {
    commonInfo().rollId = props.rollId;
  }

  // 注文一覧画面初期表示API呼び出し
  const reqParam = [
    [comConst.API_ID_ATH0102_02, {
      shopId: commonInfo().shopId,
      rollId: commonInfo().rollId,
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpServiceWithShield(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    orderInfors.value = res[0].data;
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = false;

    // 上記以外の場合
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.error.join("\n");
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = true;
  }

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "初期表示"]));
};

//////////////////////////
// ライフサイクルフック
//////////////////////////
/**
* 画面マウント時イベント
*/
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.ATH0103100;
  // 初期表示
  await ATH0103100E00();
  //modal初期化
  myModal.value.init();
});

/**
* 予備イベント
*/
const prepareOrder = async (order) => {
  // 予備イベント開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "予備イベント"]));

  // 注文一覧画面オーダーステータス変更API呼び出し
  const reqParam = [
    [comConst.API_ID_ATH0103_02, {
      shopId: commonInfo().shopId,
      rollId: commonInfo().rollId,
      orderId: order.ORDER_ID,
      toStatus: comEnum.OrderStatus.PREPARE_ORDER
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpServiceWithShield(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    orderInfors.value = res[0].data;
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = false;
    showMessage("备菜开始");
    // 上記以外の場合
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.error.join("\n");
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = true;
  }

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "予備イベント"]));
};

/**
* サービングイベント
*/
const servingOrder = async (order) => {
  // サービングイベント開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "サービングイベント"]));

  // 注文一覧画面オーダーステータス変更API呼び出し
  const reqParam = [
    [comConst.API_ID_ATH0103_02, {
      shopId: commonInfo().shopId,
      rollId: commonInfo().rollId,
      orderId: order.ORDER_ID,
      toStatus: comEnum.OrderStatus.SERVING_ORDER
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpServiceWithShield(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    orderInfors.value = res[0].data;
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = false;
    showMessage("上菜开始");
    // 上記以外の場合
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.error.join("\n");
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = true;
  }

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "サービングイベント"]));
};

/**
* 会計イベント
*/
const purchaseOrder = async (order) => {
  // 会計イベント開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "会計イベント"]));

  // 注文一覧画面オーダーステータス変更API呼び出し
  const reqParam = [
    [comConst.API_ID_ATH0103_02, {
      shopId: commonInfo().shopId,
      rollId: commonInfo().rollId,
      orderId: order.ORDER_ID,
      toStatus: comEnum.OrderStatus.PURCHASE_ORDER
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpServiceWithShield(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    orderInfors.value = res[0].data;
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = false;
    showMessage("结算完毕");
    // 上記以外の場合
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.error.join("\n");
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = true;
  }

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "会計イベント"]));
};

/**
* 返金イベント
*/
const refundOrder = async (order) => {
  // 返金イベント開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "返金イベント"]));

  // 注文一覧画面オーダーステータス変更API呼び出し
  const reqParam = [
    [comConst.API_ID_ATH0103_02, {
      shopId: commonInfo().shopId,
      rollId: commonInfo().rollId,
      orderId: order.ORDER_ID,
      toStatus: comEnum.OrderStatus.REFUND_ORDER
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpServiceWithShield(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    orderInfors.value = res[0].data;
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = false;
    showMessage("退款完毕");
    // 上記以外の場合
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.error.join("\n");
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = true;
  }

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "返金イベント"]));
};
</script>

<template>
  <Header />
  <!-- 菜单内容区域 -->
  <main>
    <div>
      <!-- エラー表示エリア -->
      <div class="align-items-center center place_items_center">
        <div class="alert alert-danger text-danger width_100" v-if="isShowerrorMsg" role="alert">{{ errorMsg }}</div>
      </div>
      <section class="order-items">
        <div class="order-item">
          <img src=""  class="order-item-title hiddenitem">
          <div class="order-item-info">
            <label class="order-item-title">商品名</label>
            <label class="order-item-title">商品编号</label>
            <label class="order-item-title">订单号</label>
            <label class="order-item-title">桌号</label>
            <label class="order-item-title">位号</label>
            <div class="order-item-right order-item-title">
              <label>数量</label>
            </div>
          </div>
        </div>
        <!-- 菜单项1 -->
        <div v-for="(order, index) in orderInfors.orderList" :key="index" class="order-items">
          <div v-for="(obj, j) in order.orderDetailList" :key="j" class="order-item">
            <img :src="obj.PRODUCT_IMG" :alt="obj.language[commonInfo().languageType]?.PRODUCT_NAME" class="order-item-img">
            <div class="order-item-info">
              <span class="item-text">{{ obj.PRODUCT_NAME }}</span>
              <span class="item-text">{{ obj.language[commonInfo().languageType]?.PRODUCT_NAME }}</span>
              <span class="item-text">{{ obj.PRODUCT_ID }}</span>
              <span class="item-text">{{ obj.ORDER_ID }}</span>
              <span class="item-text">{{ obj.TABLE_ID }}</span>
              <span class="item-text">{{ obj.SUB_TABLE_ID }}</span>
              <div class="order-item-right">
                <h1>{{ obj.NUMBER }}</h1>
                <button v-if="commonInfo().rollId == comEnum.Roll_ITEM.KITCHEN.val" @click="prepareOrder(obj)" class="prepare-order">预备</button>
                <button v-if="commonInfo().rollId == comEnum.Roll_ITEM.KITCHEN.val" @click="servingOrder(obj)" class="serving-order">出餐</button>
                <button v-if="commonInfo().rollId == comEnum.Roll_ITEM.CASHIER.val" @click="purchaseOrder(obj)" class="purchase-order">买单</button>
                <button v-if="commonInfo().rollId == comEnum.Roll_ITEM.CASHIER.val" @click="refundOrder(obj)" class="refund-order">退款</button>
              </div>
            </div>
          </div>
        </div>
        <!-- 可以继续添加菜单项 -->
      </section>
    </div>
  </main>
  <Footer />
  <CommonDialog ref="myModal" id="commonDialog" :cancelButton="''" :closeButton="''" :msg="modalmsg" :title="''"
    :okButton="modalOkBtn" @common-dialog-close="closeDialog" />
</template>

<style scoped>

.order-items {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
  width: 100%;
  display: block;
}

.order-item {
  background-color: white;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  text-align: center;
  display: flex;
  width: 100%;
  margin-bottom: 10px;
}

.order-item img {
  width: 100px;
  height: 100px;
  object-fit: cover;
}

.order-item title {
  height: 25px !important;
}

.hiddenitem {
  visibility: hidden;
}

.order-item-info {
  padding: 15px;
  display: flex;
  width: 80%;
  align-items: center;
}

.order-item-right {
  padding: 15px;
  display: flex;
  width: 60%;
  align-items: center;
  justify-content: flex-end;
}

.order-item-info .item-name {
  font-size: 1.2em;
  margin: 10px 0;
}

.order-item-info .item-description {
  color: #666;
  font-size: 0.9em;
}

.order-item-info .item-price {
  font-size: 1.1em;
  color: #d9534f;
  font-weight: bold;
}

.order-item-title {
  height: 25px !important;
  place-items: center;
  font-weight: bolder;
  padding-left: 5px;
}

.add-to-order {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  font: 0.5em sans-serif;
  text-align: center;
}

.order-aline-center {
  justify-content: center;
}
</style>