<template>
  <header class="main-header">
    <button class="mobile-nav-toggler" @click="open = !open">
      ☰
    </button>

    <nav v-show="open" class="mobile-menu">
      <ul>
        <li v-for="item in menus" :key="item.text">
          <a :href="item.link">{{ item.text }}</a>
        </li>
      </ul>
    </nav>
  </header>
</template>

<script setup>
import { ref } from 'vue'
const open = ref(true)

const menus = [
  { text: 'Home', link: '/' },
  { text: 'Menu', link: '/menu' },
  { text: 'Contact', link: '/contact' }
]
</script>
