import axios from "axios";
import loadingModal from "@/utils/common/loading-modal.js";
import commonInfo from "@/store/common/common-info.js";
import comProperty from "@/constants/com-property.js";
import comConst from "@/constants/com-const.js";

/**
 *  API共通処理およびエラー画面遷移クラスです。
 *
 *  @version 1.0
 *  @author CSC
 */
export default {
  /**
   * API通信
   * @param {*} reqParam リクエストオブジェクトの配列
   * @param {*} screenId スクリーンID
   * @returns レスポンスオブジェクトの配列
   */
  async httpService(reqParam, screenId) {
    return await _httpService(reqParam, screenId);
  },

  /**
   * API通信(ローディングモーダル表示)
   * @param {*} reqParam リクエストオブジェクトの配列
   * @param {*} screenId スクリーンID
   * @returns レスポンスオブジェクトの配列
   */
  async httpServiceWithShield(reqParam, screenId) {
    let ret = null;
    loadingModal.isshow(true);
    try {
      ret = await _httpService(reqParam, screenId);
    } finally {
      loadingModal.isshow(false);
    }
    return ret;
  },
};

/**
 * POSTリクエスト制御
 * @param {*} url リクエストURL
 * @param {*} data リクエストパラメータ
 * @param {*} headers ヘッダーオブジェクト
 * @param {*} responseType レスポンスタイプ
 * @param {*} timeout タイムアウト値
 * @returns レスポンスオブジェクト
 */
async function _postReq(url, data, headers, responseType, timeout) {
  let trace = "";
  let result = {};
  // axiosでエラーが出た場合はtraceが消失するため、traceを退避しておく
  Error.captureStackTrace(result);
  trace = result.stack;

  // config設定
  // withCredentials：CORS対応
  // axiosのタイムアウト値としてタイムアウト時間を設定
  let config = { headers: headers, timeout: timeout, withCredentials: true };
  // レスポンスタイプが設定されている場合、追加する
  if (responseType) {
    config = { ...config, responseType: responseType };
  }

  let response = await axios
    .post(url, data, config)
    .then((_response) => {
      if (_response.status === 0) {
        // httpステータスが0は規定されていないため、異常とする（axiosの不備対応）
        // rejectにより、後続のcatchへ処理を移管
        return Promise.reject(
          new Error(`undefine status：${_response.status}`)
        );
      }
      return _response;
    })
    .catch((err) => {
      console.error(err);

      // レスポンスが存在する場合
      if (err.response) {
        let status_cd = err.response.status;

        // ステータスコードが403 or 401 or CSRFトークンが存在する場合
        if (
          status_cd == comConst.FORBIDDEN ||
          status_cd == comConst.UNAUTHORIZED ||
          headers["X-CSRF-TOKEN"]
        ) {
          // エラーをthrow
          throw new Error(`HTTPステータス：${status_cd}${trace}`);
        } else {
          // トークンが存在しない(未認証)画面では呼び出し元でcatchさせるため処理なし。
          // （ログイン、ログイン時のパスワード変更の際の処理）
          return err.response;
        }
      } else {
        // エラーをthrow
        throw new Error(`undefine response：${err.message}${trace}`);
      }
    });
  console.debug(response);
  return response;
}

/**
 * リクエストヘッダー設定
 * @param {*} screenId スクリーンID
 * @param {*} contentType コンテンツタイプ
 * @returns リクエストヘッダー
 */
function _refreshRequestHeaderData(screenId, contentType) {
  const commonStore = commonInfo();
  // storeからデータを取得して設定
  let _csrfToken = commonStore.csrfToken ? commonStore.csrfToken : "";
  // スクリーンIDは引数から設定
  let _screenId = screenId ? screenId : "";
  commonStore.screenId = _screenId;

  let returnObj = {
    "Content-Type": contentType,
    "X-Requested-With": "XMLHttpRequest",
    "Screen-Id": _screenId,
    "X-CSRF-TOKEN": _csrfToken,
    "Access-Control-Allow-Origin": "*",
  };

  return returnObj;
}

/**
 * CSRFトークン更新
 */
function _updateStoreCsrfToken(retOne) {
  const commonStore = commonInfo();
  // レスポンスヘッダからCSRFトークンを取得
  let csrfToken = retOne.headers["x-csrf-token"];
  // CSRFトークンが存在する場合、storeのCSRFトークンを更新
  if (csrfToken) {
    commonStore.csrfToken = csrfToken;
  }
}

/**
 * API通信呼び出し制御
 * @param {*} reqParam リクエストオブジェクトの配列
 * @param {*} screenId スクリーンID
 * @returns レスポンスオブジェクトの配列
 */
async function _httpService(reqParam, screenId) {
  let retArray = [];

  // リクエストオブジェクトの配列分ループ
  for (let i in reqParam) {
    // reqParamは以下要素を持ったオブジェクトの配列
    /// パスパラメータ:string,
    /// リクエストパラメータ:string(JSON)|obj,
    /// コンテンツタイプ:string,
    /// レスポンスタイプ:string,
    /// タイムアウト値:number
    let param = reqParam[i];

    // コンテンツタイプを設定
    let contentType = comProperty.CONTENT_TYPE_JSON;
    if (param[2] && typeof param[2] === "string") {
      contentType = param[2];
    }
    // リクエストヘッダー設定呼び出し
    let headers = _refreshRequestHeaderData(screenId, contentType);

    // レスポンスタイプを設定
    let responseType = "";
    if (param[3] && typeof param[3] === "string") {
      responseType = param[3];
    }

    // APIタイムアウト値を設定
    let timeout = SYS_ENV_API_TIMEOUT;
    if (param[4] && typeof param[4] === "number" && param[4] !== 0) {
      timeout = param[4];
    }

    try {
      // リクエストパラメータ変換
      let isString = typeof param[1] === "string" ? true : false;
      let json = isString ? JSON.parse(param[1]) : param[1];

      // POSTリクエスト制御呼び出し
      let retOne = await _postReq(
        SYS_ENV_API_URL + param[0],
        json,
        headers,
        responseType,
        timeout
      );

      // CSRFトークン更新呼び出し
      _updateStoreCsrfToken(retOne);

      // レスポンス変換
      let resWork = isString ? JSON.stringify(retOne) : retOne;
      retArray.push(resWork);

      // API呼出し結果が異常なら後続APIの呼出しをしない（業務エラー）
      if (
        (retOne.data.resultCode &&
          retOne.data.resultCode !== comConst.API_RESULT_CODE_SUCCESS) ||
        (retOne.headers.resultCode &&
          retOne.headers.resultCode !== comConst.API_RESULT_CODE_SUCCESS)
      ) {
        break;
      }
    } finally {
      // エラー回避のfinally
    }
  }

  // 全レスポンスの配列を返却
  return retArray;
}
