<!--
 パンくずリストコンポーネント
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted } from "vue";
import commonInfo from "@/store/common/common-info.js";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import { useRouter } from "vue-router";

const router = useRouter();
const breadCrumbList = ref([]);

// 画面マウント時イベント
onMounted(async () => {
    // commonInfoから直接パンくずリストを取ろうとしたが、画面側で保存するタイミングと競合して取れないことがあるので断念
    // console.log(commonInfo().breadcrumbList);
});

//リンククリック時動作
const linkClick = async (arg, index) => {
  // パンくずからの遷移時は選択したページ以降のリストをクリア
  let pankuzu = breadCrumbList.value.slice(0, index + 1);
  commonInfo().breadcrumbList = JSON.stringify(pankuzu);
  // 画面遷移
  router.push({ name: arg ,
    params: { cameBackFlg: comConst.CAME_BACK_FLG_RETURN }});
  return false;
};

/**
 * 初期化メソッド
 * 
 * 指定の画面IDのパンくずリストを末尾に追加する
 * 既にパンくずリストに存在する場合（戻る系イベントで遷移した場合）は以降のリストをクリア
 * @param {String} screenId - 画面ID
 */
const init = (screenId)=> {
 
  // パンくずリストのID、名称を取得
  const breadCrumb = _getBreadCrumb(screenId);
      // パンくずリストを検索
  let pankuzu = [];
  if (commonInfo().breadcrumbList) {
    pankuzu = JSON.parse(commonInfo().breadcrumbList);
  }
  const index = pankuzu.findIndex(item => item.pageId === breadCrumb.val);
  if (index !== -1) {
    // 見つかった場合、以降のリストをクリア
    pankuzu.splice(index + 1);
  } else {
    // 見つからない場合、末尾に追加
    pankuzu.push({name:breadCrumb.dispname, pageId:breadCrumb.val});
  }
  breadCrumbList.value = pankuzu;
  commonInfo().breadcrumbList = JSON.stringify(pankuzu);
};

/**
 * 画面IDよりパンくずリストを取得する
 *
 * @param {String} screenId - 画面ID
 */
const _getBreadCrumb = (screenId) => {
  let breadCrumb = comEnum.EnumBREADCRUMB_LIST[screenId];
  if (!breadCrumb) {
    breadCrumb = {
      val: screenId,
      dispname: `${screenId}ページ`
    };
  }
  return breadCrumb;
};

/** expose：公開メソッド定義(scriptの一番下に記載しないと動かないです) */
defineExpose({
  init
});
</script>
<template>
<div v-if="(!!breadCrumbList && (breadCrumbList.length != 0))" class="sticky">
  <ul class="breadcrumb">
    <li v-for="(p, index) in breadCrumbList" v-bind:key="p">
        <a v-if="index < breadCrumbList.length - 1" href="#" @click.prevent.stop="linkClick(p.pageId, index)">{{p.name}}</a>
        <span v-else>{{p.name}}</span>
    </li>
  </ul>
</div>
</template>
<style scoped>
.sticky{
  min-width: 36em;
  position: sticky !important;
  top: 40px !important;
  background-color: #FFF;
  opacity: 1;
  z-index: 20;
}
</style>
