/**
 *  置換文字変換ユーティリティクラスです。
 *
 *  @version 1.0
 *  @author CSC
 */
export default class StringUtil
{
    /**
	 * 置換文字変換
     * 文字列内の置換文字をパラメータ配列の文字列へ変換する
     * 　置換前文字列は{0}のように{1}される想定。
     *
     * @param {String} str - 置換前文字列
     * @param {Array.<String>} param - 置換用の文字列（省略可）
     * @reterns {String} 置換後の文字列
     */
    static convertString(str, param) {
        let result = str;
        if (param) {
            for(let i=0; i < param.length; i++){
                let index = "{" + i + "}";
                result = result.replace(index, param[i]);
            }
        }
        return result;
    }
}
