<template>
  <section class="banner-section">
    <div class="slider-wrapper">
      <div class="slider-track" :style="{ transform: `translateX(-${currentIndex * 100}%)` }">
        <section v-for="(item, i) in slides" :key="i" class="slide">
          <div class="auto-container">
            <div class="row clearfix">
              <!-- Content -->
              <div class="content-column col-lg-6 col-md-12">
                <h1>
                  <span class="first-letter">{{ item.title1 }}</span>
                  <span class="second-letter">{{ item.title2 }}</span>
                </h1>
                <div class="text">{{ item.text }}</div>
              </div>

              <!-- Image -->
              <div class="image-column col-lg-6 col-md-12">
                <img :src="item.image" alt="" />
              </div>
            </div>
          </div>
        </section>
      </div>

      <!-- 控制按钮（可选） -->
      <button class="nav prev" @click="prev">‹</button>
      <button class="nav next" @click="next">›</button>
    </div>
  </section>
</template>

<script setup>
import { ref, onMounted, onBeforeUnmount } from 'vue'

const slides = [
  {
    title1: 'Heathly',
    title2: 'Smoothie',
    text: 'Consectetur, adipisci velit...',
    image: '/images/main-slider/content-image-1.png'
  },
  {
    title1: 'Heathly',
    title2: 'Smoothie',
    text: 'Consectetur, adipisci velit...',
    image: '/images/main-slider/content-image-2.png'
  }
]

const currentIndex = ref(0)
let timer = null

const next = () => {
  currentIndex.value = (currentIndex.value + 1) % slides.length
}

const prev = () => {
  currentIndex.value =
    (currentIndex.value - 1 + slides.length) % slides.length
}

onMounted(() => {
  timer = setInterval(next, 5000)
})

onBeforeUnmount(() => {
  clearInterval(timer)
})
</script>

<style scoped>
/* 外层容器 */
.slider-wrapper {
  position: relative;
  overflow: hidden;
}

/* 横向轨道 */
.slider-track {
  display: flex;
  width: 100%;
  transition: transform 0.6s ease;
}

/* 每一页 */
.slide {
  min-width: 100%;
}

/* 图片自适应 */
.image-column img {
  width: 100%;
  height: auto;
}

/* 左右按钮（可删） */
.nav {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  background: rgba(0,0,0,0.4);
  color: #fff;
  border: none;
  font-size: 32px;
  width: 44px;
  height: 44px;
  cursor: pointer;
  z-index: 10;
}

.nav.prev {
  left: 10px;
}

.nav.next {
  right: 10px;
}
</style>
