<script setup>
import { ref, onMounted } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import Menu from "@/components/common/Menu.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import MedicCorpInfo from "@/components/ENT0401100/MedicCorpInfo.vue";
import Stepper from "@/components/ENT0401100/Stepper.vue";
import StatusExplanation from "@/components/ENT0401100/StatusExplanation.vue";
import commonInfo from "@/store/common/common-info.js";
import apiCaller from "@/utils/common/api-caller.js";
import loadingModal from "@/utils/common/loading-modal.js";
import targetCorp from "@/store/common/target-corp.js";
import comConst from "@/constants/com-const.js";
import comEnum from "../constants/com-enum";
import StringUtil from "@/utils/common/string-util.js";
import comMessage from "@/constants/com-message.js";

const router = useRouter();
const breadcrumbObj = ref();

const modalmsg = ref("");
const myModal = ref();
const modaltitle = ref("");
const modalOkBtn = ref("");
const modalNgBtn = ref("");
const closeModal = ref();

// APIからの戻り値設定
const bizReportInpState = ref("");
const profitLossInpState = ref("");
const balancesheetInpState = ref("");
const attachementInpState = ref("");
const notificationStatus = ref("");
const notificationMethod = ref("");
const procStatusBizReportList = ref([]);
const messageErrList = ref([]);
const messageInfo = ref("");
const messageAlert = ref("");
const messageErr = ref("");
const bizReportIconClass = ref("");
const profitLossIconClass = ref("");
const balancesheetIconClass = ref("");
const attachementIconClass = ref("");

// 共通情報
const userType = ref("");
const corporationId = ref("");
const fiscalYear = ref("");
const notificationType = ref("");
const corporationName = ref("");
const prefNo = ref("");
const prefName = ref("");
const medicCorpRefNumber = ref("");
const address = ref("");

// メニュー
const selectedMenuId = ref("");

let nextScreenId = "ENT0101100";
let fileOperationManageSeq = "";

//////////////////////////
// 初期表示
//////////////////////////
/**
 * 「初期表示」イベント
 */
 const ENT0201500E00 = async () =>{

// ローディングの表示
loadingModal.isshow(true);

  // 経営情報等処理状況照会APIの呼び出し
  const reqParam = [
    [comConst.API_ID_ENT0201_46, { 
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);
  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    bizReportInpState.value = res[0].data.notificationManageDto.bizReportInpState;
    profitLossInpState.value = res[0].data.notificationManageDto.profitLossInpState;
    balancesheetInpState.value = res[0].data.notificationManageDto.balancesheetInpState;
    attachementInpState.value = res[0].data.notificationManageDto.attachementInpState;
    notificationStatus.value = res[0].data.notificationManageDto.notificationStatus;
    notificationMethod.value = res[0].data.notificationManageDto.notificationMethod;
    procStatusBizReportList.value = res[0].data.procStatusBizReportList || [];
    messageErrList.value = res[0].data.messageErrList || [];
    iconClassBizReport();
  // 上記以外
  } else {
    // ローディングの非表示
    loadingModal.isshow(false);
    // システムエラー画面へ遷移
    router.push({ name: comConst.UTL9999993 });
  }
    // 終了ログ出力
    console.log(StringUtil.convertString(comMessage.COMMON000005I, ["事業報告書等処理状況"]));
};

/**
 * コード値チェック用
 */
 const validOperationIds = [
  comEnum.EnumOPE_ID.EXCEL_FORM_UL.val,
  comEnum.EnumOPE_ID.CSV_UL.val,
  comEnum.EnumOPE_ID.EXCEL_FORM_BULK_UL.val,
  comEnum.EnumOPE_ID.CSV_BULK_UL.val,
  comEnum.EnumOPE_ID.SAVE.val,
  comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val,
  comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_BULK_UL.val,
  comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val,
  comEnum.EnumOPE_ID.EXCEL_FORM_BULK_INP_DL.val,
  comEnum.EnumOPE_ID.UL_ORI_FILE_DL.val,
  comEnum.EnumOPE_ID.UL_EXCEL_FORM_DL.val,
  comEnum.EnumOPE_ID.UL_CSV_FORM_DL.val,
  comEnum.EnumOPE_ID.UL_CSV_FORM_BULK_DL.val,
  comEnum.EnumOPE_ID.UL_EXCEL_FORM_BULK_DL.val,
  comEnum.EnumOPE_ID.PDF_BIZ_REPORT_ETC_DL.val,
  comEnum.EnumOPE_ID.CSV_BIZ_REPORT_ETC_MGT_INFO_ETC_DL.val  
];
const validProcessStateIds = [
  comEnum.EnumPROCESS_STATE_ID.PROC_WAIT.val,
  comEnum.EnumPROCESS_STATE_ID.PROCESSING.val,
  comEnum.EnumPROCESS_STATE_ID.PROC_END.val,
  comEnum.EnumPROCESS_STATE_ID.ERROR_EXISTS.val,
  comEnum.EnumPROCESS_STATE_ID.EXCEPTION_ERR.val,
  comEnum.EnumPROCESS_STATE_ID.DOWNLOAD_OK.val  
];

const isValidOperationId = (opeId) => {
  return validOperationIds.includes(opeId);
};

const isValidProcessStateId = (procStateId) => {
  return validProcessStateIds.includes(procStateId);
};

/**
 * メッセージの改行
 */
 const formatMessage = (message) => {
  return message.split('\\n').map(line => line.trim()).join('<br>');
};

/**
 * 事業報告書ステータスアイコン表示
 */
 const iconClassBizReport = () => {
  if (bizReportInpState.value === '1') {
    bizReportIconClass.value = 'bi bi-record-circle-fill text-success';
  } else if (bizReportInpState.value === '2') {
    bizReportIconClass.value = 'bi bi-triangle-fill text-warning';
  } else {
    bizReportIconClass.value = 'bi bi-dash text-danger';
  }

  if (profitLossInpState.value === '1') {
    profitLossIconClass.value = 'bi bi-record-circle-fill text-success';
  } else if (profitLossInpState.value === '2') {
    profitLossIconClass.value = 'bi bi-triangle-fill text-warning';
  } else {
    profitLossIconClass.value = 'bi bi-dash text-danger';
  }

  if (balancesheetInpState.value === '1') {
    balancesheetIconClass.value = 'bi bi-record-circle-fill text-success';
  } else if (balancesheetInpState.value === '2') {
    balancesheetIconClass.value = 'bi bi-triangle-fill text-warning';
  } else {
    balancesheetIconClass.value = 'bi bi-dash text-danger';
  }

  if (attachementInpState.value === '1') {
    attachementIconClass.value = 'bi bi-record-circle-fill text-success';
  } else if (attachementInpState.value === '2') {
    attachementIconClass.value = 'bi bi-triangle-fill text-warning';
  } else {
    attachementIconClass.value = 'bi bi-dash text-danger';
  }
};

/**
 * コード値変換
 */
 const getProcStatusTargetName = (procStatusTargetId) => {
  switch (procStatusTargetId) {
    case comEnum.EnumPROC_STATUS_TARGET_ID.BUSINESS_REPORT.val:
      return comEnum.EnumPROC_STATUS_TARGET_ID.BUSINESS_REPORT.dispname;
    case comEnum.EnumPROC_STATUS_TARGET_ID.BALANCESHEET.val:
      return comEnum.EnumPROC_STATUS_TARGET_ID.BALANCESHEET.dispname;
    case comEnum.EnumPROC_STATUS_TARGET_ID.PROFIT_LOSS.val:
      return comEnum.EnumPROC_STATUS_TARGET_ID.PROFIT_LOSS.dispname;
    case comEnum.EnumPROC_STATUS_TARGET_ID.ATTACHEMENT.val:
      return comEnum.EnumPROC_STATUS_TARGET_ID.ATTACHEMENT.dispname;
    default:
      break;
  }
};
 const getProcessStateName = (processStateId) => {
  switch (processStateId) {
    case comEnum.EnumPROCESS_STATE_ID.PROC_WAIT.val:
      return comEnum.EnumPROCESS_STATE_ID.PROC_WAIT.dispname;
    case comEnum.EnumPROCESS_STATE_ID.PROCESSING.val:
      return comEnum.EnumPROCESS_STATE_ID.PROCESSING.dispname;
    case comEnum.EnumPROCESS_STATE_ID.PROC_END.val:
      return comEnum.EnumPROCESS_STATE_ID.PROC_END.dispname;
    case comEnum.EnumPROCESS_STATE_ID.ERROR_EXISTS.val:
      return comEnum.EnumPROCESS_STATE_ID.ERROR_EXISTS.dispname;
    case comEnum.EnumPROCESS_STATE_ID.EXCEPTION_ERR.val:
      return comEnum.EnumPROCESS_STATE_ID.EXCEPTION_ERR.dispname;
    case comEnum.EnumPROCESS_STATE_ID.DOWNLOAD_OK.val:
      return comEnum.EnumPROCESS_STATE_ID.DOWNLOAD_OK.dispname;
    default:
      break;
  }
};

const getOperationName = (operationId) => {
  switch (operationId) {
    case comEnum.EnumOPE_ID.EXCEL_FORM_UL.val:
      return comEnum.EnumOPE_ID.EXCEL_FORM_UL.dispname;
    case comEnum.EnumOPE_ID.CSV_UL.val:
      return comEnum.EnumOPE_ID.CSV_UL.dispname;
    case comEnum.EnumOPE_ID.EXCEL_FORM_BULK_UL.val:
      return comEnum.EnumOPE_ID.EXCEL_FORM_BULK_UL.dispname;
    case comEnum.EnumOPE_ID.CSV_BULK_UL.val:
      return comEnum.EnumOPE_ID.CSV_BULK_UL.dispname;
    case comEnum.EnumOPE_ID.SAVE.val:
      return comEnum.EnumOPE_ID.SAVE.dispname;
    case comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val:
      return comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.dispname;
    case comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_BULK_UL.val:
      return comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_BULK_UL.dispname;
    case comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val:
      return comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.dispname;
    case comEnum.EnumOPE_ID.EXCEL_FORM_BULK_INP_DL.val:
      return comEnum.EnumOPE_ID.EXCEL_FORM_BULK_INP_DL.dispname;
    case comEnum.EnumOPE_ID.UL_ORI_FILE_DL.val:
      return comEnum.EnumOPE_ID.UL_ORI_FILE_DL.dispname;
    case comEnum.EnumOPE_ID.UL_EXCEL_FORM_DL.val:
      return comEnum.EnumOPE_ID.UL_EXCEL_FORM_DL.dispname;
    case comEnum.EnumOPE_ID.UL_CSV_FORM_DL.val:
      return comEnum.EnumOPE_ID.UL_CSV_FORM_DL.dispname;
    case comEnum.EnumOPE_ID.UL_CSV_FORM_BULK_DL.val:
      return comEnum.EnumOPE_ID.UL_CSV_FORM_BULK_DL.dispname;
    case comEnum.EnumOPE_ID.UL_EXCEL_FORM_BULK_DL.val:
      return comEnum.EnumOPE_ID.UL_EXCEL_FORM_BULK_DL.dispname;
    case comEnum.EnumOPE_ID.PDF_BIZ_REPORT_ETC_DL.val:
      return comEnum.EnumOPE_ID.PDF_BIZ_REPORT_ETC_DL.dispname;
    case comEnum.EnumOPE_ID.CSV_BIZ_REPORT_ETC_MGT_INFO_ETC_DL.val:
      return comEnum.EnumOPE_ID.CSV_BIZ_REPORT_ETC_MGT_INFO_ETC_DL.dispname;
    default:
      break;
  }
};
//////////////////////////
// ライフサイクルフック
//////////////////////////
 /**
 * 画面マウント時イベント
 */
onMounted(async () => {
  // 開始ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000004I, ["事業報告書等処理状況"]));
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.ENT0201500;
  // パンくずリストを設定
  breadcrumbObj.value.init(commonInfo().screenId); 
  // メニューの選択
  if (JSON.parse(commonInfo().breadcrumbList)[0].pageId == comConst.MNM0101100) {
    selectedMenuId.value = comConst.MNM0101100;
  } else if (JSON.parse(commonInfo().breadcrumbList)[0].pageId == comConst.MNM0201100) {
    selectedMenuId.value = comConst.MNM0201200;
  } else {
    selectedMenuId.value = comConst.ENT0101100;
  }
  //modal初期化
  myModal.value.init();

  // TargetCorpから値を取得
  userType.value = commonInfo().userType;
  corporationId.value = targetCorp().corporationId;
  fiscalYear.value = targetCorp().fiscalYear;
  notificationType.value = targetCorp().notificationType;
  corporationName.value = targetCorp().corporationName;
  prefNo.value = targetCorp().prefCode;
  prefName.value = targetCorp().prefName;
  medicCorpRefNumber.value = targetCorp().medicCorpRefNumber;
  address.value = targetCorp().address;

  // 初期表示
  await ENT0201500E00();
});

//////////////////////////
// 画面操作時のイベント
//////////////////////////
// タブクリック、戻るボタンクリック
const tabClick = async (arg) => {
  nextScreenId = arg;
  router.push({ name: nextScreenId });
};

// 次画面遷移
const nextScreen = async () => {
    router.push({ name: nextScreenId });
};

 /**
 * ダウンロードリンク押下時
 */
 const downloadLinkClick = async (fileOpeMngSeq) => {
  // 開始ログ出力
  console.log(StringUtil.convertString(comMessage.COMMON000006I, ["事業報告書等処理状況画面", "ダウンロードボタンクリック"]));
  fileOperationManageSeq = fileOpeMngSeq;
  modaltitle.value = "";
  modalmsg.value = StringUtil.convertString(comMessage.COMMON000000C, ["ダウンロード"]);
  modalOkBtn.value = "OK";
  modalNgBtn.value = "キャンセル";
  closeModal.value = closeModalAndCallApi;
  myModal.value.show();
    // 終了ログ出力
    console.log(StringUtil.convertString(comMessage.COMMON000007I, ["事業報告書等処理状況画面", "ダウンロードボタンクリック"]));
};

// 「OK」「キャンセル」ボタン押下時
const closeModalAndCallApi = (modalReturn) => {
  if (modalReturn == 1) { // OK押されたとき
    linkClick(fileOperationManageSeq);
  }
};

 /**
 * ダウンロードAPI実行
 */
 const linkClick = async(fileOpeMngSeq) => {
// ローディングの表示
loadingModal.isshow(true);
  // ダウンロードAPIの呼び出し
  const reqDownloadParam = [
    [comConst.API_ID_ENT0201_01, { 
      fileOperationManageSeq: fileOpeMngSeq,
    }],
  ];
  const screenId = commonInfo().screenId;
  const resDownload = await apiCaller.httpService(reqDownloadParam, screenId);
  
  // 結果コード = "0"（正常終了）の場合
  if (resDownload[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // ローディングの非表示
    loadingModal.isshow(false);
    // 情報表示エリアに完了メッセージ　MSG ID:COMMON000000I 0:ダウンロード
    messageInfo.value = StringUtil.convertString(comMessage.COMMON000000I, ["ダウンロード"]);
  // 結果コード = "1"（異常終了）の場合
  } else {
    // ローディングの非表示
    loadingModal.isshow(false);
    // エラー表示エリアに失敗メッセージ　MSG ID:COMMON100009E 0:ダウンロード
    messageErr.value = StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]);
    return;
  }
};
</script>

<template>
  <Header />
  <div class="contents">
    <Menu :selectedMenu="selectedMenuId" />
    <Breadcrumb ref="breadcrumbObj" />
    <MedicCorpInfo 
      :corpName="corporationName" :prefNo="prefNo" :prefName="prefName" :address="address"
      :medicCorpRefNumber="medicCorpRefNumber" :notificationMethodType="notificationMethod" />
    <Stepper :noticeStatus="notificationStatus" :notificationMethodType="notificationMethod" @stepper-back="tabClick('ENT0101100')" />
    <div v-if="messageInfo">
      <p>{{ messageInfo }}</p>
    </div>
    <div v-if="messageErrList.length > 0" class="errorBox">
      <p v-for="(messageError, index) in messageErrList" :key="index">
        {{ messageError }}
      </p>
    </div>
    <div v-if="messageErr" class="errorBox">
      <p>{{ messageErr }}</p>
    </div>
    <div v-if="messageAlert" class="alertBox">
      <p>{{ messageAlert }}</p>
    </div>
    <StatusExplanation :screenId="'ENT0201500'" />
    <ul class="nav nav-tabs" role="tablist">
      <li class="nav-item" role="presentation">
        <a data-bs-toggle="dummy" role="tab" href="#" data-bs-target="#tab-pane1" @click.prevent.stop="tabClick('ENT0201100')"
         class="nav-link me-2 fs-5 d-flex align-items-center justify-content-center">
          <i :class="bizReportIconClass"></i>事業報告書
        </a>
      </li>
      <li class="nav-item" role="presentation">
        <a data-bs-toggle="dummy" role="tab" href="#" data-bs-target="#tab-pane2" @click.prevent.stop="tabClick('ENT0201200')"
         class="nav-link me-2 fs-5 d-flex align-items-center justify-content-center">
         <i :class="profitLossIconClass"></i>貸借対照表
        </a>
      </li>
      <li class="nav-item" role="presentation">
        <a data-bs-toggle="dummy" role="tab" href="#" data-bs-target="#tab-pane3" @click.prevent.stop="tabClick('ENT0201300')"
         class="nav-link me-2 fs-5 d-flex align-items-center justify-content-center">
         <i :class="balancesheetIconClass"></i>損益計算書
        </a>
      </li>
      <li class="nav-item" role="presentation">
        <a data-bs-toggle="dummy" role="tab" href="#" data-bs-target="#tab-pane4" @click.prevent.stop="tabClick('ENT0201400')"
         class="nav-link me-2 fs-5 d-flex align-items-center justify-content-center">
         <i :class="attachementIconClass"></i>添付書類
        </a>
      </li>
      <li class="nav-item" role="presentation">
        <a data-bs-toggle="tab" role="tab" href="#" data-bs-target="#tab-pane5"
         class="nav-link me-2 fs-5 d-flex align-items-center justify-content-center active">
         <i class="bi bi-info-circle text-primary"></i>処理状況
        </a>
      </li>
    </ul>
    <div class="tab-content" id="tabCon1">
      <div id="tab-pane5" role="tabpanel" aria-labelledby="tab" tabindex="0" class="tab-pane fade p-2 show active">
        <div class="col mt-2 d-flex">
          <table class="table table-bordered table-white custom-table-2">
              <thead>
                  <tr>
                      <th class="text-center" style="width: 15%;">対象</th>
                      <th class="text-center" style="width: 30%;">操作</th>
                      <th class="text-center" style="width: 15%;">日時</th>
                      <th class="text-center" style="width: 10%;">状態</th>
                      <th class="text-center" style="width: 30%;">メッセージ</th>
                  </tr>
              </thead>
              <tbody>
                  <tr v-for="(procStatusBizReport, index) in procStatusBizReportList" :key="index">
                    <template v-if="isValidOperationId(procStatusBizReport.operationId) && isValidProcessStateId(procStatusBizReport.processStateId)">
                      <td class="align-left">
                        <span v-if="procStatusBizReport.procStatusTargetId === comEnum.EnumPROC_STATUS_TARGET_ID.ATTACHEMENT.val">
                          {{ getProcStatusTargetName(procStatusBizReport.procStatusTargetId) }}({{ procStatusBizReport.attachDocumentName }})
                        </span>
                        <span v-else>{{ getProcStatusTargetName(procStatusBizReport.procStatusTargetId) }}</span>
                      </td>
                      <td class="align-left">
                        <span v-if="procStatusBizReport.processStateId === comEnum.EnumPROCESS_STATE_ID.DOWNLOAD_OK.val">
                          <a href="#" @click.prevent="downloadLinkClick(procStatusBizReport.fileOperationManageSeq)" target="blank">{{ getOperationName(procStatusBizReport.operationId) }}</a>
                        </span>
                        <span v-else>{{ getOperationName(procStatusBizReport.operationId) }}</span>
                      </td>
                      <td class="align-center">{{ procStatusBizReport.operationDatetime }}</td>
                      <td class="align-center">{{ getProcessStateName(procStatusBizReport.processStateId) }}</td>
                      <td v-html="formatMessage(procStatusBizReport.message)" class="align-left"></td>
                    </template>
                  </tr>
              </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>
  <Footer />
  <CommonDialog ref="myModal" id="commonDialog" :title="modaltitle" :okButton="modalOkBtn" :cancelButton="modalNgBtn" closeButton=""
    :msg="modalmsg" @common-dialog-close="closeModal" />
</template>

<style scoped>
.nav-tabs .nav-link {
    min-width: 200px;
}

.custom-table-2 th {
    background-color: #CDE7F3;
    border-style: solid !important;
    border-width: 1px !important;
    border-color: #000000;
}

.custom-table-2 td {
    height: 75px !important;
    border-style: solid !important;
    border-width: 1px !important;
}

.align-center {
    text-align: center;
}

.align-content-center {
    align-content: center;
}

table.dataTable {
    width: 1440px !important;
}

table.dataTable th {
    background-color: #CDE7F3 !important;
    border-style: solid !important;
    border-width: 1px !important;
    border-color: #000000 !important;
    text-align: center !important;
}

table.dataTable td {
    height: 75px !important;
    border-style: solid !important;
    border-width: 1px !important;
}

.align-left {
    text-align: left;
}

.align-right {
    text-align: right;
}

.align-center {
    text-align: center;
}
</style>