<script setup>
import { ref } from "vue";
import commonInfo from "@/store/common/common-info.js";
import StringUtil from "@/utils/common/string-util.js";
import comConst from "@/constants/com-const.js";
import apiCaller from "@/utils/common/api-caller.js";
import { useRouter } from "vue-router";

// コンポーネントの引数
defineProps({
  isShow: { type: Boolean, default: true },
});

const router = useRouter();
// ユーザーIDなどは共通の保存場所（ストア）からとる（ログイン成功時にユーザーIDなどはストアに格納しておく前提）
const userId = ref("");
const userName = ref("");
userId.value = commonInfo().userId;
userName.value = commonInfo().userName;
/** ログ用 */
const screenName = "ヘッダー";
const languageType = ref(commonInfo().languageType);

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["common-language-change"]);

const languageTypeChange = async (value) => {
  commonInfo().languageType = value;
  languageType.value = value;
  emit("common-language-change", value);
}

const menuClick = async () => {
  //「ATH0101100：商品一覧画面」へ遷移する。
  router.push({ name: comConst.ATH0101100 });
}

const orderHistoryClick = async () => {
  //「ATH0102200：商品履歴画面」へ遷移する。
  router.push({ name: comConst.ATH0102200 });
}

</script>

<template>
  <!-- 顶部导航栏 -->
  <header>
      <nav>
          <div class="logo">
              <h1 class="cursor" v-on:click="menuClick">菜单</h1>
          </div>
          <div class="filters">
              <button class="filter-btn">筛选</button>
              <button class="filter-btn">类别</button>
              <label></label>
              <select class="filter-btn" v-model="languageType" v-on:change="languageTypeChange(languageType)">
                <option v-for="(obj, key) in commonInfo().languageList" :key="key" :value="obj.LANGUAGE_TYPE">{{ obj.LANGUAGE_NAME }}</option>
              </select>
              <button class="filter-btn" v-on:click="orderHistoryClick">订单履历</button>
          </div>
      </nav>
  </header>
</template>

<style scoped></style>
