const router = useRouter();
const breadcrumbObj = ref();

let myModal = ref();
let modaltitle = ref();
let modalmsg = ref();
let modalOkBtn = ref();
let modalCancelBtn = ref();

// 選択メニュー
const selectedMenuId = ref("");

// 代理入力の場合のみ入力が可能となる添付書類ID群
const proxyInputAttachDocumentIds = [comConst.ATTACH001_DAIRI1, comConst.ATTACH002_DAIRI2, comConst.ATTACH003_DAIRI3];

// 各画面項目
const corporationName = ref();
const prefCode = ref();
const prefName = ref();
const address = ref();
const medicCorpRefNumber = ref();
const notificationMethod = ref();
const notificationStatus = ref();
const resultCode = ref("0");
const messageInfo = ref([]);
const messageErr = ref([]);
const messageWarn = ref([]);
const attachmentList = ref();
const medicCorporationComment = defineModel("medicCorporationComment");
const prefectureComment = defineModel("prefectureComment");
const selectedAttachDocumentId = ref();
const dlType = ref("");
const renderingKey = ref(0);

// 各入力状況のアイコン
const bizReportInpStateCssClass = ref();
const balancesheetInpStateCssClass = ref();
const profitLossInpStateCssClass = ref();
const attachementInpStateCssClass = ref();

// バックエンドとのやり取り用
// --ファイルリスト
let fileList = {};
