let deleteTargetList = [];

// 編集区分
const editType = ref();

// ファイル選択コンポーネント用CSSクラス
const divClass1 = ref({
  fileInput: "col-5",
  fileInputInner: "form-control",
  fileName: "col-5 d-flex align-items-center",
  clear: "col-sm p-1 d-flex justify-content-center mw-5",
  dropArea: "col-4 fs12 border-dashedEtc",
});
const dropAreaMsg = ref("添付したいファイルをここに\n" + "ドラッグ＆ドロップしてください");

let nextScreenId = "";
/** ログ用 */
const screenName = "添付書類Web入力画面";
const E08Name = "「添付書類の入力内容を保存」ボタンクリック";
const E14Name = "各ダウンロードリストクリック";

// 画面マウント時イベント
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.ENT0201400;
  nextScreenId = "";

  // パンくずリストを設定
  breadcrumbObj.value.init(commonInfo().screenId);

  // 画面項目
  corporationName.value = targetCorp().corporationName;
  prefCode.value = targetCorp().prefCode;
  prefName.value = targetCorp().prefName;
  address.value = targetCorp().address;
  medicCorpRefNumber.value = targetCorp().medicCorpRefNumber;
  notificationMethod.value = targetCorp().notificationMethod;

  // 選択内容の初期化
  selectedAttachDocumentId.value = "";

  // 選択メニュー
  if (JSON.parse(commonInfo().breadcrumbList)[0].pageId == comConst.MNM0101100) {
    selectedMenuId.value = comConst.MNM0101100;
  } else if (JSON.parse(commonInfo().breadcrumbList)[0].pageId == comConst.MNM0201100) {
    selectedMenuId.value = comConst.MNM0201200; // ※条件式の画面IDとは別
  } else {
    selectedMenuId.value = comConst.ENT0101100;
  }

  // 添付書類情報の取得
  await ENT0201400E01();

  // textboxツールチップの有効化
  let targetList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
  targetList.map(function (_element) {
    return new Tooltip(_element, { trigger: "hover", html: true, animation: false });
  });

  //modal初期化
  myModal.value.init();

  // コメントの高さ自動調整用
  const textareaEls = document.querySelectorAll("textarea");
  textareaEls.forEach((textareaEl) => {
    let height = 0;
    height = textareaEl.scrollHeight == 0 ? 66 : textareaEl.scrollHeight + 10;
    // デフォルト値としてスタイル属性を付与
    textareaEl.setAttribute("style", `height: ${height}px;`);
    // inputイベントが発生するたびに関数呼び出し
    textareaEl.addEventListener("input", setTextareaHeight);
  });
});

// 添付書類照会API
const ENT0201400E01 = async () => {
  // 初期表示開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));
  loadingModal.isshow(true);
  const reqParam = [
    [
      comConst.API_ID_ENT0201_53,
      {
        corporationId: targetCorp().corporationId,
        fiscalYear: targetCorp().fiscalYear,
        notificationType: targetCorp().notificationType,
      },
    ],
  ];
  const screenId = commonInfo().screenId;
  // 添付書類照会APIを呼び出す
  const res = await apiCaller.httpService(reqParam, screenId);
  // 結果コードが「0:正常」の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    const resData = res[0].data;
    resultCode.value = resData.resultCode;
    messageErr.value = resData.messageErr;
    messageWarn.value = resData.messageWarn;
    medicCorporationComment.value = resData.medicCorporationComment;
    prefectureComment.value = resData.prefectureComment;
    // 届出ステータス、届出方法更新
    targetCorp().notificationStatus = resData.notificationStatus;
    notificationStatus.value = targetCorp().notificationStatus;
    targetCorp().notificationMethod = resData.notificationMethod;
    notificationMethod.value = targetCorp().notificationMethod;
    // 編集区分の設定
    editTypeSetting();

    // リストのソート
    let list = listSort(resData.attachmentList, "dispOrder", true);
    // 「グループ内いずれか必須」系の表示のため、リスト編集
    // --※編集区分の設定や届出ステータス更新の後でこれを実行すること。
    list = listEdit(list);
    // 再度リストのソート
    list = listSort(list, "dispOrder", true);
    attachmentList.value = list;

    // 各タブの入力状況アイコンの設定
    bizReportInpStateCssClass.value = getCSSClassOfInputStatus(resData.bizReportInpState);
    balancesheetInpStateCssClass.value = getCSSClassOfInputStatus(resData.balancesheetInpState);
    profitLossInpStateCssClass.value = getCSSClassOfInputStatus(resData.profitLossInpState);
    attachementInpStateCssClass.value = getCSSClassOfInputStatus(resData.attachementInpState);

    // 結果コード = "1"（異常終了）の場合
  } else {
    messageErr.value = resData.messageErr;
    messageWarn.value = resData.messageWarn;
  }

  // ローディングの非表示
  loadingModal.isshow(false);
  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

// 添付書類保存API
const ENT0201400E08 = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E08Name]));
  loadingModal.isshow(true);

  // アップロードファイルチェック
  for (let key in fileList) {
    let errMsg = ComFileUpload.checkUploadFile(fileList[key], null);
    if (errMsg.length !== 0) {
      messageErr.value = errMsg;
      // ローディングの非表示
      loadingModal.isshow(false);
      return;
    }
  }

  let dataParam = {
    corporationId: targetCorp().corporationId,
    fiscalYear: targetCorp().fiscalYear,
    prefCode: targetCorp().prefCode,
    notificationType: targetCorp().notificationType,
    fileType: comEnum.EnumFILE_TYPE.FT_ATTACHEMENT.val,
    operationId: comEnum.EnumOPE_ID.SAVE.val,
    deleteTargetList: deleteTargetList,
    screenId: commonInfo().screenId,
  };

  if (!document.querySelector(`[id=medicCorpComment1]`).disabled) {
    dataParam.medicCorpComment = medicCorporationComment.value;
  }
  if (!document.querySelector(`[id=prefComment1]`).disabled) {
    dataParam.prefComment = prefectureComment.value;
  }

  const formData = new FormData();
  formData.append("AttachDocSaveRequest", new Blob([JSON.stringify(dataParam)], { type: comProperty.CONTENT_TYPE_JSON }));
  // ファイルリストをフォームデータへ設定
  for (let key in fileList) {
    formData.append(key, fileList[key]);
  }
  const reqParam = [["ENT0201_47", formData, comProperty.CONTENT_TYPE_MULTIPART]];

  // 添付書類保存APIを呼び出す
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);
  // 結果コードが「0:正常」の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // ファイルリストと削除対象リストを初期化
    fileList = {};
    deleteTargetList = [];

    const resData = res[0].data;
    resultCode.value = resData.resultCode;
    // 完了メッセージ
    let procWord = "添付書類の保存";
    messageInfo.value = StringUtil.convertString(comMessage.COMMON000000I, [procWord]);
    messageErr.value = resData.messageErr;
    messageWarn.value = resData.messageWarn;

    // 届出ステータス、届出方法更新
    targetCorp().notificationStatus = resData.notificationStatus;
    notificationStatus.value = targetCorp().notificationStatus;
    targetCorp().notificationMethod = resData.notificationMethod;
    notificationMethod.value = targetCorp().notificationStatus;
    // 編集区分の設定
    editTypeSetting();

    // リストのソート
    let list = listSort(resData.attachmentList, "dispOrder", true);
    // 「グループ内いずれか必須」系の表示のため、リスト編集
    // --※編集区分の設定や届出ステータス更新の後でこれを実行すること。
    list = listEdit(list);
    // 再度リストのソート
    list = listSort(list, "dispOrder", true);
    attachmentList.value = list;

    // 各タブの入力状況アイコンの設定
    bizReportInpStateCssClass.value = getCSSClassOfInputStatus(resData.bizReportInpState);
    balancesheetInpStateCssClass.value = getCSSClassOfInputStatus(resData.balancesheetInpState);
    profitLossInpStateCssClass.value = getCSSClassOfInputStatus(resData.profitLossInpState);
    attachementInpStateCssClass.value = getCSSClassOfInputStatus(resData.attachementInpState);
  } else {
    const resData = res[0].data;
    resultCode.value = resData.resultCode;
    messageErr.value = resData.messageErr;
    messageWarn.value = resData.messageWarn;
    // リストのソート
    let list = listSort(resData.attachmentList, "dispOrder", true);
    // 「グループ内いずれか必須」系の表示のため、リスト編集
    list = listEdit(list);
    // 再度リストのソート
    list = listSort(list, "dispOrder", true);
    attachmentList.value = list;
  }

  // 編集区分の設定
  editTypeSetting();
  // ファイル選択Vueの再レンダリング用
  renderingKey.value += 1;
  // ローディングの非表示
  loadingModal.isshow(false);
  // TOPへ戻る
  document.getElementsByClassName("contents")[0].scrollTo({
    top: 0,
    behavior: "auto",
  });
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E08Name]));
};

// 各ダウンロードリストクリック
const ENT0201400E14 = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E14Name]));
  loadingModal.isshow(true);

  let dataParam = {};
  if (dlType.value == "blank") {
    // ブランクフォームのダウンロード
    dataParam = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      notificationType: targetCorp().notificationType,
      attachDocumentId: selectedAttachDocumentId.value,
      screenId: commonInfo().screenId,
    };
    const reqParam = [["ENT0201_15", dataParam, null, comProperty.RESPONSE_TYPE_BLOB, 0]];
    const screenId = commonInfo().screenId;
    const res = await apiCaller.httpService(reqParam, screenId);
    console.log(res[0].headers.resultcode);
    if (res[0].headers.resultcode == comConst.API_RESULT_CODE_SUCCESS) {
      // 正常時：ダウンロード
      ComFileDownload.download(res[0].data, res[0].headers, null);
    } else if (res[0].headers.resultcode == comConst.API_RESULT_CODE_ERROR) {
      // 異常時：メッセージ表示
      const resData = res[0].headers;
      if (resData.messageErr.length == 0) {
        let msgStr = "ダウンロード";
        messageErr.value.push(StringUtil.convertString(comMessage.COMMON100009E, [msgStr]));
      } else {
        messageErr.value = resData.messageErr;
      }
    } else {
      // 上記以外の場合
      let msgStr = "ダウンロード";
      messageErr.value.push(StringUtil.convertString(comMessage.COMMON100009E, [msgStr]));
    }
    resultCode.value = res[0].headers.resultCode;
  } else {
    // アップロードしたファイルのダウンロード（オリジナル）
    dataParam = {
      corporationId: targetCorp().corporationId,
      fiscalYear: targetCorp().fiscalYear,
      prefCode: targetCorp().prefCode,
      notificationType: targetCorp().notificationType,
      fileType: comEnum.EnumFILE_TYPE.FT_ATTACHEMENT.val,
      uploadOperationId: comEnum.EnumOPE_ID.SAVE.val,
      downloadOperationId: comEnum.EnumOPE_ID.UL_ORI_FILE_DL.val,
      attachDocumentId: selectedAttachDocumentId.value,
      screenId: commonInfo().screenId,
    };
    const reqParam = [["ENT0201_07", dataParam, null, comProperty.RESPONSE_TYPE_BLOB, 0]];
    const screenId = commonInfo().screenId;
    const res = await apiCaller.httpService(reqParam, screenId);
    console.log(res[0].headers.resultcode);
    if (res[0].headers.resultcode == comConst.API_RESULT_CODE_SUCCESS) {
      ComFileDownload.download(res[0].data, res[0].headers, null);
    } else if (res[0].headers.resultcode == comConst.API_RESULT_CODE_ERROR) {
      // 異常時：メッセージ表示
      const resData = res[0].headers;
      if (resData.messageErr.length == 0) {
        let msgStr = "ダウンロード";
        messageErr.value.push(StringUtil.convertString(comMessage.COMMON100009E, [msgStr]));
      } else {
        messageErr.value = resData.messageErr;
      }
    } else {
      // 上記以外の場合
      let msgStr = "ダウンロード";
      messageErr.value.push(StringUtil.convertString(comMessage.COMMON100009E, [msgStr]));
    }
    resultCode.value = res[0].headers.resultCode;
  }
  // ローディングの非表示
  loadingModal.isshow(false);
  // TOPへ戻る
  document.getElementsByClassName("contents")[0].scrollTo({
    top: 0,
    behavior: "auto",
  });
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E14Name]));
};

// リストソート
const listSort = (list, key, isAsc) => {
  list.sort((a, b) => {
    a = a[key];
    b = b[key];
    return (a === b ? 0 : a > b ? 1 : -1) * (isAsc ? 1 : -1);
  });
  return list;
};

// 編集区分の設定
const editTypeSetting = () => {
  if (
    commonInfo().userType == comEnum.EnumUSER_TYPE.MEDIC_CORP.val &&
    (targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.CORP_INP_WAIT.val ||
      targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.CORP_INP_COMP_WAIT.val ||
      targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.REMAND.val)
  ) {
    // 法人入力
    editType.value = "corpInput";
  } else if (
    commonInfo().userType == comEnum.EnumUSER_TYPE.PROXY_INPUT_STAFF.val &&
    (targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.CORP_INP_WAIT.val ||
      targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.CORP_INP_COMP_WAIT.val ||
      targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.REMAND.val)
  ) {
    // 代理入力
    editType.value = "proxyInput";
  } else if (
    commonInfo().userType == comEnum.EnumUSER_TYPE.PREF_STAFF.val &&
    targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.PREF_APPR_WAIT.val
  ) {
    // 都道府県入力
    editType.value = "prefInput";
  } else {
    // 閲覧
    editType.value = "dispOnly";
  }
};

// 入力状況に応じたCSSクラスを取得
const getCSSClassOfInputStatus = (inputStatus) => {
  let retClass = "bi-dash text-danger";
  if (inputStatus == comEnum.EnumINPUT_STATE.NOT_ENTERED.val) {
    // デフォルト値
  } else if (inputStatus == comEnum.EnumINPUT_STATE.NOTIFICATION_ENABLED.val) {
    retClass = "bi-record-circle-fill text-success";
  } else if (inputStatus == comEnum.EnumINPUT_STATE.ERROR_STATE.val) {
    retClass = "bi-triangle-fill text-warning";
  }
  return retClass;
};

/**
 *  リスト編集
 *  1. 「グループ内いずれか必須」系の注記表示のための、開始と終了を表すフラグをリストへ追加
 * 　　groupStartFlg = 1の行は、「グループ内いずれか必須」系の注記表示のためのダミー行。
 * 　　groupEndFlg = 1の行は、「グループ内いずれか必須」項目が終わったことを示す行表示のためのダミー行。
 *  2. 各ダウンロード用の追加用classをリストへ追加
 *  3. 入力エラーメッセージ、警告エラーメッセージの配列化
 *  4. 項目表示用フラグの追加
 * @param list 添付書類リスト
 * @returns list 1.と2.の値が追加された添付書類リスト
 */
const listEdit = (list) => {
  let retList = [];
  let buffList = [];
  let buffList2 = [];
  let item = {};
  let buffItem = {};
  let groupStartFlg = 0;
  let groupEndFlg = 0;
  let beforeAttachDocumentId = "";
  let beforeDispOrder = "";
  for (let k in list) {
    item = list[k];
    buffItem = JSON.stringify(list[k]);
    buffItem = JSON.parse(buffItem);
    // 「グループ内いずれか必須」開始の場合、groupStartFlg「1」のダミーレコードを挿入
    if (groupStartFlg == 0 && item.requiredFlg == "2") {
      groupStartFlg = 1;
      item.attachDocumentId = beforeAttachDocumentId + "_dummy";
      item.dispOrder = beforeDispOrder + "_dummy";
      item.groupStartFlg = 1;
      buffList.push(item);
    }
    buffItem.groupStartFlg = 0;

    // ブランクフォームダウンロードリンクの活性/非活性
    if (item.formExistsFlg == "1") {
      buffItem.isEnableBlankForm = "";
    } else {
      buffItem.isEnableBlankForm = "disabled";
    }
    // アップロードしたファイルのダウンロードリンクの活性/非活性
    if (item.fileOperationManageSeq != null && item.fileOperationManageSeq != undefined) {
      buffItem.isEnableUpdFile = "";
    } else {
      buffItem.isEnableUpdFile = "disabled";
    }
    // 入力エラーメッセージの配列化
    let buffAry = [];
    if (item.inputErrMsg != null && item.inputErrMsg != undefined) {
      buffAry = item.inputErrMsg.split("||");
    }
    buffItem.inputErrMsgAry = buffAry;
    // 警告エラーメッセージの配列化
    let buffAry2 = [];
    if (item.warnMsg != null && item.warnMsg != undefined) {
      buffAry2 = item.warnMsg.split("||");
    }
    buffItem.warnMsgAry = buffAry2;
    buffList.push(buffItem);
    if (groupStartFlg == 1 && item.requiredFlg != "2") {
      // 「グループ内いずれか必須」でなくなった場合、フラグを初期化しておく
      // 「グループ内いずれか必須」は、タイプ3などで複数あるための対応
      groupStartFlg = 0;
    }
    beforeAttachDocumentId = item.attachDocumentId;
    beforeDispOrder = item.dispOrder;
  }

  // 逆順からのソートで、「グループ内いずれか必須」終了の場合、groupEndFlg「1」のダミーレコードを後ろへ追加する
  const keys = Object.keys(buffList).reverse();
  for (let i = keys.length - 1; i >= 0; i--) {
    item = buffList[i];
    buffItem = JSON.stringify(buffList[i]);
    buffItem = JSON.parse(buffItem);

    item.groupEndFlg = 0;
    buffList2.push(item);
    // 「グループ内いずれか必須」終了の場合、groupEndFlgを「1」とする
    if (groupEndFlg == 0 && item.requiredFlg == "2") {
      groupEndFlg = 1;
      buffItem.attachDocumentId = item.attachDocumentId + "_dummy";
      buffItem.dispOrder = item.dispOrder + "_dummy";
      buffItem.groupEndFlg = 1;
      buffList2.push(buffItem);
    }
    if (groupEndFlg == 1 && item.requiredFlg != "2") {
      // 「グループ内いずれか必須」でなくなった場合、フラグを初期化しておく
      // 「グループ内いずれか必須」は、タイプ3などで複数あるための対応
      groupEndFlg = 0;
    }
  }

  // 項目表示用フラグの追加
  for (let k in buffList2) {
    item = buffList2[k];
    item.itemDispFlg = isDispItem(item.attachDocumentId, item.groupStartFlg, item.groupEndFlg);
    retList.push(item);
  }
  return retList;
};

/**
 * 項目を表示してよいかどうか
 * @param attachDocumentId
 * @param groupStartFlg 「グループ内いずれか必須」系の注記の行かどうか 0:否、1:その行である
 * @param groupEndFlg 「グループ内いずれか必須」系の注記の終端を示す行かどうか 0:否、1:その行である
 * @returns true:項目表示、false:項目非表示
 */
function isDispItem(attachDocumentId, groupStartFlg, groupEndFlg) {
  let retFlg = false;
  // 「グループ内いずれか必須」系の注記表示を表す行ではなく、かつその終端を示す行でもない場合
  if (groupStartFlg == 0 && groupEndFlg == 0) {
    // 該当する添付書類IDが、代理入力専用の場合
    if (proxyInputAttachDocumentIds.includes(attachDocumentId)) {
      // 編集区分が「代理入力」または届出ステータスが承認済みの場合
      if (editType.value == "proxyInput" || targetCorp().notificationStatus == "S5") {
        retFlg = true;
      }
    } else {
      retFlg = true;
    }
  }
  return retFlg;
}

// 「添付書類の入力内容を保存」ボタン押下時イベント
const btnSaveClick = async () => {
  modaltitle.value = "";
  modalmsg.value = StringUtil.convertString(comMessage.COMMON000000C, ["入力内容の保存"]);
  modalOkBtn.value = "OK";
  modalCancelBtn.value = "キャンセル";

  myModal.value.show();
};

/**
 * 各ダウンロードボタン押下時イベント
 * @param type （blank: ブランクフォームのダウンロード、uploaded: アップロードしたファイルのダウンロード（オリジナル）
 */
const btnDownloadClick = async (type, attachDocumentId) => {
  dlType.value = type;
  selectedAttachDocumentId.value = attachDocumentId;
  modaltitle.value = "";
  modalmsg.value = StringUtil.convertString(comMessage.COMMON000000C, ["ダウンロード"]);
  modalOkBtn.value = "OK";
  modalCancelBtn.value = "キャンセル";

  myModal.value.show();
};

/**
 * タブクリックイベント
 * @param screenId 遷移先画面ID
 */
const tabClick = async (screenId) => {
  nextScreenId = screenId;

  modalmsg.value = StringUtil.convertString(comMessage.COMMON000001C);
  myModal.value.show();
};
// Dialog閉じるイベント
const closeModal = (modalReturn) => {
  // OK押されたとき
  if (modalReturn == 1) {
    if (nextScreenId !== "") {
      // 画面IDが設定されている場合は画面遷移
      nextScreen();
    } else if (dlType.value == "") {
      // 保存処理
      ENT0201400E08();
    } else {
      // 各ダウンロードリストクリック
      ENT0201400E14();
    }
  }
};

/**
 * ファイル選択
 * @param FileSelectReturn 選択されたファイル関連情報(配列：[添付書類ID, ファイルオブジェクト])
 */
const fileSelect1 = (FileSelectReturn) => {
  // ファイルリストへ追加
  fileList[FileSelectReturn[0]] = FileSelectReturn[1];
};
/**
 * ファイル削除
 * @param FileDeleteReturn 削除指示された添付書類ID
 */
const fileDelete1 = (FileDeleteReturn) => {
  // 削除対象リストへ追加
  deleteTargetList.push(FileDeleteReturn);
};

// 次画面遷移
const nextScreen = async () => {
  router.push({ name: nextScreenId });
};

/** コメントの高さ自動設定 */
function setTextareaHeight() {
  this.style.height = "auto";
  this.style.height = `${this.scrollHeight + 10}px`;
}
</script>

