<!--
 注文履歴画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted, defineProps } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import PasswordChangeField from "@/components/ATH0102x/PasswordChangeField.vue";
import commonInfo from "@/store/common/common-info.js";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";
import apiCaller from "@/utils/common/api-caller.js";
import StringUtil from "@/utils/common/string-util.js"

//////////////////////////
// データ定義
//////////////////////////
/** VueRouter */
const router = useRouter();
/** モーダル設定 */
const modalmsg = ref("");
const modalOkBtn = ref("");
const myModal = ref();
/** エラーメッセージ */
const errorMsg = ref("");
/** 入出力項目 */
var orderInfors = ref({
  language:[]
});
const urlExpiredMessage = ref(comMessage.ATH010220003E);
/** エラー表示エリア表示制御  false：非表示 */
const isShowerrorMsg = ref(false);
/** URL有効期限切れ文言表示制御  false：非表示 */
const isShowUrlExpiredMessage = ref(false);
/** ログ用 */
const screenName = "注文履歴";
const E01Name = "「注文履歴」ボタンクリック";


//////////////////////////
// メソッド
//////////////////////////
/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = async (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  // ログイン画面へ遷移する
  router.push({ name: comConst.ATH0101100 });
};

/**
* 「初期表示」イベント
*/
const ATH0102200E00 = async () => {
  // 初期表示開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));

  // 注文履歴画面初期表示API呼び出し
  const reqParam = [
    [comConst.API_ID_ATH0102_02, {
      shopId: commonInfo().shopId ,
      tableId: commonInfo().tableId ,
      subTableId: commonInfo().subTableId
    }],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpServiceWithShield(reqParam, screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    orderInfors.value = res[0].data;
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = false;

    // 上記以外の場合
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.error.join("\n");
    // エラー文言エリアを非表示にする
    isShowerrorMsg.value = true;
  }

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

const addToCart = (productInfo) => {
  // 假设这里有 Vuex 或 Pinia 管理购物车
  var haveItem = false;
  for(var i = 0; i<commonInfo().cartList.length; i++) {
    var element = commonInfo().cartList[i];
    if (element.PRODUCT_ID == productInfo.PRODUCT_ID) {
      haveItem = true;
      break;
    }
  }
  if (!haveItem) {
    commonInfo().cartList.push(productInfo);
    showMessage("已加入购物车");
  } else {
    showMessage("购物车中已有该商品");
  }
}

//////////////////////////
// ライフサイクルフック
//////////////////////////
/**
* 画面マウント時イベント
*/
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.ATH0102200;
  // 初期表示
  await ATH0102200E00();
  //modal初期化
  myModal.value.init();
});
</script>

<template>
  <Header />
  <!-- 菜单内容区域 -->
  <main>
    <div>
      <!-- エラー表示エリア -->
      <div class="align-items-center center place_items_center">
        <div class="alert alert-danger text-danger width_100" v-if="isShowerrorMsg" role="alert">{{ errorMsg }}</div>
      </div>
      <section class="cart-items">
        <div class="cart-item">
          <img src=""  class="cart-item-title hiddenitem">
          <div class="cart-item-info">
            <label class="cart-item-title">单价</label>
            <div class="cart-item-right cart-item-title">
              <label>数量</label>
            </div>
          </div>
        </div>
        <!-- 菜单项1 -->
        <div v-for="(order, index) in orderInfors.orderList" :key="index" class="cart-items">
          <div v-for="(obj, j) in order.orderDetailList" :key="j" class="cart-item">
            <img :src="obj.PRODUCT_IMG" :alt="obj.language[commonInfo().languageType]?.PRODUCT_NAME" class="cart-item-img">
            <div class="cart-item-info">
              <span class="item-price">{{ Number(obj.PRICE).toLocaleString() }}{{ obj.PRICE_CURRENCY }}</span>
              <div class="cart-item-right">
                <h1>{{ obj.NUMBER }}</h1>
                <button @click="addToCart(obj)" class="add-to-cart">再注文</button>
              </div>
            </div>
          </div>
        </div>
        <div class="cart-item">
          <label class="cart-item-title">合計：</label>
          <div class="cart-item-info">
            <div class="cart-item-right">
              <span class="item-price">{{ Number(orderInfors.totalAmount).toLocaleString() }}{{ orderInfors.PRICE_CURRENCY }}</span>
            </div>
          </div>
        </div>
        <!-- 可以继续添加菜单项 -->
      </section>
    </div>
  </main>
  <Footer />
  <CommonDialog ref="myModal" id="commonDialog" :cancelButton="''" :closeButton="''" :msg="modalmsg" :title="''"
    :okButton="modalOkBtn" @common-dialog-close="closeDialog" />
</template>

<style scoped>

.cart-items {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
  width: 100%;
  display: block;
}

.cart-item {
  background-color: white;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  text-align: center;
  display: flex;
  width: 100%;
  margin-bottom: 10px;
}

.cart-item img {
  width: 100px;
  height: 100px;
  object-fit: cover;
}

.cart-item title {
  height: 25px !important;
}

.hiddenitem {
  visibility: hidden;
}

.cart-item-info {
  padding: 15px;
  display: flex;
  width: 80%;
  align-items: center;
}

.cart-item-right {
  padding: 15px;
  display: flex;
  width: 60%;
  align-items: center;
  justify-content: flex-end;
}

.cart-item-info .item-name {
  font-size: 1.2em;
  margin: 10px 0;
}

.cart-item-info .item-description {
  color: #666;
  font-size: 0.9em;
}

.cart-item-info .item-price {
  font-size: 1.1em;
  color: #d9534f;
  font-weight: bold;
}

.cart-item-title {
  height: 25px !important;
  place-items: center;
  font-weight: bolder;
  padding-left: 5px;
}

.add-to-cart {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  font: 0.5em sans-serif;
  text-align: center;
}

.cart-aline-center {
  justify-content: center;
}
</style>