/**
 *  ファイルアップロードに関する共通機能クラスです。
 *
 *  @version 1.0
 *  @author CSC
 */
import comProperty from "@/constants/com-property.js";
import comMessage from "@/constants/com-message.js";
import stringUtil from "@/utils/common/string-util.js";

export default class ComFileUpload {

	/**
	 * ファイル最大サイズチェック
     * １つのファイルサイズが最大値を超えていないかチェックする
	 * 
     * @param {File} selectedFile - ファイルオブジェクト
     * @reterns {String} エラーメッセージ
     */
    static checkMaxFileSize(selectedFile) {
    
    	let errMsg = "";

    	// ファイル最大サイズ取得
		const maxFileSizeText = comProperty.MAX_FILE_SIZE;
		const maxFileSizeByte = parseInt(maxFileSizeText, 10) * 1024 * 1024;

		if(selectedFile !== null && selectedFile.size > maxFileSizeByte){
			errMsg = stringUtil.convertString(comMessage.COMMON000005E, [maxFileSizeText]);
		}
		return errMsg;
	}

    /**
	 * アップロード最大サイズチェック
     * アップロードするファイルの合計サイズが最大値を超えていないかチェックする
     *
     * @param {File} selectedFiles - ファイルオブジェクト配列
     * @reterns {String} エラーメッセージ
     */
    static checkMaxRequestSize(selectedFiles) {
    
    	let errMsg = "";

		// アップロード最大サイズ取得
		const maxRequestSizeText = comProperty.MAX_REQUEST_SIZE;
		const maxRequestSizeByte = parseInt(maxRequestSizeText, 10) * 1024 * 1024;
		
		// ファイルサイズの合計を算出する
		let totalFileSize = 0;
		for(let file of selectedFiles) {
			if(file !== null) {
				totalFileSize = totalFileSize + file.size;
			}
		}

		if(totalFileSize > maxRequestSizeByte){
			errMsg = stringUtil.convertString(comMessage.COMMON000002E, [maxRequestSizeText]);
		}
		return errMsg;
	}

    /**
	 * ファイル拡張子チェック
     * ファイル名に指定の拡張子が含まれるかをチェックする
     *
     * @param {String} fileName - ファイル名
     * @param {String[]} fileExtensions - ファイル拡張子配列
     * @reterns {String} エラーメッセージ
     */
    static checkFileExtension(fileName, fileExtensions) {

        let errMsg = "";
        
	    // ファイル名、ファイル拡張子の指定がない場合、チェック不要と判断する
		if (!fileName || !fileExtensions || fileExtensions.length === 0) {
			return errMsg;
		}
		const pattern = fileExtensions.map(ext => ext.replace(".", "\\.")).join("|");
		const regex = new RegExp(`\\.(${pattern})$`, "i");
		if (!regex.test(fileName)) {
			errMsg = stringUtil.convertString(comMessage.COMMON000000E, [fileExtensions]);
		}
		return errMsg;
	}

    /**
	 * ファイル名禁止文字チェック
     * ファイル名に使用禁止文字が使われていないかをチェックする
     * 大文字小文字を区別しない
     *
     * @param {String} fileName - ファイル名
     * @reterns {String} エラーメッセージ
     */
    static checkFileName(fileName) {
    
        let errMsg = "";
  	
        // ファイル名使用禁止文字を取得
		const forbiddenChars = comProperty.FILE_FORBIDDEN_CHARACTERS;
		if (!fileName || !forbiddenChars) {
			return errMsg;
		}
 
		const chars = forbiddenChars.split(",");
		if (chars.some(char => fileName.toLowerCase().includes(char.toLowerCase()))) {
			// メッセージ用に区切り文字( ,)を除去する
			const displayForbiddenChars = forbiddenChars.replace(/[,]/g,"");
			errMsg = stringUtil.convertString(comMessage.COMMON000001E, [displayForbiddenChars]);
		}
		return errMsg;
	}

    /**
	 * ファイル名文字数制限チェック
     * ファイル名の文字数制限チェックをする
     * 制限値が0に設定されている場合は、チェックしない
     * 
     * @param {String} fileName - ファイル名
     * @reterns {String} エラーメッセージ
     */
    static checkFileNameLength(fileName) {
    
        let errMsg = "";
    
        // ファイル名制限文字数を取得
		const limit = comProperty.FILE_NAME_LENGTH_LIMIT;
		if (!fileName || limit <= 0) {
			return errMsg;
		}

		if (limit < fileName.length) {
			errMsg = stringUtil.convertString(comMessage.COMMON000003E, [limit]);
		}
		return errMsg
	}

    /**
	 * アップロードファイルチェック
     * アップロードファイルの各チェックを行う
     * 
     * @param {File} selectedFile - ファイルオブジェクト
     * @param {String[]} fileExtensions - ファイル拡張子配列
     * @reterns {String[]} エラーメッセージ配列
     */
    static checkUploadFile(selectedFile, fileExtensions) {
    
    	let errMsgs = [];

		if(selectedFile === null) {
			return errMsgs;
		}
		// ファイルサイズ0バイトチェック
		if (selectedFile.size === 0){
			errMsgs.push(comMessage.COMMON000004E);
		}

		// ファイル最大サイズチェック
		let checkResult = this.checkMaxFileSize(selectedFile);
		if (checkResult.length > 0) {
			errMsgs.push(checkResult);
		}

		// ファイル拡張子チェック
		checkResult = this.checkFileExtension(selectedFile.name, fileExtensions);
		if (checkResult.length > 0) {
			errMsgs.push(checkResult);
		}

		// ファイル名禁止文字チェック
		checkResult = this.checkFileName(selectedFile.name);
		if (checkResult.length > 0) {
			errMsgs.push(checkResult);
		}

        // ファイル名文字数制限チェック
		checkResult = this.checkFileNameLength(selectedFile.name);
		if (checkResult.length > 0) {
			errMsgs.push(checkResult);
		}

		return errMsgs;
	}

}