<script setup>
import { ref, onMounted, computed } from "vue";
import { useRouter, useRoute } from "vue-router";
import "datatables.net-bs5/css/dataTables.bootstrap5.css";
import DataTable from 'datatables.net-bs5';
import 'datatables.net';
import "@/css/customtable.css";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import Menu from "@/components/common/Menu.vue"
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import commonInfo from "@/store/common/common-info.js";
import targetCorp from "@/store/common/target-corp.js";
import MNM0201100Save from "@/store/MNM0201100/MNM0201100-save.js";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import comMessage from "@/constants/com-message.js";
import comProperty from "@/constants/com-property.js";
import StringUtil from "@/utils/common/string-util.js"
import apiCaller from "@/utils/common/api-caller.js";
import validator from "@/utils/common/validator.js";
import ComFileDownload from "@/utils/common/com-file-download.js"
import ComDate from "@/utils/common/com-date.js";

//////////////////////////
// データ定義
//////////////////////////
/** ユーザ種別Enum */
const enumUserType = comEnum.EnumUSER_TYPE;
/** 会計月区分Enum */
const enumMonthDivision = comEnum.EnumMONTH_DIVISION;
/** アップロード届出の希望有無区分Enum */
const enumExistType = comEnum.EnumUPLOAD_NOTIFICATION_EXIST_TYPE;
/** 廃止種別Enum */
const enumAbolitionType = comEnum.EnumABOLITION_TYPE;
/** vueRouter */
const route = useRoute();
const router = useRouter();
/** パンくずリスト */
const breadcrumbObj = ref();
/** APIエラーメッセージ */
const errorMsg = ref("");
/** エラー表示エリア表示判定  false：非表示 */
const isShowerrorMsg = ref(false);
/** 入力チェックエラーメッセージ */
const errorMessages = ref({});
/** レスポンス */
const responseRef = ref({
  allSelectCount: 0,
  prefMap: {},
  corporationInfoList: [],
  corporationIdList: []
});
/** 検索条件 */
const searchCriteria = ref({
  prefCode: "", // 都道府県
  medicCorpRefNumber: "", // 医療法人整理番号
  corporationName: "", // 医療法人名称
  cityName: "", // 住所（市区町村）
  townName: "", // 住所（町域・番地）
  buildingName: "", // 住所（建物名）
  bizRepoAccepHelthCenter: "", // 届出の受付保健所
  chairpersonLastName: "", // 理事長の氏名（姓）
  chairpersonFirstName: "", // 理事長の氏名（名）
  upldBizReportRequest: "", // アップロード届出の希望
  fiscalYearEnd: "", // 会計年度の決算月
  closed: "", // 廃止の有無
  limitNumber: "", // 表示件数
});
/** 画面表示用 */
// アップロード届出の希望チェックボックス
const upldBizReportRequestTypes = ref((() => {
  let array = [];
  for (let obj of Object.values(enumExistType)) {
    array.push({ dispname: obj.dispname, val: obj.val, checked: true });
  }
  return array.sort((a, b) => a.val - b.val);
})());
// 廃止の有無チェックボックス
const closedTypes = ref((() => {
  let array = [];
  for (let obj of Object.values(enumAbolitionType)) {
    array.push({ dispname: obj.dispname, val: obj.val, checked: obj.val !== "3" });
  }
  return array.sort((a, b) => a.val - b.val);
})());
// 都道府県初期値
const selectedPrefCode = ref((() => {
  // 都道府県ユーザの場合、自身の都道府県を表示
  // 機構職員ユーザ、代理入力ユーザの場合、「全国」を設定
  return commonInfo().userType === enumUserType.PREF_STAFF.val ? commonInfo().prefCode : comConst.PREF_ALL_CD;
})());
// 都道府県プルダウン非活性判定 true：非活性、false：活性
const isDisabledPref = ref((() => {
  // 都道府県ユーザの場合非活性
  return commonInfo().userType === enumUserType.PREF_STAFF.val;
})());
// 会計年度の決算月プルダウン
const fiscalYearEndList = ref((() => {
  const array = [{ dispname: "すべて", val: "00" }];
  const combinedArray = array.concat(Object.values(enumMonthDivision));
  return combinedArray.sort((a, b) => a.val - b.val);
})());
// 会計年度の決算月初期値
const selectedFiscalYearEnd = ref((() => {
  // 現在の月を初期表示
  const date = new Date();
  const month = date.getMonth() + 1;
  return month < 10 ? `0${month}` : `${month}`;
})());
// 検索結果一覧表示判定　true：表示、false：非表示
const isShowTable = ref(false);
// 検索条件(検索結果エリア用)
const searchCriteriaStr = ref("");
// 頁数
const currentPage = ref(1);
// 表示件数プルダウン
const displayCountList = ref((() => {
  // プロパティから表示件数取得
  let labelArray = comProperty.DISPLAY_COUNT_LABEL.split(",");
  let valArray = comProperty.DISPLAY_COUNT_VALUE.split(",");
  let array = [];
  labelArray.forEach((val, i) => {
    array.push({ dispname: val, val: valArray[i] })
  });
  return array.sort((a, b) => a.val - b.val);;
})());
// 表示件数初期値
const selectedCnt = ref((() => {
  return comProperty.DISPLAY_COUNT_DEFAULT_VALUE;
})());
// 法人情報 新規登録ボタン表示判定 true：表示、false：非表示
const isShowRegistButton = ref((() => {
  // 都道府県ユーザ、機構職員ユーザの場合、表示
  return commonInfo().userType === enumUserType.PREF_STAFF.val || commonInfo().userType === enumUserType.MEDIC_CARE_ORG_STAFF.val;
})());
/** 戻るフラグ */
let cameBackFlg = false;
/** colums用 */
const TEXT_CENTER = "text-center";
const TEXT_START = "text-start";
/** ログ用 */
const screenName = "法人情報検索";
const E03Name = "「検索」ボタンクリック";
const E04Name = "「法人情報 新規登録」ボタンクリック";
const E05Name = "「法人情報ダウンロードボタン」ボタンクリック";
const E06Name = "検索結果一覧の各「詳細表示」ボタンクリック";
const E07Name = "検索結果一覧-操作部分の「前の頁」ボタンクリック";
const E08Name = "検索結果一覧-操作部分の「次の頁」ボタンクリック";
const E09Name = "検索結果一覧-操作部分の「表示件数」コンボボックス";

//////////////////////////
// 算出プロパティ
//////////////////////////
/**
 * 都道府県リスト
 * @type {Object[]}
 */
const prefCodeList = computed(() => {
  // 法人マスタ検索APIの戻り値からリストを作成
  let array = [];
  Object.entries(responseRef.value.prefMap).forEach(([key, value]) => {
    array.push({ dispname: value, val: key })
  });
  return array.sort((a, b) => a.val - b.val);
});
// 検索条件欄仕様
const searchCriteriaSpecification = computed(() => {
  return {
    prefCode: {
      label: "都道府県",
      codeList: prefCodeList.value,
      itemNameNecessity: false
    },
    medicCorpRefNumber: {
      label: "医療法人整理番号",
      maxLength: 255,
      itemNameNecessity: true
    },
    corporationName: {
      label: "医療法人名称",
      maxLength: 80,
      itemNameNecessity: true
    },
    cityName: {
      label: "住所（市区町村）",
      maxLength: 21,
      itemNameNecessity: false
    },
    townName: {
      label: "住所（町域・番地）",
      maxLength: 40,
      itemNameNecessity: false
    },
    buildingName: {
      label: "住所（建物名）",
      maxLength: 40,
      itemNameNecessity: false
    },
    bizRepoAccepHelthCenter: {
      label: "届出の受付保健所",
      maxLength: 85,
      itemNameNecessity: true
    },
    chairpersonLastName: {
      label: "理事長の氏名（姓）",
      maxLength: 40,
      itemNameNecessity: true
    },
    chairpersonFirstName: {
      label: "理事長の氏名（名）",
      maxLength: 40,
      itemNameNecessity: true
    },
    upldBizReportRequest: {
      label: "アップロード届出の希望",
      codeList: Object.values(enumExistType),
      itemNameNecessity: true
    },
    fiscalYearEnd: {
      label: "会計年度の決算月",
      codeList: fiscalYearEndList.value,
      itemNameNecessity: true
    },
    closed: {
      label: "廃止の有無",
      codeList: Object.values(enumAbolitionType),
      itemNameNecessity: true
    }
  }
});
/**
 * 検索結果件数
 * @type {int}
 */
const searchResultTotalNumbers = computed(() => {
  return Number(responseRef.value.allSelectCount);
});
/**
 * 頁総数
 * @type {int}
 */
const totalPages = computed(() => {
  // API戻り値の検索結果件数を表示件数で除算（切り上げ）
  let result = (searchResultTotalNumbers.value ?? 0) / (selectedCnt.value ?? 0);
  return Math.ceil(result);
});
/** 
 * xx/xx頁（全xx件）
 * @type {String}
 */
const pageLabel = computed(() => {
  return `${currentPage.value}/${totalPages.value}頁（全${searchResultTotalNumbers.value}件）`;
});
/** 
 * 前頁（xx件）表示
 * @type {String}
 */
const prevLabel = computed(() => {
  const cnt = currentPage.value === 1 ? "" : `（${selectedCnt.value}件）`;
  return `前頁${cnt}表示`;
});
/** 
 * 次頁（xx件）表示
 * @type {String}
 */
const nextLabel = computed(() => {
  let cnt = "";
  if (currentPage.value !== totalPages.value) {
    if (currentPage.value !== (totalPages.value - 1)) {
      cnt = `（${selectedCnt.value}件）`;
    } else {
      cnt = `（${(searchResultTotalNumbers.value ?? 0) % (selectedCnt.value ?? 0)}件）`;
    }
  }
  return `次頁${cnt}表示`;
});

let table;

//////////////////////////
// メソッド
//////////////////////////
/**
 * DataTable初期化
 */
const initializeDataTable = () => {
  const tableElement = document.getElementById("detail_list");
  if (tableElement) {
    table = new DataTable(tableElement, {
      lengthChange: false,
      searching: false,
      info: false,
      paging: false,
      ordering: true,
      order: [],
      autoWidth: false,
      orderCellsTop: null, // not work (deprecated) 
      columnDefs: [
        { orderable: false, targets: 0 },
      ],
      data: responseRef.value.corporationInfoList.slice(),
      columns: [
        {
          id: 'btn_check_label0', data: 'corporationId', width: '7%', title: '操作',
          createdCell: (td, cellData, rowData, row, col) => {
            td.classList.add(TEXT_CENTER);
            const button = document.createElement('button');
            button.className = 'btn btn-primary';
            button.innerHTML = `<i class="bi bi-box-arrow-right">詳細</i>`;
            button.addEventListener('click', () => MNM0201100E06(cellData, rowData.prefName));
            td.innerHTML = '';
            td.appendChild(button);
          }
        },
        { id: 'btn_check_label1', data: 'prefName', width: '7%', title: '都道府県' },
        {
          id: 'btn_check_label2', data: 'msiMedicCorpRefNumber', width: '7%', title: '医療法人\n整理番号',
          createdCell: (td) => td.classList.add(TEXT_CENTER)
        },
        { id: 'btn_check_label3', data: 'msiCorporationName', width: '9%', title: '医療法人\n名称', createdCell: (td) => td.classList.add(TEXT_START) },
        { id: 'btn_check_label4', data: 'msiAddr', width: '17%', title: '住所', createdCell: (td) => td.classList.add(TEXT_START) },
        { id: 'btn_check_label5', data: 'msiChairpersonName', width: '8%', title: '理事長\n氏名', createdCell: (td) => td.classList.add(TEXT_CENTER) },
        { id: 'btn_check_label6', data: 'msiFiscalYearEnd', width: '6%', title: '決算月' },
        { id: 'btn_check_label7', data: 'msiClosedDate', width: '7%', title: '廃止日', createdCell: (td) => td.classList.add(TEXT_CENTER) },
        {
          id: 'btn_check_label8', data: 'updateDateTime', width: '7%', title: '最終\n更新日時',
          render: function (data, type, row) {
            let updateDateTime = data ? data.split(' ') : '';
            return updateDateTime ? `${updateDateTime[0]}\n${updateDateTime[1]}` : '';
          }
        },
        { id: 'btn_check_label9', data: 'updateUserId', width: '7%', title: '最終更新\nユーザID' },
        {
          id: 'btn_check_label10', data: 'createDateTime', width: '7%', title: '登録\n日時',
          render: function (data, type, row) {
            let createDateTime = data ? data.split(' ') : '';
            return createDateTime ? `${createDateTime[0]}\n${createDateTime[1]}` : '';
          }
        },
        { id: 'btn_check_label11', data: 'createUserId', width: '7%', title: '登録\nユーザID' }
      ],
      headerCallback: function (thead) {
        thead.closest('table').style.tableLayout = 'fixed';
        const thElements = thead.querySelectorAll('th');
        thElements.forEach(th => {
          th.style.whiteSpace = 'pre';
        });
      },
      createdRow: function (row, data, dataIndex) {
        Array.from(row.getElementsByTagName('td')).forEach(function (td) {
          td.style.overflowWrap = 'break-word';
          td.style.whiteSpace = 'normal';
        });
      }
    });
  }
};

/**
 * DataTableに新しいデータを設定し再描画
 */
const updateData = () => {
  table.clear();
  table.rows.add(responseRef.value.corporationInfoList.slice());
  table.draw();
}

/**
 * 検索条件(検索結果エリア用)生成
 * @param params 検索条件
 */
const createSearchCriteriaStr = (params) => {
  let array = [];
  let chairpersonLastName = "";
  Object.entries(params).forEach(([key, value]) => {
    let str = "";
    if (value && searchCriteriaSpecification.value.hasOwnProperty(key)) {
      let specification = searchCriteriaSpecification.value[key];
      // コード値を持つプロパティの場合
      if (specification.hasOwnProperty('codeList')) {
        // コード値を表示名に変換
        let valArray = getDispNameArray(specification.codeList, value);
        str = specification.itemNameNecessity ? `${specification.label}：${valArray.join(",")}` : valArray[0];

        // 理事長の氏名は結合
      } else if (key === "chairpersonLastName") {
        chairpersonLastName = value;
      } else if (key === "chairpersonFirstName") {
        str = `理事長の氏名：${chairpersonLastName + value}`;
      } else {
        str = specification.itemNameNecessity ? `${specification.label}：${value}` : value;
      }

      if (str) {
        array.push(str);
      }
    }
  });
  return array.join("、");
};

/**
 * コード値を表示名に変換
 * @param array コード値オブジェクトの配列
 * @param value 対象コード値
 */
const getDispNameArray = (array, value) => {

  let valArray = [];
  for (let target of value.split(",")) {
    const found = array.find(obj => obj.val === target);
    valArray.push(found ? found.dispname : "");
  }
  return valArray
};

/**
 * チェックボックスの選択値をカンマ区切りに変換
 * 未選択の場合はnullを設定
 * @param array チェックボックスの配列
 */
const getCheckedStr = (array) => {
  let checkedStr = array.filter(obj => obj.checked).map(obj => obj.val).join(",");
  if (!checkedStr) {
    checkedStr = null;
  }
  return checkedStr;
};

/**
 * チェック状態切替
 * @param value 保存済検索条件
 * @param refArray チェックボックスのref
 */
const changeCheckState = (value, refArray) => {
  let array = value ? value.split(",") : [];
  for (let obj of refArray) {
    if (array.includes(obj.val)) {
      obj.checked = true;
    } else {
      obj.checked = false;
    }
  }
};

/**
 * 入力チェック
 * @param searchCriteria 検索条件
 */
const checkInput = async (searchCriteria) => {
  const errmsg = errorMessages.value;
  let errFlg = false;     // true：エラーあり

  // 全項目のエラーメッセージを削除
  Object.keys(errmsg).forEach(key => {
    errmsg[key] = null;
  });

  Object.entries(searchCriteria).forEach(([key, value]) => {
    // 検索条件最大文字数に該当のkeyが存在する場合
    if (searchCriteriaSpecification.value.hasOwnProperty(key) && searchCriteriaSpecification.value[key].hasOwnProperty("maxLength")) {
      const maxLength = searchCriteriaSpecification.value[key].maxLength;
      // 文字列の長さチェック
      if (!validator.validLength(value, maxLength)) {
        errFlg = true;
        errmsg[key] = StringUtil.convertString(comMessage.COMMON000012E, [searchCriteriaSpecification.value[`${key}`].label, maxLength]);
      }
    }
  });
  return errFlg;
};

/**
 * 表示件数の変更
 */
const handleChangeDispCnt = async () => {
  await MNM0201100E09();
};

/**
 * 法人マスタ検索API呼出し
 * @param params 検索条件
 */
const callApiMNM020101 = async (params) => {
  const res = await apiCaller.httpServiceWithShield([[comConst.API_ID_MNM0201_01, params]], commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // レスポンスを格納
    responseRef.value = { ...res[0].data };
    // 検索条件保存
    MNM0201100Save().searchCriteria = { ...params };
    // 検索条件(検索結果エリア用)生成
    searchCriteriaStr.value = createSearchCriteriaStr(params);
    // 貢数を設定
    currentPage.value = params.dispPage ?? 1;
    // 検索結果一覧表示判定
    isShowTable.value = responseRef.value.allSelectCount > 0;
    // エラー文言エリアを非表示
    isShowerrorMsg.value = false;
    // DataTable再描画
    updateData();
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = res[0].data.messageErr.join("\n");
    // エラー文言エリアを表示する
    isShowerrorMsg.value = true;
  }
};

/**
 * 「初期表示」イベント
 */
const MNM0201100E01 = async () => {
  // 初期表示開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));
  // 検索条件設定
  // 保存済検索条件が存在しない場合、初期条件を設定
  if (!cameBackFlg) {
    searchCriteria.value = {
      ...searchCriteria.value,
      prefCode: selectedPrefCode.value,
      upldBizReportRequest: getCheckedStr(upldBizReportRequestTypes.value),
      fiscalYearEnd: selectedFiscalYearEnd.value,
      closed: getCheckedStr(closedTypes.value),
      limitNumber: selectedCnt.value
    };

  } else {
    // 保存済検索条件が存在する場合、画面項目を設定
    searchCriteria.value = { ...MNM0201100Save().searchCriteria };
    selectedPrefCode.value = searchCriteria.value.prefCode;
    selectedFiscalYearEnd.value = searchCriteria.value.fiscalYearEnd;
    selectedCnt.value = searchCriteria.value.limitNumber;
    changeCheckState(searchCriteria.value.upldBizReportRequest, upldBizReportRequestTypes.value);
    changeCheckState(searchCriteria.value.closed, closedTypes.value);
  }
  // 法人マスタ検索API呼出し
  await callApiMNM020101({ ...searchCriteria.value });

  // 初期表示終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * 「検索」ボタンクリック
 */
const MNM0201100E03 = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E03Name]));

  // エラー文言エリアを非表示
  isShowerrorMsg.value = false

  // 検索条件設定
  searchCriteria.value = {
    ...searchCriteria.value,
    prefCode: selectedPrefCode.value,
    upldBizReportRequest: getCheckedStr(upldBizReportRequestTypes.value),
    fiscalYearEnd: selectedFiscalYearEnd.value,
    closed: getCheckedStr(closedTypes.value),
    limitNumber: selectedCnt.value
  };
  // 入力チェック
  const ret = await checkInput({ ...searchCriteria.value });
  if (ret) {
    return;
  }
  isShowTable.value = false;
  // 法人マスタ検索API呼出し
  await callApiMNM020101({ ...searchCriteria.value, dispPage: 1 });

  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E03Name]));
};

/**
 * 「法人情報 新規登録」ボタンクリック
 */
const MNM0201100E04 = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E04Name]));
  router.push({ name: comConst.MNM0201200 });
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E04Name]));
};

/**
 * 「法人情報ダウンロードボタン」ボタンクリック
 */
const MNM0201100E05 = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E05Name]));

  let param = {};
  param.corporationIdList = responseRef.value.corporationIdList;
  // ユーザ種別が都道府県の場合、都道府県番号を設定
  if (commonInfo().userType === enumUserType.PREF_STAFF.val) {
    param.prefCode = commonInfo().prefCode;
  }
  // 法人情報CSVダウンロードAPI呼出し
  const reqParam = [
    [
      comConst.API_ID_MNM0201_07,
      param,
      null,
      comProperty.RESPONSE_TYPE_BLOB,
      0,
    ],
  ];
  const res = await apiCaller.httpServiceWithShield(reqParam, commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].headers.resultcode === comConst.API_RESULT_CODE_SUCCESS) {
    // ファイル名作成
    let todayYMD = ComDate.formatDateYMD(new Date()).replaceAll("/", "");
    const fileName = StringUtil.convertString(comProperty.FILE_NAME_MNMF201, [todayYMD]);
    // CSVファイルダウンロード
    ComFileDownload.download(res[0].data, res[0].headers, fileName);;
  } else {
    // エラーメッセージリストをエラー文言エリアに表示する
    errorMsg.value = ComFileDownload.getErrMessages(res[0].headers);
    // エラー文言エリアを表示する
    isShowerrorMsg.value = true;
  }

  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E05Name]));
};

/**
 * 検索結果一覧の各「詳細表示」ボタンクリック
 */
