  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E06Name]));
  // 法人IDを設定
  targetCorp().corporationId = corporationId;
  // 都道府県番号を設定
  targetCorp().prefCode = prefCodeList.value.find(obj => obj.dispname === prefName)?.val ?? "";
  // 都道府県名を設定
  targetCorp().prefName = prefName;
  // 法人情報登録・照会画面ヘ遷移
  router.push({ name: comConst.MNM0201200 });
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E06Name]));
};

