  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E07Name]));
  // 法人マスタ検索API呼出し
  await callApiMNM020101({ ...MNM0201100Save().searchCriteria, dispPage: currentPage.value - 1 });
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E07Name]));
};

