*/
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.MNM0201100;
  // 遷移先から戻ってきた場合
  if (route.params?.cameBackFlg === comConst.CAME_BACK_FLG_RETURN) {
    cameBackFlg = true;
  } else {
    // 画面内保持データをクリア
    MNM0201100Save().$reset();
  }
  // ユーザ種別が都道府県の場合、都道府県情報以外の法人情報をクリア
  if (commonInfo().userType === enumUserType.PREF_STAFF.val) {
    Object.keys(targetCorp().$state).forEach(key => {
      if (key !== 'prefCode' && key !== 'prefName') {
        targetCorp().$state[key] = "";
      }
    });
  } else {
    // ユーザ種別が都道府県以外の場合、対象の法人情報を全てクリア
    targetCorp().$reset();
  }
  // DataTable初期化
  initializeDataTable();
  // 初期表示
  await MNM0201100E01();
