/**
 * 入力チェック
 * @type {boolean}　true：チェックOK、false：チェックNG
 */
const checkInput = async () => {
  let errFlg = false; // true：エラーあり

  // 全項目のエラーメッセージを削除
  itemErrorMessages.value = {};

  // 医療法人整理番号 最大桁数
  const medicCorpRefNumMaxLen = 255;
  // 医療法人名称 最大桁数
  const corporationNameMaxLen = 80;

  // 桁数チェック
  if(selMedicCorpRefNumber.value && selMedicCorpRefNumber.value.length > medicCorpRefNumMaxLen){
    itemErrorMessages.value = {...itemErrorMessages.value, medicCorpRefNumber: StringUtil.convertString(comMessage.COMMON000012E, ["医療法人整理番号", medicCorpRefNumMaxLen])};
  }
  if(selCorporationName.value && selCorporationName.value.length > corporationNameMaxLen){
    itemErrorMessages.value = {...itemErrorMessages.value, corporationName: StringUtil.convertString(comMessage.COMMON000012E, ["医療法人名称", corporationNameMaxLen])};
  }

  // 日付フォーマットチェック YYYY-MM-DD
  const regex = /^([0-9]{4})-(0[1-9]|1[0-2])-([0-2][0-9]|3[01])$/;
  let errMsgNotificationDatetime = [];
  let errMsgApprovalDatetime = [];
  if (selNotificationDatetimeStart.value && !regex.test(selNotificationDatetimeStart.value)) {
    await errMsgNotificationDatetime.push(StringUtil.convertString(comMessage.COMMON000009E, ["届出年月日（開始）"]));
  }
  if (selNotificationDatetimeEnd.value && !regex.test(selNotificationDatetimeEnd.value)) {
    await errMsgNotificationDatetime.push(StringUtil.convertString(comMessage.COMMON000009E, ["届出年月日（終了）"]));
  }
  if (selApprovalDatetimeStart.value && !regex.test(selApprovalDatetimeStart.value)) {
    await errMsgApprovalDatetime.push(StringUtil.convertString(comMessage.COMMON000009E, ["承認年月日（開始）"]));
  }
  if (selApprovalDatetimeEnd.value && !regex.test(selApprovalDatetimeEnd.value)) {
    await errMsgApprovalDatetime.push(StringUtil.convertString(comMessage.COMMON000009E, ["承認年月日（終了）"]));
  }

  if(errMsgNotificationDatetime.length > 0){
    itemErrorMessages.value = {...itemErrorMessages.value, notificationDatetime: errMsgNotificationDatetime};
  }
  if(errMsgApprovalDatetime.length > 0){
    itemErrorMessages.value = {...itemErrorMessages.value, approvalDatetime: errMsgApprovalDatetime};
  }

  errFlg = (Object.keys(itemErrorMessages.value).length > 0);

  return !errFlg;
};

