 */
const MNM0101100E01 = async () => {
  // ローディングの表示
  loadingModal.isshow(true);

  // 一度ログアウトされた場合、storeの中身をクリア
  if(MNM0101100Save().currentLoginId !== commonInfo().userId){
    Object.keys(MNM0101100Save()).forEach(key=>MNM0101100Save()[key] = "");
    MNM0101100Save().currentLoginId = commonInfo().userId;
  }

  // 各メッセージを初期化
  messageError.value = [];
  itemErrorMessages.value = {};
  messageInfo.value = [];

  // 検索結果の選択チェックボックスをクリア
