  const isFromSearchBtn = breadcrumbList.length === 0;
  // パンくずリストによる別画面からの遷移
  const isFromBreadCrumb = (route.params?.cameBackFlg === comConst.CAME_BACK_FLG_RETURN) ;
  // トップ画面(UTL0101100)から遷移
  const isFromTop = breadcrumbList.length > 0 && breadcrumbList[breadcrumbList.length-1].pageId === comConst.UTL0101100;

  let paramPrefCode = searchCodeAll;
  if(isFromBreadCrumb){
    console.log("パンくずリストによる別画面からの遷移 ");
    if (commonInfo().userType === enumUserType.PREF_STAFF.val){
      paramPrefCode = MNM0101100Save().prefCode ? MNM0101100Save().prefCode : paramPrefCode;
    }
    await Object.keys(notificationInfo).forEach((key) => notificationInfo[key] = MNM0101100Save()[key]);
    notificationInfo.prefCode = paramPrefCode; //都道府県
    changeCheckState(MNM0101100Save().notificationStatus, checkBoxStatuses);//状態
    changeCheckState(MNM0101100Save().manageInfoStatus, checkBoxMngInfoStatuses); // 経営情報 届出状況
    changeCheckState(MNM0101100Save().notificationMethod, checkBoxMethods); //届出方法
  }else if(isFromTop){
    console.log("トップ画面から遷移");
    if (commonInfo().userType === enumUserType.PREF_STAFF.val){
      paramPrefCode = MNM0101100Save().prefCode ? MNM0101100Save().prefCode : commonInfo().prefCode;
