// 「実行」クリックによるAPI実行成功判定フラグ
const isSuccessStatusUpdate = ref(false);
// Dialog閉じるイベント
const closeModal = async (modalReturn) => {
  // OKボタンクリック時
  if (modalReturn === 1) {
    // ローディングの表示
    loadingModal.isshow(true);
    messageError.value = [];
    if(modalEvent.value === MODAL_ID_MNM0101100E09){
      // 検索結果CSVダウンロードAPI　呼び出し
      const res = await callApiMNM010106(getSavedApiParam());
      // 結果コードが「0:正常」の場合
      if (res[0].headers.resultcode === comConst.API_RESULT_CODE_SUCCESS) {
        // ファイル名作成
        let todayYM = ComDate.getTodayYM().replace("/", "");
        const fileName = todayYM + "_届出状況一覧CSVファイル.csv";
        // 正常時：ダウンロード
        ComFileDownload.download(res[0].data, res[0].headers, fileName);
      }else{
        // エラーメッセージリストをエラー文言エリアに表示する
        messageError.value = ComFileDownload.getErrMessages(res[0].headers);
      }
      // ローディングの非表示
      loadingModal.isshow(false);
    }else if(modalEvent.value === MODAL_ID_MNM0101100E10){
      // 操作アクション取得
      const selectedActionType = selectiveActionTypes.value.filter((obj)=>obj.val === actionType.value)[0];
      // CSVファイルダウンロード実行用のパラメータ
      const corporationIdList = [];
      const fiscalYearList = [];

      // 操作実行中のエラー一覧
      let operateErrMessages = [];
      isSuccessStatusUpdate.value = false;
      checkedRowIndexes.value.forEach((checkedRowId)=>{
        let errMsgs = [];
        // チェックが入った検索結果の行からデータを取得
        const result = searchResult.value.filter(obj=>(obj.corporationId + obj.fiscalYear) === checkedRowId)[0];
        // 操作：承認
        if(selectedActionType.val === "1"){
          errMsgs = changeApprWaitStatus(comConst.API_ID_ENT0101_01, result);
        // 操作：差戻し
        }else if(selectedActionType.val === "2"){
          errMsgs = changeApprWaitStatus(comConst.API_ID_ENT0101_02, result);
        // 操作：承認取消
        }else if(selectedActionType.val === "4"){
          errMsgs = changeApprStatus(comConst.API_ID_ENT0101_03, result);
        // 操作：取戻し
        }else if(selectedActionType.val === "3"){
          errMsgs = changeApprStatusAndDocument(comConst.API_ID_ENT0101_05, result);
        // 操作：CSVファイルダウンロード
        }else if(selectedActionType.val === "5" && !isDownloadCsvProcessing.value){
          corporationIdList.push(result.corporationId);
          fiscalYearList.push(result.fiscalYear);
        }
        operateErrMessages = operateErrMessages.concat(errMsgs);
      });
      if(["1","2","3","4"].includes(selectedActionType.val)){
        const errMsgArry = (await Promise.all(operateErrMessages)).flat();
        if(errMsgArry.length > 0){
          // エラー表示エリアにエラー表示
          messageError.value = errMsgArry;
        }
        // 1件でも処理が成功した場合、検索結果の更新を実行
        if(isSuccessStatusUpdate.value){
          // ステータスリストエリア更新
          await updateStatusListArea();
          // 検索結果更新
          await callApiMNM010102(getSavedApiParam());
        }
      }else if(selectedActionType.val === "5" && !isDownloadCsvProcessing.value){
        const param = {
          corporationIdList: corporationIdList,
          fiscalYearList: fiscalYearList,
          fileType: comEnum.EnumFILE_TYPE.FT_NOTICE_SEARCH_DL.val,
          operationId: comEnum.EnumOPE_ID.CSV_BIZ_REPORT_ETC_MGT_INFO_ETC_DL.val,
          screenId: commonInfo().screenId,
        }
         // 操作：CSVファイルダウンロード 実行
        await callApiMNM010108(param);
      }
    }
  }
  // ローディングの非表示
  loadingModal.isshow(false);
};

