/** ダウンロード監視 */
const monitorDownload = async (fileOpeMngSeq) => {
  // ダウンロードドロップダウンメニューを押下不可
  isDownloadCsvProcessing.value = true;
  // 非同期バッチ監視API呼び出しパラメータ設定
  const reqParam = [
    [
      comConst.API_ID_ENT0201_04, // パスパラメータ
      // リクエストパラメータ
      { fileOperationManageSeq: fileOpeMngSeq },
    ],
  ];
  // 排他制御(1秒ごと繰り返し)
  const polling = () => {
    let timerId = setTimeout(async () => {
      let finishFlg = await singleMonitorDownload(reqParam, fileOpeMngSeq);
      if (finishFlg) {
        clearTimeout(timerId);
      } else {
        polling(); // 再帰呼び出し
      }
    }, comProperty.POLLING_INTERVAL);
  };
  polling();
};

/** ダウンロード監視(1試行分) */
const singleMonitorDownload = async (reqParam, fileOpeMngSeq) => {
  let finishFlg = true;
  // 非同期バッチ監視API呼び出し
  const res = await apiCaller.httpService(reqParam, commonInfo().screenId);
  console.log("ダウンロード監視中...");

  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // 非同期バッチ監視APIの結果コードが正常の場合
    if (
      [comEnum.EnumFILE_OPERATION_MANAGE_STATUS.UNTREATED.val, comEnum.EnumFILE_OPERATION_MANAGE_STATUS.PROCESSING.val].includes(res[0].data.status)
    ) {
      // ステータスが未処理または処理中の場合
      finishFlg = false;
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.COMPLETED.val) {
      // ステータスが完了の場合
      finishFlg = true;
      // ダウンロードAPI呼び出しパラメータ設定
      const dlReqParam = [
        [
          comConst.API_ID_ENT0201_01, // パスパラメータ
          // リクエストパラメータ
          {
            fileOperationManageSeq: fileOpeMngSeq,
          },
          null,
          "blob",
          0,
        ],
      ];
      // ダウンロードAPI呼び出し
      const dlRes = await apiCaller.httpService(dlReqParam, commonInfo().screenId);

      if (dlRes[0].headers.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
        // 結果コード=正常の場合
        ComFileDownload.download(dlRes[0].data, dlRes[0].headers, null);
        // ダウンロード完了メッセージ設定
        messageInfo.value = [StringUtil.convertString(comMessage.COMMON000000I, ["ダウンロード"])];
      } else {
        // 結果コード=正常以外の場合
        // ダウンロード失敗メッセージ設定
        messageError.value = [StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"])];
      }
      // ダウンロードドロップダウンメニューの押下不可を解除
      isDownloadCsvProcessing.value = false;
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.ERR.val) {
      // ステータスがエラーの場合
      finishFlg = true;
      // ダウンロードドロップダウンメニューの押下不可を解除
      isDownloadCsvProcessing.value = false;
      // ダウンロード失敗メッセージ設定
      messageError.value = [StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"])];
    }
  } else {
    // 処理無し
  }
  return finishFlg;
};

