/** 
* 状態：承認待ちステータスの届出の変更
* @param apiId 実行するAPI ID
* @param searchResult 検索条件
*/
const changeApprWaitStatus = async (apiId, searchResult) => {
  let errMsges = [];
 // 状態が承認待ちではない
 if(searchResult.notificationStatus !== enumNoticeStatus.PREF_APPR_WAIT.val){
    //エラーメッセージ表示
    const selectedMedicCorpInfo = searchResult.prefName
       + " " + searchResult.medicCorpRefNumber
       + " " + searchResult.corporationName;
    errMsges.push(selectedMedicCorpInfo + "：" + StringUtil.convertString(comMessage.COMMON100014E)); 
    
  // 状態が承認待ち
  }else if(searchResult.notificationStatus === enumNoticeStatus.PREF_APPR_WAIT.val){
    // 指定した届出の状態に更新
    const prefecture = prefList.value.filter((prefObj)=>prefObj.dispname === searchResult.prefName)[0];
    const param = {
      corporationId: searchResult.corporationId,
      fiscalYear: searchResult.fiscalYear,
      prefCode: prefecture.val,
      notificationType: searchResult.notificationType,
      screenId: commonInfo().screenId,
    };
    const resData = await callApiChangeStatus(apiId, param);
    // 結果コードが「1:異常」の場合
    if (resData.resultCode === comConst.API_RESULT_CODE_ERROR) {
      errMsges = await Promise.all(resData.messageErr);
    }else{
      let tmpMessages = await Promise.all(resData.messageInfo);
      messageInfo.value = tmpMessages.concat(messageInfo.value);
      isSuccessStatusUpdate.value = true;
    }
  }
  // エラー表示エリアにエラー表示
  return errMsges;
}

