/**
 * 届出検索APIから取得した選択肢を画面項目に設定
 * @param resData 
 */
const setInputSelectBox = (resData)=>{
   // 都道府県の選択肢を設定
   const resPrefList = resData.prefList;
   let tmpPrefList = [{ dispname: "全国", val: searchCodeAll }];
   Object.keys(resPrefList).forEach((key)=>tmpPrefList.push({dispname: resPrefList[key], val: key}));
   prefList.value = tmpPrefList.sort((a, b) => a.val - b.val);
   // 市区町村の選択肢を設定
   let tmpCityList = [{ dispname: "すべて", val: searchCodeAll }];
   cityMapList.value = resData.cityList;
   if(notificationInfo.prefCode && notificationInfo.prefCode !== searchCodeAll){
    const resCityList = resData.cityList[notificationInfo.prefCode];
    Object.keys(resCityList).forEach((key)=>tmpCityList.push({dispname: resCityList[key], val: key}));
   }
   cityList.value = tmpCityList.sort((a, b) => a.val - b.val);
   // 会計年度 の選択肢を設定
   const resFiscalYearList = resData.fiscalYearList;
   let tmpYearList = [{ dispname: "すべて", val: searchCodeAll }];
   for(const fiscalYear of resFiscalYearList){
    tmpYearList.push({ dispname: fiscalYear + "年度", val: fiscalYear });
   }
   yearList.value = tmpYearList;
}

/**
 * チェックボックスのチェック有の選択値の配列を返却
 * @param array チェックボックスの配列
 */
const getCheckedArray = (array) => array.filter(obj => obj.checked).map(obj => obj.val);

/**
 * チェックボックスの表示用文言をカンマ区切りの文字列で返却
 * @param array チェックボックスの配列
 */
const getCheckedDispNames = (array) => array.filter(obj => obj.checked).map(obj => obj.dispname).join(",");

/**
 * チェック状態切替
 * @param value 保存済検索条件
 * @param refArray チェックボックスのref
 */
const changeCheckState = (valArray, refArray) => {
  for (let obj of refArray) {
    if (valArray && valArray.includes(obj.val)) {
      obj.checked = true;
    }else{
      obj.checked = false;
    }
  }
};

/**
 * 検索条件の表示文言設定
 */
const setSearchConditionText = () => {
  let searchText = "";
  const delimiter = " ";
  searchText += selPref.value ? selPref.options[selPref.selectedIndex].text + delimiter: ""; // 都道府県
  searchText += selCity.value ? selCity.options[selCity.selectedIndex].text + delimiter : ""; // 市区町村
  searchText += selFiscalYear.value ? "会計年度：" + selFiscalYear.options[selFiscalYear.selectedIndex].text + delimiter : ""; // 会計年度
  searchText += getCheckedArray(checkBoxStatuses).length > 0 ? "状態：" + getCheckedDispNames(checkBoxStatuses) + delimiter : ""; //状態
  searchText += selMedicCorpRefNumber.value ? "医療法人整理番号：" + selMedicCorpRefNumber.value + delimiter : ""; // 医療法人整理番号
  searchText += selCorporationName.value ? "医療法人名称：" + selCorporationName.value + delimiter : ""; // 医療法人名称
  searchText += selFiscalMonth.value ? "会計月：" + selFiscalMonth.options[selFiscalMonth.selectedIndex].text + delimiter : ""; // 会計月
  searchText += selNotificationType.value ? "届出タイプ：" + selNotificationType.options[selNotificationType.selectedIndex].text + delimiter : ""; // 届出タイプ
  // 届出年月日
  let notificationDatetime = "";
  notificationDatetime += selNotificationDatetimeStart.value ? selNotificationDatetimeStart.value : "";
  notificationDatetime += "～";
  notificationDatetime += selNotificationDatetimeEnd.value ? selNotificationDatetimeEnd.value : "";
  if(notificationDatetime !== "～"){
    searchText += "届出年月日：" + notificationDatetime + delimiter;
  }
  //承認年月日
  let approvalDatetime = "";
  approvalDatetime += selApprovalDatetimeStart.value ? selApprovalDatetimeStart.value  : "";
  approvalDatetime += "～";
  approvalDatetime += selApprovalDatetimeEnd.value  ? selApprovalDatetimeStart.value : "";
  if(approvalDatetime !== "～"){
    searchText += "承認年月日：" + approvalDatetime + delimiter;
  }
  // 届出方法
  searchText += getCheckedArray(checkBoxMethods).length > 0 ? "届出方法：" + getCheckedDispNames(checkBoxMethods) + delimiter : ""; 
  // 経営情報 届出状況
  searchText += getCheckedArray(checkBoxMngInfoStatuses).length > 0 ? "経営情報 届出状況：" + getCheckedDispNames(checkBoxMngInfoStatuses) : ""; 

  searchCriteriaStr.value = searchText;
}

/**
 * ステータスリストエリア の 件数を更新
 */
const updateStatusListArea = async () =>{
  let param = {}; 
  if (commonInfo().userType === enumUserType.PREF_STAFF.val){
    param.prefCode = commonInfo().prefCode;
    notificationInfo.prefCode = commonInfo().prefCode;
  }

  for (let i = 0; i < statusList.length; i++) {
    // 届出状態の検索パラメータ設定
    param.notificationStatus = statusList[i].statusParams;

    // 届出検索APIの呼び出し
    const reqParam = [
      [
        comConst.API_ID_MNM0101_02, param,
      ],
    ];

    const res = await apiCaller.httpService(reqParam, commonInfo().screenId);
    // 結果コードが「0:正常」の場合
    if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
      Object.assign(statusList[i], {...statusList[i], count: res[0].data.dataCount});
      setInputSelectBox(res[0].data);
    }else{
      searchResultTotalCount.value = 0;
      showSearchResult.value = false;
      searchResult.value = {};
      // エラー表示エリアにエラーメッセージ出力
      messageError.value = res[0].data.messageErr;
    }
    
  }
}

/**
 * 全選択/解除チェックボックスのチェック内容更新
 */
const changeDisplayAllCheckBox = (isSelectAllChecked) =>{
  if (isSelectAllChecked) {
    // 表示中の全検索結果の行番号を取得
    let tmpCheckedRowIndexes = checkedRowIndexes.value;
    searchResult.value.forEach(obj=>tmpCheckedRowIndexes.push(obj.corporationId+obj.fiscalYear));
    checkedRowIndexes.value = tmpCheckedRowIndexes;
    if(!checkedSelectAllCheckPages.value.includes(currentPage.value)){
      let tmp = checkedSelectAllCheckPages.value;
      tmp.push(currentPage.value);
      checkedSelectAllCheckPages.value = tmp;
    }
  }else{
    // 表示中の全検索結果の行番号をチェック対象から除外
    let tmpCheckedRowIndexes = [];
    searchResult.value.forEach(obj=>tmpCheckedRowIndexes.push(obj.corporationId+obj.fiscalYear));
    checkedRowIndexes.value = checkedRowIndexes.value.filter(rowIndex => !tmpCheckedRowIndexes.includes(rowIndex));
    checkedSelectAllCheckPages.value = checkedSelectAllCheckPages.value.filter(pageNum => pageNum !== currentPage.value);
  }
  
  // テーブル上の表記に反映
  const rows = table.rows({ 'search' : 'applied'}).nodes();
  rows.each((row) => {
    const checkbox = row.querySelector("." + ROW_QUERY_CHECKBOX);
    if (checkbox) {
      checkbox.checked = isSelectAllChecked;
    }
  });
}

