});


/**
 * 頁遷移時の選択状態の保持
 */
const restoreSelection = () => {
  const checkUser = document.querySelectorAll('.row-checkbox');
  checkUser.forEach(checkbox => {
    const userId = checkbox.getAttribute('data-userid').trim();
    if(selectUserId.value.includes(userId)) {
      checkbox.checked = true;
    } else {
      checkbox.checked = false;
    }
  });
}

/**
 * 全選択・全解除のチェック機能
 */
 const addSelectAllListener = (table) => {
  const selectAllCheckbox = document.getElementById('selectAll');
  if (selectAllCheckbox) {
    selectAllCheckbox.addEventListener('click', function() {
      const rows = table.rows({ 'search': 'applied'}).nodes();
      const isChecked = selectAllCheckbox.checked;
      rows.each(function(row) {
        const checkbox = row.querySelector('.row-checkbox');
        if(checkbox) {
          checkbox.checked = isChecked;
          const userId = checkbox.getAttribute('data-userid').trim();
          if(isChecked) {
            if (!selectUserId.value.includes(userId)) {
              selectUserId.value.push(userId);
            }
          } else {
            selectUserId.value = selectUserId.value.filter(id => id !== userId);
          }
        }
      });
    });
  }
}

/**
 * 各行のチェックボックスの管理
 */
const manageRowCheckbox = (tableElement) => {
  tableElement.addEventListener('change', function(event) {
    if(event.target.classList.contains('row-checkbox')) {
      const userId = event.target.getAttribute('data-userid').trim();
      toggleSelection(userId);

      const selectAllCheckbox = document.getElementById('selectAll');
      if (selectAllCheckbox) {
        const allChecked = Array.from(tableElement.querySelectorAll('.row-checkbox')).every(checkbox => checkbox.checked);
        const noneChecked = Array.from(tableElement.querySelectorAll('.row-checkbox')).every(checkbox => !checkbox.checked);

        if(allChecked) {
          selectAllCheckbox.checked = true;
          selectAllCheckbox.indeterminate = false;
        } else if (noneChecked) {
          selectAllCheckbox.checked = false;
          selectAllCheckbox.indeterminate = false;
        } else {
          selectAllCheckbox.checked = false;
          selectAllCheckbox.indeterminate = true;
        }
      }
    }
  });
};

/**
 * 頁総数
 * @type {int}
 */
 const totalPages = computed(() => {
  // API戻り値の検索結果件数を表示件数で除算（切り上げ）
  let result = (searchResultTotalNumbers.value ?? 0) / (selectedCnt.value ?? 0);
  return Math.ceil(result);
});
