/** 
 * 検索条件（検索結果エリア用）生成
 * @param params 検索条件
 */
const create = (params, userTypemapping, validInvalidMapping, keysExclude, prefCodeInfoMap) => {
  let array = [];

  for(const key in params) {
    if (key in params && !keysExclude.includes(key)) {
      const value = params[key];
      if (Array.isArray(value)) {
        value.forEach(item => {
          if(item) {
            if(key === 'userType') {
              array.push(userTypemapping[item] || item);
            } else if(key === 'validInvalid') {
              array.push(validInvalidMapping[item] || item);
            } else if(key === 'prefNo') {
              array.push(prefCodeInfoMap[item] || item);
            } else {
              array.push(item);
            }
          }
        });
      } else {
        if (value) {
          if (key === 'prefNo') {
            array.push(prefCodeInfoMap[value] || value);
          } else {
            array.push(value);
          }
        }
      }
    }
  }
  return array.join("、");
};

/**
 * チェックボックスの選択値をカンマ区切りに変換
 * @param array チェックボックスの配列
 */
 const getCheckedArray = (array) => array.filter(obj => obj.checked).map(obj => obj.val);

/**
 * 入力チェック
 * @param searchConditions 検索条件
 */
 async function checkInput(searchConditions) {
  let errFlg = false;
  let errmsg = {};

   // 文字数チェックの対象となる検索項目を一覧
   let array = {
    medicCorpRefNum: searchConditions.medicCorpRefNum,
    corpName: searchConditions.corpName,
    userId: searchConditions.userId
  };

  for(const [key, value] of Object.entries(array)) {
    // 桁数チェック
    if (key === 'medicCorpRefNum') {
        if(!validator.validLength(value, 255)) {
          errFlg = true;
          errmsg[key] = StringUtil.convertString(comMessage.COMMON000011E, [searchConditionsLabel['医療法人整理番号'], array.medicCorpRefNum]);
        }
      } else if (key === 'corpName') {
        if(!validator.validLength(value, 255)) {
          errFlg = true;
          errmsg[key] = StringUtil.convertString(comMessage.COMMON000011E, [searchConditionsLabel['医療法人名'], array.corpName]);
        }
      }else if (key === 'userId') {
        if(!validator.validLength(value, 20)) {
          errFlg = true;
          errmsg[key] = StringUtil.convertString(comMessage.COMMON000011E, ['ユーザID'], array.userId);
        }
      }

    // 文字種別チェック
    if (key === 'userId') {
      if (!validator.IsHalfwidthAlphanumeric(value)) {
        errFlg = true;
        errmsg[key] = StringUtil.convertString(comMessage.COMMON000013E, ['ユーザID']);
      }
    }  else {
      if (!isHalfString(value) && !isFullString(value)) {
        errFlg = true;
        errmsg[key] = StringUtil.convertString(comMessage.MNM030110001E, [searchConditionsLabel['${key}Label']]);
      }
    }
  }

  // エラーメッセージの表示やその他処理
  if (errFlg) {
    errMessages.value = errmsg;
    console.error(errmsg);
  } else {
    errMessages.value = {};
  }

  return errFlg;

};

// 全角半角文字チェック
function isHalfString(value) {
  const regex = /^[\x20-\x7E]*$/;
  return regex.test(value ?? '');
}

function isFullString(value) {
  const regex = /^[^\x20-\x7E]*$/;
  return regex.test(value ?? '');
}

/**
 * ユーザ検索API呼出し
 * @param params 検索条件
 */
 const callApiMNM030101 = async (params) => {
  const res = await apiCaller.httpService([[comConst.API_ID_MNM0301_01, params]], commonInfo().screenId);

  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // レスポンスを格納
    responseResult.value = { ...res[0].data };
    // 検索条件保存
    MNM0301100Save().searchConditions = { ...params };
    // 検索条件(検索結果エリア用)生成
    searchCriteriaStr.value = create(params, userTypemapping, validInvalidMapping, keysExclude, responseResult.value.prefCodeInfoMap);
    // 貢数を設定
    currentPage.value = params.dispPage ?? 1;
    // 検索結果一覧表示判定
    isShowTable.value = responseResult.value.dataCount > 0;
    // エラー文言エリアを表示する
    isShowerrorMsg.value = false;   
    // DataTable再描画
    updateData();
  } else {
    // 検索結果がない場合もisShowerrorMsgをfalseに設定（ユーザ検索APIの処理上、検索結果が0件だとエラー扱いになるので）
    isShowTable.value = false;

    // データ件数及び検索結果を空にする
    responseResult.value.dataCount = 0;
    responseResult.value.searchResult = []
    // エラーメッセージリストをエラー文言エリアに表示する
    messageErr.value = res[0].data.messageErr.join("\n");
    // エラー文言エリアを表示する
    isShowerrorMsg.value = true;
  }
 };

/**
 * 「初期表示イベント」 
 */
 const MNM0301100E01 = async() => {
  // ローディングの表示
  LoadingModal.isshow(true);

  // 検索条件の設定
  // 検索条件が保存されていない場合は初期値を設定する
  if (!cameBackFlg) {
    // ログインユーザごとに設定した初期値を渡す
    // ログインユーザのユーザ種別によって検索条件の初期値を変える
  // 都道府県ユーザの場合
  if([enumUserType.PREF_STAFF.val].includes(commonInfo().userType)){
    searchConditions.value = {
      ...searchConditions.value,
      // 検索条件のユーザ種別に「医療法人」のみ設定
      userType: [enumUserType.MEDIC_CORP.val],
      // 検索条件の都道府県番号に ログインユーザが所属する都道府県番号の値を設定
      prefNo: commonInfo().prefCode, 
      // 有効/無効
      validInvalid: [enumLoginUnavailableType.AVAILABLE.val],
      // 表示件数
      limitNumber: selectedCnt.value,
      // 表示頁数
      dispPage: 1,
    };
    //　都道府県ユーザ以外の場合
    } else {
      searchConditions.value = {
        ...searchConditions.value,
        // 検索条件の都道府県番号に 全国コード（00）を設定
        prefNo: comConst.PREF_ALL_CD,
        // 有効/無効
        validInvalid: [enumLoginUnavailableType.AVAILABLE.val],
        // 表示件数
        limitNumber: comProperty.DISPLAY_COUNT_DEFAULT_VALUE,
        // 表示頁数
        dispPage: 1,
      };
    }
  } else {
    // 保存済検索条件が存在する場合、画面項目を設定
    searchConditions.value = {
      ...MNM0301100Save().searchConditions
    };
    
  }

  // ユーザ検索API呼び出し
  await callApiMNM030101({ ...searchConditions.value});

  // ローディングの非表示
  LoadingModal.isshow(false);
  
 };

/**
 * 「検索」ボタンクリックイベント
 */
 const MNM0301100E04 = async () =>{
  try{ 

  // ローディングの表示
  LoadingModal.isshow(true);

  // 検索条件の設定
  searchConditions.value = {
      ...searchConditions.value,
      // ユーザ種別
      userType: getCheckedArray(userCheck.value),      
      // 都道府県番号
      prefNo: selectedPrefCode.value,
      // 医療法人整理番号
      medicCorpRefNum:medicCorpRefNum.value, 
      // 医療法人名
      corpName: corpName.value, 
      // ユーザID
      userId: userId.value,
      // 有効/無効
      validInvalid: getCheckedArray(unavailablCheck.value), 
      // 表示件数
      limitNumber: selectedCnt.value,
    };

  // 入力チェック
  const ret = await checkInput({ ...searchConditions.value});
  if (ret) {
    return;
  }

  isShowTable.value = false;

  // ユーザ検索API呼び出し
  await callApiMNM030101({ ...searchConditions.value, dispPage: 1});

  // DataTableの再描画
  updateData();
  if(table) {
    // 列の幅を調整して再描画
    table.columns.adjust().draw();
  }
  } finally {

  // ローディングの非表示
  LoadingModal.isshow(false);

  }
 };

/*
*  チェックボックスの選択チェック
*/
async function checkUserIdSeclection(userId) {
  let errorMessage = "";

  if(userId.length === 0) {
    errorMessage = StringUtil.convertString(comMessage.MNM030110000E);    
  } 
  return errorMessage;
};



 /**
 * 「実行」ボタンクリックイベント
 */
 const MNM0301100E10 = async () => {

  // ローディングの表示
  LoadingModal.isshow(true);

  
 // 選択されたユーザIDの配列作成
 const userId = selectUserId.value;

 // チェックボックスが選択されているかのチェック
 const ret = await checkUserIdSeclection(userId);
 if(ret) {
  errCheckmsg.value = ret;
  // ローディングの非表示
  LoadingModal.isshow(false);
  return;
 } 

 errCheckmsg.value = "";

  // 選択された操作を渡す
  const clickOpe = selectOpration.value;

  const screenId = commonInfo().screenId;

  // 選択された操作によって、呼び出すAPIを変える

  // 削除が選択された場合
  if (clickOpe === "3") {

    // ユーザ情報削除APIを呼び出し
    const delParam = [
      [comConst.API_ID_MNM0301_03, {
        "userId": userId,
        "screenId": screenId,
      }],
    ]; 
    const delres = await apiCaller.httpService(delParam, commonInfo().screenId);

    // ユーザ削除がうまくいった場合、再度ユーザ検索を行う
    if (delres[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {

      // 保存された検索条件でユーザ検索APIを呼び出す
      await callApiMNM030101({ ...MNM0301100Save().searchConditions });

      // 保持された選択チェックの情報を削除
      selectUserId.value = [];
      // 全選択のチェックONを解除
      resetSelectAllCheckbox();
      
      // ローディングの非表示
      LoadingModal.isshow(false);      

      // ユーザ削除がうまくいかなかった場合
    } else {
      // ローディングの非表示
      LoadingModal.isshow(false);
      // エラーメッセージリストをダイアログに表示する
      messageErr.value = delres[0].data.messageErr.join("\n");
        // エラー文言エリアを表示する
      isShowerrorMsg.value = true;

    }

    // 削除以外が選択された場合
  } else {

    // ユーザ情報更新APIの呼び出し
    const upParam = [
      [comConst.API_ID_MNM0301_04, {
        "userIdList": userId,
        "updatePgmId": screenId,
        "clickOpe": clickOpe,
      }],
    ];
    const upres = await apiCaller.httpService(upParam, commonInfo().screenId);

    // ユーザ情報更新がうまくいった場合、再度ユーザ検索を行う
    if (upres[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
      
      // 保存された検索条件でユーザ検索APIを呼び出す
      await callApiMNM030101({ ...MNM0301100Save().searchConditions });

      // 保持された選択チェックの情報を削除
      selectUserId.value = [];
      // 全選択のチェックONを解除
      resetSelectAllCheckbox();
      
      // ローディングの非表示
      LoadingModal.isshow(false);   

      // ユーザ情報更新が失敗した場合
    } else {
      // ローディングの非表示
      LoadingModal.isshow(false);
      // エラーメッセージリストをダイアログに表示する
      messageErr.value = upres[0].data.messageErr.join("\n");
        // エラー文言エリアを表示する
      isShowerrorMsg.value = true;

    }

  };

 }

 /**
  *  ユーザ情報新規登録 ボタンクリック
  */
const MNM0301100E11 = async () => {
   // ユーザ登録画面に都道府県マップを渡す
  MNM0301200Param().prefCodeInfoMap = prefList.value;
  // ユーザ登録画面へ遷移
  router.push({ name: comConst.MNM0301200 });
};

/**
 * 詳細ボタンクリック
 */
const MNM0301100E12 = async (userId) => {
  // ユーザ登録画面に都道府県マップを渡す
  MNM0301200Param().prefCodeInfoMap = prefList.value;
  // ユーザ登録画面にユーザIDを渡す
  MNM0301200Param().userId = userId;
  // ユーザ登録画面に遷移
  router.push({ name: comConst.MNM0301200 });
};

/**
 * 前頁表示ボタンクリック
 */
const MNM0301100E13 = async () => {
    // ユーザ検索APIを呼び出す
    await callApiMNM030101({ ...MNM0301100Save().searchConditions, dispPage: currentPage.value - 1 });
    restoreSelection();
    resetSelectAllCheckbox();
};

/**
 * 次頁表示ボタンクリック
 */
const MNM0301100E14 = async () => {
    // ユーザ検索APIを呼び出す
    await callApiMNM030101({ ...MNM0301100Save().searchConditions, dispPage: currentPage.value + 1});
    restoreSelection();
    resetSelectAllCheckbox();
};

/**
 * 表示件数の変更
 */
 const handleChangeDispCnt = async () => {
  await MNM0301100E15();
};


/**
 * 表示件数の変更
 */
const MNM0301100E15 = async () => {
  // ユーザ検索APIの呼び出し
await callApiMNM030101({ ...MNM0301100Save().searchConditions, limitNumber: selectedCnt.value, dispPage: 1 })
restoreSelection();
resetSelectAllCheckbox();
};


//////////////////////////
// ライフサイクルフック
//////////////////////////

// 画面マウント時イベント
onMounted(async () => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.MNM0301100;
  // 遷移先から戻ってきた場合
  // 遷移先から戻ってきた場合
  if (route.params?.cameBackFlg === comConst.CAME_BACK_FLG_RETURN) {
    cameBackFlg = true;
  } else {
    // 画面内保持データをクリア
    MNM0301100Save().$reset();
  }



  // DataTable初期化
  initializeDataTable();
  // 初期表示
  await MNM0301100E01();
  // パンくずリストを設定
  breadcrumbObj.value.init(commonInfo().screenId);

  // DataTable再描画
  updateData();
});

</script>

