/**
 * 画面制御
 * res: 経営情報等照会APIの戻り値
 */
const setScreen = async (res) => {
  // タブアイコン
  setIconClass(res[0].data.mngInfo.mngInfoInpSituation);
  // 編集区分
  if (
    [comEnum.EnumNOTICE_STATUS.CORP_INP_WAIT.val, comEnum.EnumNOTICE_STATUS.CORP_INP_COMP_WAIT.val, comEnum.EnumNOTICE_STATUS.REMAND.val].includes(
      targetCorp().notificationStatus
    ) &&
    [comEnum.EnumUSER_TYPE.MEDIC_CORP.val, comEnum.EnumUSER_TYPE.PROXY_INPUT_STAFF.val].includes(commonInfo().userType)
  ) {
    editClass.value = comEnum.EnumEDIT_CLASS.CORP_INP.val; // 法人入力
  } else if (
    targetCorp().notificationStatus == comEnum.EnumNOTICE_STATUS.PREF_APPR_WAIT.val &&
    commonInfo().userType == comEnum.EnumUSER_TYPE.PREF_STAFF.val
  ) {
    editClass.value = comEnum.EnumEDIT_CLASS.PREF_INP.val; // 都道府県入力
  } else {
    editClass.value = comEnum.EnumEDIT_CLASS.READ_ONLY.val; // 閲覧
  }
  // 法人入力以外の場合、入力項目非活性
  if (editClass.value != comEnum.EnumEDIT_CLASS.CORP_INP.val) {
    const inputElements = document.getElementsByTagName("input");
    for (const element of inputElements) {
      element.disabled = true;
    }
    const selectElements = document.getElementsByTagName("select");
    for (const element of selectElements) {
      element.disabled = true;
    }
  }
  // textareaの高さを自動調整
  const textareaEls = document.querySelectorAll("textarea");
  textareaEls.forEach((textareaEl) => {
    // textareaタグを全て取得
    let height = 0;
    height = textareaEl.scrollHeight == 0 ? 66 : textareaEl.scrollHeight + 10;
    // デフォルト値としてスタイル属性を付与
    textareaEl.setAttribute("style", `height: ${height}px;`);
    // inputイベントが発生するたびに関数呼び出し
    textareaEl.addEventListener("input", setTextareaHeight);
  });
  // アップロードした入力フォームのダウンロードボタン
  if (res[0].data.screenControl && res[0].data.screenControl.csvUploadFlg) {
    isCsvUploaded.value = true;
  }
  if (res[0].data.screenControl && res[0].data.screenControl.excelUploadFlg) {
    isExcelUploaded.value = true;
  }
};

