/**
 * 排他制御
 * 呼び出し元：初期表示、CSVアップロード、Excelアップロード
 */
const mutualExclusion = async (uploadingFileOpeMngSeq) => {
  // アップロード中ファイル有り
  if (uploadingFileOpeMngSeq && uploadingFileOpeMngSeq.length > 0) {
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000001I, ["事業報告書または経営情報等データのアップロード"])];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // 画面上部へ戻る
    scrollToTop();
    // アップロードドロップダウンメニューを押下不可
    isUploadProcessing.value = true;
    // 全ての入力項目を非活性
    const disabledElements = setDisabled();
    // 非同期バッチ監視API呼び出しパラメータ設定
    const reqParam = [
      [
        comConst.API_ID_ENT0201_04, // パスパラメータ
        // リクエストパラメータ
        { fileOperationManageSeq: uploadingFileOpeMngSeq[0] },
      ],
    ];
    // 排他制御(1秒ごと繰り返し)
    const polling = () => {
      let timerId = setTimeout(async () => {
        let finishFlg = await singleMutualExclusion(reqParam, disabledElements);
        if (finishFlg) {
          clearTimeout(timerId);
        } else {
          polling(); // 再帰呼び出し
        }
      }, comProperty.POLLING_INTERVAL);
    };
    polling();
  }
};

/**
 * 排他制御(1試行分)
 * 呼び出し元：初期表示、CSVアップロード、Excelアップロード
 */
const singleMutualExclusion = async (reqParam, disabledElements) => {
  let finishFlg = true;
  // 非同期バッチ監視API呼び出し
  const res = await apiCaller.httpService(reqParam, comConst.ENT0301110);

  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // 非同期バッチ監視APIの結果コードが正常の場合
    if (
      [comEnum.EnumFILE_OPERATION_MANAGE_STATUS.UNTREATED.val, comEnum.EnumFILE_OPERATION_MANAGE_STATUS.PROCESSING.val].includes(res[0].data.status)
    ) {
      // ステータスが未処理または処理中の場合
      finishFlg = false;
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.COMPLETED.val) {
      // ステータスが完了の場合
      finishFlg = true;
      // ローディングの表示
      loadingModal.isshow(true);
      // アップロードドロップダウンメニューの押下不可を解除
      isUploadProcessing.value = false;
      // 全ての入力項目を活性
      setNotDisabled(disabledElements);
      // 経営情報等照会API呼び出しパラメータ設定
      const reqParam = [
        [
          comConst.API_ID_ENT0301_39, // パスパラメータ
          // リクエストパラメータ
          {
            corporationId: targetCorp().corporationId,
            fiscalYear: targetCorp().fiscalYear,
            seq: ENT0301110Param().seq,
          },
        ],
      ];
      // 経営情報等照会API呼び出し
      const res = await apiCaller.httpService(reqParam, comConst.ENT0301110);
      if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
        // 結果コード=正常の場合
        // 画面項目設定
        await setScreenItemValues(res);
        // 入力チェックエラーをクリアして再設定
        messageErr.value = res[0].data.messageErr;
        messageWarn.value = res[0].data.messageWarn;
        inputMessageErr.value = res[0].data.messageErr;
        inputMessageWarn.value = res[0].data.messageWarn;
        // アップロード依頼メッセージを削除し、アップロード完了メッセージを表示
        messageInfo.value = [StringUtil.convertString(comMessage.COMMON000000I, ["アップロード"])];
        // 動的セグメントへの設定
        targetCorp().notificationStatus = res[0].data.notificationStatus;
        targetCorp().notificationMethod = res[0].data.notificationMethod;
        // ローディングの非表示
        loadingModal.isshow(false);
        // 画面上部へ戻る
        scrollToTop();
      } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
        // 結果コード=異常の場合
        // ローディングの非表示
        loadingModal.isshow(false);
        // アップロードドロップダウンメニューの押下不可を解除
        isUploadProcessing.value = false;
        // 全ての入力項目を活性
        setNotDisabled(disabledElements);
        // アップロード依頼メッセージを削除
        messageInfo.value = [];
        // メッセージ設定
        messageErr.value = [];
        res[0].data.messageErr.forEach((msg) => {
          messageErr.value.push(msg);
        });
        inputMessageErr.value.forEach((msg) => {
          messageErr.value.push(msg);
        });
        messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
        // 画面上部へ戻る
        scrollToTop();
      } else {
        // 処理無し
      }
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.ERR.val) {
      // ステータスがエラーの場合
      finishFlg = true;
      // ローディングの非表示
      loadingModal.isshow(false);
      // アップロードドロップダウンメニューの押下不可を解除
      isUploadProcessing.value = false;
      // 全ての入力項目を活性
      setNotDisabled(disabledElements);
      // アップロード依頼メッセージを削除
      messageInfo.value = [];
      // アップロード失敗メッセージを先頭に追加
      messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
      messageErr.value.unshift(StringUtil.convertString(comMessage.COMMON000018E, ["アップロード"]));
      messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
      // 画面上部へ戻る
      scrollToTop();
    }
  } else {
    // 処理無し
  }
  return finishFlg;
};

/**
 * 全ての入力項目を非活性にする
 */
const setDisabled = () => {
  const inputElements = document.getElementsByTagName("input");
  const disabledElements = [];
  for (const element of inputElements) {
    if (!element.disabled) {
      element.disabled = true;
      disabledElements.push(element);
    }
  }
  const selectElements = document.getElementsByTagName("select");
  for (const element of selectElements) {
    if (!element.disabled) {
      element.disabled = true;
      disabledElements.push(element);
    }
  }
  const textareaElements = document.getElementsByTagName("textarea");
  for (const element of textareaElements) {
    if (!element.disabled) {
      element.disabled = true;
      disabledElements.push(element);
    }
  }
  return disabledElements;
};

/**
 * 非活性にした入力項目を活性にする
 */
const setNotDisabled = (disabledElements) => {
  for (const element of disabledElements) {
    element.disabled = false;
  }
};

