/** アップロードAPI呼び出し */
const callUploadApi = async (reqParamData) => {
  // ローディングの表示
  loadingModal.isshow(true);
  // アップロードAPI呼び出しパラメータ設定
  const formData = new FormData();
  formData.append("UploadUnSyncRequestDto", new Blob([JSON.stringify(reqParamData)], { type: "application/json" }));
  formData.append("uploadFiles", uploadingFileObject.value);

  const reqParam = [
    [
      comConst.API_ID_ENT0201_29, // パスパラメータ
      // リクエストパラメータ
      formData,
      "multipart/form-data",
    ],
  ];
  // アップロードAPI呼び出し
  const res = await apiCaller.httpService(reqParam, comConst.ENT0301110);
  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // 結果コード=正常の場合
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージをクリアして再設定
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000001I, ["経営情報等データのアップロード"])];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // 画面上部へ戻る
    scrollToTop();
    // 排他制御
    await mutualExclusion([res[0].data.fileOperationManageSeq]);
  } else if (res[0].data.resultCode == comConst.API_RESULT_CODE_ERROR) {
    // 結果コード=異常の場合
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージをクリアして再設定
    messageInfo.value = [];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // メッセージ設定
    res[0].data.messageErr.forEach((msg) => {
      messageErr.value.push(msg);
    });
    res[0].data.messageInfo.forEach((msg) => {
      messageInfo.value.push(msg);
    });
    res[0].data.messageWarn.forEach((msg) => {
      messageWarn.value.push(msg);
    });
    // 画面上部へ戻る
    scrollToTop();
  } else {
    // 処理無し
  }
  // 選択ファイルリセット
  fileUploadModal.value.reset();
};

