/** ダウンロード（同期用）API呼び出し */
const callDownloadSyncApi = async (reqParamData) => {
  // ローディングの表示
  loadingModal.isshow(true);
  // ダウンロード（同期用）API呼び出しパラメータ設定
  const reqParam = [
    [
      comConst.API_ID_ENT0201_07, // パスパラメータ
      // リクエストパラメータ
      reqParamData,
      null,
      "blob",
      0,
    ],
  ];
  // ダウンロード（同期用）依頼API呼び出し
  const res = await apiCaller.httpService(reqParam, comConst.ENT0301110);
  if (res[0].headers.resultcode == comConst.API_RESULT_CODE_SUCCESS) {
    // 結果コード=正常の場合
    ComFileDownload.download(res[0].data, res[0].headers, null);
    // ローディングの非表示
    loadingModal.isshow(false);
    // ダウンロード完了メッセージを先頭に追加
    messageInfo.value = [];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageInfo.value.unshift(StringUtil.convertString(comMessage.COMMON000000I, ["ダウンロード"]));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // 画面上部へ戻る
    scrollToTop();
  } else if (res[0].headers.resultcode == comConst.API_RESULT_CODE_ERROR) {
    // 結果コード=異常の場合
    // ローディングの非表示
    loadingModal.isshow(false);
    // 新しいメッセージを先頭に追加
    messageInfo.value = [];
    messageErr.value = [];
    const errMsg = ComFileDownload.getErrMessages(res[0].headers);
    if (errMsg && errMsg.length > 0) {
      errMsg.forEach((msg) => {
        messageErr.value.push(msg);
      });
      inputMessageErr.value.forEach((msg) => {
        messageErr.value.push(msg);
      });
    } else {
      // メッセージ設定
      messageErr.value = [StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"])];
    }
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
  } else {
    // ローディングの非表示
    loadingModal.isshow(false);
    // メッセージを先頭に追加
    messageInfo.value = [];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageErr.value.unshift(StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // 画面上部へ戻る
    scrollToTop();
  }
};

/** ダウンロード監視 */
const monitorDownload = async (downloadingFileOpeMngSeq, operationId) => {
  // ダウンロード中ファイル有り
  if (downloadingFileOpeMngSeq) {
    // メッセージ表示
    messageInfo.value = [StringUtil.convertString(comMessage.COMMON000003I, ["ダウンロード"])];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // 画面上部へ戻る
    scrollToTop();
    if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val) {
      // ブランクフォームのダウンロードドロップダウンメニューを押下不可
      isDownloadBlankFormProcessing.value = true;
    } else if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val) {
      // 入力済みExcelのダウンロードドロップダウンメニューを押下不可
      isDownloadInputtedFormProcessing.value = true;
    }
    // 非同期バッチ監視API呼び出しパラメータ設定
    const reqParam = [
      [
        comConst.API_ID_ENT0201_04, // パスパラメータ
        // リクエストパラメータ
        { fileOperationManageSeq: downloadingFileOpeMngSeq },
      ],
    ];
    // 排他制御(1秒ごと繰り返し)
    const polling = () => {
      let timerId = setTimeout(async () => {
        let finishFlg = await singleMonitorDownload(reqParam, downloadingFileOpeMngSeq, operationId);
        if (finishFlg) {
          clearTimeout(timerId);
        } else {
          polling(); // 再帰呼び出し
        }
      }, comProperty.POLLING_INTERVAL);
    };
    polling();
  } else {
    // メッセージ設定
    messageInfo.value = [];
    messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
    messageErr.value.unshift(StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード依頼"]));
    messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
    // 画面上部へ戻る
    scrollToTop();
  }
};

/** ダウンロード監視(1試行分) */
const singleMonitorDownload = async (reqParam, downloadingFileOpeMngSeq, operationId) => {
  let finishFlg = true;
  // 非同期バッチ監視API呼び出し
  const res = await apiCaller.httpService(reqParam, comConst.ENT0301110);

  if (res[0].data.resultCode == comConst.API_RESULT_CODE_SUCCESS) {
    // 非同期バッチ監視APIの結果コードが正常の場合
    if (
      [comEnum.EnumFILE_OPERATION_MANAGE_STATUS.UNTREATED.val, comEnum.EnumFILE_OPERATION_MANAGE_STATUS.PROCESSING.val].includes(res[0].data.status)
    ) {
      // ステータスが未処理または処理中の場合
      finishFlg = false;
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.COMPLETED.val) {
      // ステータスが完了の場合
      finishFlg = true;
      // ダウンロードドロップダウンメニューの押下不可を解除
      if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val) {
        isDownloadBlankFormProcessing.value = false;
      } else if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val) {
        isDownloadInputtedFormProcessing.value = false;
      }
      // ダウンロードAPI呼び出しパラメータ設定
      const dlReqParam = [
        [
          comConst.API_ID_ENT0201_01, // パスパラメータ
          // リクエストパラメータ
          {
            fileOperationManageSeq: downloadingFileOpeMngSeq,
          },
          null,
          "blob",
          0,
        ],
      ];
      // ダウンロードAPI呼び出し
      const dlRes = await apiCaller.httpService(dlReqParam, comConst.ENT0301110);
      if (dlRes[0].headers.resultcode == comConst.API_RESULT_CODE_SUCCESS) {
        // 結果コード=正常の場合
        ComFileDownload.download(dlRes[0].data, dlRes[0].headers, null);
        // ダウンロードドロップダウンメニューの押下不可を解除
        if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val) {
          isDownloadBlankFormProcessing.value = false;
        } else if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val) {
          isDownloadInputtedFormProcessing.value = false;
        }
        // ダウンロード完了メッセージを表示
        messageInfo.value = [];
        messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
        messageInfo.value.unshift(StringUtil.convertString(comMessage.COMMON000000I, ["ダウンロード"]));
        messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
        // 画面上部へ戻る
        scrollToTop();
      } else {
        // 結果コード=正常以外の場合
        // ダウンロードドロップダウンメニューの押下不可を解除
        if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val) {
          isDownloadBlankFormProcessing.value = false;
        } else if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val) {
          isDownloadInputtedFormProcessing.value = false;
        }
        // ダウンロード失敗メッセージを先頭に追加
        messageInfo.value = [];
        messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
        messageErr.value.unshift(StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]));
        messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
        // 画面上部へ戻る
        scrollToTop();
      }
    } else if (res[0].data.status == comEnum.EnumFILE_OPERATION_MANAGE_STATUS.ERR.val) {
      // ステータスがエラーの場合
      finishFlg = true;
      // ダウンロードドロップダウンメニューの押下不可を解除
      if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_BLANK_UL.val) {
        isDownloadBlankFormProcessing.value = false;
      } else if (operationId == comEnum.EnumOPE_ID.EXCEL_FORM_INP_DL.val) {
        isDownloadInputtedFormProcessing.value = false;
      }
      // ダウンロード失敗メッセージを先頭に追加
      messageInfo.value = [];
      messageErr.value = JSON.parse(JSON.stringify(inputMessageErr.value));
      messageErr.value.unshift(StringUtil.convertString(comMessage.COMMON100009E, ["ダウンロード"]));
      messageWarn.value = JSON.parse(JSON.stringify(inputMessageWarn.value));
      // 画面上部へ戻る
      scrollToTop();
    }
  } else {
    // 処理無し
  }
  return finishFlg;
};

