    ENT0301_39res[0].data.mngInfo.reportNotApplicableFlg = comEnum.EnumREPORT_NOT_APPLICABLE.REPORT_NOT_APPLICABLE.val;
    ENT0301_39res[0].data.mngInfoSalaryByJobtype.n0001HospitalClinicDivision = comEnum.EnumHOSPITAL_CLINIC_DIVISION.REPORT_NOT_APPLICABLE.val;
    // 画面描画に必要な項目を補完
    const inputItemDto = { value: "", messageErr: [], messageWarn: [] };
    for (const [key, value] of Object.entries(collapse3ref.value.getMngInfoSBJ())) {
      if (mngInfoSBJ.value[key] == null) {
        mngInfoSBJ.value[key] = JSON.parse(JSON.stringify(inputItemDto));
      }
    }
  } else {
    // 報告対象に変更
    ENT0301_39res[0].data.mngInfo.reportNotApplicableFlg = comEnum.EnumREPORT_NOT_APPLICABLE.REPORT_APPLICABLE.val;
    if (ENT0301_39res[0].data.mngInfoSalaryByJobtype.hospitalClinicType == comEnum.EnumHOSPITAL_CLINIC_TYPE.HOSPITAL.val) {
      ENT0301_39res[0].data.mngInfoSalaryByJobtype.n0001HospitalClinicDivision = comEnum.EnumHOSPITAL_CLINIC_DIVISION.HOSPITAL.val;
    } else if (ENT0301_39res[0].data.mngInfoSalaryByJobtype.hospitalClinicType == comEnum.EnumHOSPITAL_CLINIC_TYPE.CLINIC.val) {
      ENT0301_39res[0].data.mngInfoSalaryByJobtype.n0001HospitalClinicDivision = comEnum.EnumHOSPITAL_CLINIC_DIVISION.CLINIC.val;
    }
    // 画面描画に必要な項目を補完
    const inputItemDto = { value: "", messageErr: [], messageWarn: [] };
    for (const [key, value] of Object.entries(collapse1ref.value.getMngInfoSBJ())) {
      if (mngInfoSBJ.value[key] == null) {
        mngInfoSBJ.value[key] = JSON.parse(JSON.stringify(inputItemDto));
      }
    }
    for (const [key, value] of Object.entries(collapse2ref.value.getMngInfoSBJ())) {
      if (mngInfoSBJ.value[key] == null) {
        mngInfoSBJ.value[key] = JSON.parse(JSON.stringify(inputItemDto));
      }
    }
  }
  setScreenItemValues(ENT0301_39res);
  setScreen(ENT0301_39res);
