/**
 * ローディング表示関数です。
 * 
 * @version 1.0
 * @author CSC
 */

/**
 * フォーカスの遷移の制御
 * Tabキーによるフォーカスの遷移をキャンセルする。
 * 
 * @param {Event} event - Eventオブジェクト
 * @returns なし
 */
const _listener = (event) => {
  let preventKeys = ["Tab", "ArrowUp", "ArrowDown", "ArrowRight", "ArrowLeft", " ", "Home", "End", "PageUp", "PageDown"];
  if (preventKeys.includes(event.key)) {
    event.preventDefault();
  }
};

/**
 * ローディングの表示
 * ローディングの表示中はフォーカスの移動を禁止とする。
 * また、利用者側でローディング画面の非表示ができないようにする。
 * 
 * @param {boolean} flg - ローディングの表示フラグ（true :表示、false :非表示）
 * @returns なし
 */
export default {
  isshow(flg) {
    let spnnerElement = document.getElementById("sys_spinner");
    let bodyElement = document.getElementById("sys_body");
    if (flg) {
      // スピナー貼る
      document.activeElement.blur(); // フォーカスはずし
      spnnerElement.classList.remove("invisible", "hide");
      spnnerElement.classList.add("visible", "show");
      bodyElement.classList.add("overflow-hidden");
      document.addEventListener("keydown", _listener);
    } else {
      // スピナー消す
      spnnerElement.classList.remove("visible", "show");
      spnnerElement.classList.add("invisible", "hide");
      bodyElement.classList.remove("overflow-hidden");
      document.removeEventListener("keydown", _listener);
    }
  },
};
