<!--
 メニューコンポーネント
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, onMounted } from "vue";
import comEnum from "@/constants/com-enum.js";
import commonInfo from "@/store/common/common-info.js";
import { useRouter } from "vue-router";

// コンポーネントの引数
const props = defineProps({
  selectedMenu: { type: String, default: "UTL0101100" },
});
const router = useRouter();
// ログインユーザー属性が医療法人かどうか
const isMedicCorp = ref(true);
// ログインユーザー属性が代理入力かどうか
const isProxyStaff = ref(false);

// 画面マウント時イベント
onMounted(async () => {
  //ユーザー属性の判定
  let userType = commonInfo().userType;
  isMedicCorp.value = userType == comEnum.EnumUSER_TYPE.MEDIC_CORP.val;
  isProxyStaff.value = userType == comEnum.EnumUSER_TYPE.PROXY_INPUT_STAFF.val;
});

//リンククリック時動作
const linkClick = async (arg) => {
  // メニューからの遷移時はパンくずリストをクリア
  commonInfo().breadcrumbList = "[]";
  // 画面遷移
  router.push({ name: arg });
};
</script>
<template>
  <div class="d-flex sticky">
    <div class="col ms-0" style="min-width: 29.375em">
      <a
        type="button"
        @click="linkClick('UTL0101100')"
        style="margin-left: 0px !important"
        :class="{ 'btn btn-primary rounded-0 me-0': true, 'btn-selected': props.selectedMenu == 'UTL0101100' }"
        ><i class="bi bi-house"></i>トップ</a
      >
      <a
        type="button"
        @click="linkClick('ENT0101100')"
        v-if="isMedicCorp"
        :class="{ 'btn btn-primary rounded-0 me-0': true, 'btn-selected': props.selectedMenu == 'ENT0101100' }"
        ><i class="bi bi-file-earmark"></i>年度別届出状況一覧</a
      >
      <a
        type="button"
        @click="linkClick('MNM0201200')"
        v-if="isMedicCorp"
        :class="{ 'btn btn-primary rounded-0 me-0': true, 'btn-selected': props.selectedMenu == 'MNM0201200' }"
        ><i class="bi bi-building"></i>法人情報</a
      >
      <a
        type="button"
        @click="linkClick('MNM0101100')"
        v-if="!isMedicCorp"
        :class="{ 'btn btn-primary rounded-0 me-0': true, 'btn-selected': props.selectedMenu == 'MNM0101100' }"
        ><i class="bi bi-search"></i>届出検索</a
      >
      <button
        type="button"
        v-if="!isMedicCorp"
        id="dropHojinMenuButton"
        data-bs-toggle="dropdown"
        aria-expanded="false"
        :class="{ 'btn btn-primary rounded-0 me-0 dropdown-toggle': true, 'drp-selected': props.selectedMenu == 'MNM0201200' }"
      >
        <i class="bi bi-building"></i>法人情報
      </button>
      <ul class="dropdown-menu" aria-labelledby="dropHojinMenuButton" id="dropHojinMenu">
        <li>
          <a
            @click="linkClick('MNM0201100')"
            :class="{ 'dropdown-item rounded-2 d-flex align-items-center': true, 'btn-selected': props.selectedMenu == 'MNM0201100' }"
            ><i class="bi bi-search"></i>法人情報検索</a
          >
        </li>
        <li v-if="!isProxyStaff">
          <a
            @click="linkClick('MNM0201200')"
            :class="{ 'dropdown-item rounded-2 d-flex align-items-center': true, 'btn-selected': props.selectedMenu == 'MNM0201200' }"
            ><i class="bi bi-building-add"></i>法人情報登録</a
          >
        </li>
      </ul>
      <a
        type="button"
        @click="linkClick('MNM0301100')"
        v-if="!isProxyStaff && !isMedicCorp"
        :class="{ 'btn btn-primary rounded-0 me-0': true, 'btn-selected': props.selectedMenu == 'MNM0301100' }"
        ><i class="bi bi-search"></i>ユーザ検索</a
      >
    </div>
    <div class="dropdown col-auto me-0">
      <button class="btn btn-primary rounded-0 dropdown-toggle" type="button" id="dropMainMenuButton" data-bs-toggle="dropdown" aria-expanded="false">
        <i class="bi bi-gear"></i> 設定
      </button>
      <ul class="dropdown-menu" aria-labelledby="dropMainMenuButton" id="dropMainMenu">
        <li>
          <a
            @click="linkClick('MNM0301300')"
            :class="{ 'dropdown-item rounded-2 d-flex align-items-center': true, 'btn-selected': props.selectedMenu == 'MNM0301300' }"
            ><i class="bi bi-person-fill"></i>ユーザ登録情報</a
          >
        </li>
        <li>
          <a
            @click="linkClick('ATH0102100')"
            :class="{ 'dropdown-item rounded-2 d-flex align-items-center': true, 'btn-selected': props.selectedMenu == 'ATH0102100' }"
            ><i class="bi bi-key"></i>パスワード変更</a
          >
        </li>
      </ul>
    </div>
  </div>
</template>
<style scoped>
.sticky {
  position: sticky !important;
  top: 0px !important;
  background-color: #fff;
  opacity: 1;
  z-index: 30;
}
</style>
