/**
 *  法人情報登録・参照画面の画面内保持データを定義する
 *
 *  @version 1.0
 *  @author CSC
 */
import { defineStore } from "pinia";

const MNM0201200Save = defineStore("MNM0201200Save", {
  state: () => {
    return {
      prefCode: "", // 登録する都道府県
      medicCorpRefNumber: "", // 医療法人整理番号
      corporationName: "", // 医療法人名称
      postalNumberFirstThree: "", // 郵便番号〒 （上）
      postalNumberLastFour: "", // 郵便番号〒 （下）
      prefName: "", // 都道府県
      cityName: "", // 市区町村
      townName: "", // 町域・番地
      buildingName: "", // 建物名
      bizRepoAccepHelthCenter: "", // 届出を受付ている保健所
      chairpersonLastName: "", // 理事長の氏名（性）
      chairpersonFirstName: "", // 理事長の氏名（名）
      ulpdBizReportRequest: "", // アップロードによる届出の希望
      fiscalYearEnd: "", // 会計年度の決算月
      registrationDate: "", // 登記年月日
      closedDate: "", // 廃止日
      screenMode: "",
      enumPrefRegistMaps: [],
    };
  },
  persist: {
    storage: window.sessionStorage,
  },
});

export default MNM0201200Save;
