/**
 *  対象の法人情報を定義する
 *
 *  @version 1.0
 *  @author CSC
 */
import { defineStore } from "pinia";

const targetCorp = defineStore("targetCorp", {
  state: () => {
    return {
      prefCode: "",             // 都道府県番号
      prefName: "",             // 都道府県名
      corporationId: "",        // 法人ID
      corporationName: "",      // 法人名称
      medicCorpRefNumber: "",   // 医療法人整理番号
      address: "",	            // 住所
      fiscalYear: "",	        // 会計年度
      notificationType: "",	    // 届出タイプ
      notificationStatus: "",	// 届出ステータス
      procStatus: "",	        // 処理ステータス
      notificationMethod: "",	// 届出方法
    };
},
persist: {
  storage: window.sessionStorage,
},
});

export default targetCorp;