import axios from "axios";
const define = (name, value) => {
  Object.defineProperty(window, name, {
    value: value,
    writable: false,
  });
};

export default {
  async initDefine() {
    let response = await axios.get(import.meta.env.VITE_APP_ENV_PATH);
    for (let i in response.data) {
      define(response.data[i].key, response.data[i].value);
    }
  },
};
