import { createApp } from 'vue'
import { createPinia } from 'pinia';
import { createPersistedState } from 'pinia-plugin-persistedstate'
import router from "@/router/index.js";
import errorHandle from "@/utils/common/error-handle.js";
import envConst from "@/utils/common/env-const.js";
import "bootstrap";
import "./css/bootstrap.min.css";
import "./css/common.css";
import './css_milktea/bootstrap.css'
import './css_milktea/style.css'
import './css_milktea/responsive.css'
import './css_milktea/header.css'
import './css_milktea/animate.css'
import App from './App.vue'

mainInit(createApp(App));

async function mainInit(app) {
  // 設定ファイル読み込み
  await envConst.initDefine();
  // pinia初期設定
  app.use(createPinia().use(createPersistedState()));
  // router初期設定
  await app.use(router);
  //ブラウザバックでのページ遷移を防止
  router.beforeEach((to, from, next) => {
    history.pushState(null, null, null);
    next();
  });
  router.afterEach((to, from, failure) => {
    history.pushState(null, null, null);
  });
  errorHandle.errorHandlerService(app);
  app.mount('#app');
}
