<script setup>
import { ref, onMounted } from "vue";
import AmountInput from "@/components/ENT0x/AmountInput.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";

/* ---------------------金額入力の例--------------------- */
const amauntInput = ref(null);
const infoMessage = ref('');
// 内部保持されている値
const amountNumber = ref('123456789');

// フォーカスイン時のイベント
const funcIn = (event) =>{
  // TODO:ここでエラーメッセージを消すとか？もろもろの処理を行う
  infoMessage.value = '(ユーザー入力中...)';
};
// フォーカスアウト時のイベント
const funcOut = (event) =>{
  // TODO:ここで入力チェックとか？もろもろの処理を行う
  infoMessage.value = '';
};
// codeでfocusあてるボタン押下イベント
const funcBtnClick = async () => {
  amauntInput.value.focusInput();
};

/* ---------------------モーダルの例--------------------- */
const myModal = ref();
const modalmsg = ref("");
const cancelBtn = ref("");
let closeModal = (modalReturn) => {};
const dialogTestOutput = ref("");

// 画面マウント時イベント
onMounted(async () => {
  //modal初期化
  myModal.value.init();
});

// モーダル（はい・いいえ）出す＋消すときのイベント割り当てメソッド
const showMessage = (msg, ngBtn, closeFunc) => {
  modalmsg.value = msg;
  cancelBtn.value = ngBtn;
  closeModal = closeFunc;
  myModal.value.show();
};

// Hogeボタン押下時イベント１（ダイアログひらくまえの処理）
const clickHoge_1 = () => {
  dialogTestOutput.value = "Hoge押下";
  showMessage("Hoge押下時メッセージ", "いいえ", clickHoge_2);
};
// Hogeボタン押下時イベント２（ダイアログとじたあとの処理）
const clickHoge_2 = (modalReturn) => {
  dialogTestOutput.value += "⇒Hoge閉じる";
  if (modalReturn == 1) { // OK押されたとき
    dialogTestOutput.value += "（はい）";
  } else {
    dialogTestOutput.value += "（いいえ）";
  }
  setTimeout(() => {showMessage("Hoge3", "いいえ", clickHoge_3)}, 300);
  
};
const clickHoge_3 = (modalReturn) => {
  dialogTestOutput.value += "⇒Hoge3";
};
// Piyoボタン押下時イベント１（ダイアログひらくまえの処理）
const clickPiyo_1 = () => {
  dialogTestOutput.value = "Piyo押下";
  showMessage("Piyo押下時メッセージ", "いいえ", clickPiyo_2);
};

// Piyoボタン押下時イベント２（ダイアログとじたあとの処理）
const clickPiyo_2 = (modalReturn) => {
  dialogTestOutput.value += "⇒Piyo閉じる";
  if (modalReturn == 1) { // OK押されたとき
    dialogTestOutput.value += "（はい）";
  } else {
    dialogTestOutput.value += "（いいえ）";
  }
};

// クリアボタン押下時イベント１（ダイアログひらくまえの処理）
const clickClear_1 = () => {
  showMessage("クリアします", "", clickClear_2);
};
// クリアボタン押下時イベント２（ダイアログとじたあとの処理）
const clickClear_2 = (modalReturn) => {
  dialogTestOutput.value = ""; 
};

</script>
<template>
  <div class="tab-pane p-2" style="height:18rem">
    TEST5
    <div class="row ms-2" style="width: 36rem;">
      内部保持されている値：{{ amountNumber }} {{ infoMessage }}
    </div>
    <div class="row ms-2" style="width: 36rem;">
      <AmountInput id="amount" ref="amauntInput" v-model="amountNumber" class="form-control width-250" @focus="funcIn" @blur="funcOut" />←活性(focusあてると内部保持値表示)
    </div>
    <div class="row ms-2 my-2" style="width: 36rem;">
      <button style="width:11rem;" @click="funcBtnClick">codeでfocus当てる</button>
    </div>
    <div class="row ms-2" style="width: 36rem;">
      <AmountInput id="amount2" v-model="amountNumber" class="form-control width-300" :disabled="true" />←非活性(focus当たらない)
    </div>
    <hr />
    <div class="row ms-2 my-2" style="width: 36rem;">
      {{ dialogTestOutput }}<br />
    </div>
    <button id="hoge" style="width:4rem;" @click="clickHoge_1">Hoge</button>
    <button id="piyo" style="width:4rem;" @click="clickPiyo_1">Piyo</button>
    <button id="clear" style="width:4rem;" @click="clickClear_1">クリア</button>
  </div>
  <CommonDialog ref="myModal" id="commonDialog5" title="てすと" okButton="はい" :cancelButton="cancelBtn" closeButton=""
  :msg="modalmsg" @common-dialog-close="closeModal" />
</template>

<style scoped>
.width-250 {
  width: 250px !important;
}
.width-300 {
  width: 250px !important;
}
</style>