<!--
 項目名表示コンポーネント（添付書類Web入力画面）
 @version 1.0
 @author CSC
-->
<template>
  <!-- 項目名表示 -->
  <div
    class="p-3 border bg-light"
    data-bs-toggle="tooltip"
    data-bs-custom-class="text-tooltip"
    data-bs-placement="right"
    :title="props.attachDocumentDetailName"
  >
    {{ attachDocumentName }} <span v-if="chkRequiredMark" class="required_mark">※</span>
  </div>
</template>
<script setup>
import { onMounted, ref, computed } from "vue";
import { Tooltip } from "bootstrap";

/** props：コンポーネントの引数 */
const props = defineProps({
  /**
   * 添付書類ID
   * @type {string}
   */
  attachDocumentId: String,
  /**
   * 添付書類名
   * @type {string}
   *
   */
  attachDocumentName: String,
  /**
   * 添付書類詳細名
   * @type {string}
   */
  attachDocumentDetailName: String,
  /**
   * 必須フラグ
   * @type {string}
   */
  requiredFlg: String,
  /**
   * 編集区分
   * @type {string}
   */
  editType: String,
  /**
   * 代理入力の場合のみ入力が可能となる添付書類ID群
   * @type {Array}
   */
  proxyInputAttachDocumentIds: Array,
});

/** コンポーネントのメソッド公開 */
defineExpose({});

// 変数
/** 添付書類ID */
const attachDocumentId = ref();
/** 添付書類名 */
const attachDocumentName = ref(false);
/** 添付書類詳細名 */
const attachDocumentDetailName = ref(false);
/** 必須フラグ */
const requiredFlg = ref(false);
/** 編集区分 */
const editType = ref();
/** 代理入力の場合のみ入力が可能となる添付書類ID群 */
const proxyInputAttachDocumentIds = ref([]);

/**
 * コンポーネントのマウント後の処理
 */
onMounted(() => {
  // 初期処理
  init();

  // textboxツールチップの有効化
  let targetList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
  targetList.map(function (_element) {
    return new Tooltip(_element, { trigger: "hover", html: true, animation: false });
  });
});

// 関数
/**
 * ファイル選択コンポーネント初期表示
 */
const init = () => {
  // 添付書類ID
  if (props.attachDocumentId !== undefined) {
    attachDocumentId.value = props.attachDocumentId;
  }
  // 添付書類名の設定
  if (props.attachDocumentName !== undefined) {
    attachDocumentName.value = props.attachDocumentName;
  }
  // 添付書類詳細名の設定
  if (props.attachDocumentDetailName !== undefined && props.attachDocumentDetailName !== "") {
    attachDocumentDetailName.value = props.attachDocumentDetailName;
  }
  if (props.requiredFlg !== undefined) {
    requiredFlg.value = props.requiredFlg;
  }
  if (props.editType !== undefined) {
    editType.value = props.editType;
  }
  if (props.proxyInputAttachDocumentIds !== null && props.proxyInputAttachDocumentIds !== undefined) {
    proxyInputAttachDocumentIds.value = props.proxyInputAttachDocumentIds;
  }
};

/**
 * 必須マーク表示( true:表示、false:非表示)
 */
const chkRequiredMark = computed(() => {
  let retFlg = false;
  // 該当する添付書類IDが、代理入力専用の場合
  if (props.proxyInputAttachDocumentIds.includes(attachDocumentId.value)) {
    if (editType.value == "proxyInput") {
      retFlg = true;
    } else {
      // 何もしない
    }
  } else if (requiredFlg.value == "1") {
    retFlg = true;
  } else {
    // 何もしない
  }
  return retFlg;
});
</script>
