<!--
 ユーザ登録画面
 @version 1.0
 @author CSC
-->
<script setup>
import { ref, watch, onMounted, onUnmounted, computed } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import Menu from "@/components/common/Menu.vue";
import Breadcrumb from "@/components/common/Breadcrumb.vue";
import commonInfo from "@/store/common/common-info.js";
import loadingModal from "@/utils/common/loading-modal.js";
import apiCaller from "@/utils/common/api-caller.js";
import comConst from "@/constants/com-const.js";
import comEnum from "@/constants/com-enum.js";
import comMessage from "@/constants/com-message.js";
import stringUtil from "@/utils/common/string-util.js";
import CommonDialog from "@/components/common/CommonDialog.vue";
import MNM0301200Param from "@/store/MNM0301200/mnm0301200-param.js";

//////////////////////////
// データ定義
//////////////////////////

/** VueRouter */
const router = useRouter();
/** パンくずリスト */
const breadcrumbObj = ref();
/** モーダルメッセージ用 */
const modalmsg = ref("");
const modaltitle = ref("");
const modalOkBtn = ref("");
const modalCancelBtn = ref("");
const modalCloseBtn = ref("");
const myModal = ref();
const errInfoMap = ref([]);
let closeModal = (modalReturn) => {};

/** 入出力項目 */
const prefCodeBox = ref();
const managerLastNameTextBox = ref();
const managerLastFirstTextBox = ref();
const telephoneNumberTextBox = ref();
const mailAddress1TextBox = ref();
const mailAddress2TextBox = ref();
const mailAddress3TextBox = ref();

/** ログ用 */
const screenName = "ユーザ登録";
const registProc = "登録";
const updateProc = "更新";
const deleteProc = "削除";
const reMailProc = "登録通知メール再送信";

/** ユーザ情報 */
const userInfo = ref({
  userId: "", // ユーザID
  userType: "", // ユーザ種別
  prefName: "", // 都道府県名
  corporationName: "", // 医療法人
  managerLastName: "", // 担当者（姓）
  managerFirstName: "", // 担当者（名）
  telephoneNumber: "", // 担当者の連絡先（電話番号）
  mailAddress1: "", // 担当者のメールアドレス➀
  mailAddress2: "", // 担当者のメールアドレス➁
  mailAddress3: "", // 担当者のメールアドレス➂
  passwordForcedChangeFlg: "", // パスワード強制変更
  loginUnavailable: "", // ユーザIDの有効／無効
  corporationId: "", // 法人ID
  prefCode: "", // 都道府県番号
});

/** エラーメッセージ */
const messageErr = ref("");

/** 更新完了メッセージ */
const updateMsg = ref("");

/** 更新完了メッセージ表示判定  false：非表示 */
const isShowUpdateMsg = ref(false);

/** 画面の非活性状態(戻るボタン除く)を管理  true：非活性 */
const isScreenDisabled = ref(true);

/** ユーザ種別Enum */
const enumUserType = comEnum.EnumUSER_TYPE;
/** パスワード強制変更種別Enum */
const enumPwdForcedChangeType = comEnum.EnumPWD_FORCED_CHANGE_TYPE;
/** ログイン有効無効種別Enum */
const enumLoginUnavailableType = comEnum.EnumLOGIN_UNAVAILABLE_TYPE;

/** エラー表示エリア表示判定  false：非表示 */
const isShowerrorMsg = ref(false);

/** ユーザ種別(ラジオボタン用) */
const radioUserTypes = ref([
  {
    dispname: enumUserType.MEDIC_CORP.dispname,
    val: enumUserType.MEDIC_CORP.val,
    visible: true,
  },
  {
    dispname: enumUserType.PREF_STAFF.dispname,
    val: enumUserType.PREF_STAFF.val,
    visible: true,
  },
  {
    dispname: enumUserType.PROXY_INPUT_STAFF.dispname,
    val: enumUserType.PROXY_INPUT_STAFF.val,
    visible: true,
  },
  {
    dispname: enumUserType.MEDIC_CARE_ORG_STAFF.dispname,
    val: enumUserType.MEDIC_CARE_ORG_STAFF.val,
    visible: true,
  },
]);

/** パスワード強制変更種別(ラジオボタン用) */
const radioLoginUnavailables = ref([
  {
    dispname: enumLoginUnavailableType.AVAILABLE.dispname,
    val: enumLoginUnavailableType.AVAILABLE.val,
  },
  {
    dispname: enumLoginUnavailableType.UNAVAILABLE.dispname,
    val: enumLoginUnavailableType.UNAVAILABLE.val,
  },
]);

//////////////////////////
// 算出プロパティ
//////////////////////////

/**
 * 都道府県リスト設定
 * @type {String[]}
 */
const prefCodeMap = computed(() => {
  if (MNM0301200Param().prefCodeInfoMap) {
    return MNM0301200Param().prefCodeInfoMap.filter((obj) => obj.val !== comConst.PREF_ALL_CD);
  } else {
    return [];
  }
});

/**
 * 編集モード判定
 * @type {boolean}　true：編集モード、false：新規登録モード
 */
const isEditMode = computed(() => {
  // ユーザIDに値がある場合、編集モード
  return MNM0301200Param().userId !== "";
});

/**
 * 遷移元画面ID取得
 * @type {String}
 */
const getFromScreenId = computed(() => {
  // 法人IDに値がある場合、法人情報登録・照会画面、ない場合はユーザ検索画面から遷移
  let fromScreenId = comConst.MNM0301100;
  if (MNM0301200Param().corporationId) {
    fromScreenId = comConst.MNM0201200;
  }
  return fromScreenId;
});

/**
 * 「登録」ボタン表示判定
 * @type {boolean}　true：表示、false：非表示
 */
const isShowRegistButton = computed(() => {
  // ログインユーザ種別が都道府県または機構職員の場合、表示する
  return [enumUserType.PREF_STAFF.val, enumUserType.MEDIC_CARE_ORG_STAFF.val].includes(commonInfo().userType);
});

/**
 * 「登録通知メール再送信ボタン」ボタン表示判定
 * @type {boolean}　true：表示、false：非表示
 */
const isShowRresendMailButton = computed(() => {
  // ログインユーザ種別が都道府県または機構職員、かつ、編集モードの場合、表示する
  return isEditMode.value && [enumUserType.PREF_STAFF.val, enumUserType.MEDIC_CARE_ORG_STAFF.val].includes(commonInfo().userType);
});

/**
 * 「削除」ボタン表示判定
 * @type {boolean}　true：表示、false：非表示
 */
const isShowDeleteButton = computed(() => {
  // ログインユーザ種別が都道府県または機構職員、かつ、編集モードの場合、表示する
  return isEditMode.value && [enumUserType.PREF_STAFF.val, enumUserType.MEDIC_CARE_ORG_STAFF.val].includes(commonInfo().userType);
});

/**
 * 「ユーザ種別」表示判定
 * @type {boolean[]}　true：１つ以上の種別が表示、false：全ての種別が非表示
 */
const isShowUserTypes = computed(() => {
  let isMedicCorp = false;
  let isPrefStaff = false;
  let isProxyInputStaff = false;
  let isMedicCareOrgStaff = false;

  const setVisible = () => {
    radioUserTypes.value[0].visible = isMedicCorp;
    radioUserTypes.value[1].visible = isPrefStaff;
    radioUserTypes.value[2].visible = isProxyInputStaff;
    radioUserTypes.value[3].visible = isMedicCareOrgStaff;
    return isMedicCorp || isPrefStaff || isProxyInputStaff || isMedicCareOrgStaff;
  };

  // ログインユーザ種別が法人または代理入力の場合、表示しない
  if ([enumUserType.MEDIC_CORP.val, enumUserType.PROXY_INPUT_STAFF.val].includes(commonInfo().userType)) {
    return setVisible();
  }

  // 遷移元が法人情報登録・照会画面の場合
  if (getFromScreenId.value === comConst.MNM0201200) {
    // 取得したユーザ情報.ユーザ種別が医療法人の場合、「医療法人」を表示する
    isMedicCorp = true;

    // 遷移元がユーザ検索画面の場合
  } else {
    // 取得したユーザ情報.ユーザ種別が都道府県の場合、「都道府県」を表示する
    isPrefStaff = [enumUserType.PREF_STAFF.val].includes(userInfo.value.userType);

    // 取得したユーザ情報.ユーザ種別が医療法人の場合、「医療法人」を表示する
    isMedicCorp = [enumUserType.MEDIC_CORP.val].includes(userInfo.value.userType);

    // ログインユーザ種別が機構職員、かつ取得したユーザ情報.ユーザ種別が医療法人以外の場合
    if ([enumUserType.MEDIC_CARE_ORG_STAFF.val].includes(commonInfo().userType) && ![enumUserType.MEDIC_CORP.val].includes(userInfo.value.userType)) {
      // 「医療法人」以外を表示する
      isPrefStaff = true;
      isProxyInputStaff = true;
      isMedicCareOrgStaff = true;
    }
  }
  return setVisible();
});

/**
 * 「都道府県」表示判定
 * @type {boolean}　true：表示、false：非表示
 */
const isShowPref = computed(() => {
  let isShow = false;

  // ログインユーザ種別が法人または代理入力の場合、表示しない
  if ([enumUserType.MEDIC_CORP.val, enumUserType.PROXY_INPUT_STAFF.val].includes(commonInfo().userType)) {
    return isShow;
  }

  // 遷移元が法人情報登録・照会画面の場合
  if (getFromScreenId.value === comConst.MNM0201200) {
    // 取得したユーザ情報.ユーザ種別が医療法人の場合、表示する
    isShow = [enumUserType.MEDIC_CORP.val].includes(userInfo.value.userType);

    // 遷移元がユーザ検索画面の場合
  } else {
    // 取得したユーザ情報.ユーザ種別が都道府県の場合、表示する
    isShow = [enumUserType.PREF_STAFF.val].includes(userInfo.value.userType);
  }
  return isShow;
});

/**
 * 「都道府県」非活性判定
 * @type {boolean}　true：非活性、false：活性
 */
const isDisabledPref = computed(() => {
  let isDisabled = false;

  // 遷移元が法人情報登録・照会画面の場合
  if (getFromScreenId.value === comConst.MNM0201200) {
    // 取得したユーザ情報.ユーザ種別が医療法人の場合、非活性にする
    isDisabled = ![enumUserType.MEDIC_CORP.val].includes(userInfo.value.userType);

    // 遷移元がユーザ検索画面の場合
  } else if (!isEditMode.value) {
    // ユーザ情報.ユーザ種別が都道府県の場合、活性にする
    isDisabled = [enumUserType.PREF_STAFF.val].includes(userInfo.value.userType);

    if (enumUserType.MEDIC_CARE_ORG_STAFF.val === userInfo.value.userType || enumUserType.PROXY_INPUT_STAFF.val === userInfo.value.userType) {
      userInfo.value.prefCode = "";
    }
  }
  return !isDisabled;
});

/**
 * 「ユーザ種別」非活性判定
 * @type {boolean}　true：非活性、false：活性
 */
const isDisabledUserType = computed(() => {
  // 法人情報登録・照会の場合は非活性にする
  if (getFromScreenId.value === comConst.MNM0201200) {
    return !isEditMode.value;
  }
  // 編集モードの場合、非活性する
  return isEditMode.value;
});
/**
 * 「パスワード強制変更」非活性判定
 * @type {boolean}　true：非活性、false：活性
 */
const isDisabledPasswordForcedChangeFlg = computed(() => {
  // 新規登録モードの場合、非活性する
  return !isEditMode.value;
});

//////////////////////////
// ウォッチャー
//////////////////////////
watch(isShowPref, (newVal) => {
  // 都道府県が非表示になった場合、設定値をクリアする
  if (!newVal) {
    userInfo.value.prefCode = "";
  }
});

//////////////////////////
// メソッド
//////////////////////////

/**
 * OKメッセージ表示
 * タイトルなし、OKボタンのみ表示
 * @type {String}　メッセージ
 */
const showOkMessage = async (msg, closeFunc) => {
  modalmsg.value = msg;
  closeModal = closeFunc;
  modalCloseBtn.value = "OK";
  myModal.value.show();
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  router.push({
    name: getFromScreenId.value,
    params: { cameBackFlg: comConst.CAME_BACK_FLG_RETURN },
  });
};

// 実行ボタンに渡すユーザIDのリストを作成
const getUserId = () => {
  const list = [];
  if (userInfo.value.userId) {
    list.push(userInfo.value.userId.trim());
  }
  return list;
};

/**
 * 「初期表示」イベント
 */
const MNM0301200E01 = async () => {
  console.log(stringUtil.convertString(comMessage.COMMON000004I, [screenName]));
  // ローディングの表示
  loadingModal.isshow(true);

  // 編集モードの場合
  if (isEditMode.value) {
    // 開始ログ
    // ユーザ照会APIの呼び出し
    const reqParam = [
      [
        comConst.API_ID_MNM0301_02,
        {
          userId: MNM0301200Param().userId,
        },
      ],
    ];
    const screenId = commonInfo().screenId;
    const res = await apiCaller.httpService(reqParam, screenId);
    console.debug(res);
    //結果コード = "0"（正常終了）の場合
    if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
      const resData = res[0].data;
      if (resData.medicCorpRefNumber) {
        resData.corporationName = "(" + resData.medicCorpRefNumber + ")" + resData.corporationName;
      }
      userInfo.value = {
        userId: resData.userId,
        userType: resData.userType,
        prefName: resData.prefName,
        corporationName: resData.corporationName,
        managerLastName: resData.managerLastName,
        managerFirstName: resData.managerFirstName,
        telephoneNumber: resData.telephoneNumber,
        mailAddress1: resData.mailAddress1,
        mailAddress2: resData.mailAddress2,
        mailAddress3: resData.mailAddress3,
        passwordForcedChangeFlg: resData.passwordForcedChangeFlg,
        loginUnavailable: resData.loginUnavailable,
        corporationId: resData.corporationId,
        prefCode: resData.prefCode,
      };

      // エラー表示エリアを非表示にする
      isShowerrorMsg.value = false;

      // 結果コード = "1"（異常終了）の場合
    } else {
      // エラーメッセージリストをエラー表示エリアに表示する
      messageErr.value = res[0].data.messageErr.join("\n");
      // エラー表示エリアを表示する
      isShowerrorMsg.value = true;
      // ローディングの非表示
      loadingModal.isshow(false);
      return;
    }
  } else {
    // ボタン制御、入力項目の表示・非表示、活性・非活性制御
    // ⇒　算出プロパティを使って実装

    // 初期値設定
    // 遷移元がユーザ検索画面の場合
    if (getFromScreenId.value === comConst.MNM0301100) {
      // ログインユーザ種別が機構職員の場合
      if ([enumUserType.MEDIC_CARE_ORG_STAFF.val].includes(commonInfo().userType)) {
        // ユーザ種別、都道府県を未選択にする
        userInfo.value.userType = "";
        userInfo.value.prefCode = "";
        userInfo.value.prefName = "";

        // ログインユーザ種別が都道府県の場合
      } else if ([enumUserType.PREF_STAFF.val].includes(commonInfo().userType)) {
        // ユーザ種別、都道府県にログインユーザ情報を設定する
        userInfo.value.userType = enumUserType.PREF_STAFF.val;
        userInfo.value.prefCode = MNM0301200Param().prefCode;
      }
    }

    // 遷移元が法人情報登録・照会画面の場合
    if (getFromScreenId.value === comConst.MNM0201200) {
      // 都道府県、法人名に対象法人の値を設定する
      userInfo.value.userType = enumUserType.MEDIC_CORP.val;
      userInfo.value.prefCode = MNM0301200Param().prefCode;
      userInfo.value.prefName = MNM0301200Param().prefName;
      if (MNM0301200Param().medicCorpRefNumber) {
        userInfo.value.corporationName = "（" + MNM0301200Param().medicCorpRefNumber + "）" + MNM0301200Param().corporationName;
      } else {
        userInfo.value.corporationName = MNM0301200Param().corporationName;
      }
    }
    // パスワード強制変更、ユーザIDの有効／無効を「有効」に設定する
    userInfo.value.passwordForcedChangeFlg = enumPwdForcedChangeType.NOT_FORCED_CHANGE.val;
    userInfo.value.loginUnavailable = enumLoginUnavailableType.AVAILABLE.val;
  }

  // 画面状態を活性にする
  isScreenDisabled.value = false;

  // ローディングの非表示
  loadingModal.isshow(false);

  console.log(stringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * 「戻る」ボタンクリックイベント
 */
const MNM0301200E03 = async () => {
  router.push({
    name: getFromScreenId.value,
    params: { cameBackFlg: comConst.CAME_BACK_FLG_RETURN },
  });
};

/**
 * 「登録」ボタンクリックイベント
 */
const MNM0301200E02 = async () => {
  // ローディングの表示
  loadingModal.isshow(true);
  isShowUpdateMsg.value = false;
  updateMsg.value = "";
  errInfoMap.value = [];

  // ユーザIDが未設定の場合(新規登録モード）
  if (!isEditMode.value) {
    console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, registProc]));

    // ユーザ登録APIの呼び出し
    const reqParam = [
      [
        comConst.API_ID_MNM0301_05,
        {
          userType: userInfo.value.userType,
          prefCode: userInfo.value.prefCode,
          corporationId: MNM0301200Param().corporationId,
          managerLastName: userInfo.value.managerLastName,
          managerFirstName: userInfo.value.managerFirstName,
          telephoneNumber: userInfo.value.telephoneNumber,
          mailAddress1: userInfo.value.mailAddress1,
          mailAddress2: userInfo.value.mailAddress2,
          mailAddress3: userInfo.value.mailAddress3,
          passwordForcedChangeFlg: userInfo.value.passwordForcedChangeFlg,
          loginUnavailable: userInfo.value.loginUnavailable,
          updatePgmId: commonInfo().screenId,
        },
      ],
    ];
    const screenId = commonInfo().screenId;
    const res = await apiCaller.httpService(reqParam, screenId);
    console.debug(res);
    // 結果コード = "0"（正常終了）の場合
    if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
      // ユーザIDを設定する（更新モードに変更される）
      userInfo.value.userId = res[0].data.userId;
      MNM0301200Param().userId = res[0].data.userId;

      // エラー表示エリアを非表示にする
      isShowerrorMsg.value = false;

      // 登録処理完了メッセージを表示する
      isShowUpdateMsg.value = true;
      updateMsg.value = stringUtil.convertString(comMessage.COMMON000000I, ["ユーザ情報の登録"]);

      // 結果コード = "1"（異常終了）の場合
    } else {
      const responseData = ref();
      responseData.value = res[0].data; // エラーメッセージを設定
      errInfoMap.value = responseData.value.messageErrMap;

      if (errInfoMap.value){
        await focusCtrl(errInfoMap);
      }

      // エラーメッセージリストをエラー表示エリアに表示する
      if (res[0].data.messageErr.length > 0) {
        messageErr.value = res[0].data.messageErr.join("\n");
        // エラー表示エリアを表示する
        isShowerrorMsg.value = true;
      }
    }

    console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, registProc]));

    // ユーザIDが設定されている場合(更新モード）
  } else {
    console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, updateProc]));

    // ユーザIDの配列作成
    const userId = getUserId();

    // ユーザ更新APIの呼び出し
    const reqParam = [
      [
        comConst.API_ID_MNM0301_04,
        {
          userIdList: userId,
          userType: userInfo.value.userType,
          prefCode: userInfo.value.prefCode,
          corporationId: userInfo.value.corporationId,
          managerLastName: userInfo.value.managerLastName,
          managerFirstName: userInfo.value.managerFirstName,
          telephoneNumber: userInfo.value.telephoneNumber,
          mailAddress1: userInfo.value.mailAddress1,
          mailAddress2: userInfo.value.mailAddress2,
          mailAddress3: userInfo.value.mailAddress3,
          passwordForcedChangeFlg: userInfo.value.passwordForcedChangeFlg,
          loginUnavailable: userInfo.value.loginUnavailable,
          updatePgmId: commonInfo().screenId,
        },
      ],
    ];
    const screenId = commonInfo().screenId;
    const res = await apiCaller.httpService(reqParam, screenId);
    console.debug(res);
    // 結果コード = "0"（正常終了）の場合
    if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
      // エラー表示エリアを非表示にする
      isShowerrorMsg.value = false;

      isShowUpdateMsg.value = true;
      updateMsg.value = stringUtil.convertString(comMessage.COMMON000000I, ["ユーザ情報の更新"]);

      // 結果コード = "1"（異常終了）の場合
    } else {
      // 入力項目のエラーメッセージを表示する
      const responseData = ref();
      responseData.value = res[0].data; // エラーメッセージを設定
      errInfoMap.value = responseData.value.messageErrMap;

      if (errInfoMap.value) {
        await focusCtrl(errInfoMap);
      }

      // エラーメッセージリストをエラー表示エリアに表示する
      if (res[0].data.messageErr.length > 0) {
        messageErr.value = res[0].data.messageErr.join("\n");
        // エラー表示エリアを表示する
        isShowerrorMsg.value = true;
      }
    }
    console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, updateProc]));
  }
  // ローディングの非表示
  loadingModal.isshow(false);
};

/**
 * 「登録通知メール再送信」ボタンクリックイベント
 */
const MNM0301200E05 = async () => {
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, reMailProc]));

  // ローディングの表示
  loadingModal.isshow(true);

  const reqParam = [
    [
      comConst.API_ID_MNM0301_08,
      {
        userId: userInfo.value.userId,
        updatePgmId: commonInfo().screenId,
      },
    ],
  ];
  const screenId = commonInfo().screenId;
  const res = await apiCaller.httpService(reqParam, screenId);
  console.debug(res);
  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // 更新処理完了メッセージをダイヤログに表示する
    showOkMessage(stringUtil.convertString(comMessage.COMMON000003I, ["登録通知メールの再送信"]));

    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラーメッセージリストをエラー表示エリアに表示する
    messageErr.value = res[0].data.messageErr.join("\n");
    // エラー表示エリアを表示する
    isShowerrorMsg.value = true;
  }
  // ローディングの非表示
  loadingModal.isshow(false);

  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, reMailProc]));
};

/**
 * 「削除」ボタンクリックイベント
 */
const MNM0301200E04 = async () => {
  console.log(stringUtil.convertString(comMessage.COMMON000006I, [screenName, deleteProc]));

  // ユーザIDの配列作成
  const userId = getUserId();

  // ローディングの表示
  loadingModal.isshow(true);
  // ユーザ削除APIの呼び出し
  const reqParam = [
    [
      comConst.API_ID_MNM0301_03,
      {
        userId: userId,
        screenId: commonInfo().screenId,
      },
    ],
  ];
  const screenId = commonInfo().ScreenID;
  const res = await apiCaller.httpService(reqParam, screenId);
  console.debug(res);
  // 結果コード = "0"（正常終了）の場合
  if (res[0].data.resultCode === comConst.API_RESULT_CODE_SUCCESS) {
    // 削除処理完了メッセージをダイヤログに表示する
    showOkMessage(stringUtil.convertString(comMessage.MNM0301_0300I), closeDialog);

    // エラー表示エリアを非表示にする
    isShowerrorMsg.value = false;

    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラーメッセージリストをエラー表示エリアに表示する
    messageErr.value = res[0].data.messageErr.join("\n");
    // エラー表示エリアを表示する
    isShowerrorMsg.value = true;
  }
  // ローディングの非表示
  loadingModal.isshow(false);

  console.log(stringUtil.convertString(comMessage.COMMON000007I, [screenName, deleteProc]));
};

