      // フォーカス指定
      managerLastNameTextBox.value.focus();
      focusFlg = true;
    }
  }
  if (errInfoMap.value.managerFirstName) {
    if (!focusFlg) {
      // フォーカス指定
      managerLastFirstTextBox.value.focus();
      focusFlg = true;
    }
  }
  if (errInfoMap.value.telephoneNumber) {
    if (!focusFlg) {
      // フォーカス指定
      telephoneNumberTextBox.value.focus();
      focusFlg = true;
    }
  }
  if (errInfoMap.value.mailAddress1) {
    if (!focusFlg) {
      // フォーカス指定
      mailAddress1TextBox.value.focus();
      focusFlg = true;
    }
  }
  if (errInfoMap.value.mailAddress2) {
    if (!focusFlg) {
      // フォーカス指定
      mailAddress2TextBox.value.focus();
      focusFlg = true;
    }
  }
  if (errInfoMap.value.mailAddress3) {
    if (!focusFlg) {
      // フォーカス指定
      mailAddress3TextBox.value.focus();
      focusFlg = true;
    }
  }
};

