/**
 *  ユーザ登録画面の画面間連携データ（パラメータ）を定義する
 *
 *  @version 1.0
 *  @author CSC
 */
import { defineStore } from "pinia";

const MNM0101100Save = defineStore("MNM0101100Save", {
    state: () => {
      return {
        prefCode: "", //都道府県
        cityCode: "", //市区町村
        fiscalYear: "", //会計年度
        notificationStatus: [], //状態
        medicCorpRefNumber: "", //医療法人整理番号
        corporationName: "", //医療法人名称
        fiscalYearEnd: "", //会計月
        notificationType: "", //届出タイプ
        notificationDatetimeStart: "", //届出年月日（開始）
        notificationDatetimeEnd: "", //届出年月日（終了）
        approvalDatetimeStart: "", //承認年月日（開始）
        approvalDatetimeEnd: "", //承認年月日（終了）
        manageInfoStatus: [], //経営情報届出状況
        notificationMethod: [], //届出方法
        displayCount: "", //表示件数
        pageCount: "", //表示頁数
        currentLoginId: "", //ログイン中ユーザーID
      };
    },
    persist: {
      storage: window.sessionStorage,
    },
  });
  
  export default MNM0101100Save;