<!--
 人数入力テキストボックス(自動計算項目)コンポーネント
 @version 1.0
 @author CSC
-->
<template>
  <input
    :id="id"
    type="text"
    class="form-control me-3"
    :disabled="props.ictFlg == comEnum.EnumINPUT_CHANGE_TYPE.CALCULATED_VALUE.val"
    :value="dispValue"
    placeholder=" "
    :class="{ errordisp: inputItemDto.messageErr.length > 0 }"
    @input="handleInput($event)"
    @blur="handleBlur"
    @focus="handleFocus"
  />
</template>
<script setup>
import { onMounted, ref, defineModel, computed } from "vue";
import comEnum from "@/constants/com-enum.js";

/** 内部変数定義 */
// フォーカス有無
const isFocus = ref(false);
// inputタグ へのテンプレート参照
const inputDom = ref(null);
// 内部保持する値
const internalValue = defineModel(); // 部品に指定されたv-model属性を参照（https://ja.vuejs.org/api/sfc-script-setup#definemodel）
// 画面表示する値（フォーカス有無で切り分け）
const dispValue = computed(() => {
  // 自動計算
  if (props.ictFlg == comEnum.EnumINPUT_CHANGE_TYPE.CALCULATED_VALUE.val) {
    // 自動計算ONの場合
    if (props.valList.length > 0) {
      if (props.valList.length == props.valList.filter((val) => val == "-").length) {
        return "-"; // 元データが全て"-"だったら"-"を返す
      } else {
        const numberList = props.valList.map((str) => {
          if (str && isFinite(str)) {
            return Number(str);
          } else {
            return 0;
          }
        });
        return numberList.reduce((num1, num2) => num1 + num2).toLocaleString("ja-JP");
      }
    } else {
      return 0;
    }
  } else {
    // 手動入力の場合
    if (!isFocus.value) {
      let rep = "";
      // 前後の空白は詰める＋NULLは空白にする
      if (internalValue.value != null) {
        rep = (internalValue.value + "").trim().replace(/,/g, "");
      }
      if (
        props.sickbedFeatureReportExist == comEnum.EnumSICKBED_FEATURE_REPORT_EXIST_CLASS.AVAILBLE_DISPATCH_INCLUDE.dispname &&
        !internalValue.value
      ) {
        internalValue.value = "-";
        rep = "-";
      }
      return rep;
    } else {
      return internalValue.value;
    }
  }
});

/** props：引数定義 */
const props = defineProps({
  id: String,
  ictFlg: String,
  inputItemDto: { type: Object, default: { value: "", messageErr: [], messageWarn: [] } },
  valList: { type: Object, default: [] },
  sickbedFeatureReportExist: String,
});

/** emit：イベント定義 */
const emit = defineEmits(["blur", "focus", "input"]);

// 画面生成時のイベント
onMounted(() => {
  // NOP
});

// 内部のinputタグにフォーカスあてる
const focusInput = () => {
  inputDom.value.focus();
};

// フォーカス時のイベント
const handleFocus = (event) => {
  isFocus.value = true; // フラグ更新のみ
  emit("focus", event);
};

// フォーカスアウト時のイベント
function handleBlur(event) {
  isFocus.value = false; // フラグ更新のみ
  emit("blur", event);
}

// テキスト変更時のイベント
const handleInput = (event) => {
  // 画面で入力された値を数値変換して内部値に入れる
  let rep = "";
  // 前後の空白は詰める＋NULLは空白にする
  if (event.target.value != null) {
    rep = (event.target.value + "").trim().replace(/,/g, "");
  }
  if (rep !== "" && isFinite(rep)) {
    // 数値と認識できる値であれば、数値変換して再度文字列にする（先頭の0などが削除される）
    rep = Number(rep) + "";
  }
  internalValue.value = rep; // 数値にできそうなのは数値に変換して保持
  // エラー枠の表示を解除
  event.target.classList.remove("errordisp");
  emit("input", event);
};

/** expose：公開メソッド定義(scriptの一番下に記載) */
defineExpose({
  focusInput,
});
</script>
<style scoped>
/** コンポーネント固有のstyle設定 */
</style>
