<!--
経営情報等Web入力画面用ファイルアップロードダイヤログ
コピー元コンポーネント：カスタムダイアログ（アップロード用）コンポーネント /components/ENT0x/UploadDialog.vue
 @version 1.0
 @author CSC
-->
<template>
  <div :id="id" class="modal fade" tabindex="-1" aria-labelledby="ModalLabel" aria-hidden="true" data-bs-keyboard="false" data-bs-backdrop="static">
    <div class="modal-dialog modal-lg50" style="position: fixed; top: 50%; left: 50%; transform: translate(-50%, -55%)">
      <div class="modal-content" style="max-height: 600px">
        <div class="modal-body">
          <div class="containerx">
            <div class="row mb-2">
              <FileSelectComponent
                ref="fileSelectRef"
                :divClass="{ fileName: 'col-10 ps-2 d-flex align-items-center', clear: 'col', fileInput: 'w-100', dropArea: '' }"
                :dropareamsg="'添付したいファイルをここにドラッグ＆ドロップしてください'"
                :accept="fileType"
                dropAreaAddClass="rounded mt-3 p-3"
              />
            </div>
            <div class="row mt-3">
              <div class="d-grid gap-2 d-md-flex justify-content-md-center">
                <button :id="id + 'upload'" type="button" tabindex="1" class="btn btn-primary" ref="btnclose" @click="upload">アップロード</button>
                <button :id="id + 'close'" type="button" tabindex="1" class="btn btn-secondary" ref="btnclose" @click="close">閉じる</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
<script setup>
import { onMounted, onBeforeUnmount, ref } from "vue";
import { Modal } from "bootstrap";
import FileSelectComponent from "@/components/common/FileSelect.vue";

const btnclose = ref();
const myModal = ref();
const fileSelectRef = ref();

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["upload-dialog-close", "upload-dialog-upload"]);

/** props：このコンポーネントの引数定義 */
const props = defineProps({
  id: String,
  fileType: String,
});

// 画面生成時
onMounted(() => {});

// 画面破棄時
onBeforeUnmount(() => {});

// 初期化メソッド
const init = () => {
  if (!myModal.value) {
    myModal.value = new Modal(document.querySelector("#" + props.id));
  }
};

// ダイアログ表示メソッド
const show = () => {
  if (!!myModal.value) {
    myModal.value.show();
  }
};

// 強制非表示メソッド
const hide = () => {
  if (!!myModal.value) {
    myModal.value.hide();
  }
};

// 閉じるボタンクリック
const close = () => {
  hide(); //ダイアログは消す
  fileSelectRef.value.reset();
  emit("upload-dialog-close");
};

// アップロードボタンクリック
const upload = () => {
  // ダイアログは消さない
  emit("upload-dialog-upload");
};

// 選択したファイル名を返す
const getFile = () => {
  return fileSelectRef.value.getFile();
};

// 選択したファイル名をクリア
const reset = () => {
  fileSelectRef.value.reset();
};

/** expose：公開メソッド定義(scriptの一番下に記載しないと動かないです) */
defineExpose({
  init,
  show,
  hide,
  getFile,
  reset,
});
</script>
<style scoped>
/** コンポーネント固有のstyle設定 */
.modal-lg50 {
  width: 50% !important;
  max-width: 1000px !important;
  min-width: 500px !important;
}
</style>
