<script setup>
import { ref, onMounted } from "vue";
import testInfo from "@/store/test-info.js";
import CommonDialog from "@/components/common/CommonDialog.vue";

/* ---------------------モーダル(async/await)の例---------------------
   async/awaitの仕様を詳しく理解してない場合は参考にしないでください
   https://developer.mozilla.org/ja/docs/Web/JavaScript/Reference/Statements/async_function#%E8%A7%A3%E8%AA%AC
 */
const myModal = ref();
const modalmsg = ref("");
const okBtn = ref("");
const cancelBtn = ref("");
const dialogTestOutput = ref("");
let resolveFunc = (arg) => {};

// 画面マウント時イベント
onMounted(async () => {
  //modal初期化
  myModal.value.init();
});

const showMessage = async (msg) => {
  modalmsg.value = msg;
  okBtn.value = "OK";
  cancelBtn.value = "キャンセル";
  myModal.value.show();
  // asyncがついたメソッドでPromiseオブジェクトを返すとawaitで待機するようになる
  // 参考）https://qiita.com/suin/items/97041d3e0691c12f4974
  return new Promise((resolve) => {
    // Promiseオブジェクトのresolveをglobal変数に退避しておく
    resolveFunc = resolve;
  });
};
const clickHuga = async () => {
  dialogTestOutput.value = "Huga押下時";
  // awaitでPromiseオブジェクト内のresolveが実行されるまで待機する
  let modalReturn = await showMessage("Huga押下");
  dialogTestOutput.value += "⇒Huga押下後(" + modalReturn + ")";
};

const closeModal = (modalReturn) => {
  // Promiseオブジェクト内のresolveを実行する（引数がawaitの箇所の戻り値になる）
  resolveFunc(modalReturn);
};

/* ---------------------store取得の例--------------------- */
const storeMsg = ref();

const syutoku = () => {
  storeMsg.value = testInfo().testMsg;
  testInfo().$reset(); // storeの内容を全削除する
};

function test4alert(arg) {
  alert(arg);
};

/** expose：公開メソッド定義(scriptの一番下に記載しないと動かないです) */
defineExpose({
  test4alert
});

</script>
<template>
  <div class="tab-pane p-2" style="background-color: #cdeedc; height:18rem">
    TEST4
    <div class="row me-0" style="width: 11rem;">
      <button id="btn0" type="button" class="col btn btn-danger ms-2" @click="syutoku">取得</button>
    </div>
    storeから取得したメッセージ：{{ storeMsg }}
    <hr />
    <div class="row me-0 my-2" style="width: 20rem;">
      {{ dialogTestOutput }}<br />
    </div>
    <button id="huga" style="width:4rem;" @click="clickHuga">Huga</button>
  </div>
  <CommonDialog ref="myModal" id="commonDialog4" title="てすと" :okButton="okBtn" :cancelButton="cancelBtn" closeButton=""
  :msg="modalmsg" @common-dialog-close="closeModal" />
</template>

