<!--
 標準ダイアログコンポーネント
 @version 1.0
 @author CSC
-->
<template>
  <div :id="id" class="modal" tabindex="-1"
    aria-labelledby="ModalLabel" aria-hidden="true" data-bs-keyboard="false" data-bs-backdrop="static">
    <div class="modal-dialog modal-lg" style="position: fixed; top: 50%; left: 50%; transform: translate(-50%, -55%);">
      <div class="modal-content" style="max-height: 600px;">
        <div class="modal-body">
          <div class="container">
            <div class="row" style="text-align: left">
              <div class="col common-dialog-title ps-2 mb-3 pt-1 pb-1">
                {{ title }}
              </div>
            </div>
            <div class="row">
              <div class="col">
                <p class="common-dialog-message">
                  {{ msg }}
                </p>
              </div>
            </div>
            <div class="row m-2">
              <div class="d-grid gap-2 d-md-flex justify-content-md-center">
                <button :id="id + 'btn3'" type="button" tabindex="1" class="btn btn-primary"
                 v-if="!!closeButton" ref="btn3" @click="close(3)">
                  {{ closeButton }}
                </button>
                <button :id="id + 'btn1'" type="button" tabindex="1" class="btn btn-success"
                 v-if="!!okButton" ref="btn1" @click="close(1)">
                  {{ okButton }}
                </button>
                <button :id="id + 'btn2'" type="button" tabindex="1" class="btn btn-secondary"
                 v-if="!!cancelButton" ref="btn2" @click="close(2)">
                  {{ cancelButton }}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
<script setup>
import { onMounted, onBeforeUnmount, ref } from "vue";
import { Modal } from "bootstrap";

const btn1 = ref();
const btn2 = ref();
const btn3 = ref();
const myModal = ref();

/** このコンポーネントから呼び出し元画面に送るイベント定義 */
const emit = defineEmits(["common-dialog-close"]);

/** props：このコンポーネントの引数定義 */
const props = defineProps({
  id: String,
  msg: String,
  title: String,
  okButton: {type:String, default:"OK"},
  cancelButton: {type:String, default:"キャンセル"},
  closeButton: {type:String, default:""}
});

// 画面生成時
onMounted(() =>{
    // modal表示完了時の初期化イベント追加
    document.addEventListener('shown.bs.modal', shown);
});

// 画面破棄時
onBeforeUnmount(() =>{
    // modal表示完了時の初期化イベント削除
    document.removeEventListener('shown.bs.modal', shown);
});

// shown.bs.modalイベントで呼ばれる関数
const shown = () =>{
  // if(!!btn1.value){
  //   // document.getElementById(btn1.value.id).focus();
  //   // btn1.value.focus();
  //   setTimeout(() => {
  //     if(!!btn1.value){
  //       document.getElementById(btn1.value.id).focus();
  //       btn1.value.focus();
  //     }
  //   }, 500);
    
  // }
}

// closeイベント
const close = (arg1) => {
  if (!!myModal.value) {
    myModal.value.hide();
  }
  emit("common-dialog-close", arg1);
};

// 初期化メソッド
const init = () => {
  if (!myModal.value) {
    myModal.value = new Modal(document.querySelector("#" + props.id));
  }
};

// ダイアログ表示メソッド
const show = () => {
  if (!!myModal.value) {
    myModal.value.show();
  }
};

// 強制非表示メソッド
const hide = () => {
  close(0);
};

/** expose：公開メソッド定義(scriptの一番下に記載しないと動かないです) */
defineExpose({
  init,
  show,
  hide
});
</script>
<style scoped>
/** コンポーネント固有のstyle設定 */
.common-dialog-title {
  font-size: 1.25rem;
  font-weight: 100%;
  line-height: 150%;
}
.common-dialog-message {
  width:  15rem;
  line-height: 150%;
  max-height: calc(1.5em * 12);
  text-align: left;
  margin-right: auto;
  margin-left: auto;
  white-space: pre-wrap;
  word-break: break-all;
  overflow-y: hidden;
}
</style>
