<!--
 メール詳細画面
 @version 1.0
 @author C
-->
<script setup>
import { ref, onMounted, reactive } from 'vue';
import { useRouter } from 'vue-router';
import Header from '@/components/common/Header.vue';
import Footer from '@/components/common/Footer.vue';
import Menu from '@/components/common/Menu.vue';
import Breadcrumb from '@/components/common/Breadcrumb.vue';
import CommonDialog from "@/components/common/CommonDialog.vue";
import StatusExplanation from '@/components/ENT0401100/StatusExplanation.vue';
import MedicCorpInfo from '@/components/ENT0401100/MedicCorpInfo.vue';
import comConst from '@/constants/com-const.js';
import comEnum from '@/constants/com-enum.js';
import commonInfo from '@/store/common/common-info.js';
import targetCorp from '@/store/common/target-corp.js';
import StringUtil from '@/utils/common/string-util.js';
import comMessage from '@/constants/com-message.js';
import loadingModal from '@/utils/common/loading-modal.js';
import apiCaller from '@/utils/common/api-caller.js';
import comDate from '@/utils/common/com-date.js';
import ENT0201100Param from '@/store/ENT0201100/ent0201100-param.js';

/** VueRouter */
const router = useRouter();

// メール情報
const mailInfo = ref({});

/** 画面名 */
const screenName = 'メール詳細';
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();

// 初期表示
const ENT0201300E01 = async () => {
	// 開始ログ
	console.log(StringUtil.convertString(comMessage.COMMON000004I, [screenName]));

	// ローディングの表示
	loadingModal.isshow(true);

	// メール情報画面照会APIの呼び出し
	const reqManageInfoParam = [
		[
			comConst.  API_ID_ENT0201_06,
			{
        emailId: commonInfo().emailId
			},
		],
	];
	const res = await apiCaller.httpService(reqManageInfoParam, commonInfo().screenId);
	// 結果コード = "0"（正常終了）の場合
	if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
		// ローディングの非表示
		loadingModal.isshow(false);
		mailInfo.value = res[0].data.mailInfo || {};
    mailInfo.value.CONTENT = mailInfo.value.CONTENT.replace(/\r?\n/g, "<br/>")
	}
	// 上記以外
	else {
		// ローディングの非表示
		loadingModal.isshow(false);
		// 終了ログ
		console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
		// システムエラー画面へ遷移
		router.push({ name: comConst.UTL9999993 });
	}

	// 終了ログ
	console.log(StringUtil.convertString(comMessage.COMMON000005I, [screenName]));
};

/**
 * Dialog閉じるイベント
 * @type {String}　Dialog戻り値
 */
const closeDialog = (modalReturn) => {
  if (modalReturn == 1) {
    if ("delete" === eventName.value) {
      // メール情報削除
      ENT0201100E03();
    }
  }
};

/**
 * 注文一覧画面
 */
const ENT0201300E06 = () => {	
  // 「ENT0201200：注文一覧画面」へ遷移する。
  router.push({ name: comConst.ENT0201200});
};

/**
 * 確認ダイアログ表示
 * タイトルなし、メッセージ表示
 * @type {String}　メッセージ
 */
const showMessage = (msg) => {
  modalmsg.value = msg;
  modalOkBtn.value = "OK";
  myModal.value.show();
};

// 画面マウント時イベント
onMounted(async () => {
	// 自分の画面IDを設定
	commonInfo().screenId = comConst.ENT0201300;
	// modal初期化
	myModal.value.init();

	// 初期表示
	await ENT0201300E01();
});

</script>

<template>
  <div class="menu">	
	<button class="menu-btn" v-on:click="ENT0201300E06">オーダ一覧</button>
  </div>
  <div class="container">
    <h2 class="title">メール情報</h2>

    <table class="mail-table">
      <tbody>
        <tr v-if="mailInfo.CONTENT != ''">
          <td width="120px">メールアドレス</td>
          <td width="100%">{{ mailInfo.EMAIL_ADDRESS }}</td>
        </tr>
        <tr v-if="mailInfo.CONTENT != ''">
          <td width="120px">受信サーバ</td>
          <td width="100%">{{ mailInfo.SUBJECT }}</td>
        </tr>
        <tr v-if="mailInfo.CONTENT != ''">
          <td width="120px">メール内容</td>
          <td width="100%"><div v-html="mailInfo.CONTENT"></div></td>
        </tr>
        <tr v-if="mailInfo.CONTENT === ''">
          <td colspan="5" class="no-data">データがありません</td>
        </tr>
      </tbody>
    </table>
  </div>
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

<style scoped>

.title {
  font-size: 24px;
  text-align: center;
  margin-bottom: 20px;
}

.actions {
  text-align: right;
  margin-bottom: 10px;
}

.mail-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 14px;
}

.mail-table th,
.mail-table td {
  border: 1px solid #ccc;
  padding: 8px;
  text-align: left;
}

.mail-table th {
  background-color: #f4f4f4;
}

.btn {
  padding: 6px 12px;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 13px;
}

.btn.add {
  background-color: #28a745;
  color: white;
}

.btn.edit {
  background-color: #007bff;
  color: white;
  margin-right: 6px;
}

.btn.delete {
  background-color: #dc3545;
  color: white;
}

.no-data {
  text-align: center;
  color: #888;
  font-style: italic;
}
</style>
