<script setup>
import { ref, onMounted } from "vue";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import CommonDialog from "@/components/common/CommonDialog.vue";
import commonInfo from "@/store/common/common-info.js";
import targetCorp from "@/store/common/target-corp.js";
import { useRouter } from "vue-router";
import apiCaller from "@/utils/common/api-caller.js";
import validator from "@/utils/common/validator.js";
import StringUtil from "@/utils/common/string-util.js";
import comConst from "@/constants/com-const.js";
import comMessage from "@/constants/com-message.js";
import ATH0101200Param from "@/store/ATH0101200/ath0101200-param.js";

// ルータ
const router = useRouter();
const props = defineProps({
  shopId: String,
  languageType: String,
});
// ポップアップ画面メッセージ
const modalmsg = ref("");
// ポップアップ画面OKボタン
const modalOkBtn = ref("OK");
// ポップアップ画面
const myModal = ref();
// エラーメッセージID、エラーメッセージ
const errorMsgId = ref("");
// 警告メッセージID
const warnMsgId = ref("");

const mode = ref("");
mode.value = SYS_ENV_MODE; // 設定ファイルから取得してセット
/** ログ用 */
const screenName = "トップ画面";
const E01Name = "初期表示";
var ATH0101100Data = ref([]);
var messageErrFlg = ref(false);
var messageErr = ref("");

// 画面マウント時イベント
onMounted(() => {
  // modal初期化
  myModal.value.init();
  ATH0101100E01();
});

/**
* 初期表示イベント
*/
const ATH0101100E01 = async () => {

  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E01Name]));


  // 利用規約同意API呼出し
  const reqParam = [
    [
      comConst.API_ID_ATH0101_01,
      { shopId: commonInfo().shopId ,
        languageType: commonInfo().languageType 
      },
    ],
  ];
  const res = await apiCaller.httpServiceWithShield(reqParam, commonInfo().screenId);
  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    // 結果格納
    ATH0101100Data.value = res[0].data;

    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラーメッセージを表示する
    messageErrFlg.value = true;
    messageErr.value = res[0].data.error;
  }

  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E01Name]));
};

// 言語選択
const languageChange = async(languageType) => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, "言語選択"]));
  
  // 商品一覧取得API呼出し
  const reqParam = [
    [
      comConst.API_ID_ATH0101_01,
      { shopId: commonInfo().shopId,
        languageType: languageType
      },
    ],
  ];
  const res = await apiCaller.httpServiceWithShield(reqParam, commonInfo().screenId);
  // 結果コード = "0"（正常終了）の場合
  if (res[0].status === comConst.API_RESULT_CODE_SUCCESS) {
    // 結果格納
    ATH0101100Data.value = res[0].data;

    // 結果コード = "1"（異常終了）の場合
  } else {
    // エラーメッセージを表示する
    messageErrFlg.value = true;
    messageErr.value = res[0].data.messageErr.join("\n");
  }
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, "言語選択"]));
}

// Dialog閉じるイベント
const closeDialog = (modalReturn) => {
  if ("ATH010110005E" === errorMsgId.value) {
    // OKボタン押下後、「ATH0103100：パスワードリセット画面」へ遷移する。
    router.push({ name: comConst.ATH0103100 });
  } else if ("ATH010110001I" === warnMsgId.value) {
    // OKボタン押下後、「ATH0101200：利用規約同意画面」へ遷移する。
    router.push({ name: comConst.ATH0101200 });
  } else {
    // 「UTL0101100：トップ画面」へ遷移する。
    router.push({ name: comConst.UTL0101100 });
  }
};

// 商品クリック
const itemClick = (productInfo) => {
  ATH0101200Param().productInfo = productInfo;
  // 商品リンク押下後、「ATH0101200：商品詳細画面」へ遷移する。
  router.push({ name: comConst.ATH0101200 });
};
</script>

<template>
  <Header />
  <!-- 菜单内容区域 -->
  <main>
    <div>
      <!-- エラー表示エリア -->
      <div class="align-items-center center place_items_center">
        <div class="alert alert-danger text-danger width_100" v-if="messageErrFlg" role="alert">{{ messageErr }}</div>
      </div>
      <section class="menu-items">
        <!-- 菜单项1 -->
        <div v-for="(obj, index) in ATH0101100Data" :key="index" class="menu-item" v-on:click="itemClick(obj)">
          <img :src="obj.PRODUCT_IMG" :alt="obj.language[commonInfo().languageType]?.PRODUCT_NAME" class="menu-item-img">
          <div class="menu-item-info">
            <h3 class="item-name">{{ obj.language[commonInfo().languageType]?.PRODUCT_NAME }}</h3>
            <p class="item-description">{{ obj.language[commonInfo().languageType]?.PRODUCT_DETAIL }}</p>
            <span class="item-price">{{ Number(obj.PRICE).toLocaleString() }}{{ obj.PRICE_CURRENCY }}</span>
          </div>
        </div>

        <!-- 更多菜单项 -->
        <!-- 可以继续添加菜单项 -->
      </section>
    </div>
  </main>
  <Footer />
  <CommonDialog
    ref="myModal"
    id="commonDialog"
    :cancelButton="''"
    :closeButton="''"
    :msg="modalmsg"
    :okButton="modalOkBtn"
    @common-dialog-close="closeDialog"
  />
</template>

