/**
 *  日付に関する共通機能クラスです。
 *
 *  @version 1.0
 *  @author CSC
 */
export default class ComDate {

    /**
     * 現在日付を取得し、yyyy/MM/dd HH:mm形式の文字列を返却する
     *
     * @reterns {String} 現在日時
     */
    static getTodayYMDHM() {
        const now = new Date();
        const dateString = this.formatDateYMDHM(now);
        return dateString;
    }

    /**
     * 現在日付を取得し、yyyy/MM形式の文字列を返却する
     *
     * @reterns {String} 現在日時
     */
    static getTodayYM() {
        const now = new Date();
        const dateString = this.formatDateYM(now);
        return dateString;
    }

    /**
     * 「現在日時－1ヵ月」を取得し、yyyy/MM/dd HH:mm形式の文字列を返却する
     *
     * @reterns {String} 現在日時－1か月
     */
    static getLastMonthYMDHM() {
        const now = new Date();
        now.setMonth(now.getMonth() - 1);
        const dateString = this.formatDateYMDHM(now);
        return dateString;
    }

    /**
     * 「現在日時－1ヵ月」を取得し、yyyy/MM形式の文字列を返却する
     *
     * @reterns {String} 現在日時－1か月
     */
    static getLastMonthYM() {
        const now = new Date();
        now.setMonth(now.getMonth() - 1);
        const dateString = this.formatDateYM(now);
        return dateString;
    }

    /**
     * 「現在日時の1年前」を取得し、yyyy/MM形式の文字列を返却する
     *
     * @reterns {String} 現在日時－1年
     */
    static getLastYearYM() {
        const now = new Date();
        now.setYear(now.getFullYear() - 1);
        const dateString = this.formatDateYM(now);
        return dateString;
    }

    /**
     * 「現在日時の前年－1ヵ月」を取得し、yyyy/MM形式の文字列を返却する
     *
     * @reterns {String} 現在日時の前年－1ヵ月
     */
    static getLastYearLastMonthYM() {
        const now = new Date();
        now.setYear(now.getFullYear() - 1);
        now.setMonth(now.getMonth() - 1);
        const dateString = this.formatDateYM(now);
        return dateString;
    }

    /**
     * 「指定日の1年後」を取得し、yyyy/MM形式の文字列を返却する
     *
     * @param {Date} date - 指定日
     * @reterns {String} 指定日+1年
     */
    static getNextYearYM(date) {
        const now = new Date(date);
        now.setMonth(now.getMonth() + 12);
        const dateString = this.formatDateYM(now);
        return dateString;
    }

    /**
     * 指定日をyyyy/MM/dd HH:mm形式にフォーマットした文字列を返却する
     *
     * @param {Date} date - 指定日
     * @reterns {String} フォーマット後の指定日
     */
    static formatDateYMDHM(date) {
        const options = {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: 'numeric',
            minute: 'numeric',
        }
        return date.toLocaleDateString('ja-JP', options);
    }

    /**
     * 指定日をyyyy/MM/dd形式にフォーマットした文字列を返却する
     *
     * @param {Date} date - 指定日
     * @reterns {String} フォーマット後の指定日
     */
    static formatDateYMD(date) {
        const options = {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
        }
        return date.toLocaleDateString('ja-JP', options);
    }

    /**
     * 指定日をyyyy/MM形式にフォーマットした文字列を返却する
     *
     * @param {Date} date - 指定日
     * @reterns {String} フォーマット後の指定日
     */
    static formatDateYM(date) {
        const options = {
            year: 'numeric',
            month: '2-digit',
        }
        return date.toLocaleDateString('ja-JP', options);
    }

	/**
	 * 現在の時刻を取得（デバッグ用）
	 * 
	 * @returns YYYY/MM/DD HH:Mi:ss.SSS
	 */
	static getNowTime(date) {
		//var now = new Date();
		let xYear = date.getFullYear();
		let xMonth = date.getMonth() + 1;
		let xDate = date.getDate();
		let xHour = date.getHours();
		let xMin = date.getMinutes();
		let xSec = date.getSeconds();
		let xMsec = date.getMilliseconds();

		return xYear + "/" + xMonth + "/" + xDate + "　" + xHour + ":" + xMin + ":" + xSec + "." + xMsec;
	}

    /**
     * 指定日をyyyy-MM-dd形式にフォーマットした文字列を返却する
     *
     * @param {Date|String|Number} date - 指定日（Dateオブジェクトまたは、yyyyMMddまたはyyyy/MM/dd形式文字列・数値）
     * @reterns {String} フォーマット後の指定日
     */
    static formatDateYMDHyphen(date) {
        let wkDate = new Date('');

        if (typeof date == 'number' || /^\d+$/.test(date)) { // 数値の場合
            // 文字列化
            let wkString = date + '';
            if(wkString.length == 8){
                // yyyy/MM/dd形式に変更
                wkString = wkString.substring(0, 4) + '/' + wkString.substring(4, 6) + '/' + wkString.substring(6, 8);
            } else {
                // 8文字（yyyyMMdd形式）でない場合は、不正なフォーマットなのでDate型にさせない
                wkString = '';
            }
            wkDate = new Date(wkString);

        } else if(typeof date == 'string'){ // 文字列の場合
           if(date.replaceAll('-', '/').split("/").length == 3){
            // Date型へ変換(yyyy/MM/dd・yyyy/M/d・yyyy-MM-dd 形式であれば正しく変換可能)
            wkDate = new Date(date);
           } else {
            // 区切り文字が足りない場合は不正なDate型へ変換させる
            wkDate = new Date('');
           }

        } else if(Object.prototype.toString.call(date) == '[object Date]'){ // Date型の場合
            wkDate = date;
        }

        // 正しいDate型か判定
        let isVaildDate = !isNaN(wkDate.getTime());

        if(isVaildDate) {
            // yyyy-MM-dd形式の文字列へ変換して返す
            return wkDate.toLocaleDateString('ja-JP', {year:'numeric', month:'2-digit', day:'2-digit'}).replaceAll('/', '-');
        } else {
            // 不正な日付の場合は空文字を返す
            return '';
        }
    }
}

