<script setup>
import { onMounted } from "vue";
import { useRouter } from "vue-router";
import Header from "@/components/common/Header.vue";
import Footer from "@/components/common/Footer.vue";
import comMessage from "@/constants/com-message.js";
import comConst from "@/constants/com-const.js";
import commonInfo from "@/store/common/common-info.js";
import StringUtil from "@/utils/common/string-util.js"

//////////////////////////
// データ定義
//////////////////////////
const router = useRouter();
const screenName = "システムエラー";
const E00Name = "トップ画面リンク";

//////////////////////////
// メソッド
//////////////////////////
const linkClick = async () => {
  // 処理開始ログ
  console.log(StringUtil.convertString(comMessage.COMMON000006I, [screenName, E00Name]));
  router.push({ name: comConst.UTL0101100 });
  // 処理終了ログ
  console.log(StringUtil.convertString(comMessage.COMMON000007I, [screenName, E00Name]));
};

//////////////////////////
// ライフサイクルフック
//////////////////////////
/**
* 画面マウント時イベント
*/
onMounted(() => {
  // 自分の画面IDを設定
  commonInfo().screenId = comConst.UTL9999993;
  commonInfo().breadcrumbList = "";
});
</script>

<template>
  <Header :isShow="false" />
  <div class="contents orgheight align-items-center">
    <div class="text-center">
      <label for="errMsg">予期しないエラーが発生しました。画面下に記載された問い合わせ先に連絡してください。<br />
        <a href="#" @click.prevent.stop="linkClick">トップ画面へ戻る</a>
      </label>
    </div>
  </div>
  <Footer />
</template>

<style scoped>
.orgheight {
  display: grid;
}
</style>